  CARDIOVASCULAR = 'Cardiovascular',
  RESPIRATORY = 'Respiratory',
  ABDOMINAL = 'Abdominal',
  NEUROLOGICAL = 'Neurological',
  MUSCULOSKELETAL = 'Musculoskeletal',
  ENDOCRINE = 'Endocrine',
  VASCULAR = 'Vascular',
  CRANIAL_NERVES = 'Cranial Nerves'
}

export interface ExamStep {
  id: string;
  title: string;
  description: string;
  category: 'Preparation' | 'Inspection' | 'Palpation' | 'Percussion' | 'Auscultation' | 'Special Tests' | 'Conclusion';
}

