import { GoogleGenAI, Type } from "@google/genai";
import { ClinicalCorrelation } from "../types";

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY! });
  }

  async getClinicalCorrelation(sign: string, context: string): Promise<ClinicalCorrelation> {
    const response = await this.ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Explain the clinical significance of '${sign}' in a ${context} physical examination. Provide depth suitable for a senior medical student or resident.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            sign: { type: Type.STRING },
            pathophysiology: { type: Type.STRING, description: "Detailed biological mechanism" },
            causes: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING },
              description: "List of top 3-5 differential diagnoses"
            },
            clinicalSignificance: { type: Type.STRING, description: "What this means for the patient and diagnosis" }
          },
          required: ["sign", "pathophysiology", "causes", "clinicalSignificance"]
        }
      }
    });

    try {
      return JSON.parse(response.text);
    } catch (error) {
      console.error("Failed to parse Gemini response", error);
      throw new Error("Invalid response from AI");
    }
  }

  async getExaminationSummary(examName: string): Promise<string> {
    const response = await this.ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Provide a concise clinical summary and purpose of the ${examName} following the style of Talley and O'Connor. Include key things not to miss.`
    });
    return response.text || "No summary available.";
  }
}

