import React, { useState, useEffect } from 'react';
import { Examination, ClinicalCorrelation } from '../types';
import { GeminiService } from '../services/geminiService';
import { 
  ChevronRight, 
  Info, 
  CheckCircle2, 
  Zap, 
  Loader2,
  AlertTriangle,
  Lightbulb
} from 'lucide-react';

interface ExamViewProps {
  exam: Examination;
  onBack: () => void;
}

const ExamView: React.FC<ExamViewProps> = ({ exam, onBack }) => {
  const [activeTab, setActiveTab] = useState<'steps' | 'summary' | 'correlation'>('steps');
  const [summary, setSummary] = useState<string | null>(null);
  const [loadingSummary, setLoadingSummary] = useState(false);
  const [correlation, setCorrelation] = useState<ClinicalCorrelation | null>(null);
  const [loadingCorrelation, setLoadingCorrelation] = useState(false);
  const [selectedSign, setSelectedSign] = useState<string | null>(null);

  const gemini = new GeminiService();

  useEffect(() => {
    const fetchSummary = async () => {
      setLoadingSummary(true);
      try {
        const text = await gemini.getExaminationSummary(exam.name);
        setSummary(text);
      } catch (err) {
        console.error(err);
      } finally {
        setLoadingSummary(false);
      }
    };
    fetchSummary();
  }, [exam.id]);

  const fetchCorrelation = async (sign: string) => {
    setSelectedSign(sign);
    setLoadingCorrelation(true);
    try {
      const data = await gemini.getClinicalCorrelation(sign, exam.system);
      setCorrelation(data);
      setActiveTab('correlation');
    } catch (err) {
      console.error(err);
    } finally {
      setLoadingCorrelation(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto py-8 px-4">
      <button 
        onClick={onBack}
        className="text-sm font-medium text-blue-600 hover:text-blue-700 flex items-center gap-1 mb-6"
      >
        <ChevronRight className="w-4 h-4 rotate-180" />
        Back to Library
      </button>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden mb-8">
        <div className="p-8 bg-gradient-to-br from-blue-600 to-indigo-700 text-white">
          <div className="flex items-center gap-2 mb-2">
            <span className="px-2 py-0.5 bg-blue-400/30 rounded text-xs font-medium backdrop-blur-sm border border-blue-300/30">
              {exam.system}
            </span>
          </div>
          <h2 className="text-3xl font-bold mb-3">{exam.name}</h2>
          <p className="text-blue-100 max-w-2xl">{exam.shortDescription}</p>
        </div>

        <div className="flex border-b border-slate-200">
          <button 
            onClick={() => setActiveTab('steps')}
            className={`flex-1 py-4 text-sm font-semibold border-b-2 transition-all ${
              activeTab === 'steps' ? 'border-blue-600 text-blue-600' : 'border-transparent text-slate-500 hover:text-slate-700'
            }`}
          >
            Examination Steps
          </button>
          <button 
            onClick={() => setActiveTab('summary')}
            className={`flex-1 py-4 text-sm font-semibold border-b-2 transition-all ${
              activeTab === 'summary' ? 'border-blue-600 text-blue-600' : 'border-transparent text-slate-500 hover:text-slate-700'
            }`}
          >
            Clinical Overview
          </button>
          <button 
            disabled={!correlation}
            onClick={() => setActiveTab('correlation')}
            className={`flex-1 py-4 text-sm font-semibold border-b-2 transition-all ${
              activeTab === 'correlation' ? 'border-blue-600 text-blue-600' : 'border-transparent text-slate-400 cursor-not-allowed'
            }`}
          >
            Sign Correlation
          </button>
        </div>

        <div className="p-8">
          {activeTab === 'steps' && (
            <div className="space-y-8">
              {['Preparation', 'Inspection', 'Palpation', 'Percussion', 'Auscultation', 'Special Tests', 'Conclusion'].map(cat => {
                const catSteps = exam.steps.filter(s => s.category === cat);
                if (catSteps.length === 0) return null;
                return (
                  <div key={cat}>
                    <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-4 flex items-center gap-2">
                      <span className="w-1 h-4 bg-blue-500 rounded-full"></span>
                      {cat}
                    </h3>
                    <div className="space-y-4">
                      {catSteps.map((step) => (
                        <div key={step.id} className="group relative pl-8 pb-4 border-l border-slate-100 last:border-0">
                          <div className="absolute left-[-5px] top-1.5 w-2.5 h-2.5 rounded-full bg-slate-200 group-hover:bg-blue-500 transition-colors"></div>
                          <div className="flex justify-between items-start gap-4">
                            <div>
                              <h4 className="font-bold text-slate-800 mb-1">{step.title}</h4>
                              <p className="text-sm text-slate-600 leading-relaxed">{step.description}</p>
                            </div>
                            <button 
                              onClick={() => fetchCorrelation(step.title)}
                              className="p-2 hover:bg-blue-50 rounded-lg text-blue-500 transition-all flex items-center gap-1 text-xs font-medium whitespace-nowrap"
                              title="Ask AI for clinical significance"
                            >
                              {loadingCorrelation && selectedSign === step.title ? (
                                <Loader2 className="w-4 h-4 animate-spin" />
                              ) : (
                                <Zap className="w-4 h-4" />
                              )}
                              Correlation
                            </button>
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                );
              })}
            </div>
          )}

          {activeTab === 'summary' && (
            <div className="prose prose-slate max-w-none">
              {loadingSummary ? (
                <div className="flex flex-col items-center justify-center py-12">
                  <Loader2 className="w-8 h-8 text-blue-600 animate-spin mb-4" />
                  <p className="text-slate-500 text-sm italic">Synthesizing clinical expertise...</p>
                </div>
              ) : (
                <div className="bg-slate-50 rounded-xl p-6 border border-slate-100">
                   <div className="flex items-center gap-2 text-blue-600 mb-4">
                    <Info className="w-5 h-5" />
                    <span className="font-bold">Expert Summary</span>
                  </div>
                  <div className="text-slate-700 leading-relaxed whitespace-pre-wrap">
                    {summary}
                  </div>
                </div>
              )}
            </div>
          )}

          {activeTab === 'correlation' && correlation && (
            <div className="animate-in fade-in slide-in-from-bottom-4 duration-300">
              <div className="flex items-center justify-between mb-6">
                <div>
                  <p className="text-xs font-bold text-blue-600 uppercase tracking-widest mb-1">Clinical Sign Detail</p>
                  <h3 className="text-2xl font-bold text-slate-900">{correlation.sign}</h3>
                </div>
                <div className="bg-amber-50 text-amber-700 p-3 rounded-xl border border-amber-100 flex items-center gap-3">
                  <Lightbulb className="w-6 h-6" />
                  <div>
                    <p className="text-[10px] font-bold uppercase">Pro Tip</p>
                    <p className="text-xs font-medium">Always correlate with patient history.</p>
                  </div>
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <div className="md:col-span-2 space-y-6">
                  <section>
                    <h4 className="text-sm font-bold text-slate-800 mb-2 flex items-center gap-2">
                      <Zap className="w-4 h-4 text-blue-500" />
                      Pathophysiology
                    </h4>
                    <p className="text-slate-600 text-sm leading-relaxed bg-slate-50 p-4 rounded-lg border border-slate-100">
                      {correlation.pathophysiology}
                    </p>
                  </section>
                  <section>
                    <h4 className="text-sm font-bold text-slate-800 mb-2 flex items-center gap-2">
                      <CheckCircle2 className="w-4 h-4 text-green-500" />
                      Clinical Significance
                    </h4>
                    <p className="text-slate-600 text-sm leading-relaxed">
                      {correlation.clinicalSignificance}
                    </p>
                  </section>
                </div>

                <div className="space-y-6">
                  <section className="bg-slate-900 text-white p-5 rounded-2xl shadow-lg">
                    <h4 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-4">Top Differentials</h4>
                    <ul className="space-y-3">
                      {correlation.causes.map((cause, idx) => (
                        <li key={idx} className="flex items-start gap-2 text-sm">
                          <span className="w-5 h-5 rounded-full bg-blue-500 flex-shrink-0 flex items-center justify-center text-[10px] font-bold">
                            {idx + 1}
                          </span>
                          {cause}
                        </li>
                      ))}
                    </ul>
                  </section>

                  <div className="p-4 bg-red-50 rounded-xl border border-red-100 text-red-700 text-xs flex gap-3">
                    <AlertTriangle className="w-5 h-5 flex-shrink-0" />
                    <div>
                      <p className="font-bold mb-1">Red Flag Warning</p>
                      <p>Sudden onset or associated with systemic symptoms requires urgent review.</p>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default ExamView;

import React, { useState, useMemo } from 'react';
