              ))}

              {filteredExams.length === 0 && (
                <div className="col-span-full py-20 bg-slate-100 rounded-3xl border-2 border-dashed border-slate-200 flex flex-col items-center justify-center text-slate-400">
                  <Search className="w-12 h-12 mb-4 opacity-20" />
