                  <div className="p-6 bg-red-50 rounded-2xl border border-red-100 text-red-800 flex gap-4 shadow-sm">
                    <AlertTriangle className="w-6 h-6 flex-shrink-0" />
                    <div>
                      <p className="font-black text-[10px] uppercase tracking-wider mb-1">Critical Warning</p>
                      <p className="text-xs font-medium leading-relaxed">If associate with tachycardia or tachypnea, initiate stabilization protocol immediately.</p>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default ExamView;

import React, { useState, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import ExamView from './components/ExamView';
