import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Examination, ClinicalCorrelation, ExamStep, AudioSimulation } from '../types';
import { GeminiService } from '../services/geminiService';
import { 
  ChevronRight, 
  Info, 
  CheckCircle2, 
  Zap, 
  Loader2,
  AlertTriangle,
  Lightbulb,
  Play,
  Pause,
  ClipboardList,
  Target,
  Volume2,
  XCircle,
  ChevronDown,
  ChevronUp,
  Ear
} from 'lucide-react';

interface ExamViewProps {
  exam: Examination;
  onBack: () => void;
}

const ExamView: React.FC<ExamViewProps> = ({ exam, onBack }) => {
  const [activeTab, setActiveTab] = useState<'steps' | 'summary' | 'correlation' | 'media' | 'audio'>('steps');
  const [summary, setSummary] = useState<string | null>(null);
  const [loadingSummary, setLoadingSummary] = useState(false);
  const [correlation, setCorrelation] = useState<ClinicalCorrelation | null>(null);
  const [loadingCorrelation, setLoadingCorrelation] = useState(false);
  const [selectedSign, setSelectedSign] = useState<string | null>(null);

  const [checkedSteps, setCheckedSteps] = useState<Set<string>>(new Set());
  const [isChecklistMode, setIsChecklistMode] = useState(false);
  const [expandedStep, setExpandedStep] = useState<string | null>(null);

  // Audio state
  const [currentAudio, setCurrentAudio] = useState<AudioSimulation | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  const gemini = new GeminiService();

  useEffect(() => {
    const fetchSummary = async () => {
      setLoadingSummary(true);
      try {
        const text = await gemini.getExaminationSummary(exam.name);
        setSummary(text);
      } catch (err) {
        console.error(err);
      } finally {
        setLoadingSummary(false);
      }
    };
    fetchSummary();
  }, [exam.id]);

  const fetchCorrelation = async (sign: string) => {
    setSelectedSign(sign);
    setLoadingCorrelation(true);
    try {
      const data = await gemini.getClinicalCorrelation(sign, exam.system);
      setCorrelation(data);
      setActiveTab('correlation');
    } catch (err) {
      console.error(err);
    } finally {
      setLoadingCorrelation(false);
    }
  };

  const toggleStep = (id: string) => {
    setCheckedSteps(prev => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  };

  const playAudio = (sim: AudioSimulation) => {
    if (currentAudio?.id === sim.id) {
      if (isPlaying) {
        audioRef.current?.pause();
        setIsPlaying(false);
      } else {
        audioRef.current?.play();
        setIsPlaying(true);
      }
    } else {
      setCurrentAudio(sim);
      setIsPlaying(true);
      if (audioRef.current) {
        audioRef.current.src = sim.url;
        audioRef.current.play();
      }
    }
  };

  const progress = useMemo(() => {
    if (exam.steps.length === 0) return 0;
    return Math.round((checkedSteps.size / exam.steps.length) * 100);
  }, [checkedSteps, exam.steps]);

  return (
    <div className="max-w-4xl mx-auto py-8 px-4">
      <audio ref={audioRef} onEnded={() => setIsPlaying(false)} />

      <div className="flex items-center justify-between mb-6">
        <button 
          onClick={onBack}
          className="text-sm font-medium text-blue-600 hover:text-blue-700 flex items-center gap-1"
        >
          <ChevronRight className="w-4 h-4 rotate-180" />
          Back to Library
        </button>

        <button 
          onClick={() => setIsChecklistMode(!isChecklistMode)}
          className={`px-4 py-2 rounded-lg text-sm font-bold flex items-center gap-2 transition-all ${
            isChecklistMode 
              ? 'bg-green-100 text-green-700 border border-green-200 shadow-inner' 
              : 'bg-white text-slate-600 border border-slate-200 hover:bg-slate-50'
          }`}
        >
          <ClipboardList className="w-4 h-4" />
          {isChecklistMode ? 'Practicing (Checklist On)' : 'Study Mode (Checklist Off)'}
        </button>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden mb-8">
        <div className="p-8 bg-gradient-to-br from-blue-600 to-indigo-700 text-white relative overflow-hidden">
          <div className="relative z-10">
            <div className="flex items-center gap-2 mb-2">
              <span className="px-2 py-0.5 bg-blue-400/30 rounded text-xs font-medium backdrop-blur-sm border border-blue-300/30">
                {exam.system}
              </span>
            </div>
            <h2 className="text-3xl font-bold mb-3">{exam.name}</h2>
            <p className="text-blue-100 max-w-2xl">{exam.shortDescription}</p>

            {isChecklistMode && (
              <div className="mt-6">
                <div className="flex justify-between items-center mb-2">
                  <span className="text-xs font-bold uppercase tracking-wider text-blue-200 flex items-center gap-2">
                    <Target className="w-3 h-3" />
                    OSCE Progress
                  </span>
                  <span className="text-xs font-bold">{progress}%</span>
                </div>
                <div className="w-full h-2 bg-blue-900/40 rounded-full overflow-hidden border border-blue-400/20">
                  <div 
                    className="h-full bg-green-400 transition-all duration-500 ease-out" 
                    style={{ width: `${progress}%` }}
                  />
                </div>
              </div>
            )}
          </div>
          <div className="absolute top-[-20px] right-[-20px] opacity-10 pointer-events-none">
            <ClipboardList className="w-64 h-64" />
          </div>
        </div>

        <div className="flex border-b border-slate-200 overflow-x-auto bg-slate-50/50">
          {[
            { id: 'steps', label: 'Protocol', icon: <ClipboardList className="w-4 h-4" /> },
            { id: 'media', label: 'Video Demo', icon: <Play className="w-4 h-4" /> },
            { id: 'audio', label: 'Auscultation', icon: <Ear className="w-4 h-4" /> },
            { id: 'summary', label: 'Summary', icon: <Info className="w-4 h-4" /> },
            { id: 'correlation', label: 'Analysis', icon: <Zap className="w-4 h-4" /> }
          ].map(tab => (
            <button 
              key={tab.id}
              onClick={() => setActiveTab(tab.id as any)}
              className={`flex-1 min-w-[120px] py-4 text-sm font-semibold border-b-2 transition-all flex items-center justify-center gap-2 ${
                activeTab === tab.id ? 'border-blue-600 text-blue-600 bg-white' : 'border-transparent text-slate-500 hover:text-slate-700'
              }`}
            >
              {tab.icon}
              {tab.label}
            </button>
          ))}
        </div>

        <div className="p-8">
          {activeTab === 'steps' && (
            <div className="space-y-10">
              {['Preparation', 'Inspection', 'Palpation', 'Percussion', 'Auscultation', 'Special Tests', 'Conclusion'].map(cat => {
                const catSteps = exam.steps.filter(s => s.category === cat);
                if (catSteps.length === 0) return null;
                return (
                  <div key={cat} className="animate-in fade-in duration-500">
                    <h3 className="text-xs font-black text-slate-400 uppercase tracking-[0.2em] mb-6 flex items-center gap-3">
                      <span className="w-1.5 h-1.5 bg-blue-500 rounded-full"></span>
                      {cat}
                    </h3>
                    <div className="space-y-4">
                      {catSteps.map((step) => {
                        const isChecked = checkedSteps.has(step.id);
                        const isExpanded = expandedStep === step.id;
                        return (
                          <div 
                            key={step.id} 
                            className={`group relative border-l-2 transition-all rounded-r-xl overflow-hidden ${
                              isChecked 
                                ? 'border-green-500 bg-green-50/30' 
                                : 'border-slate-100 hover:border-blue-300 hover:bg-slate-50/20'
                            }`}
                          >
                            <div 
                              onClick={() => isChecklistMode ? toggleStep(step.id) : setExpandedStep(isExpanded ? null : step.id)}
                              className="px-6 py-4 cursor-pointer flex justify-between items-start gap-4"
                            >
                              <div className="flex-1">
                                <div className="flex items-center gap-3 mb-2">
                                  {isChecklistMode && (
                                    <div className={`w-5 h-5 rounded border-2 flex items-center justify-center transition-all ${
                                      isChecked ? 'bg-green-500 border-green-500' : 'bg-white border-slate-300'
                                    }`}>
                                      {isChecked && <CheckCircle2 className="w-3 h-3 text-white" />}
                                    </div>
                                  )}
                                  <h4 className={`font-bold transition-colors ${isChecked ? 'text-green-800' : 'text-slate-800'}`}>
                                    {step.title}
                                  </h4>
                                </div>
                                <p className={`text-sm leading-relaxed max-w-xl transition-colors ${isChecked ? 'text-green-700/80' : 'text-slate-600'}`}>
                                  {step.description}
                                </p>
                              </div>
                              <div className="flex items-center gap-4">
                                <button 
                                  onClick={(e) => { e.stopPropagation(); fetchCorrelation(step.title); }}
                                  className="p-2 hover:bg-blue-100/50 rounded-lg text-blue-500 transition-all"
                                  title="Ask AI for clinical significance"
                                >
                                  {loadingCorrelation && selectedSign === step.title ? (
                                    <Loader2 className="w-4 h-4 animate-spin" />
                                  ) : (
                                    <Zap className="w-4 h-4" />
                                  )}
                                </button>
                                {isExpanded ? <ChevronUp className="w-4 h-4 text-slate-400" /> : <ChevronDown className="w-4 h-4 text-slate-400" />}
                              </div>
                            </div>

                            {(isExpanded || (isChecklistMode && isChecked)) && (
                              <div className="px-6 pb-6 pt-2 bg-white/50 animate-in slide-in-from-top-2 duration-200 border-t border-slate-100">
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mt-4">
                                  {/* Negative Findings */}
                                  <div className="space-y-3">
                                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2">
                                      <CheckCircle2 className="w-3 h-3 text-green-500" />
                                      Negative Findings (Normal)
                                    </p>
                                    <ul className="space-y-2">
                                      {step.negativeFindings?.map((nf, i) => (
                                        <li key={i} className="text-xs text-slate-600 flex items-start gap-2">
                                          <span className="text-green-500">•</span> {nf}
                                        </li>
                                      )) || <li className="text-xs text-slate-400 italic">Standard normal appearance</li>}
                                    </ul>
                                  </div>

                                  {/* Positive Findings */}
                                  <div className="space-y-4">
                                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2">
                                      <XCircle className="w-3 h-3 text-red-500" />
                                      Positive Findings (Abnormal)
                                    </p>
                                    <div className="space-y-3">
                                      {step.positiveFindings?.map((pf, i) => (
                                        <div key={i} className="space-y-2">
                                          <p className="text-xs font-semibold text-red-700 bg-red-50 p-2 rounded border border-red-100">{pf.description}</p>
                                          {pf.imageUrl && (
                                            <div className="rounded-lg overflow-hidden border border-slate-200">
                                              <img src={pf.imageUrl} alt={pf.description} className="w-full h-auto" />
                                            </div>
                                          )}
                                        </div>
                                      )) || <li className="text-xs text-slate-400 italic">No specific signs listed</li>}
                                    </div>
                                  </div>
                                </div>
                              </div>
                            )}
                          </div>
                        );
                      })}
                    </div>
                  </div>
                );
              })}
            </div>
          )}

          {activeTab === 'audio' && (
            <div className="space-y-8 animate-in fade-in slide-in-from-bottom-2">
              <div className="bg-slate-900 rounded-3xl p-8 text-white relative overflow-hidden shadow-2xl">
                <div className="absolute top-0 right-0 p-8 opacity-10">
                  <Volume2 className="w-32 h-32" />
                </div>

                <div className="relative z-10">
                  <div className="flex items-center gap-3 mb-6">
                    <div className="p-3 bg-blue-500/20 rounded-2xl border border-blue-500/30">
                      <Ear className="w-8 h-8 text-blue-400" />
                    </div>
                    <div>
                      <h3 className="text-2xl font-bold">Auscultation Simulation</h3>
