import { GoogleGenAI, Type } from "@google/genai";
import { ClinicalCorrelation, Examination, GroundingSource } from "../types";

export class GeminiService {

  async getClinicalCorrelation(sign: string, context: string): Promise<ClinicalCorrelation> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Explain the clinical significance of '${sign}' in a ${context} physical examination. Provide depth suitable for a senior medical student or resident.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            sign: { type: Type.STRING },
            pathophysiology: { type: Type.STRING },
            causes: { type: Type.ARRAY, items: { type: Type.STRING } },
            clinicalSignificance: { type: Type.STRING }
          },
          required: ["sign", "pathophysiology", "causes", "clinicalSignificance"]
        }
      }
    });

    try {
      const jsonStr = response.text || "{}";
      return JSON.parse(jsonStr);
    } catch (error) {
      console.error("Failed to parse correlation", error);
      throw error;
    }
  }

  async populateExamination(exam: Examination): Promise<{ steps: any[], sources: GroundingSource[] }> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const prompt = `Research the official medical protocol for a '${exam.name}' within the ${exam.system} system. 
    Use reliable sources like Geeky Medics, OSCEstop, or standard textbooks like Talley and O'Connor.
    Provide a detailed, step-by-step examination protocol.

    Structure the response as JSON with:
    1. steps: an array of objects { id, title, description, category, negativeFindings: string[], positiveFindings: { description: string }[] }
    Categories must be one of: Preparation, Inspection, Palpation, Percussion, Auscultation, Special Tests, Conclusion.`;

    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview", // Use Pro for better complex synthesis
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            steps: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING },
                  title: { type: Type.STRING },
                  description: { type: Type.STRING },
                  category: { type: Type.STRING },
                  negativeFindings: { type: Type.ARRAY, items: { type: Type.STRING } },
                  positiveFindings: {
                    type: Type.ARRAY,
                    items: {
                      type: Type.OBJECT,
                      properties: { description: { type: Type.STRING } }
                    }
                  }
                },
                required: ["id", "title", "description", "category"]
              }
            }
          },
          required: ["steps"]
        }
      }
    });

    const sources: GroundingSource[] = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
      title: chunk.web?.title || "Medical Source",
      uri: chunk.web?.uri || "#"
    })) || [];

    try {
      const data = JSON.parse(response.text || "{}");
      return { steps: data.steps, sources };
    } catch (error) {
      console.error("Failed to parse examination data", error);
      throw error;
    }
  }

  async getExaminationSummary(examName: string): Promise<string> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Provide a concise clinical summary and purpose of the ${examName} following the style of Talley and O'Connor. Include key things not to miss.`
    });
    return response.text || "No summary available.";
  }
}

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Examination, ClinicalCorrelation, ExamStep, AudioSimulation, GroundingSource } from '../types';
import { GeminiService } from '../services/geminiService';
import { 
  ChevronRight, 
  Info, 
  CheckCircle2, 
  Zap, 
  Loader2,
  AlertTriangle,
  Lightbulb,
  Play,
  Pause,
  ClipboardList,
  Target,
  Volume2,
  XCircle,
  ChevronDown,
  ChevronUp,
  Ear,
  Search,
  BookOpen,
  ExternalLink,
  Globe
} from 'lucide-react';

interface ExamViewProps {
  exam: Examination;
  onBack: () => void;
}

const ExamView: React.FC<ExamViewProps> = ({ exam: initialExam, onBack }) => {
  const [exam, setExam] = useState<Examination>(initialExam);
  const [activeTab, setActiveTab] = useState<'steps' | 'summary' | 'correlation' | 'media' | 'audio'>('steps');
  const [summary, setSummary] = useState<string | null>(null);
  const [loadingSummary, setLoadingSummary] = useState(false);
  const [isResearching, setIsResearching] = useState(false);
  const [correlation, setCorrelation] = useState<ClinicalCorrelation | null>(null);
  const [loadingCorrelation, setLoadingCorrelation] = useState(false);
  const [selectedSign, setSelectedSign] = useState<string | null>(null);

  const [checkedSteps, setCheckedSteps] = useState<Set<string>>(new Set());
  const [isChecklistMode, setIsChecklistMode] = useState(false);
  const [expandedStep, setExpandedStep] = useState<string | null>(null);

  const [currentAudio, setCurrentAudio] = useState<AudioSimulation | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  const gemini = useMemo(() => new GeminiService(), []);

  // Research effect for draft exams
  useEffect(() => {
    const researchExam = async () => {
      if (exam.steps.length === 0 || exam.isDraft) {
        setIsResearching(true);
        try {
          const result = await gemini.populateExamination(exam);
          setExam(prev => ({
            ...prev,
            steps: result.steps,
            sources: result.sources,
            isDraft: false
          }));
        } catch (err) {
          console.error("Research failed", err);
        } finally {
          setIsResearching(false);
        }
      }
    };
    researchExam();
  }, [exam.id, gemini]);

  useEffect(() => {
    const fetchSummary = async () => {
      setLoadingSummary(true);
      try {
        const text = await gemini.getExaminationSummary(exam.name);
        setSummary(text);
      } catch (err) {
        console.error(err);
      } finally {
        setLoadingSummary(false);
      }
    };
    if (!isResearching) fetchSummary();
  }, [exam.id, isResearching, gemini]);

  const fetchCorrelation = async (sign: string) => {
    setSelectedSign(sign);
    setLoadingCorrelation(true);
    try {
      const data = await gemini.getClinicalCorrelation(sign, exam.system);
      setCorrelation(data);
      setActiveTab('correlation');
    } catch (err) {
      console.error(err);
    } finally {
      setLoadingCorrelation(false);
    }
  };

  const toggleStep = (id: string) => {
    setCheckedSteps(prev => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  };

  const playAudio = (sim: AudioSimulation) => {
    if (currentAudio?.id === sim.id) {
      if (isPlaying) {
        audioRef.current?.pause();
        setIsPlaying(false);
      } else {
        audioRef.current?.play();
        setIsPlaying(true);
      }
    } else {
      setCurrentAudio(sim);
      setIsPlaying(true);
      if (audioRef.current) {
        audioRef.current.src = sim.url;
        audioRef.current.play();
      }
    }
  };

  const progress = useMemo(() => {
    if (exam.steps.length === 0) return 0;
    return Math.round((checkedSteps.size / exam.steps.length) * 100);
  }, [checkedSteps, exam.steps]);

  if (isResearching) {
    return (
      <div className="max-w-4xl mx-auto py-24 px-4 flex flex-col items-center justify-center">
        <div className="relative mb-12">
          <div className="w-32 h-32 border-4 border-blue-100 border-t-blue-600 rounded-full animate-spin"></div>
          <div className="absolute inset-0 flex items-center justify-center">
            <Globe className="w-12 h-12 text-blue-200 animate-pulse" />
          </div>
        </div>
        <h2 className="text-3xl font-black text-slate-900 mb-4 text-center">Synthesizing Protocol</h2>
        <p className="text-slate-500 text-center max-w-md mb-8 leading-relaxed">
          Our AI is currently reviewing reliable medical sources (BMJ, Geeky Medics, OSCEstop) 
          to provide the most accurate {exam.name} protocol.
        </p>
        <div className="w-full max-w-md bg-white border border-slate-200 rounded-2xl overflow-hidden shadow-sm">
          <div className="p-4 bg-slate-50 border-b border-slate-200 flex items-center gap-2">
            <Search className="w-4 h-4 text-slate-400" />
            <span className="text-xs font-bold text-slate-500 uppercase tracking-widest">Medical Search Log</span>
          </div>
          <div className="p-6 space-y-4">
            <div className="flex items-center gap-3 text-sm text-slate-600">
              <CheckCircle2 className="w-4 h-4 text-green-500" />
              Connecting to medical databases...
            </div>
            <div className="flex items-center gap-3 text-sm text-slate-600">
              <div className="w-4 h-4 rounded-full bg-blue-100 border border-blue-200 animate-pulse"></div>
              Identifying clinical stigmata for {exam.name}...
            </div>
            <div className="flex items-center gap-3 text-sm text-slate-400">
              <div className="w-4 h-4 rounded-full border border-slate-200"></div>
              Structuring examination categories...
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto py-8 px-4">
      <audio ref={audioRef} onEnded={() => setIsPlaying(false)} />

      <div className="flex items-center justify-between mb-6">
        <button 
          onClick={onBack}
          className="text-sm font-medium text-blue-600 hover:text-blue-700 flex items-center gap-1"
        >
          <ChevronRight className="w-4 h-4 rotate-180" />
          Back to Library
        </button>

        <button 
          onClick={() => setIsChecklistMode(!isChecklistMode)}
