                    <Lightbulb className="w-6 h-6 text-white" />
                  </div>
                  <div>
                    <p className="text-[10px] font-black uppercase tracking-widest text-amber-600 mb-1">Practical Pearl</p>
                    <p className="text-sm font-bold leading-snug">Always confirm findings with a senior colleague when unsure.</p>
                  </div>
                </div>
              </div>

              <div className="grid grid-cols-1 lg:grid-cols-3 gap-12">
                <div className="lg:col-span-2 space-y-12">
                  <section>
                    <div className="flex items-center gap-3 mb-6">
                      <div className="w-8 h-8 bg-blue-100 rounded-xl flex items-center justify-center">
                        <Zap className="w-5 h-5 text-blue-600" />
                      </div>
                      <h4 className="text-sm font-black text-slate-900 uppercase tracking-[0.2em]">Physiology</h4>
                    </div>
                    <div className="bg-white p-8 rounded-[2rem] border-2 border-slate-50 shadow-sm">
                      <p className="text-slate-600 text-lg leading-relaxed font-medium">
                        {correlation.pathophysiology}
                      </p>
                    </div>
                  </section>
                  <section>
                    <div className="flex items-center gap-3 mb-6">
                      <div className="w-8 h-8 bg-green-100 rounded-xl flex items-center justify-center">
                        <CheckCircle2 className="w-5 h-5 text-green-600" />
                      </div>
                      <h4 className="text-sm font-black text-slate-900 uppercase tracking-[0.2em]">Clinical Significance</h4>
                    </div>
                    <p className="text-slate-600 text-lg leading-relaxed bg-green-50/20 p-8 rounded-[2rem] border-2 border-green-50 font-medium">
                      {correlation.clinicalSignificance}
                    </p>
                  </section>
                </div>

                <div className="space-y-8">
                  <section className="bg-slate-900 text-white p-8 rounded-[2.5rem] shadow-2xl relative overflow-hidden">
                    <div className="absolute top-0 right-0 p-8 opacity-5">
                      <AlertTriangle className="w-32 h-32" />
                    </div>
                    <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.3em] mb-8 border-b border-slate-800 pb-4">Top Differential Diagnoses</h4>
                    <ul className="space-y-6 relative z-10">
                      {correlation.causes.map((cause, idx) => (
                        <li key={idx} className="flex items-start gap-4 group">
                          <div className="w-8 h-8 rounded-xl bg-blue-600 flex-shrink-0 flex items-center justify-center text-sm font-black shadow-lg shadow-blue-500/30">
                            {idx + 1}
                          </div>
                          <span className="text-base font-bold text-slate-200 group-hover:text-white transition-colors">{cause}</span>
                        </li>
                      ))}
                    </ul>
                  </section>

                  <div className="p-8 bg-red-50 rounded-[2rem] border-2 border-red-100 text-red-900 flex gap-6 shadow-xl shadow-red-200/20">
                    <AlertTriangle className="w-10 h-10 flex-shrink-0 text-red-600" />
                    <div>
                      <p className="font-black text-[10px] uppercase tracking-[0.2em] mb-2">Critical Flag</p>
                      <p className="text-sm font-bold leading-relaxed">Finding '{correlation.sign}' in an acute setting requires rapid clinical stabilization and escalation.</p>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

