      case 'downloading': return <Loader2 className="w-5 h-5 text-blue-500 animate-spin" />;
      case 'paused': return <Pause className="w-5 h-5 text-slate-400" />;
      default: return <RefreshCw className="w-5 h-5 text-slate-300" />;
