import React, { useState, useMemo, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import ExamView from './components/ExamView';
import DownloadManager from './components/DownloadManager';
import { ExamSystem, Examination } from './types';
import { EXAMINATIONS } from './constants';
import { downloadManager } from './services/downloadManagerService';
import { storage } from './services/storageService';
import { 
  BookOpen, 
  GraduationCap, 
  ArrowRight, 
  Search, 
  Filter, 
  Sparkles, 
  Globe, 
  CloudDownload,
  CheckCircle2,
  RefreshCw
} from 'lucide-react';

const App: React.FC = () => {
  const [selectedSystem, setSelectedSystem] = useState<ExamSystem | null>(null);
  const [selectedExam, setSelectedExam] = useState<Examination | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [currentView, setCurrentView] = useState<'library' | 'downloads'>('library');
  const [downloadedIds, setDownloadedIds] = useState<Set<string>>(new Set());
  const [syncingIds, setSyncingIds] = useState<Set<string>>(new Set());

  // Refresh downloaded cache
  useEffect(() => {
    const refreshDownloaded = async () => {
      const all = await storage.getAllDownloaded();
      setDownloadedIds(new Set(all.map(e => e.id)));
    };
    refreshDownloaded();

    const unsub = downloadManager.subscribe((tasks) => {
      refreshDownloaded();
      const currentSyncing = new Set(
        tasks.filter(t => t.status === 'downloading' || t.status === 'pending').map(t => t.examId)
      );
      setSyncingIds(currentSyncing);
    });
    return unsub;
  }, []);

  const filteredExams = useMemo(() => {
    let result = EXAMINATIONS;

    if (selectedSystem) {
      result = result.filter(e => e.system === selectedSystem);
    }

    if (searchQuery.trim()) {
      const q = searchQuery.toLowerCase();
      result = result.filter(e => 
        e.name.toLowerCase().includes(q) ||
        e.shortDescription.toLowerCase().includes(q) ||
        e.system.toLowerCase().includes(q) ||
        e.keywords.some(k => k.toLowerCase().includes(q))
      );
    }

    return result;
  }, [selectedSystem, searchQuery]);

  const handleSelectExam = async (exam: Examination) => {
    const stored = await storage.getExamination(exam.id);
    setSelectedExam(stored || exam);
  };

  const handleQuickSync = (e: React.MouseEvent, examId: string) => {
    e.stopPropagation();
    downloadManager.addTask(examId);
  };

  return (
    <div className="flex min-h-screen bg-white">
      <Sidebar 
        selectedSystem={selectedSystem} 
        onSelectSystem={setSelectedSystem} 
        searchQuery={searchQuery}
        onSearch={setSearchQuery}
        onViewDownloads={() => setCurrentView(currentView === 'downloads' ? 'library' : 'downloads')}
        currentView={currentView}
      />

      <main className="flex-1 overflow-y-auto">
        {selectedExam ? (
          <ExamView 
            exam={selectedExam} 
            onBack={() => setSelectedExam(null)} 
          />
        ) : currentView === 'downloads' ? (
          <DownloadManager />
        ) : (
          <div className="max-w-7xl mx-auto py-16 px-10">
            <header className="mb-20">
              <div className="flex items-center gap-4 text-blue-600 mb-6">
                <div className="p-3 bg-blue-50 rounded-[1.2rem] border border-blue-100">
                  <GraduationCap className="w-8 h-8" />
                </div>
                <div className="flex flex-col">
                  <span className="text-[10px] font-black uppercase tracking-[0.4em] text-slate-400 mb-1">Institutional Access</span>
                  <span className="text-sm font-black uppercase tracking-[0.2em]">MedEx Clinical Research Portal</span>
                </div>
              </div>
              <h1 className="text-7xl font-black text-slate-900 tracking-tighter mb-8 max-w-4xl">
                Expert Examination Library.
              </h1>
              <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-10">
                <p className="text-2xl text-slate-500 max-w-3xl font-medium leading-relaxed">
                  A dynamic clinical repository mirroring the Talley & O'Connor taxonomy. 
                  Synthesize protocols in real-time using global medical research.
                </p>

                <div className="flex items-center gap-6 bg-slate-50 p-6 rounded-[2rem] border-2 border-slate-100">
                  <div className="flex -space-x-4">
                    {[1,2,3,4].map(i => (
                      <div key={i} className="w-12 h-12 rounded-full border-4 border-slate-50 bg-blue-600 flex items-center justify-center text-white font-black text-xs">
                        {String.fromCharCode(64 + i)}
                      </div>
                    ))}
                  </div>
                  <div>
                    <p className="text-sm font-black text-slate-900">42,000+ Students</p>
                    <p className="text-xs font-bold text-slate-400">Practicing OSCEs monthly</p>
                  </div>
                </div>
              </div>

              <div className="mt-12 flex items-center gap-4">
                <div className="flex items-center gap-3 px-6 py-2 bg-blue-600 text-white rounded-full text-xs font-black uppercase tracking-widest shadow-xl shadow-blue-500/20">
                  <Filter className="w-4 h-4" />
                  {selectedSystem || 'All Clinical Systems'}
                </div>
                {searchQuery && (
                  <div className="flex items-center gap-3 px-6 py-2 bg-slate-100 text-slate-700 rounded-full text-xs font-black uppercase tracking-widest border-2 border-slate-200">
                    Query: "{searchQuery}"
                    <button onClick={() => setSearchQuery('')} className="ml-2 p-1 hover:bg-slate-200 rounded-full">×</button>
                  </div>
                )}
              </div>
            </header>

            <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-10">
              {filteredExams.map((exam) => {
                const isDownloaded = downloadedIds.has(exam.id);
                const isSyncing = syncingIds.has(exam.id);
                return (
                  <div
                    key={exam.id}
                    onClick={() => handleSelectExam(exam)}
                    className={`group p-10 rounded-[3rem] shadow-sm border-2 transition-all text-left flex flex-col h-full relative overflow-hidden cursor-pointer ${
                      isDownloaded 
                        ? 'bg-white border-green-100 shadow-green-500/5' 
                        : 'bg-slate-50 border-slate-100 hover:border-blue-400 hover:bg-white'
                    }`}
                  >
                    <div className="absolute top-0 right-0 p-8 flex items-center gap-2">
                      {isDownloaded ? (
                        <div className="flex items-center gap-2 px-4 py-2 bg-green-50 text-green-600 rounded-2xl text-[10px] font-black uppercase tracking-widest border border-green-100 shadow-sm">
                          <CheckCircle2 className="w-3 h-3" />
                          Offline Ready
                        </div>
                      ) : isSyncing ? (
                        <div className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-lg shadow-blue-500/20 animate-pulse">
                          <RefreshCw className="w-3 h-3 animate-spin" />
                          Syncing...
                        </div>
                      ) : exam.isDraft && (
                        <div className="flex items-center gap-2 px-4 py-2 bg-blue-50 text-blue-600 rounded-2xl text-[10px] font-black uppercase tracking-widest border border-blue-100 shadow-sm group-hover:bg-blue-600 group-hover:text-white transition-all">
                          <Sparkles className="w-3 h-3" />
                          Research Ready
                        </div>
                      )}
                    </div>

                    <div className="mb-8 relative z-10">
                      <span className="inline-block px-4 py-1.5 rounded-xl bg-slate-900 text-white text-[10px] font-black uppercase tracking-widest">
                        {exam.system}
                      </span>
                    </div>

                    <h3 className="text-3xl font-black text-slate-900 group-hover:text-blue-600 transition-colors mb-4 relative z-10 tracking-tight leading-none">
                      {exam.name}
                    </h3>

                    <p className="text-slate-500 mb-10 flex-1 leading-relaxed text-lg font-medium relative z-10">
                      {exam.shortDescription}
                    </p>

                    <div className="flex items-center justify-between mt-auto relative z-10 border-t border-slate-50 pt-8">
                      <span className={`text-xs font-black uppercase tracking-widest flex items-center gap-3 transition-all ${
                          isDownloaded ? 'text-green-600' : 'text-slate-900 group-hover:text-blue-600 group-hover:gap-5'
                        }`}>
                        {isDownloaded ? 'Open Content' : exam.isDraft ? 'Preview Protocol' : 'Open Protocol'}
                        <ArrowRight className="w-5 h-5" />
                      </span>

                      {!isDownloaded && !isSyncing && (
                        <button 
                          onClick={(e) => handleQuickSync(e, exam.id)}
                          className="p-3 bg-white border border-slate-200 rounded-2xl text-slate-400 hover:bg-blue-600 hover:text-white hover:border-blue-600 transition-all shadow-sm group/sync"
                          title="Quick Sync for Offline"
                        >
                          <CloudDownload className="w-5 h-5 group-hover/sync:scale-110 transition-transform" />
                        </button>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

