  const [checkedSteps, setCheckedSteps] = useState<Set<string>>(new Set());
  const [isChecklistMode, setIsChecklistMode] = useState(false);
  const [expandedStep, setExpandedStep] = useState<string | null>(null);

  const [currentAudio, setCurrentAudio] = useState<AudioSimulation | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  const [reviewExamId, setReviewExamId] = useState<string | null>(null);

  const gemini = useMemo(() => new GeminiService(), []);

  useEffect(() => {
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  // Research effect for draft exams
  useEffect(() => {
    const researchExam = async () => {
      if (exam.steps.length === 0 || exam.isDraft) {
        if (!isOnline) return;
        setIsResearching(true);
        try {
          const result = await gemini.populateExamination(exam);
          setExam(prev => ({
            ...prev,
            steps: result.steps,
            sources: result.sources,
            isDraft: false
          }));
        } catch (err) {
          console.error("Research failed", err);
        } finally {
          setIsResearching(false);
        }
      }
    };
    researchExam();
  }, [exam.id, gemini, isOnline]);

  useEffect(() => {
    const fetchSummary = async () => {
      if (!isOnline) return;
      setLoadingSummary(true);
      try {
        const text = await gemini.getExaminationSummary(exam.name);
        setSummary(text);
      } catch (err) {
        console.error(err);
      } finally {
        setLoadingSummary(false);
      }
    };
    if (!isResearching && exam.steps.length > 0) fetchSummary();
  }, [exam.id, isResearching, gemini, isOnline, exam.steps.length]);

  const fetchCorrelation = async (sign: string) => {
    if (!isOnline) return;
    setSelectedSign(sign);
    setLoadingCorrelation(true);
    try {
      const data = await gemini.getClinicalCorrelation(sign, exam.system);
      setCorrelation(data);
      setActiveTab('correlation');
    } catch (err) {
      console.error(err);
    } finally {
      setLoadingCorrelation(false);
    }
  };

  const toggleStep = (id: string) => {
    setCheckedSteps(prev => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  };

  const playAudio = (sim: AudioSimulation) => {
    const audioUrl = sim.localUrl || sim.url;
    if (currentAudio?.id === sim.id) {
      if (isPlaying) {
        audioRef.current?.pause();
        setIsPlaying(false);
      } else {
        audioRef.current?.play();
        setIsPlaying(true);
      }
    } else {
      setCurrentAudio(sim);
      setIsPlaying(true);
      if (audioRef.current) {
        audioRef.current.src = audioUrl;
        audioRef.current.play();
      }
    }
  };

  const progress = useMemo(() => {
    if (exam.steps.length === 0) return 0;
    return Math.round((checkedSteps.size / exam.steps.length) * 100);
  }, [checkedSteps, exam.steps]);

  if (isResearching) {
    return (
      <div className="max-w-4xl mx-auto py-24 px-4 flex flex-col items-center justify-center">
        <div className="relative mb-12">
          <div className="w-32 h-32 border-4 border-blue-100 border-t-blue-600 rounded-full animate-spin"></div>
          <div className="absolute inset-0 flex items-center justify-center">
            <Globe className="w-12 h-12 text-blue-200 animate-pulse" />
          </div>
        </div>
        <h2 className="text-3xl font-black text-slate-900 mb-4 text-center">Synthesizing Protocol</h2>
        <p className="text-slate-500 text-center max-w-md mb-8 leading-relaxed">
          Our AI is currently reviewing reliable medical sources to provide the most accurate {exam.name} protocol.
        </p>
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto py-8 px-4">
      <audio ref={audioRef} onEnded={() => setIsPlaying(false)} />

      {reviewExamId && <QuickReviewModal examId={reviewExamId} onClose={() => setReviewExamId(null)} />}

      <div className="flex items-center justify-between mb-6">
        <button 
          onClick={onBack}
          className="text-sm font-medium text-blue-600 hover:text-blue-700 flex items-center gap-1"
        >
          <ChevronRight className="w-4 h-4 rotate-180" />
          Back to Library
        </button>

        <div className="flex items-center gap-3">
          {!isOnline && (
            <div className="flex items-center gap-2 px-3 py-1.5 bg-amber-50 text-amber-600 rounded-full text-[10px] font-black uppercase tracking-widest border border-amber-100">
              <WifiOff className="w-3 h-3" />
              Offline
            </div>
          )}
          {exam.isDownloaded && (
            <div className="flex items-center gap-2 px-3 py-1.5 bg-green-50 text-green-600 rounded-full text-[10px] font-black uppercase tracking-widest border border-green-100">
              <Database className="w-3 h-3" />
              Local Cache
            </div>
          )}
          <button 
            onClick={() => setIsChecklistMode(!isChecklistMode)}
            className={`px-4 py-2 rounded-lg text-sm font-bold flex items-center gap-2 transition-all ${
              isChecklistMode 
                ? 'bg-green-100 text-green-700 border border-green-200 shadow-inner' 
                : 'bg-white text-slate-600 border border-slate-200 hover:bg-slate-50'
            }`}
          >
            <ClipboardList className="w-4 h-4" />
            {isChecklistMode ? 'OSCE Practice Active' : 'Protocol Review'}
          </button>
        </div>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden mb-8">
        <div className="p-8 bg-gradient-to-br from-slate-900 to-blue-900 text-white relative overflow-hidden">
          <div className="relative z-10">
            <div className="flex items-center gap-2 mb-2">
              <span className="px-2 py-0.5 bg-blue-500/30 rounded text-xs font-bold backdrop-blur-sm border border-blue-400/30">
                {exam.system}
              </span>
            </div>
            <h2 className="text-4xl font-black mb-3 tracking-tight">{exam.name}</h2>
            <p className="text-blue-200 max-w-2xl text-lg font-medium">{exam.shortDescription}</p>

            <div className="mt-6 flex flex-wrap gap-3">
              {(exam.relatedExamIds || []).map(id => {
                const related = EXAMINATIONS.find(e => e.id === id);
                if (!related) return null;
                return (
                  <button 
                    key={id}
                    onClick={() => setReviewExamId(id)}
                    className="flex items-center gap-2 px-3 py-1.5 bg-white/10 hover:bg-white/20 rounded-full border border-white/20 text-[10px] font-black uppercase tracking-widest backdrop-blur-md transition-all"
                  >
                    <LinkIcon className="w-3 h-3" />
                    Review: {related.name}
                  </button>
                );
              })}
            </div>

            {isChecklistMode && (
              <div className="mt-8 bg-black/20 p-6 rounded-2xl border border-white/10">
                <div className="flex justify-between items-center mb-4">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 bg-green-500 rounded-xl flex items-center justify-center shadow-lg">
                      <Target className="w-6 h-6 text-white" />
                    </div>
                    <div>
                      <p className="text-xs font-black uppercase tracking-widest text-blue-300">Examination Progress</p>
                      <p className="text-lg font-bold">{progress}% Completed</p>
                    </div>
                  </div>
                </div>
                <div className="w-full h-3 bg-white/10 rounded-full overflow-hidden">
                  <div 
                    className="h-full bg-green-500 transition-all duration-700 cubic-bezier(0.4, 0, 0.2, 1)" 
                    style={{ width: `${progress}%` }}
                  />
                </div>
              </div>
            )}
          </div>
          <div className="absolute top-[-40px] right-[-40px] opacity-10 pointer-events-none rotate-12">
            <BookOpen className="w-96 h-96" />
          </div>
        </div>

        <div className="flex border-b border-slate-200 overflow-x-auto bg-slate-50">
          {[
            { id: 'steps', label: 'Protocol', icon: <ClipboardList className="w-4 h-4" /> },
            { id: 'media', label: 'Video Demo', icon: <Play className="w-4 h-4" />, disabled: !isOnline && !exam.isDownloaded },
            { id: 'audio', label: 'Auscultation', icon: <Ear className="w-4 h-4" />, hide: !exam.audioSimulations?.length },
            { id: 'summary', label: 'Expert Summary', icon: <Info className="w-4 h-4" />, disabled: !isOnline && !summary },
            { id: 'correlation', label: 'Sign Analysis', icon: <Zap className="w-4 h-4" />, disabled: !isOnline && !correlation }
          ].filter(t => !t.hide).map(tab => (
            <button 
              key={tab.id}
              disabled={tab.disabled}
              onClick={() => setActiveTab(tab.id as any)}
              className={`flex-1 min-w-[140px] py-5 text-sm font-black uppercase tracking-widest border-b-2 transition-all flex items-center justify-center gap-3 ${
                activeTab === tab.id 
                  ? 'border-blue-600 text-blue-600 bg-white shadow-sm' 
                  : tab.disabled ? 'opacity-40 cursor-not-allowed' : 'border-transparent text-slate-400 hover:text-slate-600'
              }`}
            >
              {tab.icon}
              {tab.label}
              {tab.disabled && <WifiOff className="w-3 h-3 text-red-400" />}
            </button>
          ))}
        </div>

        <div className="p-10">
          {activeTab === 'steps' && (
            <div className="space-y-12">
              {['Preparation', 'Inspection', 'Palpation', 'Percussion', 'Auscultation', 'Special Tests', 'Conclusion'].map(cat => {
                const catSteps = exam.steps.filter(s => s.category === cat);
                if (catSteps.length === 0) return null;
                return (
                  <div key={cat} className="animate-in fade-in duration-700">
                    <h3 className="text-xs font-black text-slate-300 uppercase tracking-[0.3em] mb-8 flex items-center gap-4">
                      <div className="h-px bg-slate-100 flex-1"></div>
                      {cat}
                      <div className="h-px bg-slate-100 flex-1"></div>
                    </h3>
                    <div className="space-y-6">
                      {catSteps.map((step) => {
                        const isChecked = checkedSteps.has(step.id);
                        const isExpanded = expandedStep === step.id;
                        return (
                          <div 
                            key={step.id} 
                            className={`group relative border-2 transition-all rounded-[1.5rem] overflow-hidden ${
                              isChecked 
                                ? 'border-green-500 bg-green-50/20' 
                                : 'border-slate-100 hover:border-blue-200 hover:bg-slate-50/50'
                            }`}
                          >
                            <div 
                              onClick={() => isChecklistMode ? toggleStep(step.id) : setExpandedStep(isExpanded ? null : step.id)}
                              className="px-8 py-6 cursor-pointer flex justify-between items-start gap-6"
                            >
                              <div className="flex-1 flex gap-4">
                                {isChecklistMode && (
                                  <div className={`w-6 h-6 rounded-lg border-2 flex items-center justify-center transition-all flex-shrink-0 mt-0.5 ${
                                    isChecked ? 'bg-green-500 border-green-500 shadow-lg shadow-green-500/20' : 'bg-white border-slate-200'
                                  }`}>
                                    {isChecked && <CheckCircle2 className="w-4 h-4 text-white" />}
                                  </div>
                                )}
                                <div>
                                  <h4 className={`text-lg font-black tracking-tight mb-2 transition-colors ${isChecked ? 'text-green-800' : 'text-slate-900'}`}>
                                    {step.title}
                                  </h4>
                                  <p className={`text-base leading-relaxed transition-colors ${isChecked ? 'text-green-700/70' : 'text-slate-500'}`}>
                                    {step.description}
                                  </p>
                                </div>
                              </div>
                              <div className="flex items-center gap-4">
                                <button 
                                  disabled={!isOnline}
                                  onClick={(e) => { e.stopPropagation(); fetchCorrelation(step.title); }}
                                  className={`p-3 rounded-2xl transition-all shadow-sm ${
                                    !isOnline ? 'bg-slate-50 text-slate-300 cursor-not-allowed' : 'hover:bg-blue-100 text-blue-500'
                                  }`}
                                  title={isOnline ? "Clinical Analysis" : "Online Only"}
                                >
                                  {loadingCorrelation && selectedSign === step.title ? (
                                    <Loader2 className="w-5 h-5 animate-spin" />
                                  ) : (
                                    <Zap className="w-5 h-5" />
                                  )}
                                </button>
                                {isExpanded ? <ChevronUp className="w-5 h-5 text-slate-400" /> : <ChevronDown className="w-5 h-5 text-slate-400" />}
                              </div>
                            </div>

                            {(isExpanded || (isChecklistMode && isChecked)) && (
                              <div className="px-10 pb-10 pt-4 bg-white/40 animate-in slide-in-from-top-4 duration-300 border-t border-slate-100/50">
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                                  <div className="space-y-4">
                                    <p className="text-[10px] font-black text-green-600 uppercase tracking-widest flex items-center gap-2">
                                      <CheckCircle2 className="w-4 h-4" />
                                      Negative Findings
                                    </p>
                                    <ul className="space-y-3">
                                      {step.negativeFindings?.map((nf, i) => (
                                        <li key={i} className="text-sm text-slate-600 bg-green-50/50 p-3 rounded-xl border border-green-100 flex items-start gap-3">
                                          <div className="w-1.5 h-1.5 rounded-full bg-green-400 mt-2"></div> {nf}
                                        </li>
                                      )) || <li className="text-sm text-slate-400 italic bg-slate-50 p-3 rounded-xl">Standard negative/normal expected.</li>}
                                    </ul>
                                  </div>

                                  <div className="space-y-4">
                                    <p className="text-[10px] font-black text-red-600 uppercase tracking-widest flex items-center gap-2">
                                      <XCircle className="w-4 h-4" />
                                      Positive Findings
                                    </p>
                                    <div className="space-y-3">
                                      {step.positiveFindings?.map((pf, i) => (
                                        <div key={i} className="space-y-3 group/finding">
                                          <p className="text-sm font-bold text-red-800 bg-red-50 p-4 rounded-xl border border-red-100 shadow-sm">{pf.description}</p>
                                          {(pf.localImageUrl || pf.imageUrl) && (
                                            <div className="rounded-2xl overflow-hidden border border-slate-100 mt-2">
                                              <img src={pf.localImageUrl || pf.imageUrl} alt={pf.description} className="w-full h-auto" />
                                            </div>
                                          )}
                                        </div>
                                      )) || <li className="text-sm text-slate-400 italic bg-slate-50 p-3 rounded-xl">No pathognomonic stigmata listed.</li>}
                                    </div>
                                  </div>
                                </div>
                              </div>
                            )}
                          </div>
                        );
                      })}
                    </div>
                  </div>
                );
              })}

              {/* Related/Review Links Footer in Protocol */}
              {exam.relatedExamIds && exam.relatedExamIds.length > 0 && (
                <div className="mt-12 bg-blue-50/50 rounded-3xl p-8 border border-blue-100">
                  <div className="flex items-center gap-3 mb-6">
                    <LinkIcon className="w-5 h-5 text-blue-600" />
                    <h4 className="text-sm font-black text-slate-900 uppercase tracking-widest">Clinical Crosstalk</h4>
                  </div>
                  <p className="text-sm text-slate-500 mb-6 font-medium">This examination shares clinical concepts with the following specialized modules:</p>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    {exam.relatedExamIds.map(id => {
                      const related = EXAMINATIONS.find(e => e.id === id);
                      if (!related) return null;
                      return (
                        <button 
                          key={id}
                          onClick={() => setReviewExamId(id)}
                          className="p-4 bg-white rounded-2xl border border-slate-200 flex items-center justify-between hover:border-blue-400 transition-all group shadow-sm"
                        >
                          <div className="text-left">
                            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">{related.system}</p>
                            <p className="text-sm font-bold text-slate-900 group-hover:text-blue-600 transition-colors">{related.name}</p>
                          </div>
                          <ChevronRight className="w-4 h-4 text-slate-300 group-hover:text-blue-600 group-hover:translate-x-1 transition-all" />
                        </button>
                      );
                    })}
                  </div>
                </div>
              )}

              {/* Sources Section */}
              {exam.sources && exam.sources.length > 0 && (
                <div className="mt-20 pt-10 border-t border-slate-100">
                  <h4 className="text-xs font-black text-slate-400 uppercase tracking-widest mb-6 flex items-center gap-3">
                    <Globe className="w-4 h-4" />
                    Medical Reference Sources
                  </h4>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    {exam.sources.map((source, idx) => (
                      <a 
                        key={idx} 
                        href={source.uri} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className={`p-4 rounded-2xl border flex items-center justify-between transition-all group ${
                          !isOnline ? 'bg-slate-50 border-slate-100 opacity-60 cursor-not-allowed' : 'bg-slate-50 border-slate-200 hover:bg-white hover:border-blue-300 hover:shadow-md'
                        }`}
                        onClick={(e) => !isOnline && e.preventDefault()}
                      >
                        <div className="flex items-center gap-3 overflow-hidden">
                          <div className="w-8 h-8 rounded-lg bg-blue-100 flex items-center justify-center flex-shrink-0">
                            {isOnline ? <ExternalLink className="w-4 h-4 text-blue-600" /> : <WifiOff className="w-4 h-4 text-slate-400" />}
                          </div>
                          <span className="text-sm font-bold text-slate-700 truncate">{source.title}</span>
                        </div>
                        {isOnline && <ChevronRight className="w-4 h-4 text-slate-300 group-hover:text-blue-500 group-hover:translate-x-1 transition-all" />}
                      </a>
                    ))}
                  </div>
                </div>
              )}
            </div>
          )}

          {activeTab === 'audio' && (
            <div className="space-y-8 animate-in fade-in slide-in-from-bottom-2">
              <div className="bg-slate-900 rounded-[2.5rem] p-12 text-white relative overflow-hidden shadow-2xl">
                <div className="absolute top-0 right-0 p-12 opacity-5 pointer-events-none">
                  <Volume2 className="w-64 h-64" />
                </div>

                <div className="relative z-10">
                  <div className="flex items-center gap-5 mb-10">
                    <div className="p-4 bg-blue-500/20 rounded-[1.5rem] border border-blue-500/30">
                      <Ear className="w-10 h-10 text-blue-400" />
                    </div>
                    <div>
                      <h3 className="text-3xl font-black tracking-tight">Virtual Stethoscope</h3>
                      <p className="text-slate-400 font-medium">Identify key cardiac and respiratory pathology.</p>
                    </div>
                  </div>

                  {currentAudio ? (
                    <div className="bg-white/5 border border-white/10 p-8 rounded-[2rem] backdrop-blur-xl mb-10">
                      <div className="flex items-center justify-between gap-8">
                        <div className="flex-1">
                          <div className="flex items-center gap-2 mb-2">
                            <span className="text-[10px] font-black text-blue-400 uppercase tracking-widest px-2 py-1 bg-blue-500/10 rounded-lg">{currentAudio.type} Pathology</span>
                          </div>
                          <h4 className="text-2xl font-black mb-3">{currentAudio.name}</h4>
                          <p className="text-slate-300 leading-relaxed text-lg italic">"{currentAudio.description}"</p>
                        </div>
                        <button 
                          onClick={() => playAudio(currentAudio)}
                          className={`w-24 h-24 rounded-full flex items-center justify-center shadow-2xl transition-all active:scale-90 ${
                            isPlaying ? 'bg-red-600 shadow-red-500/20' : 'bg-blue-600 shadow-blue-500/20'
                          }`}
                        >
                          {isPlaying ? <Pause className="w-10 h-10" /> : <Play className="w-10 h-10 ml-2" />}
                        </button>
                      </div>
                    </div>
                  ) : (
                    <div className="py-20 text-center text-slate-500 border-2 border-dashed border-slate-800 rounded-[2rem] mb-10">
                      <p className="text-lg font-medium">Select a simulation from the library below.</p>
                    </div>
                  )}

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    {exam.audioSimulations?.map((sim) => (
                      <button
                        key={sim.id}
                        onClick={() => playAudio(sim)}
                        disabled={!isOnline && !sim.localUrl}
                        className={`text-left p-6 rounded-2xl border transition-all ${
                          currentAudio?.id === sim.id 
                            ? 'bg-blue-600/20 border-blue-500/50 shadow-lg' 
                            : !isOnline && !sim.localUrl ? 'bg-white/5 border-white/5 opacity-30 cursor-not-allowed' : 'bg-white/5 border-white/10 hover:bg-white/10'
                        }`}
                      >
                        <div className="flex items-center justify-between mb-2">
                          <span className="text-sm font-black">{sim.name}</span>
                          {!isOnline && !sim.localUrl ? <WifiOff className="w-4 h-4 text-red-400" /> : <Volume2 className={`w-5 h-5 ${currentAudio?.id === sim.id && isPlaying ? 'text-blue-400 animate-pulse' : 'text-slate-500'}`} />}
                        </div>
                        <div className="h-1 w-full bg-slate-800 rounded-full overflow-hidden">
                          {currentAudio?.id === sim.id && isPlaying && <div className="h-full bg-blue-500 w-full animate-[progress_3s_linear_infinite]"></div>}
                        </div>
                      </button>
                    ))}
                  </div>
                </div>
              </div>
            </div>
          )}

          {activeTab === 'media' && (
            <div className="animate-in fade-in slide-in-from-bottom-4">
              {exam.videoUrl && isOnline ? (
                <div>
                   <div className="flex items-center gap-3 mb-8">
                    <div className="w-10 h-10 bg-red-100 rounded-xl flex items-center justify-center">
                      <Play className="w-6 h-6 text-red-600" />
                    </div>
                    <h3 className="text-2xl font-black">Clinical Technique Video</h3>
                  </div>
                  <div className="aspect-video w-full bg-slate-900 rounded-[2rem] overflow-hidden shadow-2xl ring-4 ring-white shadow-slate-200">
                    <iframe 
                      className="w-full h-full"
                      src={exam.videoUrl}
                      title={`${exam.name} Video Demo`}
                      frameBorder="0"
                      allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
                      allowFullScreen
                    ></iframe>
                  </div>
                </div>
              ) : (
                <div className="py-32 flex flex-col items-center justify-center text-slate-300 bg-slate-50 rounded-[3rem] border-4 border-dashed border-slate-100">
                  {!isOnline ? (
                    <>
                      <WifiOff className="w-20 h-20 mb-6 opacity-10" />
                      <p className="text-xl font-bold text-slate-400">Connection Required</p>
                      <p className="text-sm max-w-xs text-center">Video streaming is not supported in offline mode to save storage space.</p>
                    </>
                  ) : (
                    <>
                      <Play className="w-20 h-20 mb-6 opacity-10" />
                      <p className="text-xl font-bold">Technique Video Unavailable</p>
                      <p className="text-sm">We are currently sourcing high-quality footage for this protocol.</p>
                    </>
                  )}
                </div>
              )}
            </div>
          )}

          {activeTab === 'summary' && (
            <div className="animate-in fade-in slide-in-from-bottom-4">
              {loadingSummary ? (
                <div className="flex flex-col items-center justify-center py-20">
                  <Loader2 className="w-10 h-10 text-blue-600 animate-spin mb-6" />
                  <p className="text-slate-400 font-bold uppercase tracking-widest">Compiling expert consensus...</p>
                </div>
              ) : summary ? (
                <div className="bg-white rounded-[2rem] p-10 border-2 border-slate-100 shadow-xl shadow-slate-200/50">
                   <div className="flex items-center gap-4 text-slate-900 mb-10 pb-6 border-b border-slate-100">
                    <div className="w-12 h-12 bg-blue-600 rounded-2xl flex items-center justify-center shadow-lg shadow-blue-500/20">
                      <BookOpen className="w-6 h-6 text-white" />
