import React, { useState, useMemo, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import ExamView from './components/ExamView';
import DownloadManager from './components/DownloadManager';
import { ExamSystem, Examination } from './types';
import { EXAMINATIONS } from './constants';
import { downloadManager } from './services/downloadManagerService';
import { storage } from './services/storageService';
import { 
  BookOpen, 
  GraduationCap, 
  ArrowRight, 
  Search, 
  Filter, 
  Sparkles, 
  Globe, 
  CloudDownload,
  CheckCircle2,
  RefreshCw
} from 'lucide-react';

const App: React.FC = () => {
  const [selectedSystem, setSelectedSystem] = useState<ExamSystem | null>(null);
  const [selectedExam, setSelectedExam] = useState<Examination | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [currentView, setCurrentView] = useState<'library' | 'downloads'>('library');
  const [downloadedIds, setDownloadedIds] = useState<Set<string>>(new Set());
  const [syncingIds, setSyncingIds] = useState<Set<string>>(new Set());

  // Refresh downloaded cache
  useEffect(() => {
    const refreshDownloaded = async () => {
      const all = await storage.getAllDownloaded();
      setDownloadedIds(new Set(all.map(e => e.id)));
    };
    refreshDownloaded();

    const unsub = downloadManager.subscribe((tasks) => {
      refreshDownloaded();
      const currentSyncing = new Set(
        tasks.filter(t => t.status === 'downloading' || t.status === 'pending').map(t => t.examId)
      );
      setSyncingIds(currentSyncing);
    });
    return unsub;
  }, []);

  const filteredExams = useMemo(() => {
    let result = EXAMINATIONS;

    if (selectedSystem) {
      result = result.filter(e => e.system === selectedSystem);
    }

    if (searchQuery.trim()) {
      const q = searchQuery.toLowerCase();
      result = result.filter(e => 
        e.name.toLowerCase().includes(q) ||
        e.shortDescription.toLowerCase().includes(q) ||
        e.system.toLowerCase().includes(q) ||
        e.keywords.some(k => k.toLowerCase().includes(q))
      );
    }

    return result;
  }, [selectedSystem, searchQuery]);

  const handleSelectExam = async (exam: Examination) => {
    const stored = await storage.getExamination(exam.id);
    setSelectedExam(stored || exam);
  };

  const handleQuickSync = (e: React.MouseEvent, examId: string) => {
    e.stopPropagation();
    downloadManager.addTask(examId);
  };

  return (
    <div className="flex min-h-screen bg-white">
      <Sidebar 
        selectedSystem={selectedSystem} 
        onSelectSystem={setSelectedSystem} 
        searchQuery={searchQuery}
        onSearch={setSearchQuery}
        onViewDownloads={() => setCurrentView(currentView === 'downloads' ? 'library' : 'downloads')}
        currentView={currentView}
      />

      <main className="flex-1 overflow-y-auto">
        {selectedExam ? (
          <ExamView 
            exam={selectedExam} 
            onBack={() => setSelectedExam(null)} 
          />
        ) : currentView === 'downloads' ? (
          <DownloadManager />
        ) : (
          <div className="max-w-6xl mx-auto py-10 px-6">
            <header className="mb-10">
              <div className="flex items-center gap-3 text-blue-600 mb-4">
                <div className="p-2 bg-blue-50 rounded-lg border border-blue-100">
                  <GraduationCap className="w-5 h-5" />
                </div>
                <div className="flex flex-col">
                  <span className="text-[8px] font-black uppercase tracking-[0.3em] text-slate-400 mb-0.5">Institutional Access</span>
                  <span className="text-xs font-black uppercase tracking-[0.1em]">MedEx Clinical Research Portal</span>
                </div>
              </div>
              <h1 className="text-4xl font-black text-slate-900 tracking-tight mb-4 max-w-2xl">
                Expert Examination Library
              </h1>
              <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
                <p className="text-base text-slate-500 max-w-xl font-medium leading-relaxed">
                  A dynamic clinical repository mirroring the Talley & O'Connor taxonomy. 
                  Synthesize protocols in real-time using global medical research.
                </p>

                <div className="flex items-center gap-4 bg-slate-50 p-3 rounded-2xl border border-slate-100">
                  <div className="flex -space-x-2">
                    {[1,2,3,4].map(i => (
                      <div key={i} className="w-8 h-8 rounded-full border-2 border-slate-50 bg-blue-600 flex items-center justify-center text-white font-black text-[10px]">
                        {String.fromCharCode(64 + i)}
                      </div>
                    ))}
                  </div>
                  <div>
                    <p className="text-xs font-black text-slate-900">42,000+ Students</p>
                    <p className="text-[10px] font-bold text-slate-400">Practicing OSCEs</p>
                  </div>
                </div>
              </div>

              <div className="mt-6 flex items-center gap-2">
                <div className="flex items-center gap-2 px-3 py-1 bg-blue-600 text-white rounded-full text-[10px] font-black uppercase tracking-widest shadow-md">
                  <Filter className="w-3 h-3" />
                  {selectedSystem || 'All Clinical Systems'}
                </div>
                {searchQuery && (
                  <div className="flex items-center gap-2 px-3 py-1 bg-slate-100 text-slate-700 rounded-full text-[10px] font-black uppercase tracking-widest border border-slate-200">
                    Query: "{searchQuery}"
                    <button onClick={() => setSearchQuery('')} className="ml-1 p-0.5 hover:bg-slate-200 rounded-full">×</button>
                  </div>
                )}
              </div>
            </header>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {filteredExams.map((exam) => {
                const isDownloaded = downloadedIds.has(exam.id);
                const isSyncing = syncingIds.has(exam.id);
                return (
                  <div
                    key={exam.id}
                    onClick={() => handleSelectExam(exam)}
                    className={`group p-6 rounded-3xl shadow-sm border transition-all text-left flex flex-col h-full relative overflow-hidden cursor-pointer ${
                      isDownloaded 
                        ? 'bg-white border-green-100' 
                        : 'bg-slate-50 border-slate-100 hover:border-blue-400 hover:bg-white hover:shadow-md'
                    }`}
                  >
                    <div className="absolute top-0 right-0 p-4 flex items-center gap-2">
                      {isDownloaded ? (
                        <div className="flex items-center gap-1.5 px-2 py-1 bg-green-50 text-green-600 rounded-lg text-[8px] font-black uppercase tracking-widest border border-green-100">
                          <CheckCircle2 className="w-2.5 h-2.5" />
                          Offline
                        </div>
                      ) : isSyncing ? (
                        <div className="flex items-center gap-1.5 px-2 py-1 bg-blue-600 text-white rounded-lg text-[8px] font-black uppercase tracking-widest shadow-md animate-pulse">
                          <RefreshCw className="w-2.5 h-2.5 animate-spin" />
                          Syncing
                        </div>
                      ) : exam.isDraft && (
                        <div className="flex items-center gap-1.5 px-2 py-1 bg-blue-50 text-blue-600 rounded-lg text-[8px] font-black uppercase tracking-widest border border-blue-100 group-hover:bg-blue-600 group-hover:text-white transition-all">
                          <Sparkles className="w-2.5 h-2.5" />
                          Research
                        </div>
                      )}
                    </div>

                    <div className="mb-4 relative z-10">
                      <span className="inline-block px-2 py-1 rounded-lg bg-slate-900 text-white text-[8px] font-black uppercase tracking-widest">
                        {exam.system}
                      </span>
                    </div>

                    <h3 className="text-xl font-black text-slate-900 group-hover:text-blue-600 transition-colors mb-2 relative z-10 tracking-tight">
                      {exam.name}
                    </h3>

                    <p className="text-slate-500 mb-6 flex-1 leading-relaxed text-sm font-medium relative z-10">
                      {exam.shortDescription}
                    </p>

                    <div className="flex items-center justify-between mt-auto relative z-10 border-t border-slate-100 pt-4">
                      <span className={`text-[10px] font-black uppercase tracking-widest flex items-center gap-2 transition-all ${
                          isDownloaded ? 'text-green-600' : 'text-slate-900 group-hover:text-blue-600 group-hover:gap-3'
                        }`}>
                        {isDownloaded ? 'Open Content' : exam.isDraft ? 'Preview Protocol' : 'Open Protocol'}
                        <ArrowRight className="w-4 h-4" />
                      </span>

                      {!isDownloaded && !isSyncing && (
                        <button 
                          onClick={(e) => handleQuickSync(e, exam.id)}
                          className="p-2 bg-white border border-slate-200 rounded-xl text-slate-400 hover:bg-blue-600 hover:text-white hover:border-blue-600 transition-all shadow-sm group/sync"
                          title="Quick Sync for Offline"
                        >
                          <CloudDownload className="w-4 h-4 group-hover/sync:scale-110 transition-transform" />
                        </button>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { downloadManager } from '../services/downloadManagerService';
import { DownloadTask } from '../types';
import { 
  CloudDownload, 
  Trash2, 
  Pause, 
  Play, 
  X, 
  CheckCircle2, 
  AlertCircle,
  Loader2,
  Package,
  ArrowDownToLine,
  RefreshCw,
  LayoutGrid
} from 'lucide-react';

const DownloadManager: React.FC = () => {
  const [tasks, setTasks] = useState<DownloadTask[]>([]);
  const [isPaused, setIsPaused] = useState(false);
  const [isDraggingOverTrash, setIsDraggingOverTrash] = useState(false);

  useEffect(() => {
    const unsub = downloadManager.subscribe((newTasks) => {
      setTasks(newTasks);
      setIsPaused(downloadManager.getPauseState());
    });
    return unsub;
  }, []);

  const handleDragStart = (e: React.DragEvent, taskId: string) => {
    e.dataTransfer.setData('taskId', taskId);
  };

  const handleDropTrash = (e: React.DragEvent) => {
    e.preventDefault();
    const taskId = e.dataTransfer.getData('taskId');
    if (taskId) {
      downloadManager.cancelTask(taskId);
    }
    setIsDraggingOverTrash(false);
  };

  const getStatusIcon = (status: DownloadTask['status']) => {
    switch (status) {
      case 'completed': return <CheckCircle2 className="w-4 h-4 text-green-500" />;
      case 'failed': return <AlertCircle className="w-4 h-4 text-red-500" />;
      case 'downloading': return <Loader2 className="w-4 h-4 text-blue-500 animate-spin" />;
      case 'paused': return <Pause className="w-4 h-4 text-slate-400" />;
      default: return <RefreshCw className="w-4 h-4 text-slate-300" />;
    }
  };

  return (
    <div className="max-w-5xl mx-auto py-8 px-6 animate-in fade-in duration-500">
      <header className="flex items-center justify-between mb-8">
        <div>
          <div className="flex items-center gap-2 text-blue-600 mb-2">
            <div className="p-2 bg-blue-50 rounded-xl border border-blue-100">
              <CloudDownload className="w-5 h-5" />
            </div>
            <div className="flex flex-col">
              <span className="text-[7px] font-black uppercase tracking-[0.3em] text-slate-400 mb-0.5">Asset Pipeline</span>
              <span className="text-[10px] font-black uppercase tracking-[0.1em]">Synchronous Engine</span>
            </div>
          </div>
          <h1 className="text-3xl font-black text-slate-900 tracking-tight">Content Manager</h1>
        </div>

        <div className="flex items-center gap-3">
          <button 
            onClick={() => downloadManager.togglePause()}
            className={`flex items-center gap-2 px-4 py-2 rounded-xl font-black uppercase tracking-widest text-[10px] transition-all ${
              isPaused 
                ? 'bg-green-600 text-white shadow-lg shadow-green-500/20' 
                : 'bg-slate-100 text-slate-600 border border-slate-200'
            }`}
          >
            {isPaused ? <Play className="w-3 h-3" /> : <Pause className="w-3 h-3" />}
            {isPaused ? 'Resume' : 'Pause All'}
          </button>
        </div>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 flex flex-col">
          <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4 flex items-center gap-2">
            <Package className="w-3 h-3" />
            Active Sync Queue ({tasks.filter(t => t.status !== 'completed').length})
          </h3>

          <div className="flex-1 bg-slate-50/50 rounded-2xl border border-slate-100 overflow-hidden">
            {tasks.length === 0 ? (
              <div className="py-20 flex flex-col items-center justify-center text-slate-300">
                <ArrowDownToLine className="w-12 h-12 mb-3 opacity-10" />
                <p className="text-sm font-bold">Queue Empty</p>
                <p className="text-xs">No active downloads.</p>
              </div>
            ) : (
              <div className="max-h-[500px] overflow-y-auto p-3 space-y-2 custom-scrollbar">
                {tasks.map((task) => (
                  <div 
                    key={task.id}
                    draggable
                    onDragStart={(e) => handleDragStart(e, task.id)}
                    className={`group relative p-4 bg-white rounded-xl border transition-all cursor-grab active:cursor-grabbing ${
                      task.status === 'downloading' ? 'border-blue-500 shadow-sm' : 'border-slate-100 hover:border-slate-200'
                    }`}
                  >
                    <div className="flex items-center justify-between gap-4 mb-3">
                      <div className="flex items-center gap-3">
                        <div className={`p-2 rounded-lg ${task.status === 'completed' ? 'bg-green-50' : 'bg-slate-50'}`}>
                          {getStatusIcon(task.status)}
                        </div>
                        <div>
                          <h4 className="text-sm font-black text-slate-900 tracking-tight">{task.examName}</h4>
                          <p className="text-[8px] font-bold text-slate-400 uppercase tracking-widest">
                            {task.type.replace('_', ' ')} • {task.id}
                          </p>
                        </div>
                      </div>

                      <div className="text-right">
                        <p className="text-xs font-black text-slate-900">{task.progress}%</p>
                      </div>
                    </div>

                    <div className="h-1.5 w-full bg-slate-100 rounded-full overflow-hidden mb-1">
                      <div 
                        className={`h-full transition-all duration-500 ${
                          task.status === 'failed' ? 'bg-red-500' : 
                          task.status === 'completed' ? 'bg-green-500' : 'bg-blue-600'
                        }`}
                        style={{ width: `${task.progress}%` }}
                      />
                    </div>

                    {task.error && (
                      <p className="text-[9px] font-bold text-red-500 mt-1 flex items-center gap-1">
                        <AlertCircle className="w-2.5 h-2.5" />
                        {task.error}
                      </p>
                    )}

                    <button 
                      onClick={() => downloadManager.cancelTask(task.id)}
                      className="absolute top-2 right-2 p-1.5 text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all"
                    >
                      <X className="w-3 h-3" />
                    </button>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>

        <div className="space-y-6">
          <div 
            onDragOver={(e) => { e.preventDefault(); setIsDraggingOverTrash(true); }}
            onDragLeave={() => setIsDraggingOverTrash(false)}
            onDrop={handleDropTrash}
            className={`p-6 rounded-3xl border-2 border-dashed transition-all flex flex-col items-center justify-center text-center ${
              isDraggingOverTrash 
                ? 'border-red-500 bg-red-50 text-red-600' 
                : 'border-slate-100 bg-slate-50 text-slate-400'
            }`}
          >
            <div className={`p-4 rounded-full mb-3 transition-all ${isDraggingOverTrash ? 'bg-red-200 scale-110' : 'bg-slate-200'}`}>
              <Trash2 className={`w-8 h-8 ${isDraggingOverTrash ? 'text-red-600' : 'text-slate-400'}`} />
            </div>
            <h4 className="text-sm font-black mb-1 tracking-tight">Drop to Cancel</h4>
            <p className="text-[10px] font-medium leading-relaxed">
              Drag items here to remove from pipeline.
            </p>
          </div>

          <div className="bg-slate-900 rounded-3xl p-6 text-white relative overflow-hidden shadow-xl">
            <div className="absolute top-0 right-0 p-4 opacity-5 pointer-events-none">
              <LayoutGrid className="w-16 h-16" />
            </div>
            <h4 className="text-[8px] font-black text-slate-500 uppercase tracking-widest mb-4 border-b border-slate-800 pb-1">Sync Statistics</h4>
            <div className="grid grid-cols-2 gap-4">
              <div>
                <p className="text-xl font-black text-white">{tasks.filter(t => t.status === 'completed').length}</p>
                <p className="text-[8px] font-bold text-slate-400 uppercase tracking-widest">Saved</p>
              </div>
              <div>
                <p className="text-xl font-black text-blue-400">{tasks.filter(t => t.status === 'downloading').length}</p>
                <p className="text-[8px] font-bold text-slate-400 uppercase tracking-widest">Active</p>
              </div>
            </div>

            <div className="mt-6 p-3 bg-white/5 rounded-xl border border-white/10 flex gap-2">
              <RefreshCw className="w-4 h-4 text-blue-400 flex-shrink-0" />
              <p className="text-[10px] text-slate-300 leading-relaxed font-medium">
                Smart Retry logic backoff enabled.
              </p>
            </div>
          </div>
        </div>
      </div>
      <style>{`
        .custom-scrollbar::-webkit-scrollbar {
          width: 4px;
        }
        .custom-scrollbar::-webkit-scrollbar-track {
          background: transparent;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb {
          background: #e2e8f0;
          border-radius: 10px;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover {
          background: #cbd5e1;
        }
      `}</style>
    </div>
  );
};

export default DownloadManager;

