            </div>
          ) : (
            <div className="p-12 text-center text-sm">Protocol not found.</div>
          )}
        </div>

        <div className="p-4 bg-slate-50 border-t border-slate-100 flex justify-end">
          <button 
            onClick={onClose}
            className="px-6 py-2 bg-slate-900 text-white rounded-full font-black uppercase tracking-widest text-[10px]"
          >
            Close Review
          </button>
        </div>
      </div>
    </div>
  );
};

const ExamView: React.FC<ExamViewProps> = ({ exam: initialExam, onBack }) => {
  const [exam, setExam] = useState<Examination>(initialExam);
  const [activeTab, setActiveTab] = useState<'steps' | 'summary' | 'correlation' | 'media' | 'audio'>('steps');
  const [summary, setSummary] = useState<string | null>(null);
  const [loadingSummary, setLoadingSummary] = useState(false);
  const [isResearching, setIsResearching] = useState(false);
  const [correlation, setCorrelation] = useState<ClinicalCorrelation | null>(null);
  const [loadingCorrelation, setLoadingCorrelation] = useState(false);
  const [selectedSign, setSelectedSign] = useState<string | null>(null);
  const [isOnline, setIsOnline] = useState(navigator.onLine);

  const [checkedSteps, setCheckedSteps] = useState<Set<string>>(new Set());
  const [isChecklistMode, setIsChecklistMode] = useState(false);
  const [expandedStep, setExpandedStep] = useState<string | null>(null);

  const [currentAudio, setCurrentAudio] = useState<AudioSimulation | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  const [reviewExamId, setReviewExamId] = useState<string | null>(null);

  const gemini = useMemo(() => new GeminiService(), []);

  useEffect(() => {
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  // Research effect for draft exams
  useEffect(() => {
    const researchExam = async () => {
      if (exam.steps.length === 0 || exam.isDraft) {
        if (!isOnline) return;
        setIsResearching(true);
        try {
          const result = await gemini.populateExamination(exam);
          setExam(prev => ({
            ...prev,
            steps: result.steps,
            sources: result.sources,
            isDraft: false
          }));
        } catch (err) {
          console.error("Research failed", err);
        } finally {
          setIsResearching(false);
        }
      }
    };
    researchExam();
  }, [exam.id, gemini, isOnline]);

  useEffect(() => {
    const fetchSummary = async () => {
      if (!isOnline) return;
      setLoadingSummary(true);
      try {
        const text = await gemini.getExaminationSummary(exam.name);
        setSummary(text);
      } catch (err) {
        console.error(err);
      } finally {
        setLoadingSummary(false);
      }
    };
    if (!isResearching && exam.steps.length > 0) fetchSummary();
  }, [exam.id, isResearching, gemini, isOnline, exam.steps.length]);

  const fetchCorrelation = async (sign: string) => {
    if (!isOnline) return;
    setSelectedSign(sign);
    setLoadingCorrelation(true);
    try {
      const data = await gemini.getClinicalCorrelation(sign, exam.system);
      setCorrelation(data);
      setActiveTab('correlation');
    } catch (err) {
      console.error(err);
    } finally {
      setLoadingCorrelation(false);
    }
  };

  const toggleStep = (id: string) => {
    setCheckedSteps(prev => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  };

  const playAudio = (sim: AudioSimulation) => {
    const audioUrl = sim.localUrl || sim.url;
    if (currentAudio?.id === sim.id) {
      if (isPlaying) {
        audioRef.current?.pause();
        setIsPlaying(false);
      } else {
        audioRef.current?.play();
        setIsPlaying(true);
      }
    } else {
      setCurrentAudio(sim);
      setIsPlaying(true);
      if (audioRef.current) {
        audioRef.current.src = audioUrl;
        audioRef.current.play();
      }
    }
  };

  const progress = useMemo(() => {
    if (exam.steps.length === 0) return 0;
    return Math.round((checkedSteps.size / exam.steps.length) * 100);
  }, [checkedSteps, exam.steps]);

  if (isResearching) {
    return (
      <div className="max-w-4xl mx-auto py-16 px-6 flex flex-col items-center justify-center">
        <div className="relative mb-8">
          <div className="w-20 h-20 border-4 border-blue-100 border-t-blue-600 rounded-full animate-spin"></div>
          <div className="absolute inset-0 flex items-center justify-center">
            <Globe className="w-8 h-8 text-blue-200 animate-pulse" />
          </div>
        </div>
        <h2 className="text-2xl font-black text-slate-900 mb-2 text-center">Synthesizing Protocol</h2>
        <p className="text-slate-500 text-center max-w-sm mb-6 text-sm leading-relaxed">
          AI is reviewing clinical consensus for {exam.name}.
        </p>
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto py-6 px-4">
      <audio ref={audioRef} onEnded={() => setIsPlaying(false)} />

      {reviewExamId && <QuickReviewModal examId={reviewExamId} onClose={() => setReviewExamId(null)} />}

      <div className="flex items-center justify-between mb-4">
        <button 
          onClick={onBack}
          className="text-xs font-medium text-blue-600 hover:text-blue-700 flex items-center gap-1"
        >
          <ChevronRight className="w-3 h-3 rotate-180" />
          Back
        </button>

        <div className="flex items-center gap-2">
          {!isOnline && (
            <div className="flex items-center gap-1.5 px-2 py-1 bg-amber-50 text-amber-600 rounded-lg text-[8px] font-black uppercase tracking-widest border border-amber-100">
              <WifiOff className="w-2.5 h-2.5" />
              Offline
            </div>
          )}
          {exam.isDownloaded && (
            <div className="flex items-center gap-1.5 px-2 py-1 bg-green-50 text-green-600 rounded-lg text-[8px] font-black uppercase tracking-widest border border-green-100">
              <Database className="w-2.5 h-2.5" />
              Cached
            </div>
          )}
          <button 
            onClick={() => setIsChecklistMode(!isChecklistMode)}
            className={`px-3 py-1.5 rounded-lg text-[10px] font-bold flex items-center gap-1.5 transition-all ${
              isChecklistMode 
                ? 'bg-green-100 text-green-700 border border-green-200' 
                : 'bg-white text-slate-600 border border-slate-200 hover:bg-slate-50'
            }`}
          >
            <ClipboardList className="w-3.5 h-3.5" />
            {isChecklistMode ? 'OSCE Active' : 'Review Protocol'}
          </button>
        </div>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden mb-6">
        <div className="p-6 bg-gradient-to-br from-slate-900 to-blue-900 text-white relative overflow-hidden">
          <div className="relative z-10">
            <div className="flex items-center gap-2 mb-1.5">
              <span className="px-1.5 py-0.5 bg-blue-500/30 rounded text-[9px] font-bold backdrop-blur-sm border border-blue-400/30">
                {exam.system}
              </span>
            </div>
            <h2 className="text-2xl font-black mb-1.5 tracking-tight">{exam.name}</h2>
            <p className="text-blue-200 max-w-xl text-sm font-medium">{exam.shortDescription}</p>

            <div className="mt-4 flex flex-wrap gap-2">
              {(exam.relatedExamIds || []).map(id => {
                const related = EXAMINATIONS.find(e => e.id === id);
                if (!related) return null;
                return (
                  <button 
                    key={id}
                    onClick={() => setReviewExamId(id)}
                    className="flex items-center gap-1.5 px-2 py-1 bg-white/10 hover:bg-white/20 rounded-lg border border-white/20 text-[8px] font-black uppercase tracking-widest transition-all"
                  >
                    <LinkIcon className="w-2.5 h-2.5" />
                    {related.name}
                  </button>
                );
              })}
            </div>

            {isChecklistMode && (
              <div className="mt-6 bg-black/20 p-4 rounded-xl border border-white/10">
                <div className="flex justify-between items-center mb-2">
                  <div className="flex items-center gap-2">
                    <Target className="w-4 h-4 text-green-500" />
                    <div>
                      <p className="text-[8px] font-black uppercase tracking-widest text-blue-300">OSCE Progress</p>
                      <p className="text-sm font-bold">{progress}%</p>
                    </div>
                  </div>
                </div>
                <div className="w-full h-1.5 bg-white/10 rounded-full overflow-hidden">
                  <div 
                    className="h-full bg-green-500 transition-all duration-500" 
                    style={{ width: `${progress}%` }}
                  />
                </div>
              </div>
            )}
          </div>
        </div>

        <div className="flex border-b border-slate-200 overflow-x-auto bg-slate-50">
          {[
            { id: 'steps', label: 'Steps', icon: <ClipboardList className="w-3.5 h-3.5" /> },
            { id: 'media', label: 'Video', icon: <Play className="w-3.5 h-3.5" />, disabled: !isOnline && !exam.isDownloaded },
            { id: 'audio', label: 'Audio', icon: <Ear className="w-3.5 h-3.5" />, hide: !exam.audioSimulations?.length },
            { id: 'summary', label: 'Summary', icon: <Info className="w-3.5 h-3.5" />, disabled: !isOnline && !summary },
            { id: 'correlation', label: 'Analysis', icon: <Zap className="w-3.5 h-3.5" />, disabled: !isOnline && !correlation }
          ].filter(t => !t.hide).map(tab => (
            <button 
              key={tab.id}
              disabled={tab.disabled}
              onClick={() => setActiveTab(tab.id as any)}
              className={`flex-1 min-w-[100px] py-3 text-[10px] font-black uppercase tracking-widest border-b-2 transition-all flex items-center justify-center gap-2 ${
                activeTab === tab.id 
                  ? 'border-blue-600 text-blue-600 bg-white' 
                  : tab.disabled ? 'opacity-40 cursor-not-allowed' : 'border-transparent text-slate-400 hover:text-slate-600'
              }`}
            >
