                    <div className="space-y-3">
                      {catSteps.map((step) => {
                        const isChecked = checkedSteps.has(step.id);
                        const isExpanded = expandedStep === step.id;
                        return (
                          <div 
                            key={step.id} 
                            className={`group relative border transition-all rounded-xl overflow-hidden ${
                              isChecked 
                                ? 'border-green-500 bg-green-50/20' 
                                : 'border-slate-100 hover:border-blue-200'
                            }`}
                          >
                            <div 
                              onClick={() => isChecklistMode ? toggleStep(step.id) : setExpandedStep(isExpanded ? null : step.id)}
                              className="px-4 py-3 cursor-pointer flex justify-between items-start gap-4"
                            >
                              <div className="flex-1 flex gap-3">
                                {isChecklistMode && (
                                  <div className={`w-5 h-5 rounded border flex items-center justify-center transition-all flex-shrink-0 mt-0.5 ${
                                    isChecked ? 'bg-green-500 border-green-500' : 'bg-white border-slate-200'
                                  }`}>
                                    {isChecked && <CheckCircle2 className="w-3 h-3 text-white" />}
                                  </div>
                                )}
                                <div>
                                  <h4 className={`text-sm font-black tracking-tight mb-0.5 ${isChecked ? 'text-green-800' : 'text-slate-900'}`}>
                                    {step.title}
                                  </h4>
                                  <p className={`text-xs leading-relaxed ${isChecked ? 'text-green-700/70' : 'text-slate-500'}`}>
                                    {step.description}
                                  </p>
                                </div>
                              </div>
                              <div className="flex items-center gap-2">
                                <button 
                                  disabled={!isOnline}
                                  onClick={(e) => { e.stopPropagation(); fetchCorrelation(step.title); }}
                                  className={`p-1.5 rounded-lg transition-all ${
                                    !isOnline ? 'text-slate-200' : 'hover:bg-blue-50 text-blue-500'
                                  }`}
                                >
                                  {loadingCorrelation && selectedSign === step.title ? (
                                    <Loader2 className="w-3.5 h-3.5 animate-spin" />
                                  ) : (
                                    <Zap className="w-3.5 h-3.5" />
                                  )}
                                </button>
                                {isExpanded ? <ChevronUp className="w-4 h-4 text-slate-300" /> : <ChevronDown className="w-4 h-4 text-slate-300" />}
                              </div>
                            </div>

                            {(isExpanded || (isChecklistMode && isChecked)) && (
                              <div className="px-6 pb-6 pt-2 bg-white/40 border-t border-slate-100/50">
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                  <div className="space-y-3">
                                    <p className="text-[9px] font-black text-green-600 uppercase tracking-widest flex items-center gap-1.5">
                                      <CheckCircle2 className="w-3 h-3" />
                                      Negative Findings
                                    </p>
                                    <ul className="space-y-2">
                                      {step.negativeFindings?.map((nf, i) => (
                                        <li key={i} className="text-[11px] text-slate-600 bg-green-50/50 p-2 rounded-lg border border-green-100 flex items-start gap-2">
                                          <div className="w-1 h-1 rounded-full bg-green-400 mt-1.5"></div> {nf}
                                        </li>
                                      )) || <li className="text-[10px] text-slate-400 italic">None listed.</li>}
                                    </ul>
                                  </div>

                                  <div className="space-y-3">
                                    <p className="text-[9px] font-black text-red-600 uppercase tracking-widest flex items-center gap-1.5">
                                      <XCircle className="w-3 h-3" />
                                      Positive Findings
                                    </p>
                                    <div className="space-y-2">
                                      {step.positiveFindings?.map((pf, i) => (
                                        <div key={i} className="space-y-2">
                                          <p className="text-[11px] font-bold text-red-800 bg-red-50 p-2 rounded-lg border border-red-100">{pf.description}</p>
                                          {(pf.localImageUrl || pf.imageUrl) && (
                                            <div className="rounded-lg overflow-hidden border border-slate-100">
