                  <div className="flex items-center gap-2 mb-4">
                    <LinkIcon className="w-4 h-4 text-blue-600" />
                    <h4 className="text-[10px] font-black text-slate-900 uppercase tracking-widest">Cross-References</h4>
                  </div>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                    {exam.relatedExamIds.map(id => {
                      const related = EXAMINATIONS.find(e => e.id === id);
                      if (!related) return null;
                      return (
                        <button 
                          key={id}
                          onClick={() => setReviewExamId(id)}
                          className="p-3 bg-white rounded-xl border border-slate-200 flex items-center justify-between hover:border-blue-400 transition-all group"
