                <div className="py-12 flex flex-col items-center justify-center text-slate-300">
                  <WifiOff className="w-10 h-10 mb-2 opacity-10" />
                  <p className="text-sm font-bold">Unavailable Offline</p>
                </div>
              )}
            </div>
          )}

          {activeTab === 'correlation' && (
            <div className="animate-in fade-in">
              {correlation ? (
                <div className="space-y-6">
                  <div>
                    <p className="text-[8px] font-black text-blue-600 uppercase tracking-[0.3em] mb-1">Pathology Focus</p>
                    <h3 className="text-3xl font-black text-slate-900 tracking-tight">{correlation.sign}</h3>
                  </div>
                  <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm">
                    <h4 className="text-[10px] font-black text-slate-900 uppercase tracking-widest mb-3 flex items-center gap-2">
