                <div className="py-12 flex flex-col items-center justify-center text-slate-300">
                  <WifiOff className="w-10 h-10 mb-2 opacity-10" />
                  <p className="text-sm font-bold">Analysis Unavailable Offline</p>
                </div>
              )}
            </div>
          )}
        </div>
