import { DownloadTask, DownloadTaskStatus, Examination, ExamStep, AudioSimulation } from '../types';
import { GeminiService } from './geminiService';
import { storage } from './storageService';
import { EXAMINATIONS } from '../constants';

export class DownloadManagerService {
  private tasks: DownloadTask[] = [];
  private isPaused: boolean = false;
  private maxConcurrency: number = 2;
  private activeCount: number = 0;
  private listeners: Set<(tasks: DownloadTask[]) => void> = new Set();
  private gemini = new GeminiService();

  constructor() {
    const saved = localStorage.getItem('medex_download_queue');
    if (saved) {
      this.tasks = JSON.parse(saved).map((t: any) => ({
        ...t,
        status: t.status === 'downloading' ? 'pending' : t.status
      }));
    }
    this.processQueue();
  }

  private notify() {
    localStorage.setItem('medex_download_queue', JSON.stringify(this.tasks));
    this.listeners.forEach(l => l([...this.tasks]));
  }

  subscribe(listener: (tasks: DownloadTask[]) => void) {
    this.listeners.add(listener);
    listener([...this.tasks]);
    return () => this.listeners.delete(listener);
  }

  addTask(examId: string, type: DownloadTask['type'] = 'deep_sync') {
    const exam = EXAMINATIONS.find(e => e.id === examId);
    if (!exam) return;

    const existing = this.tasks.find(t => t.examId === examId && t.status !== 'completed');
    if (existing) return;

    const newTask: DownloadTask = {
      id: Math.random().toString(36).substr(2, 9),
      examId,
      examName: exam.name,
      type,
      status: 'pending',
      progress: 0,
      retryCount: 0,
      createdAt: Date.now()
    };

    this.tasks = [newTask, ...this.tasks];
    this.notify();
    this.processQueue();
  }

  retryTask(taskId: string) {
    const task = this.tasks.find(t => t.id === taskId);
    if (task) {
      task.status = 'pending';
      task.progress = 0;
      task.retryCount = 0;
      task.error = undefined;
      this.notify();
      this.processQueue();
    }
  }

  cancelTask(taskId: string) {
    this.tasks = this.tasks.filter(t => t.id !== taskId);
    this.notify();
    this.processQueue();
  }

  togglePause() {
    this.isPaused = !this.isPaused;
    if (!this.isPaused) this.processQueue();
    this.notify();
  }

  private async processQueue() {
    if (this.isPaused || this.activeCount >= this.maxConcurrency) return;

    const nextTask = this.tasks.find(t => t.status === 'pending');
    if (!nextTask) return;

    this.activeCount++;
    await this.runTask(nextTask);
    this.activeCount--;
    this.processQueue();
  }

  private async fetchAsBase64(url: string): Promise<string | undefined> {
    try {
      const response = await fetch(url);
      const blob = await response.blob();
      return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.onloadend = () => resolve(reader.result as string);
        reader.onerror = reject;
        reader.readAsDataURL(blob);
      });
    } catch (e) {
      console.warn(`Failed to fetch asset: ${url}`, e);
      return undefined;
    }
  }

  private async runTask(task: DownloadTask) {
    task.status = 'downloading';
    task.progress = 5;
    this.notify();

    try {
      const baseExam = EXAMINATIONS.find(e => e.id === task.examId);
      if (!baseExam) throw new Error('Exam definition not found');

      // STAGE 1: Protocol Structure (TEXT ONLY)
      // This is the first separate call to ensure the core protocol is retrieved correctly.
      task.progress = 20;
      task.error = "Phase 1: Retrieving Protocol Structure...";
      this.notify();
      const populated = await this.gemini.populateExamination(baseExam);

      // STAGE 2: Clinical Enrichment (SEPARATE TEXT CALLS)
      // We process findings in separate calls to prevent bulk JSON format errors.
      task.progress = 40;
      task.error = "Phase 2: Enriching Clinical Findings...";
      this.notify();

      const enrichedSteps: ExamStep[] = await Promise.all(populated.steps.map(async (step: ExamStep, idx: number) => {
        // Increment progress slightly per step
        task.progress = 40 + Math.floor((idx / populated.steps.length) * 20);
        this.notify();

        const enrichedStep = { ...step };

        // If step has no findings, attempt a quick enrichment call
        if (!step.positiveFindings || step.positiveFindings.length === 0) {
          try {
             const enrichment = await this.gemini.getClinicalCorrelation(step.title, baseExam.system);
             enrichedStep.positiveFindings = [{ description: enrichment.clinicalSignificance }];
          } catch (e) {
             console.warn("Skipping enrichment for step", step.title);
          }
        }
        return enrichedStep;
      }));

      // STAGE 3: Media & Assets (IO CALLS)
      task.progress = 70;
      task.error = "Phase 3: Fetching Offline Assets...";
      this.notify();

      const processedSteps: ExamStep[] = await Promise.all(enrichedSteps.map(async (step: ExamStep) => {
        const processedStep = { ...step };
        if (step.imageUrl) {
          processedStep.localImageUrl = await this.fetchAsBase64(step.imageUrl);
        }
        if (step.positiveFindings) {
          processedStep.positiveFindings = await Promise.all(step.positiveFindings.map(async (pf) => {
            if (pf.imageUrl) {
              return { ...pf, localImageUrl: await this.fetchAsBase64(pf.imageUrl) };
            }
            return pf;
          }));
        }
        return processedStep;
      }));

      // STAGE 4: Audio Simulations (IO CALLS)
      task.progress = 90;
      task.error = "Phase 4: Finalizing Auscultation Cache...";
      this.notify();

      const audioSimulations: AudioSimulation[] = await Promise.all((baseExam.audioSimulations || []).map(async (sim) => {
        return {
          ...sim,
          localUrl: await this.fetchAsBase64(sim.url)
        };
      }));

      // Final merge and Atomic Save
      const finalExam: Examination = {
        ...baseExam,
        steps: processedSteps,
        sources: populated.sources,
        audioSimulations: audioSimulations.length > 0 ? audioSimulations : baseExam.audioSimulations,
        isDraft: false
      };

      await storage.saveExamination(finalExam);

      task.status = 'completed';
      task.progress = 100;
      task.error = undefined;
    } catch (err: any) {
      console.error('Sync pipeline failed', err);
      await this.handleError(task, err);
    } finally {
      this.notify();
    }
  }

  private async handleError(task: DownloadTask, error: any) {
    const errorMessage = error?.message || 'Unknown error';
    task.retryCount++;

    if (task.retryCount <= 2) {
      let delay = 3000 * Math.pow(2, task.retryCount);
      task.error = `Retrying in ${Math.round(delay/1000)}s... (${errorMessage})`;
      this.notify();
      await new Promise(r => setTimeout(r, delay));
      task.status = 'pending';
    } else {
      task.status = 'failed';
      task.error = `Critical Error: ${errorMessage}. Manual retry required.`;
    }
  }

  getTasks() { return [...this.tasks]; }
  getPauseState() { return this.isPaused; }
}

