import { 
  GraduationCap, 
  ArrowRight, 
  Sparkles, 
  CloudDownload,
  CheckCircle2,
  RefreshCw,
  ChevronDown,
  ChevronRight,
  Activity,
  Wind,
  Stethoscope,
  Brain,
  Bone,
  Droplets,
  FolderOpen,
  Layers
} from 'lucide-react';

const systemIcons: Record<string, React.ReactNode> = {
  [ExamSystem.CARDIOVASCULAR]: <Activity className="w-5 h-5" />,
  [ExamSystem.RESPIRATORY]: <Wind className="w-5 h-5" />,
  [ExamSystem.ABDOMINAL]: <Stethoscope className="w-5 h-5" />,
  [ExamSystem.NEUROLOGICAL]: <Brain className="w-5 h-5" />,
  [ExamSystem.MUSCULOSKELETAL]: <Bone className="w-5 h-5" />,
  [ExamSystem.ENDOCRINE]: <Droplets className="w-5 h-5" />,
  [ExamSystem.VASCULAR]: <Activity className="w-5 h-5" />,
  [ExamSystem.CRANIAL_NERVES]: <Brain className="w-5 h-5" />,
  [ExamSystem.GENERAL]: <Layers className="w-5 h-5" />,
};

const App: React.FC = () => {
  const [selectedSystem, setSelectedSystem] = useState<ExamSystem | null>(null);
  const [selectedExam, setSelectedExam] = useState<Examination | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [currentView, setCurrentView] = useState<'library' | 'downloads'>('library');
  const [downloadedIds, setDownloadedIds] = useState<Set<string>>(new Set());
  const [syncingIds, setSyncingIds] = useState<Set<string>>(new Set());
  const [expandedSystems, setExpandedSystems] = useState<Set<string>>(new Set([ExamSystem.CARDIOVASCULAR]));

  // Sync expanded state with sidebar selection
  useEffect(() => {
    if (selectedSystem) {
      setExpandedSystems(prev => new Set(prev).add(selectedSystem));
    }
  }, [selectedSystem]);

  useEffect(() => {
    const refreshDownloaded = async () => {
      const all = await storage.getAllDownloaded();
      setDownloadedIds(new Set(all.map(e => e.id)));
    };
    refreshDownloaded();

    const unsub = downloadManager.subscribe((tasks) => {
      refreshDownloaded();
      const currentSyncing = new Set(
        tasks.filter(t => t.status === 'downloading' || t.status === 'pending').map(t => t.examId)
      );
      setSyncingIds(currentSyncing);
    });
    return unsub;
  }, []);

  const toggleSystem = (system: string) => {
    setExpandedSystems(prev => {
      const next = new Set(prev);
      if (next.has(system)) next.delete(system);
      else next.add(system);
      return next;
    });
  };

  const groupedExams = useMemo(() => {
    const groups: Record<string, Examination[]> = {};

    let filtered = EXAMINATIONS;
    if (searchQuery.trim()) {
      const q = searchQuery.toLowerCase();
      filtered = filtered.filter(e => 
        e.name.toLowerCase().includes(q) ||
        e.shortDescription.toLowerCase().includes(q) ||
        e.system.toLowerCase().includes(q) ||
        e.keywords.some(k => k.toLowerCase().includes(q))
      );
    }

    filtered.forEach(exam => {
      if (!groups[exam.system]) groups[exam.system] = [];
      groups[exam.system].push(exam);
    });

    return groups;
  }, [searchQuery]);

  // If a system is filtered by sidebar, only show that group
  const displayGroups = useMemo(() => {
    if (selectedSystem) {
      return { [selectedSystem]: groupedExams[selectedSystem] || [] };
    }
    return groupedExams;
  }, [selectedSystem, groupedExams]);

  const handleSelectExam = async (exam: Examination) => {
    const stored = await storage.getExamination(exam.id);
    setSelectedExam(stored || exam);
  };

  const handleQuickSync = (e: React.MouseEvent, examId: string) => {
    e.stopPropagation();
    downloadManager.addTask(examId);
  };

  return (
    <div className="flex min-h-screen bg-[#F8FAFC]">
      <Sidebar 
        selectedSystem={selectedSystem} 
        onSelectSystem={setSelectedSystem} 
        searchQuery={searchQuery}
        onSearch={setSearchQuery}
        onViewDownloads={() => setCurrentView(currentView === 'downloads' ? 'library' : 'downloads')}
        currentView={currentView}
      />

      <main className="flex-1 overflow-y-auto custom-scrollbar">
        {selectedExam ? (
          <ExamView 
            exam={selectedExam} 
            onBack={() => setSelectedExam(null)} 
          />
        ) : currentView === 'downloads' ? (
          <DownloadManager />
        ) : (
          <div className="max-w-6xl mx-auto py-10 px-8">
            <header className="mb-12">
              <div className="flex items-center gap-3 text-blue-600 mb-4">
                <div className="p-2.5 bg-blue-50 rounded-xl border border-blue-100 shadow-sm">
                  <GraduationCap className="w-5 h-5" />
                </div>
                <div className="flex flex-col">
                  <span className="text-[8px] font-black uppercase tracking-[0.3em] text-slate-400 mb-0.5">Clinical Repository</span>
                  <span className="text-xs font-black uppercase tracking-[0.1em]">Talley & O'Connor Taxonomy</span>
                </div>
              </div>
              <h1 className="text-4xl font-black text-slate-900 tracking-tight mb-4">
                Protocol Library
              </h1>
              <p className="text-base text-slate-500 max-w-2xl font-medium leading-relaxed">
                A hierarchical index of evidence-based clinical examinations. 
                Synthesize full protocols including auscultation audio and clinical correlation signs.
              </p>
            </header>

            <div className="space-y-6">
              {Object.entries(displayGroups).map(([system, exams]) => {
                const isExpanded = expandedSystems.has(system);
                const hasResults = exams.length > 0;
                if (!hasResults && searchQuery) return null;

                return (
                  <div key={system} className="group/system">
                    <button 
                      onClick={() => toggleSystem(system)}
                      className={`w-full flex items-center justify-between p-4 rounded-2xl transition-all border ${
                        isExpanded 
                          ? 'bg-white border-blue-100 shadow-sm mb-4' 
                          : 'bg-transparent border-transparent hover:bg-slate-200/50'
                      }`}
                    >
                      <div className="flex items-center gap-4">
                        <div className={`p-2 rounded-xl transition-colors ${isExpanded ? 'bg-blue-600 text-white shadow-md' : 'bg-slate-200 text-slate-500 group-hover/system:bg-slate-300'}`}>
                          {systemIcons[system] || <FolderOpen className="w-5 h-5" />}
                        </div>
                        <div className="text-left">
                          <h3 className={`font-black tracking-tight text-lg ${isExpanded ? 'text-slate-900' : 'text-slate-600'}`}>
                            {system}
                          </h3>
                          <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
                            {exams.length} Protocols available
                          </p>
                        </div>
                      </div>
                      <div className={`transition-transform duration-300 ${isExpanded ? 'rotate-180 text-blue-600' : 'text-slate-400'}`}>
                        <ChevronDown className="w-6 h-6" />
                      </div>
                    </button>

                    {isExpanded && (
                      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 pl-4 border-l-2 border-blue-50/50 ml-6 pb-6 animate-in slide-in-from-top-2 duration-300">
                        {exams.map((exam) => {
                          const isDownloaded = downloadedIds.has(exam.id);
                          const isSyncing = syncingIds.has(exam.id);
                          return (
                            <div
                              key={exam.id}
                              onClick={() => handleSelectExam(exam)}
                              className={`group/card p-5 rounded-2xl shadow-sm border transition-all flex flex-col relative overflow-hidden cursor-pointer ${
                                isDownloaded 
                                  ? 'bg-white border-green-100 hover:border-green-300' 
                                  : 'bg-white border-slate-200 hover:border-blue-400 hover:shadow-md'
                              }`}
                            >
                              <div className="flex items-start justify-between mb-3">
                                <div className="p-1.5 bg-slate-50 rounded-lg border border-slate-100 group-hover/card:bg-blue-50 transition-colors">
                                   <FolderOpen className={`w-3.5 h-3.5 ${isDownloaded ? 'text-green-500' : 'text-slate-400 group-hover/card:text-blue-500'}`} />
                                </div>
                                <div className="flex items-center gap-1.5">
                                  {isDownloaded ? (
                                    <div className="px-1.5 py-0.5 bg-green-50 text-green-600 rounded-md text-[7px] font-black uppercase tracking-widest border border-green-100">
                                      Saved
                                    </div>
                                  ) : isSyncing ? (
                                    <RefreshCw className="w-3 h-3 text-blue-500 animate-spin" />
                                  ) : exam.isDraft && (
                                    <Sparkles className="w-3 h-3 text-blue-400 animate-pulse" />
                                  )}
                                </div>
                              </div>

                              <h4 className="text-sm font-black text-slate-900 group-hover/card:text-blue-600 transition-colors mb-1 tracking-tight">
                                {exam.name}
                              </h4>

                              <p className="text-slate-500 mb-4 line-clamp-2 leading-relaxed text-[11px] font-medium flex-1">
                                {exam.shortDescription}
                              </p>

                              <div className="flex items-center justify-between mt-auto pt-3 border-t border-slate-50">
                                <span className="text-[9px] font-black uppercase tracking-widest text-slate-400 flex items-center gap-1 group-hover/card:text-blue-600 group-hover/card:gap-2 transition-all">
                                  Protocol <ArrowRight className="w-3 h-3" />
                                </span>

                                {!isDownloaded && !isSyncing && (
                                  <button 
                                    onClick={(e) => handleQuickSync(e, exam.id)}
                                    className="p-1.5 text-slate-300 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-all"
                                  >
                                    <CloudDownload className="w-3.5 h-3.5" />
                                  </button>
                                )}
                              </div>
                            </div>
                          );
                        })}
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          </div>
        )}
      </main>
      <style>{`
        .custom-scrollbar::-webkit-scrollbar {
          width: 5px;
        }
        .custom-scrollbar::-webkit-scrollbar-track {
          background: transparent;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb {
          background: #E2E8F0;
          border-radius: 10px;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover {
          background: #CBD5E1;
        }
      `}</style>
    </div>
  );
};

