                  <span className="text-xs font-black uppercase tracking-[0.1em]">Collegiate Taxonomy</span>
                </div>
              </div>
              <h1 className="text-4xl font-black text-slate-900 tracking-tight mb-4">
                Protocol Library
              </h1>
              <p className="text-base text-slate-500 max-w-2xl font-medium leading-relaxed">
                A hierarchical index of evidence-based clinical examinations. 
                Synthesize full protocols including auscultation audio and clinical correlation signs.
              </p>
            </header>

            <div className="space-y-8">
              {Object.entries(displayGroups).map(([system, exams]) => {
                const isExpanded = expandedSystems.has(system);
                const hasResults = exams.length > 0;
                if (!hasResults && searchQuery) return null;

                const style = systemStyles[system] || systemStyles[ExamSystem.GENERAL];

                return (
                  <div key={system} className="group/system">
                    <button 
                      onClick={() => toggleSystem(system)}
                      className={`w-full flex items-center justify-between p-5 rounded-3xl transition-all border-2 backdrop-blur-md ${
                        isExpanded 
                          ? `${style.bg} ${style.color} ${style.ring} ring-4 mb-6 shadow-xl` 
                          : `bg-white/60 border-slate-100 hover:bg-white hover:border-slate-300 shadow-sm`
                      }`}
                    >
                      <div className="flex items-center gap-5">
                        <div className={`p-3 rounded-2xl transition-all duration-500 shadow-inner ${isExpanded ? `${style.text} bg-white scale-110 shadow-lg` : 'bg-slate-100 text-slate-400 group-hover/system:bg-slate-200'}`}>
                          {style.icon}
