                        <ChevronDown className="w-5 h-5" />
                      </div>
                    </button>

                    {isExpanded && (
                      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-5 pl-4 ml-6 pb-6 animate-in slide-in-from-top-4 duration-500 border-l-2 border-slate-100">
