                    <span className="w-1 h-1 rounded-full bg-slate-200"></span>
                    <span className="text-[9px] font-black uppercase tracking-[0.4em] text-blue-500">v2.4 Engine</span>
                  </div>
                  <span className="text-xs font-black uppercase tracking-[0.1em] text-slate-800">Advanced Collegiate Repository</span>
                </div>
              </div>
              <h1 className="text-5xl font-black text-slate-900 tracking-tight mb-5 leading-[1.1]">
                Master the Art of <span className="text-transparent bg-clip-text bg-gradient-to-r from-blue-600 to-indigo-600">Physical Exam</span>
              </h1>
              <p className="text-lg text-slate-500 max-w-2xl font-medium leading-relaxed">
