        <div className="absolute top-0 right-0 w-[500px] h-[500px] bg-blue-500/5 blur-[120px] rounded-full pointer-events-none -z-10"></div>
        <div className="absolute bottom-40 left-40 w-[400px] h-[400px] bg-rose-400/5 blur-[120px] rounded-full pointer-events-none -z-10"></div>

        {selectedExam ? (
          <ExamView 
            exam={selectedExam} 
            onBack={() => setSelectedExam(null)} 
          />
        ) : currentView === 'downloads' ? (
          <DownloadManager />
        ) : (
