                  </div>
                </div>
                <div className="flex flex-col">
                  <div className="flex items-center gap-2 mb-1">
                    <span className="text-[10px] font-black uppercase tracking-[0.4em] text-slate-400">MedEx Nexus</span>
                    <span className="w-1.5 h-1.5 rounded-full bg-blue-500 animate-pulse"></span>
                    <span className="text-[10px] font-black uppercase tracking-[0.4em] text-blue-500">Tier 1 Engine</span>
                  </div>
                  <span className="text-sm font-black uppercase tracking-[0.1em] text-slate-800">High-Fidelity Clinical Repository</span>
                </div>
              </div>
              <h1 className="text-6xl font-black text-slate-900 tracking-tighter mb-5 leading-[1.05]">
                Master the Art of <br/>
                <span className="text-transparent bg-clip-text bg-gradient-to-r from-blue-600 via-indigo-600 to-violet-600">Physical Exam</span>
              </h1>
              <p className="text-xl text-slate-500 max-w-2xl font-medium leading-relaxed">
                Experience the next generation of clinical education. Synthesized matrices for evidence-based diagnostics, 
                enhanced by deep medical reasoning.
              </p>
            </header>

            <div className="space-y-12">
              {Object.entries(displayGroups).map(([system, exams]) => {
                const isExpanded = expandedSystems.has(system);
                const hasResults = exams.length > 0;
                if (!hasResults && searchQuery) return null;

                const style = systemStyles[system] || systemStyles[ExamSystem.GENERAL];

                return (
                  <div key={system} className="group/system animate-in fade-in slide-in-from-bottom-8 duration-700">
                    {/* Glassmorphic Neon Heading */}
                    <button 
                      onClick={() => toggleSystem(system)}
                      className={`w-full flex items-center justify-between p-7 rounded-[38px] transition-all duration-700 border-2 backdrop-blur-2xl group/btn overflow-hidden relative ${
                        isExpanded 
                          ? `${style.activeBg} ${style.border} ${style.glow} mb-10 scale-[1.02] shadow-2xl z-10` 
