const ExamView: React.FC<ExamViewProps> = ({ exam: initialExam, onBack }) => {
  const [exam, setExam] = useState<Examination>(initialExam);
  const [activeTab, setActiveTab] = useState<'steps' | 'summary' | 'correlation' | 'media' | 'audio'>('steps');
  const [summary, setSummary] = useState<string | null>(null);
  const [loadingSummary, setLoadingSummary] = useState(false);
  const [isResearching, setIsResearching] = useState(false);
  const [correlation, setCorrelation] = useState<ClinicalCorrelation | null>(null);
  const [loadingCorrelation, setLoadingCorrelation] = useState(false);
  const [selectedSign, setSelectedSign] = useState<string | null>(null);
  const [isOnline, setIsOnline] = useState(navigator.onLine);

  const [checkedSteps, setCheckedSteps] = useState<Set<string>>(new Set());
  const [isChecklistMode, setIsChecklistMode] = useState(false);
  const [expandedCategories, setExpandedCategories] = useState<Set<string>>(new Set(['Preparation']));
  const [expandedStep, setExpandedStep] = useState<string | null>(null);

  const [currentAudio, setCurrentAudio] = useState<AudioSimulation | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const audioRef = useRef<HTMLAudioElement | null>(null);
  const [reviewExamId, setReviewExamId] = useState<string | null>(null);

  const gemini = useMemo(() => new GeminiService(), []);
  const style = systemStyles[exam.system] || systemStyles[ExamSystem.GENERAL];

  useEffect(() => {
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  useEffect(() => {
    const researchExam = async () => {
      if (exam.steps.length === 0 || exam.isDraft) {
        if (!isOnline) return;
        setIsResearching(true);
        try {
          const result = await gemini.populateExamination(exam);
          setExam(prev => ({
            ...prev,
            steps: result.steps,
            sources: result.sources,
            isDraft: false
          }));
        } catch (err) {
          console.error("Research failed", err);
        } finally {
          setIsResearching(false);
        }
      }
    };
    researchExam();
  }, [exam.id, gemini, isOnline]);

  useEffect(() => {
    const fetchSummary = async () => {
      if (!isOnline) return;
      setLoadingSummary(true);
      try {
        const text = await gemini.getExaminationSummary(exam.name);
        setSummary(text);
      } catch (err) {
        console.error(err);
      } finally {
        setLoadingSummary(false);
      }
    };
    if (!isResearching && exam.steps.length > 0) fetchSummary();
  }, [exam.id, isResearching, gemini, isOnline, exam.steps.length]);

  const fetchCorrelation = async (sign: string) => {
    if (!isOnline) return;
    setSelectedSign(sign);
    setLoadingCorrelation(true);
    try {
      const data = await gemini.getClinicalCorrelation(sign, exam.system);
      setCorrelation(data);
      setActiveTab('correlation');
    } catch (err) {
      console.error(err);
    } finally {
      setLoadingCorrelation(false);
    }
  };

  const toggleCategory = (cat: string) => {
    setExpandedCategories(prev => {
      const next = new Set(prev);
      if (next.has(cat)) next.delete(cat);
      else next.add(cat);
      return next;
    });
  };

  const toggleStep = (id: string) => {
    setCheckedSteps(prev => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  };

  const playAudio = (sim: AudioSimulation) => {
    const audioUrl = sim.localUrl || sim.url;
    if (currentAudio?.id === sim.id) {
      if (isPlaying) {
        audioRef.current?.pause();
        setIsPlaying(false);
      } else {
        audioRef.current?.play();
        setIsPlaying(true);
      }
    } else {
      setCurrentAudio(sim);
      setIsPlaying(true);
      if (audioRef.current) {
        audioRef.current.src = audioUrl;
        audioRef.current.play();
      }
    }
  };

  const progress = useMemo(() => {
    if (exam.steps.length === 0) return 0;
    return Math.round((checkedSteps.size / exam.steps.length) * 100);
  }, [checkedSteps, exam.steps]);

  if (isResearching) {
    return (
      <div className="max-w-4xl mx-auto py-24 px-6 flex flex-col items-center justify-center animate-in zoom-in-95 duration-700">
        <div className="relative mb-14">
          <div className={`w-32 h-32 border-4 border-slate-100 rounded-full animate-[spin_3s_linear_infinite] border-t-blue-600 shadow-2xl`}></div>
          <div className="absolute inset-0 flex items-center justify-center">
            <Sparkles className="w-12 h-12 text-blue-500 animate-pulse" />
          </div>
          <div className="absolute -inset-8 bg-blue-500/10 blur-3xl rounded-full -z-10 animate-pulse"></div>
        </div>
        <h2 className="text-4xl font-black text-slate-900 mb-4 text-center tracking-tighter">Constructing Protocol Matrix</h2>
        <p className="text-slate-500 text-center max-w-sm mb-10 text-lg font-medium leading-relaxed">
          Nexus agents are correlating high-fidelity protocols for <br/><span className="text-blue-600 font-black">{exam.name}</span>.
        </p>
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto py-8 px-6 animate-in fade-in slide-in-from-bottom-6 duration-700">
      <audio ref={audioRef} onEnded={() => setIsPlaying(false)} />

      {reviewExamId && <QuickReviewModal examId={reviewExamId} onClose={() => setReviewExamId(null)} />}

      {/* Dynamic Background Elements */}
      <div className={`fixed top-0 right-0 w-[600px] h-[600px] blur-[150px] rounded-full -z-20 opacity-30 ${style.bg} pointer-events-none`}></div>

      {/* Navigation Layer */}
      <div className="flex items-center justify-between mb-10 relative z-20">
        <button 
          onClick={onBack}
          className="group flex items-center gap-4 px-6 py-3 bg-white/80 backdrop-blur-xl rounded-[22px] border border-slate-100 text-[11px] font-black uppercase tracking-widest text-slate-600 hover:text-blue-700 hover:border-blue-300 hover:shadow-2xl hover:shadow-blue-500/10 transition-all active:scale-95"
        >
          <ChevronRight className="w-5 h-5 rotate-180 transition-transform group-hover:-translate-x-2" />
          Back to Hub
        </button>

        <div className="flex items-center gap-4">
          {!isOnline && (
            <div className="flex items-center gap-3 px-4 py-2 bg-rose-500 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-rose-200 animate-pulse">
              <WifiOff className="w-4 h-4" />
              Nexus Link Lost
            </div>
          )}
          <button 
            onClick={() => setIsChecklistMode(!isChecklistMode)}
            className={`px-7 py-3 rounded-[24px] text-[11px] font-black uppercase tracking-[0.2em] flex items-center gap-3 transition-all shadow-2xl relative overflow-hidden group ${
              isChecklistMode 
                ? 'bg-emerald-600 text-white shadow-emerald-500/30' 
                : 'bg-slate-900 text-white hover:bg-black shadow-slate-900/30'
            }`}
          >
            <div className="absolute inset-0 bg-gradient-to-r from-white/10 to-transparent opacity-0 group-hover:opacity-100 transition-opacity"></div>
            <ClipboardList className="w-5 h-5 relative z-10" />
            <span className="relative z-10">{isChecklistMode ? 'Terminate Mock OSCE' : 'Engage Training Mode'}</span>
          </button>
        </div>
      </div>

      {/* Cinematic Hero Section */}
      <div className={`relative rounded-[60px] overflow-hidden mb-12 transition-all duration-1000 border-4 backdrop-blur-3xl shadow-3xl ${style.border} ${style.glow}`}>
        <div className={`absolute inset-0 opacity-40 bg-gradient-to-br from-white/20 via-transparent to-black pointer-events-none`}></div>
        <div className="p-12 md:p-16 bg-slate-950 relative">
          {/* Dynamic Accents */}
          <div className={`absolute top-0 right-0 w-80 h-80 blur-[120px] rounded-full opacity-30 ${style.bg} animate-pulse`}></div>
          <div className="absolute bottom-0 left-0 w-80 h-80 blur-[120px] rounded-full opacity-20 bg-blue-500/20"></div>

          <div className="relative z-10">
            <div className="flex items-center gap-4 mb-6">
              <div className={`px-5 py-2 rounded-full text-[11px] font-black uppercase tracking-[0.3em] border backdrop-blur-3xl transition-all duration-700 ${style.bg} ${style.border} ${style.text} shadow-xl`}>
                {exam.system} Protocols
              </div>
              <div className="flex items-center gap-2 px-4 py-2 rounded-full bg-white/5 border border-white/10 text-[10px] font-black text-slate-400 uppercase tracking-widest backdrop-blur-sm">
                <Target className="w-4 h-4 text-blue-400" />
                Mastery Level: 01
              </div>
            </div>

            <h2 className="text-5xl md:text-6xl font-black text-white mb-6 tracking-tighter leading-[1]">{exam.name}</h2>
            <p className="text-slate-400 max-w-2xl text-xl font-medium leading-relaxed opacity-90">{exam.shortDescription}</p>

            <div className="mt-10 flex flex-wrap gap-4">
              {(exam.relatedExamIds || []).map(id => {
                const related = EXAMINATIONS.find(e => e.id === id);
                if (!related) return null;
                return (
                  <button 
                    key={id}
                    onClick={() => setReviewExamId(id)}
                    className="flex items-center gap-3 px-5 py-2.5 bg-white/5 hover:bg-white/15 rounded-[20px] border border-white/10 text-[10px] font-black text-white uppercase tracking-widest transition-all hover:scale-105 active:scale-95 group/rel"
                  >
                    <LinkIcon className="w-4 h-4 text-blue-400 group-hover/rel:rotate-45 transition-transform" />
                    {related.name}
                  </button>
                );
              })}
            </div>

            {isChecklistMode && (
              <div className="mt-12 bg-white/5 backdrop-blur-[40px] p-10 rounded-[48px] border border-white/10 shadow-3xl animate-in zoom-in-95 duration-700">
                <div className="flex justify-between items-end mb-6">
                  <div>
                    <p className="text-[11px] font-black uppercase tracking-[0.4em] text-emerald-400 mb-2">Diagnostic Integrity</p>
                    <h4 className="text-5xl font-black text-white tabular-nums tracking-tighter">{progress}<span className="text-emerald-400 text-3xl">%</span></h4>
                  </div>
                  <div className="text-right">
                    <p className="text-[11px] font-black uppercase tracking-[0.4em] text-slate-500 mb-2">Operations Complete</p>
                    <p className="text-3xl font-black text-white">{checkedSteps.size} <span className="text-slate-700">/ {exam.steps.length}</span></p>
                  </div>
                </div>
                <div className="w-full h-5 bg-white/5 rounded-full overflow-hidden border border-white/10 p-1 shadow-inner">
                  <div 
                    className={`h-full bg-gradient-to-r ${style.accent} rounded-full transition-all duration-1000 shadow-[0_0_30px_rgba(59,130,246,0.6)]`} 
                    style={{ width: `${progress}%` }}
                  />
                </div>
              </div>
            )}
          </div>
        </div>

        {/* Improved Neon Glassmorphic Tab System */}
        <div className="flex border-t border-white/10 bg-slate-950/80 backdrop-blur-[60px] overflow-x-auto custom-scrollbar">
          {[
            { id: 'steps', label: 'Protocol Matrix', icon: <ClipboardList className="w-5 h-5" /> },
            { id: 'audio', label: 'Soundscapes', icon: <Ear className="w-5 h-5" />, hide: !exam.audioSimulations?.length },
            { id: 'media', label: 'Matrix Stream', icon: <Play className="w-5 h-5" />, disabled: !isOnline && !exam.isDownloaded },
            { id: 'summary', label: 'Deep Insights', icon: <Info className="w-5 h-5" />, disabled: !isOnline && !summary },
            { id: 'correlation', label: 'Sign Analysis', icon: <Zap className="w-5 h-5" />, disabled: !isOnline && !correlation }
          ].filter(t => !t.hide).map(tab => (
            <button 
              key={tab.id}
              disabled={tab.disabled}
              onClick={() => setActiveTab(tab.id as any)}
              className={`flex-1 min-w-[160px] py-8 text-[11px] font-black uppercase tracking-[0.25em] transition-all flex flex-col items-center justify-center gap-4 relative group/tab ${
                activeTab === tab.id 
                  ? 'text-white' 
                  : tab.disabled ? 'opacity-20 cursor-not-allowed' : 'text-slate-500 hover:text-slate-300'
              }`}
            >
              <div className={`p-3.5 rounded-[22px] transition-all duration-500 ${activeTab === tab.id ? `${style.secondary} shadow-2xl scale-125 rotate-3` : 'bg-white/5 group-hover/tab:bg-white/10 group-hover/tab:scale-110'}`}>
                {tab.icon}
              </div>
              <span className="relative z-10">{tab.label}</span>
              {activeTab === tab.id && (
                <div className={`absolute bottom-0 left-0 right-0 h-1.5 ${style.secondary} shadow-[0_0_20px_rgba(59,130,246,0.8)] animate-pulse`}></div>
              )}
            </button>
          ))}
        </div>
      </div>

      {/* Main Content Modules */}
      <div className="space-y-10">
        {activeTab === 'steps' && (
          <div className="space-y-10">
            {['Preparation', 'Inspection', 'Palpation', 'Percussion', 'Auscultation', 'Special Tests', 'Conclusion'].map((cat, index) => {
              const catSteps = exam.steps.filter(s => s.category === cat);
              if (catSteps.length === 0) return null;
              const isCatExpanded = expandedCategories.has(cat);
              const checkedInCat = catSteps.filter(s => checkedSteps.has(s.id)).length;
              const catProgress = Math.round((checkedInCat / catSteps.length) * 100);

              return (
                <div key={cat} className="animate-in fade-in slide-in-from-bottom-8 duration-700" style={{ animationDelay: `${index * 80}ms` }}>
                  {/* Category Module - High Intensity Glassmorphism */}
                  <div className={`rounded-[48px] border-2 transition-all duration-700 overflow-hidden shadow-2xl ${
                    isCatExpanded 
                      ? 'bg-white/90 border-slate-200 backdrop-blur-2xl mb-6' 
                      : 'bg-white/50 border-slate-100/50 hover:border-slate-300 backdrop-blur-xl'
                  }`}>
                    <button 
                      onClick={() => toggleCategory(cat)}
                      className={`w-full flex items-center justify-between p-8 transition-all relative overflow-hidden group/cat-btn ${isCatExpanded ? 'bg-slate-50/50' : ''}`}
                    >
                      <div className="absolute inset-0 bg-gradient-to-r from-blue-50/10 to-transparent opacity-0 group-hover/cat-btn:opacity-100 transition-opacity"></div>

                      <div className="flex items-center gap-7 relative z-10">
                        <div className={`w-16 h-16 rounded-3xl flex items-center justify-center font-black text-2xl transition-all duration-700 ${
                          isCatExpanded ? `${style.secondary} text-white shadow-3xl scale-110 rotate-6` : 'bg-slate-100 text-slate-400 group-hover/cat-btn:bg-slate-200'
                        }`}>
                          {index + 1}
                        </div>
                        <div className="text-left">
                          <h3 className={`font-black tracking-tighter text-3xl ${isCatExpanded ? 'text-slate-900' : 'text-slate-600'}`}>
                            {cat}
                          </h3>
                          <div className="flex items-center gap-3 mt-2">
                             <div className="h-2 w-24 bg-slate-200 rounded-full overflow-hidden shadow-inner">
                               <div className={`h-full transition-all duration-1000 shadow-xl ${catProgress === 100 ? 'bg-emerald-500' : style.secondary}`} style={{ width: `${catProgress}%` }}></div>
                             </div>
                             <span className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500">
                               {checkedInCat} / {catSteps.length} Verified
                             </span>
                          </div>
                        </div>
                      </div>
                      <div className={`transition-all duration-700 p-3 rounded-full ${isCatExpanded ? `rotate-180 bg-white text-slate-950 shadow-2xl scale-110` : 'text-slate-300 bg-slate-50'}`}>
                        <ChevronDown className="w-7 h-7" />
                      </div>
                    </button>

                    {isCatExpanded && (
                      <div className="p-8 space-y-5 animate-in slide-in-from-top-4 duration-500">
                        {catSteps.map((step) => {
                          const isChecked = checkedSteps.has(step.id);
                          const isStepExpanded = expandedStep === step.id;
                          return (
                            <div 
                              key={step.id} 
                              className={`group relative border-2 transition-all duration-500 rounded-[32px] overflow-hidden ${
                                isChecked 
                                  ? 'border-emerald-500 bg-emerald-50/20 shadow-emerald-100/50' 
                                  : 'border-slate-50 bg-slate-50/40 hover:border-blue-300 hover:bg-white hover:shadow-3xl hover:shadow-blue-500/10 hover:scale-[1.01]'
                              }`}
                            >
                              <div 
                                onClick={() => isChecklistMode ? toggleStep(step.id) : setExpandedStep(isStepExpanded ? null : step.id)}
                                className="px-8 py-7 cursor-pointer flex justify-between items-start gap-6"
                              >
                                <div className="flex-1 flex gap-6">
                                  {isChecklistMode && (
                                    <div className={`w-8 h-8 rounded-xl border-3 flex items-center justify-center transition-all duration-500 flex-shrink-0 mt-0.5 shadow-xl ${
                                      isChecked ? 'bg-emerald-500 border-emerald-500 scale-125 rotate-6 shadow-emerald-400/50' : 'bg-white border-slate-200'
                                    }`}>
                                      {isChecked && <CheckCircle2 className="w-5 h-5 text-white" />}
                                    </div>
                                  )}
                                  <div>
                                    <h4 className={`text-xl font-black tracking-tight mb-2 ${isChecked ? 'text-emerald-900' : 'text-slate-900'}`}>
                                      {step.title}
                                    </h4>
                                    <p className={`text-sm leading-relaxed font-medium ${isChecked ? 'text-emerald-800/60' : 'text-slate-500'}`}>
                                      {step.description}
                                    </p>
                                  </div>
                                </div>
                                <div className="flex items-center gap-4">
                                  <button 
                                    disabled={!isOnline}
                                    onClick={(e) => { e.stopPropagation(); fetchCorrelation(step.title); }}
                                    className={`p-3.5 rounded-2xl transition-all shadow-xl group/zap-btn ${
                                      !isOnline ? 'text-slate-200' : 'hover:bg-blue-600 hover:text-white hover:shadow-2xl hover:scale-110 bg-white border border-slate-100 text-blue-500'
                                    }`}
                                  >
                                    {loadingCorrelation && selectedSign === step.title ? (
                                      <Loader2 className="w-5 h-5 animate-spin" />
                                    ) : (
                                      <Zap className="w-5 h-5 group-hover/zap-btn:animate-bounce" />
                                    )}
                                  </button>
                                  <div className={`transition-transform duration-500 ${isStepExpanded ? 'rotate-180' : ''}`}>
                                     <ChevronDown className="w-7 h-7 text-slate-300" />
                                  </div>
                                </div>
