import React, { useState, useEffect, useRef } from 'react';
import { Examination, AudioSimulation, ClinicalCorrelation } from '../types';
import { GeminiService } from '../services/geminiService';
import { SYSTEM_THEMES, DEFAULT_STYLE } from '../theme';
import { 
  ChevronRight, ClipboardList, Target, Ear, Play, Info, Zap, 
  CheckCircle2, ChevronDown, Lightbulb, Loader2, Sparkles, Volume2, Pause, 
  WifiOff, BookOpen, ExternalLink, X
} from 'lucide-react';

interface ExamViewProps {
  exam: Examination;
  onBack: () => void;
}

const ExamView: React.FC<ExamViewProps> = ({ exam: initialExam, onBack }) => {
  const [exam, setExam] = useState(initialExam);
  const [activeTab, setActiveTab] = useState<'steps' | 'summary' | 'correlation' | 'media' | 'audio'>('steps');
  const [summary, setSummary] = useState<string | null>(null);
  const [loadingSummary, setLoadingSummary] = useState(false);
  const [isResearching, setIsResearching] = useState(false);
  const [correlation, setCorrelation] = useState<ClinicalCorrelation | null>(null);
  const [loadingCorrelation, setLoadingCorrelation] = useState(false);
  const [selectedSign, setSelectedSign] = useState<string | null>(null);
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [checkedSteps, setCheckedSteps] = useState<Set<string>>(new Set());
  const [isChecklistMode, setIsChecklistMode] = useState(false);
  const [expandedCategories, setExpandedCategories] = useState<Set<string>>(new Set(['Preparation']));
  const [expandedStep, setExpandedStep] = useState<string | null>(null);
  const [currentAudio, setCurrentAudio] = useState<AudioSimulation | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  const gemini = new GeminiService();
  const style = SYSTEM_THEMES[exam.system] || DEFAULT_STYLE;

  useEffect(() => {
    const research = async () => {
      if (exam.steps.length === 0 && isOnline) {
        setIsResearching(true);
        try {
          const res = await gemini.populateExamination(exam);
          setExam(prev => ({ ...prev, steps: res.steps, sources: res.sources, isDraft: false }));
        } catch (e) { console.error(e); }
        finally { setIsResearching(false); }
      }
    };
    research();
  }, [exam.id, isOnline]);

  useEffect(() => {
    if (activeTab === 'summary' && !summary && isOnline) {
      setLoadingSummary(true);
      gemini.getExaminationSummary(exam.name).then(s => {
        setSummary(s);
        setLoadingSummary(false);
      });
    }
  }, [activeTab]);

  const fetchCorrelation = async (sign: string) => {
    if (!isOnline) return;
    setSelectedSign(sign);
    setLoadingCorrelation(true);
    try {
      const data = await gemini.getClinicalCorrelation(sign, exam.system);
      setCorrelation(data);
      setActiveTab('correlation');
    } finally { setLoadingCorrelation(false); }
  };

  const progress = exam.steps.length > 0 ? Math.round((checkedSteps.size / exam.steps.length) * 100) : 0;

  if (isResearching) return (
    <div className="h-full flex flex-col items-center justify-center p-20">
      <Loader2 className="w-10 h-10 text-blue-600 animate-spin mb-4" />
      <p className="text-xs font-black uppercase text-slate-400">Synthesizing Matrix...</p>
    </div>
  );

  return (
    <div className="max-w-3xl mx-auto py-6 px-4 animate-in fade-in slide-in-from-bottom-2 duration-500">
      <audio ref={audioRef} onEnded={() => setIsPlaying(false)} />

      <div className="flex items-center justify-between mb-6">
        <button onClick={onBack} className="flex items-center gap-2 px-4 py-2 bg-white/80 backdrop-blur rounded-xl border border-slate-100 text-[10px] font-black uppercase text-slate-600 hover:text-blue-700 transition-all">
          <ChevronRight className="w-3.5 h-3.5 rotate-180" /> Back
        </button>
        <button onClick={() => setIsChecklistMode(!isChecklistMode)} className={`px-5 py-2 rounded-xl text-[10px] font-black uppercase flex items-center gap-2 shadow-md ${isChecklistMode ? 'bg-emerald-600 text-white' : 'bg-slate-900 text-white'}`}>
          <ClipboardList className="w-4 h-4" /> {isChecklistMode ? 'Finish' : 'OSCE Mode'}
        </button>
      </div>

      <div className={`rounded-[32px] overflow-hidden mb-8 border-2 transition-all ${style.border} ${style.glow}`}>
        <div className="p-8 md:p-10 bg-slate-950 relative">
          <div className="flex items-center gap-3 mb-4">
            <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase border ${style.bg} ${style.border} ${style.text}`}>{exam.system}</span>
          </div>
          <h2 className="text-3xl font-black text-white mb-3 tracking-tighter">{exam.name}</h2>
          <p className="text-xs text-slate-400 font-medium max-w-xl">{exam.shortDescription}</p>
          {isChecklistMode && (
            <div className="mt-6 w-full h-2 bg-white/5 rounded-full overflow-hidden">
              <div className={`h-full ${style.secondary} transition-all duration-700`} style={{ width: `${progress}%` }} />
            </div>
          )}
        </div>
        <div className="flex bg-slate-950/90 backdrop-blur-xl overflow-x-auto">
          {['steps', 'audio', 'media', 'summary', 'correlation'].map((tab: any) => (
            <button key={tab} onClick={() => setActiveTab(tab)} className={`flex-1 py-4 text-[9px] font-black uppercase flex flex-col items-center gap-2 relative transition-all ${activeTab === tab ? 'text-white' : 'text-slate-500'}`}>
              <span className="capitalize">{tab}</span>
              {activeTab === tab && <div className={`absolute bottom-0 h-1 w-full ${style.secondary}`} />}
            </button>
          ))}
        </div>
      </div>

      <div className="space-y-4">
        {activeTab === 'steps' && exam.steps.map((step, idx) => {
          const isExpanded = expandedStep === step.id;
          const isChecked = checkedSteps.has(step.id);
          return (
            <div key={step.id} className={`rounded-2xl border p-4 transition-all ${isChecked ? 'bg-emerald-50/20 border-emerald-200' : 'bg-white border-slate-100 shadow-sm'}`}>
              <div className="flex items-start gap-3 cursor-pointer" onClick={() => isChecklistMode ? setCheckedSteps(p => {const n=new Set(p); if(n.has(step.id)) n.delete(step.id); else n.add(step.id); return n;}) : setExpandedStep(isExpanded ? null : step.id)}>
                {isChecklistMode && <div className={`w-5 h-5 rounded border-2 shrink-0 ${isChecked ? 'bg-emerald-500 border-emerald-500' : 'bg-white border-slate-200'}`} />}
                <div className="flex-1">
                  <h4 className="font-black text-slate-900 text-xs">{step.title}</h4>
                  <p className="text-[10px] text-slate-500">{step.description}</p>
                </div>
                <button onClick={(e) => { e.stopPropagation(); fetchCorrelation(step.title); }} className="p-2 text-blue-500"><Zap className="w-3.5 h-3.5" /></button>
              </div>
            </div>
          );
        })}
        {activeTab === 'summary' && loadingSummary && <Loader2 className="w-6 h-6 animate-spin mx-auto py-10" />}
        {activeTab === 'summary' && summary && <div className="p-8 bg-white rounded-[32px] border border-slate-100 text-sm leading-relaxed text-slate-700 font-medium">{summary}</div>}
      </div>
    </div>
  );
};

