interface ExamViewProps {
  exam: Examination;
  onBack: () => void;
}

const ExamView: React.FC<ExamViewProps> = ({ exam: initialExam, onBack }) => {
  const [exam, setExam] = useState(initialExam);
  const [activeTab, setActiveTab] = useState<'steps' | 'summary' | 'correlation' | 'media' | 'audio'>('steps');
  const [summary, setSummary] = useState<string | null>(null);
  const [loadingSummary, setLoadingSummary] = useState(false);
  const [isResearching, setIsResearching] = useState(false);
  const [correlation, setCorrelation] = useState<ClinicalCorrelation | null>(null);
  const [loadingCorrelation, setLoadingCorrelation] = useState(false);
  const [selectedSign, setSelectedSign] = useState<string | null>(null);
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [checkedSteps, setCheckedSteps] = useState<Set<string>>(new Set());
  const [isChecklistMode, setIsChecklistMode] = useState(false);
  const [expandedCategories, setExpandedCategories] = useState<Set<string>>(new Set(['Preparation']));
  const [expandedStep, setExpandedStep] = useState<string | null>(null);
  const [currentAudio, setCurrentAudio] = useState<AudioSimulation | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  const gemini = new GeminiService();
  const style = SYSTEM_THEMES[exam.system] || DEFAULT_STYLE;

  useEffect(() => {
    const research = async () => {
      if (exam.steps.length === 0 && isOnline) {
        setIsResearching(true);
        try {
          const res = await gemini.populateExamination(exam);
          setExam(prev => ({ ...prev, steps: res.steps, sources: res.sources, isDraft: false }));
        } catch (e) { console.error(e); }
        finally { setIsResearching(false); }
      }
    };
    research();
  }, [exam.id, isOnline]);

  useEffect(() => {
    if (activeTab === 'summary' && !summary && isOnline) {
      setLoadingSummary(true);
      gemini.getExaminationSummary(exam.name).then(s => {
        setSummary(s);
        setLoadingSummary(false);
      });
    }
  }, [activeTab]);

  const fetchCorrelation = async (sign: string) => {
    if (!isOnline) return;
    setSelectedSign(sign);
    setLoadingCorrelation(true);
    try {
      const data = await gemini.getClinicalCorrelation(sign, exam.system);
      setCorrelation(data);
      setActiveTab('correlation');
    } finally { setLoadingCorrelation(false); }
  };

  const progress = exam.steps.length > 0 ? Math.round((checkedSteps.size / exam.steps.length) * 100) : 0;

  if (isResearching) return (
    <div className="h-full flex flex-col items-center justify-center p-20 animate-in fade-in zoom-in duration-500">
      <Loader2 className="w-10 h-10 text-blue-600 animate-spin mb-4" />
      <p className="text-xs font-black uppercase text-slate-400">Synthesizing Matrix...</p>
    </div>
  );

  return (
    <div className="max-w-3xl mx-auto py-6 px-4 animate-in fade-in slide-in-from-bottom-2 duration-700">
      <audio ref={audioRef} onEnded={() => setIsPlaying(false)} />

      <div className="flex items-center justify-between mb-6">
        <Tooltip content="Return to Repository" position="right">
          <button onClick={onBack} className="flex items-center gap-2 px-4 py-2 bg-white/80 backdrop-blur rounded-xl border border-slate-100 text-[10px] font-black uppercase text-slate-600 hover:text-blue-700 transition-all hover:scale-105 active:scale-95">
            <ChevronRight className="w-3.5 h-3.5 rotate-180" /> Back
          </button>
        </Tooltip>
        <Tooltip content={isChecklistMode ? "Exit Examination Mode" : "Start Simulated OSCE"}>
          <button onClick={() => setIsChecklistMode(!isChecklistMode)} className={`px-5 py-2 rounded-xl text-[10px] font-black uppercase flex items-center gap-2 shadow-md transition-all hover:scale-105 active:scale-95 ${isChecklistMode ? 'bg-emerald-600 text-white' : 'bg-slate-900 text-white'}`}>
            <ClipboardList className="w-4 h-4" /> {isChecklistMode ? 'Finish' : 'OSCE Mode'}
          </button>
        </Tooltip>
      </div>

      <div className={`rounded-[32px] overflow-hidden mb-8 border-2 transition-all duration-700 ${style.border} ${style.glow}`}>
        <div className="p-8 md:p-10 bg-slate-950 relative overflow-hidden">
          <div className="absolute top-0 right-0 p-8 opacity-10 pointer-events-none group-hover:rotate-12 transition-transform duration-1000">
             <div className="scale-[5]">{style.icon}</div>
          </div>
          <div className="relative z-10">
            <div className="flex items-center gap-3 mb-4">
              <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase border ${style.bg} ${style.border} ${style.text}`}>{exam.system}</span>
              <Tooltip content="Level 1 Clinical Synthesis">
                <Target className="w-3 h-3 text-blue-500" />
              </Tooltip>
            </div>
            <h2 className="text-3xl font-black text-white mb-3 tracking-tighter">{exam.name}</h2>
            <p className="text-xs text-slate-400 font-medium max-w-xl">{exam.shortDescription}</p>
            {isChecklistMode && (
              <div className="mt-6 w-full h-2 bg-white/5 rounded-full overflow-hidden border border-white/5">
                <div className={`h-full ${style.secondary} transition-all duration-1000 ease-out`} style={{ width: `${progress}%` }} />
              </div>
            )}
          </div>
        </div>
        <div className="flex bg-slate-950/90 backdrop-blur-xl overflow-x-auto border-t border-white/5">
          {[
            { id: 'steps', label: 'Protocol', icon: <ClipboardList className="w-3.5 h-3.5" /> },
            { id: 'audio', label: 'Audio', icon: <Ear className="w-3.5 h-3.5" /> },
            { id: 'media', label: 'Video', icon: <Play className="w-3.5 h-3.5" /> },
            { id: 'summary', label: 'Insights', icon: <Info className="w-3.5 h-3.5" /> },
            { id: 'correlation', label: 'AI Study', icon: <Zap className="w-3.5 h-3.5" /> }
          ].map((tab: any) => (
            <Tooltip key={tab.id} content={`View ${tab.label}`}>
              <button 
                onClick={() => setActiveTab(tab.id)} 
                className={`flex-1 min-w-[80px] py-4 text-[9px] font-black uppercase flex flex-col items-center gap-2 relative transition-all duration-300 ${activeTab === tab.id ? 'text-white' : 'text-slate-500 hover:text-slate-300'}`}
              >
                <div className={`p-1.5 rounded-lg transition-all ${activeTab === tab.id ? style.secondary : 'bg-white/5'}`}>{tab.icon}</div>
                {tab.label}
                {activeTab === tab.id && <div className={`absolute bottom-0 h-1 w-full ${style.secondary} animate-in fade-in slide-in-from-bottom-1`} />}
              </button>
            </Tooltip>
          ))}
        </div>
      </div>

      <div className="space-y-4">
        {activeTab === 'steps' && exam.steps.map((step, idx) => {
          const isExpanded = expandedStep === step.id;
          const isChecked = checkedSteps.has(step.id);
          return (
            <div key={step.id} className={`rounded-2xl border p-4 transition-all duration-500 animate-in fade-in slide-in-from-left-4 ${isChecked ? 'bg-emerald-50/20 border-emerald-200' : 'bg-white border-slate-100 shadow-sm hover:shadow-md'}`} style={{ animationDelay: `${idx * 50}ms` }}>
              <div className="flex items-start gap-3 cursor-pointer" onClick={() => isChecklistMode ? setCheckedSteps(p => {const n=new Set(p); if(n.has(step.id)) n.delete(step.id); else n.add(step.id); return n;}) : setExpandedStep(isExpanded ? null : step.id)}>
                {isChecklistMode && (
                  <Tooltip content={isChecked ? "Unmark Step" : "Mark as Completed"}>
                    <div className={`w-5 h-5 rounded border-2 shrink-0 transition-all ${isChecked ? 'bg-emerald-500 border-emerald-500 scale-110' : 'bg-white border-slate-200'}`}>
                      {isChecked && <CheckCircle2 className="w-full h-full text-white p-0.5" />}
                    </div>
                  </Tooltip>
                )}
                <div className="flex-1">
                  <h4 className="font-black text-slate-900 text-xs transition-colors duration-300 group-hover:text-blue-600">{step.title}</h4>
                  <p className="text-[10px] text-slate-500 leading-relaxed">{step.description}</p>
                </div>
                <Tooltip content="AI Correlation Analysis">
                  <button onClick={(e) => { e.stopPropagation(); fetchCorrelation(step.title); }} className="p-2 text-blue-500 hover:scale-125 transition-transform active:rotate-12">
                    <Zap className="w-3.5 h-3.5" />
                  </button>
                </Tooltip>
              </div>
            </div>
          );
        })}
        {activeTab === 'summary' && (
          <div className="animate-in zoom-in-95 duration-500">
            {loadingSummary ? <Loader2 className="w-6 h-6 animate-spin mx-auto py-10 text-blue-600" /> : 
            summary && <div className="p-8 bg-white rounded-[32px] border border-slate-100 text-sm leading-relaxed text-slate-700 font-medium shadow-sm">{summary}</div>}
          </div>
        )}
      </div>
    </div>
  );
};

