import React, { useState, useEffect } from 'react';
import { downloadManager } from '../services/downloadManagerService';
import { DownloadTask } from '../types';
import Tooltip from './Tooltip';
import { 
  CloudDownload, 
  Trash2, 
  Pause, 
  Play, 
  X, 
  CheckCircle2, 
  AlertCircle,
  Loader2,
  Package,
  ArrowDownToLine,
  RefreshCw,
  Info
} from 'lucide-react';

const DownloadManager: React.FC = () => {
  const [tasks, setTasks] = useState<DownloadTask[]>([]);
  const [isPaused, setIsPaused] = useState(false);
  const [isDraggingOverTrash, setIsDraggingOverTrash] = useState(false);

  useEffect(() => {
    const unsub = downloadManager.subscribe((newTasks) => {
      setTasks(newTasks);
      setIsPaused(downloadManager.getPauseState());
    });
    return () => { unsub(); };
  }, []);

  const getStatusIcon = (status: DownloadTask['status']) => {
    switch (status) {
      case 'completed': return <CheckCircle2 className="w-3.5 h-3.5 text-green-500" />;
      case 'failed': return <AlertCircle className="w-3.5 h-3.5 text-red-500" />;
      case 'downloading': return <Loader2 className="w-3.5 h-3.5 text-blue-500 animate-spin" />;
      case 'paused': return <Pause className="w-3.5 h-3.5 text-slate-400" />;
      default: return <RefreshCw className="w-3.5 h-3.5 text-slate-300" />;
    }
  };

  return (
    <div className="max-w-4xl mx-auto py-8 px-6 animate-in fade-in duration-700 flex flex-col h-full overflow-hidden">
      <header className="flex items-center justify-between mb-8 shrink-0">
        <div className="flex items-center gap-4">
           <div className="p-2.5 bg-blue-50 rounded-xl border border-blue-100 text-blue-600 animate-pulse"><CloudDownload className="w-5 h-5" /></div>
           <div><h1 className="text-xl font-black text-slate-900 tracking-tight uppercase">Assets</h1></div>
        </div>
        <Tooltip content={isPaused ? "Resume All Tasks" : "Pause Queue Processing"}>
          <button 
            onClick={() => downloadManager.togglePause()}
            className={`px-4 py-2 rounded-xl font-black uppercase tracking-widest text-[9px] transition-all duration-300 hover:scale-105 active:scale-95 shadow-md ${isPaused ? 'bg-green-600 text-white' : 'bg-slate-100 text-slate-600'}`}
          >
            {isPaused ? 'Resume' : 'Pause'}
          </button>
        </Tooltip>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-6 flex-1 min-h-0">
        <div className="lg:col-span-3 flex flex-col min-h-0">
          <div className="flex-1 bg-slate-50 rounded-[28px] border border-slate-100 overflow-y-auto p-4 space-y-3 custom-scrollbar">
            {tasks.length === 0 ? (
              <div className="h-full flex flex-col items-center justify-center text-slate-300 animate-in fade-in zoom-in-90 duration-1000">
                <ArrowDownToLine className="w-8 h-8 mb-2 opacity-10" />
                <p className="text-[10px] font-black uppercase tracking-widest">Pipeline Empty</p>
              </div>
            ) : tasks.map((task, idx) => (
              <div key={task.id} className="p-4 bg-white rounded-2xl border border-slate-100 shadow-sm animate-in slide-in-from-right-4 duration-500" style={{ animationDelay: `${idx * 100}ms` }}>
                <div className="flex items-center justify-between gap-3 mb-2">
                   <div className="flex items-center gap-3">
                      <Tooltip content={task.status.toUpperCase()}>
                        <div className="p-2 bg-slate-50 rounded-lg">{getStatusIcon(task.status)}</div>
                      </Tooltip>
                      <div>
                        <h4 className="text-[11px] font-black text-slate-900 leading-none mb-1">{task.examName}</h4>
                        <p className="text-[8px] font-bold text-slate-400 uppercase tracking-widest">{task.type}</p>
                      </div>
                   </div>
                   <div className="text-[10px] font-black tabular-nums">{task.progress}%</div>
                </div>
                <div className="w-full h-1.5 bg-slate-50 rounded-full overflow-hidden border border-slate-100">
                  <div className="h-full bg-blue-600 transition-all duration-1000 ease-out" style={{ width: `${task.progress}%` }} />
                </div>
              </div>
            ))}
          </div>
        </div>

        <div className="space-y-4 flex flex-col">
          <Tooltip content="Drop active tasks here to remove them from queue" position="left">
            <div 
              onDrop={(e) => { e.preventDefault(); const id = e.dataTransfer.getData('taskId'); if(id) downloadManager.cancelTask(id); setIsDraggingOverTrash(false); }}
              onDragOver={(e) => { e.preventDefault(); setIsDraggingOverTrash(true); }}
              onDragLeave={() => setIsDraggingOverTrash(false)}
              className={`flex-1 min-h-[100px] rounded-[28px] border-2 border-dashed flex flex-col items-center justify-center transition-all duration-500 ${isDraggingOverTrash ? 'border-red-500 bg-red-50 text-red-500 scale-105 rotate-3' : 'border-slate-100 bg-slate-50 text-slate-400'}`}
            >
              <Trash2 className={`w-5 h-5 mb-2 ${isDraggingOverTrash ? 'animate-bounce' : ''}`} />
              <p className="text-[9px] font-black uppercase tracking-widest">Cancel Task</p>
            </div>
          </Tooltip>

          <div className="p-6 bg-slate-900 rounded-[28px] text-white shadow-2xl group transition-transform hover:scale-105">
             <div className="flex items-center gap-2 text-blue-400 mb-3">
                <Tooltip content="Current Queue Performance" position="left">
                  <Info className="w-3.5 h-3.5 group-hover:rotate-12 transition-transform" />
                </Tooltip>
                <span className="text-[8px] font-black uppercase tracking-widest">Queue Stat</span>
             </div>
             <p className="text-xl font-black">{tasks.filter(t => t.status === 'completed').length} / {tasks.length}</p>
             <p className="text-[9px] font-bold text-slate-500 uppercase tracking-widest">Matrices Cached</p>
          </div>
        </div>
      </div>
    </div>
  );
};

