        <div className="relative group/search">
          <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-slate-400 group-focus-within/search:text-blue-500 transition-colors pointer-events-none" />
          <input 
            type="text" 
            value={searchQuery}
            onChange={(e) => onSearch(e.target.value)}
            placeholder="Search Protocol..." 
            className="w-full pl-8 pr-3 py-2 bg-slate-50 border-none rounded-xl text-[11px] font-medium focus:ring-2 focus:ring-blue-500 transition-all placeholder:text-slate-400"
          />
