          className="w-full pl-16 pr-40 py-6 bg-white border-2 border-slate-100 rounded-[32px] text-base font-bold text-slate-900 focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 transition-all shadow-xl shadow-slate-200/50"
