import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Examination, ClinicalCorrelation, ExamStep } from '../types';
import { GeminiService } from '../services/geminiService';
import { SYSTEM_THEMES, DEFAULT_STYLE } from '../theme';
import Tooltip from './Tooltip';
import DifferentialPanel from './DifferentialPanel';
import { 
  ChevronRight, ClipboardList, Target, Ear, Play, Info, Zap, 
  CheckCircle2, ChevronDown, Lightbulb, Loader2, Sparkles, X, ListCheck, BrainCircuit
} from 'lucide-react';

interface ExamViewProps {
  exam: Examination;
  onBack: () => void;
}

const ExamView: React.FC<ExamViewProps> = ({ exam: initialExam, onBack }) => {
  const [exam, setExam] = useState(initialExam);
  const [activeTab, setActiveTab] = useState<'steps' | 'summary' | 'correlation' | 'media' | 'audio'>('steps');
  const [summary, setSummary] = useState<string | null>(null);
  const [loadingSummary, setLoadingSummary] = useState(false);
  const [isResearching, setIsResearching] = useState(false);
  const [correlation, setCorrelation] = useState<ClinicalCorrelation | null>(null);
  const [loadingCorrelation, setLoadingCorrelation] = useState(false);
  const [isOnline] = useState(navigator.onLine);
  const [checkedSteps, setCheckedSteps] = useState<Set<string>>(new Set());
  const [isChecklistMode, setIsChecklistMode] = useState(false);
  const [expandedCategories, setExpandedCategories] = useState<Set<string>>(new Set());
  const [expandedStep, setExpandedStep] = useState<string | null>(null);
  const [showDifferentialPanel, setShowDifferentialPanel] = useState(false);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  const gemini = new GeminiService();
  const style = SYSTEM_THEMES[exam.system] || DEFAULT_STYLE;

  const categorizedSteps = useMemo(() => {
    const groups: Record<string, ExamStep[]> = {};
    exam.steps.forEach(step => {
      const cat = step.category || 'General';
      if (!groups[cat]) groups[cat] = [];
      groups[cat].push(step);
    });
    return groups;
  }, [exam.steps]);

  useEffect(() => {
    setExpandedCategories(new Set(Object.keys(categorizedSteps)));
  }, [categorizedSteps]);

  useEffect(() => {
    const research = async () => {
      if (exam.steps.length === 0 && isOnline) {
        setIsResearching(true);
        try {
          const res = await gemini.populateExamination(exam);
          setExam(prev => ({ ...prev, steps: res.steps, sources: res.sources, isDraft: false }));
        } catch (e) { console.error(e); }
        finally { setIsResearching(false); }
      }
    };
    research();
  }, [exam.id, isOnline]);

  useEffect(() => {
    if (activeTab === 'summary' && !summary && isOnline) {
      setLoadingSummary(true);
      gemini.getExaminationSummary(exam.name).then(s => {
        setSummary(s);
        setLoadingSummary(false);
      });
    }
  }, [activeTab]);

  const fetchCorrelation = async (sign: string) => {
    if (!isOnline) return;
    setLoadingCorrelation(true);
    try {
      const data = await gemini.getClinicalCorrelation(sign, exam.system);
      setCorrelation(data);
      setActiveTab('correlation');
    } finally { setLoadingCorrelation(false); }
  };

  const toggleCategory = (cat: string) => {
    setExpandedCategories(prev => {
      const next = new Set(prev);
      if (next.has(cat)) next.delete(cat);
      else next.add(cat);
      return next;
    });
  };

  const selectedFindingTitles = useMemo(() => {
    return Array.from(checkedSteps)
      .map(id => exam.steps.find(s => s.id === id)?.title || '')
      .filter(t => t !== '');
  }, [checkedSteps, exam.steps]);

  const progress = exam.steps.length > 0 ? Math.round((checkedSteps.size / exam.steps.length) * 100) : 0;

  if (isResearching) return (
    <div className="h-full flex flex-col items-center justify-center p-20 animate-in fade-in zoom-in duration-500">
      <Loader2 className="w-10 h-10 text-blue-600 animate-spin mb-4" />
      <p className="text-xs font-black uppercase text-slate-400">Synthesizing Protocol Matrix...</p>
    </div>
  );

  return (
    <div className="max-w-4xl mx-auto py-6 px-6 animate-in fade-in slide-in-from-bottom-2 duration-700 relative">
      <audio ref={audioRef} />

      {showDifferentialPanel && isChecklistMode && (
        <DifferentialPanel 
          findings={selectedFindingTitles}
          system={exam.system}
          onClose={() => setShowDifferentialPanel(false)}
          isOnline={isOnline}
        />
      )}

      <div className="flex items-center justify-between mb-8">
        <Tooltip content="Return to Repository" position="right">
          <button onClick={onBack} className="flex items-center gap-2 px-5 py-2.5 bg-white/80 backdrop-blur rounded-2xl border border-slate-100 text-[10px] font-black uppercase text-slate-600 hover:text-blue-700 transition-all hover:scale-105 active:scale-95 shadow-sm">
            <ChevronRight className="w-4 h-4 rotate-180" /> Back
          </button>
        </Tooltip>

        <div className="flex gap-3">
          {isChecklistMode && (
            <button 
              onClick={() => setShowDifferentialPanel(!showDifferentialPanel)} 
              className={`px-6 py-2.5 rounded-2xl text-[10px] font-black uppercase flex items-center gap-3 shadow-xl transition-all hover:scale-105 active:scale-95 ${showDifferentialPanel ? 'bg-blue-600 text-white' : 'bg-white text-blue-600 border border-blue-100'}`}
            >
              <BrainCircuit className="w-4 h-4" /> AI Analysis
            </button>
          )}
          <Tooltip content={isChecklistMode ? "Exit Examination Mode" : "Start Simulated OSCE Mode"}>
            <button onClick={() => setIsChecklistMode(!isChecklistMode)} className={`px-6 py-2.5 rounded-2xl text-[10px] font-black uppercase flex items-center gap-3 shadow-xl transition-all hover:scale-105 active:scale-95 ${isChecklistMode ? 'bg-emerald-600 text-white' : 'bg-slate-900 text-white'}`}>
              <ListCheck className="w-4 h-4" /> {isChecklistMode ? 'Complete Exam' : 'OSCE Mode'}
            </button>
          </Tooltip>
        </div>
      </div>

      <div className={`rounded-[40px] overflow-hidden mb-10 border-2 transition-all duration-700 ${style.border} ${style.glow}`}>
        <div className="p-10 md:p-12 bg-slate-950 relative overflow-hidden">
          <div className="absolute top-0 right-0 p-12 opacity-15 pointer-events-none group-hover:rotate-12 transition-transform duration-1000">
             <div className="scale-[6]">{style.icon}</div>
          </div>
          <div className="relative z-10">
            <div className="flex items-center gap-3 mb-6">
              <span className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase border-2 ${style.bg} ${style.border} ${style.text}`}>{exam.system}</span>
              <Tooltip content="Tier 1 Evidence Synthesis">
                <Target className="w-4 h-4 text-blue-500" />
              </Tooltip>
            </div>
            <h2 className="text-4xl font-black text-white mb-4 tracking-tighter leading-tight">{exam.name}</h2>
            <p className="text-sm text-slate-400 font-medium max-w-2xl leading-relaxed">{exam.shortDescription}</p>
            {isChecklistMode && (
              <div className="mt-8">
                <div className="flex justify-between items-end mb-2">
                  <span className="text-[10px] font-black uppercase text-slate-500 tracking-widest">Protocol Execution</span>
                  <span className="text-xl font-black text-white">{progress}%</span>
                </div>
                <div className="w-full h-3 bg-white/5 rounded-full overflow-hidden border border-white/5 p-0.5">
                  <div className={`h-full ${style.secondary} rounded-full transition-all duration-1000 ease-out shadow-[0_0_15px_rgba(255,255,255,0.3)]`} style={{ width: `${progress}%` }} />
                </div>
              </div>
            )}
          </div>
        </div>
        <div className="flex bg-slate-950/90 backdrop-blur-2xl overflow-x-auto border-t border-white/5 scrollbar-hide">
          {[
            { id: 'steps', label: 'Protocol', icon: <ClipboardList className="w-4 h-4" /> },
            { id: 'audio', label: 'Audio', icon: <Ear className="w-4 h-4" /> },
            { id: 'media', label: 'Video', icon: <Play className="w-4 h-4" /> },
            { id: 'summary', label: 'Summary', icon: <Info className="w-4 h-4" /> },
            { id: 'correlation', label: 'AI Deep Dive', icon: <Zap className="w-4 h-4" /> }
          ].map((tab: any) => (
            <Tooltip key={tab.id} content={`View ${tab.label}`}>
              <button 
                onClick={() => setActiveTab(tab.id)} 
                className={`flex-1 min-w-[100px] py-6 text-[10px] font-black uppercase flex flex-col items-center gap-3 relative transition-all duration-500 ${activeTab === tab.id ? 'text-white' : 'text-slate-500 hover:text-slate-300'}`}
              >
                <div className={`p-2 rounded-xl transition-all duration-500 ${activeTab === tab.id ? `${style.secondary} shadow-lg shadow-${style.secondary}/20 scale-110` : 'bg-white/5'}`}>{tab.icon}</div>
                {tab.label}
                {activeTab === tab.id && <div className={`absolute bottom-0 h-1.5 w-full ${style.secondary} animate-in fade-in slide-in-from-bottom-2`} />}
              </button>
            </Tooltip>
          ))}
        </div>
      </div>

      <div className="space-y-12">
        {activeTab === 'steps' && Object.entries(categorizedSteps).map(([category, steps], catIdx) => (
          <div key={category} className="animate-in fade-in slide-in-from-bottom-6 duration-700" style={{ animationDelay: `${catIdx * 150}ms` }}>
            <div 
              onClick={() => toggleCategory(category)}
              className="flex items-center justify-between mb-5 px-2 cursor-pointer group/cat"
            >
              <div className="flex items-center gap-4">
                <div className={`w-1 h-8 rounded-full ${style.secondary} shadow-lg`} />
                <h3 className="text-xl font-black text-slate-900 tracking-tight group-hover/cat:text-blue-600 transition-colors uppercase">{category}</h3>
              </div>
              <ChevronDown className={`w-5 h-5 text-slate-300 transition-transform duration-500 ${expandedCategories.has(category) ? 'rotate-180 text-blue-500' : ''}`} />
            </div>

            {expandedCategories.has(category) && (
              <div className="space-y-4 ml-5 pl-5 border-l-2 border-slate-100">
                {steps.map((step) => {
                  const isChecked = checkedSteps.has(step.id);
                  const isExpanded = expandedStep === step.id;
                  return (
                    <div 
                      key={step.id} 
                      className={`group/step rounded-[24px] border-2 p-5 transition-all duration-500 ${
                        isChecked 
                          ? 'bg-emerald-50/30 border-emerald-200/50 shadow-sm' 
                          : 'bg-white border-slate-50 shadow-sm hover:border-blue-100 hover:shadow-xl hover:shadow-blue-500/5 hover:-translate-y-1'
                      }`}
                    >
                      <div className="flex items-start gap-5">
                        {isChecklistMode ? (
                          <Tooltip content={isChecked ? "Unmark Sign" : "Mark as Observed"}>
                            <button 
                              onClick={() => {
                                setCheckedSteps(p => {
                                  const n = new Set(p);
                                  if (n.has(step.id)) n.delete(step.id);
                                  else n.add(step.id);
                                  return n;
                                });
                                if (!showDifferentialPanel) setShowDifferentialPanel(true);
                              }}
                              className={`w-6 h-6 rounded-lg border-2 shrink-0 transition-all duration-500 flex items-center justify-center ${
                                isChecked ? 'bg-emerald-500 border-emerald-500 scale-125 shadow-lg shadow-emerald-200' : 'bg-white border-slate-200 hover:border-emerald-400'
                              }`}
                            >
                              {isChecked && <CheckCircle2 className="w-4 h-4 text-white" />}
                            </button>
                          </Tooltip>
                        ) : (
                          <div className={`w-2 h-2 rounded-full mt-2 shrink-0 ${style.secondary} opacity-50`} />
                        )}

                        <div className="flex-1" onClick={() => !isChecklistMode && setExpandedStep(isExpanded ? null : step.id)}>
                          <div className="flex items-center gap-3 mb-1">
                            <h4 className={`font-black text-[13px] tracking-tight transition-colors ${isChecked ? 'text-emerald-700' : 'text-slate-900 group-hover/step:text-blue-600'}`}>{step.title}</h4>
                            {!isChecklistMode && step.positiveFindings && (
                              <Tooltip content="Pathophysiology Linked">
                                <Sparkles className="w-3 h-3 text-amber-400 animate-pulse" />
                              </Tooltip>
                            )}
                          </div>
                          <p className={`text-[11px] leading-relaxed transition-colors ${isChecked ? 'text-emerald-600/70' : 'text-slate-500'}`}>{step.description}</p>

                          {isExpanded && step.positiveFindings && (
                             <div className="mt-4 p-4 bg-slate-50 rounded-2xl border border-slate-100 animate-in zoom-in-95 duration-300">
                               <div className="flex items-center gap-2 mb-2 text-amber-600">
                                 <Lightbulb className="w-3.5 h-3.5" />
                                 <span className="text-[10px] font-black uppercase">Clinical Insight</span>
                               </div>
                               {step.positiveFindings.map((pf, i) => (
                                 <p key={i} className="text-[10px] text-slate-600 italic leading-relaxed">{pf.description}</p>
                               ))}
                             </div>
                          )}
                        </div>

                        <Tooltip content="Deep Reasoning Matrix">
                          <button 
                            onClick={(e) => { e.stopPropagation(); fetchCorrelation(step.title); }} 
                            className={`p-3 rounded-xl transition-all duration-500 hover:scale-125 active:rotate-12 ${
                              activeTab === 'correlation' ? 'bg-blue-600 text-white shadow-lg shadow-blue-200' : 'bg-blue-50 text-blue-600 hover:bg-blue-100'
                            }`}
                          >
                            <Zap className="w-4 h-4" />
                          </button>
                        </Tooltip>
                      </div>
                    </div>
                  );
                })}
              </div>
            )}
          </div>
        ))}

        {activeTab === 'correlation' && (
          <div className="animate-in fade-in zoom-in-95 duration-700 space-y-6">
            {loadingCorrelation ? (
              <div className="flex flex-col items-center justify-center py-20">
                <Loader2 className="w-10 h-10 text-blue-600 animate-spin mb-4" />
                <p className="text-[10px] font-black uppercase text-slate-400">Synthesizing Clinical Logic...</p>
              </div>
            ) : correlation ? (
              <div className="p-10 bg-white rounded-[40px] border-2 border-blue-100 shadow-2xl shadow-blue-500/5">
                <div className="flex items-center gap-4 mb-8">
                   <div className="p-3 bg-blue-600 text-white rounded-2xl shadow-lg shadow-blue-500/30"><Zap className="w-6 h-6" /></div>
                   <div>
                     <h3 className="text-2xl font-black text-slate-900 tracking-tight">{correlation.sign}</h3>
                     <p className="text-[10px] font-black uppercase tracking-widest text-blue-600">Clinical Correlation Matrix</p>
                   </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                  <div className="space-y-6">
                    <div>
                      <h5 className="text-[10px] font-black uppercase text-slate-400 mb-3 tracking-[0.2em]">Pathophysiology</h5>
                      <p className="text-sm leading-relaxed text-slate-700 font-medium">{correlation.pathophysiology}</p>
                    </div>
                    <div>
                      <h5 className="text-[10px] font-black uppercase text-slate-400 mb-3 tracking-[0.2em]">Key Causes</h5>
                      <ul className="space-y-2">
                        {correlation.causes.map((cause, i) => (
                          <li key={i} className="flex items-center gap-3 text-sm text-slate-600 font-medium">
                            <div className="w-1.5 h-1.5 rounded-full bg-blue-500" />
                            {cause}
                          </li>
                        ))}
                      </ul>
                    </div>
                  </div>
                  <div className="bg-blue-50/50 p-8 rounded-[32px] border border-blue-100/50">
                    <h5 className="text-[10px] font-black uppercase text-blue-600 mb-4 tracking-[0.2em]">Clinical Significance</h5>
                    <p className="text-sm leading-relaxed text-slate-800 font-semibold">{correlation.clinicalSignificance}</p>
                    <div className="mt-8 pt-6 border-t border-blue-200/50 flex items-center gap-3">
                       <Sparkles className="w-5 h-5 text-amber-500" />
                       <p className="text-[10px] font-black text-slate-500 italic uppercase">Generated by MedEx AI Nexus</p>
                    </div>
                  </div>
                </div>
              </div>
            ) : (
              <div className="p-20 text-center bg-slate-50 rounded-[40px] border-2 border-dashed border-slate-200">
                <Zap className="w-10 h-10 text-slate-300 mx-auto mb-4 opacity-20" />
                <p className="text-[10px] font-black uppercase text-slate-400">Select a sign to trigger deep synthesis</p>
              </div>
            )}
          </div>
        )}

        {activeTab === 'summary' && (
          <div className="animate-in zoom-in-95 duration-700">
            {loadingSummary ? (
              <Loader2 className="w-8 h-8 animate-spin mx-auto py-20 text-blue-600" />
            ) : summary && (
              <div className="p-10 bg-white rounded-[40px] border-2 border-slate-100 shadow-xl relative overflow-hidden group/summ">
                <div className="absolute top-0 left-0 w-2 h-full bg-gradient-to-b from-blue-500 to-indigo-600" />
