  async getAdvancedClinicalCorrelation(examination: Examination, clinicalCondition: ClinicalCondition, relevantFindings: string[]): Promise<ClinicalCorrelation> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    // Construct the prompt with specific standards and grounding instructions
    const prompt = `You are a medical expert, specializing in Intensive Care Medicine (CICM) and Anaesthesia (ANZCA).
    Provide a detailed explanation of the following clinical findings in relation to ${clinicalCondition.label}:
    -Examination: ${examination.name}
    -Relevant Findings: ${relevantFindings.join(', ')}

    Ensure explanations are at a CICM/ANZCA standard, including the pathophysiology, clinical significance, and evidence base.
    When providing the evidence base, incorporate Google Search grounding, citing specific journal articles or textbook references (including author, title, journal/publisher, year, and page/URL, styled as a modern bibliographic citation).

    Format the output as follows:
    # Pathophysiology:
    <Pathophysiology explanation>

    # Clinical Significance:
    <Clinical Significance explanation>

    # Evidence Base:
    - <Citation 1>
    - <Citation 2>
    ...
    `;

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
    });
    const content = response.data.response.candidates[0].content.parts[0].text;
    const splitContent = content.split('\n# ');
    const [pathophysiologyPart, clinicalSignificancePart, evidenceBasePart] = splitContent;

    const pathophysiology = pathophysiologyPart.replace('Pathophysiology:','').trim();
    const clinicalSignificance = clinicalSignificancePart.replace('Clinical Significance:','').trim();
    const evidenceBase = evidenceBasePart.replace('Evidence Base:','').trim();

    // Splitting the evidence base into individual citations
    const evidenceBaseCitations = evidenceBase.split('- ')
    .filter(citation => citation.trim() !== '')  // Filter out any empty strings
    .map(citation => citation.trim());         // Trim whitespace from each citation

    return {
      explanation: {
        pathophysiology,
        clinicalSignificance,
        evidenceBaseCitations,
      },
      groundingSources: [{
        searchQuery: prompt.split('\n').filter(line => line.includes('Relevant Findings:'))[0].split(':')[1].trim(),
        citation: evidenceBaseCitations
      }]
    };
  }
