        </div>
      </div>

      <nav className="flex-1 overflow-y-auto p-3 space-y-1 custom-scrollbar overscroll-contain">
        <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest px-2 mb-2">Core Hub</p>

        <Tooltip content="Main Knowledge Base" position="right">
