import { GoogleGenAI, Type } from "@google/genai";
import { ClinicalCorrelation, Examination, GroundingSource, DiagnosisSuggestion, ClinicalCondition } from "../types";

export class GeminiService {

  async getClinicalCorrelation(sign: string, context: string): Promise<ClinicalCorrelation> {
    // Note: Creating AI instance right before making API call to ensure it uses up-to-date API key
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    // 1. Generate Structured Text Correlation with Google Search Grounding
    const textResponse = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: `Explain the deep clinical and physiological significance of '${sign}' in a ${context} context. 
      The explanation MUST meet the academic depth of a CICM (Intensive Care) or ANZCA (Anaesthesia) fellowship examination standard. 
      Focus on detailed pathophysiology, pressure-volume loops if relevant, and complex clinical significance.`,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            sign: { type: Type.STRING },
            pathophysiology: { type: Type.STRING },
            causes: { type: Type.ARRAY, items: { type: Type.STRING } },
            clinicalSignificance: { type: Type.STRING },
            imagePrompt: { type: Type.STRING, description: "Detailed description of a textbook-style medical illustration for this sign (e.g. PV loop, anatomical diagram)." }
          },
          required: ["sign", "pathophysiology", "causes", "clinicalSignificance", "imagePrompt"]
        }
      }
    });

    const sources: GroundingSource[] = textResponse.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
      title: chunk.web?.title || "Academic Source",
      uri: chunk.web?.uri || "#"
    })) || [];

    let correlation: ClinicalCorrelation;
    try {
      correlation = JSON.parse(textResponse.text || "{}");
      correlation.sources = sources;
    } catch (error) {
      console.error("Failed to parse correlation text", error);
      throw error;
    }

    // 2. Generate High-Fidelity Diagnostic Visualization
    // Using gemini-3-pro-image-preview for textbook-standard medical diagrams
    try {
      const imageResponse = await ai.models.generateContent({
        model: 'gemini-3-pro-image-preview',
        contents: {
          parts: [
            {
              text: `A professional, high-fidelity medical textbook illustration. Topic: ${correlation.imagePrompt || sign}. 
              Style: Detailed anatomical or physiological diagram, clean white background, clear scientific labeling, 
              meeting the standard of the New England Journal of Medicine or a major critical care textbook. 
              Focus on: ${correlation.sign} mechanisms.`,
            },
          ],
        },
        config: {
          imageConfig: {
            aspectRatio: "16:9",
            imageSize: "1K"
          },
          tools: [{googleSearch: {}}], // Use grounding for the visual to ensure anatomical accuracy
        },
      });

      for (const part of imageResponse.candidates[0].content.parts) {
        if (part.inlineData) {
          const base64EncodeString: string = part.inlineData.data;
          correlation.imageUrl = `data:image/png;base64,${base64EncodeString}`;
          break;
        }
      }
    } catch (imageError: any) {
      console.warn("High-fidelity image generation failed (Check API Billing/Project):", imageError);
      // Fallback: If "Requested entity was not found", we should signal this in the UI
      if (imageError.message?.includes("Requested entity was not found")) {
        throw new Error("PRO_KEY_REQUIRED");
      }
    }

    return correlation;
  }

  async getDifferentialDiagnosis(findings: string[], system: string): Promise<DiagnosisSuggestion[]> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Given these physical examination findings in the ${system} system: [${findings.join(', ')}], suggest a list of differential diagnoses. Focus on high-yield and "must-not-miss" conditions.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              condition: { type: Type.STRING },
              probability: { type: Type.STRING, enum: ["High", "Moderate", "Low"] },
              reasoning: { type: Type.STRING },
              keyFindings: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ["condition", "probability", "reasoning", "keyFindings"]
          }
        }
      }
    });

    try {
      return JSON.parse(response.text || "[]");
    } catch (error) {
      console.error("Failed to parse differentials", error);
      return [];
    }
  }

  async getFindingsForCondition(conditionName: string): Promise<ClinicalCondition> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `List all potential physical examination findings for '${conditionName}'. 
      For each specific finding, include a direct 'link' to a high-quality academic reference (e.g. Life in the Fast Lane, Deranged Physiology, or a major medical journal) that explains the pathophysiology at a CICM/ANZCA fellowship level.
      Categorize findings by anatomical or examination sequence consistent with Talley and O'Connor taxonomy.`,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            name: { type: Type.STRING },
            system: { type: Type.STRING },
            description: { type: Type.STRING },
            findings: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  category: { type: Type.STRING },
                  sign: { type: Type.STRING },
                  significance: { type: Type.STRING },
                  link: { type: Type.STRING, description: "URL to academic reference" }
                },
                required: ["category", "sign", "significance", "link"]
              }
            }
          },
          required: ["name", "description", "findings"]
        }
      }
    });

    try {
      return JSON.parse(response.text || "{}");
    } catch (error) {
      console.error("Failed to parse condition findings", error);
      throw error;
    }
  }

  async populateExamination(exam: Examination): Promise<{ steps: any[], sources: GroundingSource[] }> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const prompt = `Research the official medical protocol for a '${exam.name}' within the ${exam.system} system. 
    Use reliable sources like Geeky Medics, OSCEstop, or standard textbooks like Talley and O'Connor.
    Provide a detailed, step-by-step examination protocol.

    Structure the response as JSON with:
    1. steps: an array of objects { id, title, description, category, negativeFindings: string[], positiveFindings: { description: string }[] }
    Categories must be one of: Preparation, Inspection, Palpation, Percussion, Auscultation, Special Tests, Conclusion.`;

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview", 
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            steps: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING },
                  title: { type: Type.STRING },
                  description: { type: Type.STRING },
                  category: { type: Type.STRING },
                  negativeFindings: { type: Type.ARRAY, items: { type: Type.STRING } },
                  positiveFindings: {
                    type: Type.ARRAY,
                    items: {
                      type: Type.OBJECT,
                      properties: { description: { type: Type.STRING } }
                    }
                  }
                },
                required: ["id", "title", "description", "category"]
              }
            }
          },
          required: ["steps"]
        }
      }
    });

    const sources: GroundingSource[] = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
      title: chunk.web?.title || "Medical Source",
      uri: chunk.web?.uri || "#"
    })) || [];

    try {
      const data = JSON.parse(response.text || "{}");
      return { steps: data.steps, sources };
    } catch (error) {
      console.error("Failed to parse examination data", error);
      throw error;
    }
  }

  async getExaminationSummary(examName: string): Promise<string> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Provide a concise clinical summary and purpose of the ${examName} following the style of Talley and O'Connor. Include key things not to miss.`,
      config: {
        thinkingConfig: { thinkingBudget: 0 }
      }
    });
    return response.text || "No summary available.";
  }
}

import React, { useState, useEffect } from 'react';
