const ClinicalCorrelationView: React.FC = () => {
  const [query, setQuery] = useState('');
  const [loading, setLoading] = useState(false);
  const [correlation, setCorrelation] = useState<ClinicalCorrelation | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [showKeyGate, setShowKeyGate] = useState(false);

  const gemini = new GeminiService();

  const handleOpenKeySelector = async () => {
    // @ts-ignore
    await window.aistudio.openSelectKey();
    setShowKeyGate(false);
    // Proceed to trigger search again if query was pending
    if (query) handleSearch();
  };

  const handleSearch = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!query.trim()) return;

    setLoading(true);
    setError(null);
    try {
      // Check for key selection first if possible, but following race condition rule
      // @ts-ignore
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) {
        setShowKeyGate(true);
        setLoading(false);
        return;
      }

      const result = await gemini.getClinicalCorrelation(query, "intensive care and anaesthesia");
      setCorrelation(result);
    } catch (err: any) {
      if (err.message === "PRO_KEY_REQUIRED") {
        setShowKeyGate(true);
      } else {
        setError("Analysis failed. Please try a specific medical sign (e.g., Pulsus Paradoxus).");
        console.error(err);
      }
    } finally {
      setLoading(false);
    }
  };

  if (showKeyGate) {
    return (
      <div className="max-w-xl mx-auto py-20 px-8 text-center animate-in fade-in zoom-in-95 duration-500">
