              <ShieldCheck className="w-8 h-8 text-white" />
            </div>
            <h2 className="text-2xl font-black text-white uppercase tracking-tight mb-4">Pro Tier Diagnostics</h2>
            <p className="text-sm text-slate-400 mb-8 font-medium leading-relaxed">
              High-fidelity textbook illustrations and CICM-grade grounded analysis require a selected Pro API key from a paid GCP project.
            </p>
            <div className="space-y-4">
              <button 
                onClick={handleOpenKeySelector}
                className="w-full py-4 bg-white text-slate-900 rounded-2xl text-[11px] font-black uppercase tracking-widest flex items-center justify-center gap-3 hover:bg-blue-50 transition-all shadow-xl"
              >
                Select Pro API Key <ChevronRight className="w-4 h-4" />
              </button>
              <a 
                href="https://ai.google.dev/gemini-api/docs/billing" 
                target="_blank" 
                rel="noopener noreferrer"
                className="inline-flex items-center gap-2 text-[10px] font-bold text-slate-500 hover:text-white transition-colors uppercase tracking-widest"
              >
                <CreditCard className="w-3.5 h-3.5" /> Billing Documentation
              </a>
            </div>
