import { useState, useMemo, useEffect } from 'react';
import { Examination, ExamSystem } from '../types';
import { EXAMINATIONS } from '../constants';
import { storage } from '../services/storageService';

export function useExaminations(searchQuery: string, initialSelectedSystem: ExamSystem | null, downloadedIds: Set<string>) {
  const [selectedSystem, setSelectedSystem] = useState<ExamSystem | null>(initialSelectedSystem);
  const [selectedExam, setSelectedExam] = useState<Examination | null>(null);
  const [expandedSystems, setExpandedSystems] = useState<Set<string>>(new Set([ExamSystem.CARDIOVASCULAR]));
  const [downloadedExams, setDownloadedExams] = useState<Examination[]>([]);

  // Fetch full exam objects from storage whenever the set of downloaded IDs changes
  useEffect(() => {
    const loadDownloaded = async () => {
      const all = await storage.getAllDownloaded();
      setDownloadedExams(all);
    };
    loadDownloaded();
  }, [downloadedIds]);

  useEffect(() => {
    if (selectedSystem) {
      setExpandedSystems(prev => new Set(prev).add(selectedSystem));
    }
  }, [selectedSystem]);

  const groupedExams = useMemo(() => {
    const groups: Record<string, Examination[]> = {};
    let filtered = EXAMINATIONS;

    if (searchQuery.trim()) {
      const q = searchQuery.toLowerCase();
      filtered = filtered.filter(e => 
        e.name.toLowerCase().includes(q) ||
        e.shortDescription.toLowerCase().includes(q) ||
        e.system.toLowerCase().includes(q) ||
        e.keywords.some(k => k.toLowerCase().includes(q))
      );
    }

    filtered.forEach(exam => {
      // If we have a fully downloaded version of this exam, use it in the groups 
      // so that selecting it from the system list also uses the cached data.
      const stored = downloadedExams.find(d => d.id === exam.id);
      const examToUse = stored || exam;

      if (!groups[examToUse.system]) groups[examToUse.system] = [];
      groups[examToUse.system].push(examToUse);
    });
    return groups;
  }, [searchQuery, downloadedExams]);

  const displayGroups = useMemo(() => {
    if (selectedSystem) {
      return { [selectedSystem]: groupedExams[selectedSystem] || [] };
    }
    return groupedExams;
  }, [selectedSystem, groupedExams]);

  const handleSelectExam = async (exam: Examination) => {
    // Attempt to get the most up-to-date version from storage
    const stored = await storage.getExamination(exam.id);
    setSelectedExam(stored || exam);
  };

  const toggleSystemExpansion = (system: string) => {
    setExpandedSystems(prev => {
      const next = new Set(prev);
      if (next.has(system)) next.delete(system);
      else next.add(system);
      return next;
    });
  };

  return {
    selectedSystem,
    setSelectedSystem,
    selectedExam,
    setSelectedExam,
    displayGroups,
    expandedSystems,
    toggleSystemExpansion,
    handleSelectExam,
    downloadedExams: downloadedExams.filter(e => 
      !searchQuery || 
      e.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
      e.system.toLowerCase().includes(searchQuery.toLowerCase())
    )
  };
}

