import { GoogleGenAI, Type } from "@google/genai";
import { ClinicalCorrelation, Examination, GroundingSource, DiagnosisSuggestion, ClinicalCondition } from "../types";

export class GeminiService {

  private async generateIllustration(prompt: string, isPro: boolean = false): Promise<string | undefined> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    try {
      if (isPro) {
        // High-fidelity path using Imagen
        const response = await ai.models.generateImages({
          model: 'imagen-4.0-generate-001',
          prompt: `A professional medical textbook illustration. Topic: ${prompt}. Style: Clean, detailed scientific diagram, white background, precise anatomical labeling, realistic colors. No text watermarks. High resolution.`,
          config: {
            numberOfImages: 1,
            aspectRatio: '16:9',
          },
        });
        const base64Bytes = response.generatedImages[0].image.imageBytes;
        return `data:image/png;base64,${base64Bytes}`;
      } else {
        // Standard path using gemini-2.5-flash-image (more likely to work on standard/free tiers)
        const response = await ai.models.generateContent({
          model: 'gemini-2.5-flash-image',
          contents: {
            parts: [
              {
                text: `Generate a professional medical textbook illustration of: ${prompt}. Clean white background, scientific diagram style, clear labeling.`,
              },
            ],
          },
          config: {
            imageConfig: {
              aspectRatio: "16:9"
            }
          }
        });

        for (const part of response.candidates[0].content.parts) {
          if (part.inlineData) {
            return `data:image/png;base64,${part.inlineData.data}`;
          }
        }
      }
    } catch (error: any) {
      console.error("Illustration generation failed", error);
      // If pro fails, we don't necessarily want to throw if it's just an image
      return undefined;
    }
    return undefined;
  }

  async getClinicalCorrelation(sign: string, context: string, isPro: boolean = false): Promise<ClinicalCorrelation> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    // Use Flash for standard, Pro for fellowship-grade analysis
    const model = isPro ? "gemini-3-pro-preview" : "gemini-3-flash-preview";

    const textResponse = await ai.models.generateContent({
      model: model,
      contents: `Explain the clinical and physiological significance of '${sign}' in a ${context} context. 
      ${isPro ? 'Provide deep fellowship-level (CICM/ANZCA) analysis.' : 'Provide a clear, high-yield clinical explanation.'}
      Focus on pathophysiology, pressure-volume loops if relevant, and causes.`,
      config: {
        tools: isPro ? [{ googleSearch: {} }] : [],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            sign: { type: Type.STRING },
            pathophysiology: { type: Type.STRING },
            causes: { type: Type.ARRAY, items: { type: Type.STRING } },
            clinicalSignificance: { type: Type.STRING },
            imagePrompt: { type: Type.STRING, description: "Prompt for a medical illustration." }
          },
          required: ["sign", "pathophysiology", "causes", "clinicalSignificance", "imagePrompt"]
        }
      }
    });

    // Safely extract grounding chunks by casting to any to avoid 'unknown' type issues with map
    const groundingMetadata = textResponse.candidates?.[0]?.groundingMetadata;
    const groundingChunks = (groundingMetadata as any)?.groundingChunks;
    const sources: GroundingSource[] = Array.isArray(groundingChunks) 
      ? groundingChunks.map((chunk: any) => ({
          title: chunk.web?.title || "Academic Source",
          uri: chunk.web?.uri || "#"
        })) 
      : [];

    let correlation: ClinicalCorrelation;
    try {
      correlation = JSON.parse(textResponse.text || "{}");
      correlation.sources = sources;
    } catch (error) {
      console.error("Failed to parse correlation text", error);
      throw error;
    }

    // Generate illustration based on the selected tier
    correlation.imageUrl = await this.generateIllustration(correlation.imagePrompt || correlation.sign, isPro);

    return correlation;
  }

  async populateExamination(exam: Examination): Promise<Partial<Examination>> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const prompt = `Research the official medical protocol for a '${exam.name}' within the ${exam.system} system. 
    Use reliable sources like Geeky Medics, OSCEstop, or standard textbooks.
    Provide a detailed, step-by-step examination protocol and a prompt for a high-quality header illustration.

    Structure the response as JSON with:
    1. steps: an array of objects { id, title, description, category, imagePrompt: string }
    2. headerImagePrompt: string
    Categories: Preparation, Inspection, Palpation, Percussion, Auscultation, Special Tests, Conclusion.`;

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview", 
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            steps: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING },
                  title: { type: Type.STRING },
                  description: { type: Type.STRING },
                  category: { type: Type.STRING },
                  imagePrompt: { type: Type.STRING }
                },
                required: ["id", "title", "description", "category"]
              }
            },
            headerImagePrompt: { type: Type.STRING }
          },
          required: ["steps", "headerImagePrompt"]
        }
      }
    });

    // Safely extract grounding chunks by casting to any to avoid 'unknown' type issues with map
    const groundingMetadata = response.candidates?.[0]?.groundingMetadata;
    const groundingChunks = (groundingMetadata as any)?.groundingChunks;
    const sources: GroundingSource[] = Array.isArray(groundingChunks)
      ? groundingChunks.map((chunk: any) => ({
          title: chunk.web?.title || "Medical Source",
          uri: chunk.web?.uri || "#"
        }))
      : [];

    try {
      const data = JSON.parse(response.text || "{}");
      // Use standard generation for general protocols
      const headerImageUrl = await this.generateIllustration(data.headerImagePrompt, false);
      return { 
        steps: data.steps, 
        sources, 
        headerImageUrl, 
        headerImagePrompt: data.headerImagePrompt 
      };
    } catch (error) {
      console.error("Failed to parse examination data", error);
      throw error;
    }
  }

  async getExaminationSummary(examName: string): Promise<string> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Provide a concise clinical summary and purpose of the ${examName} following the style of Talley and O'Connor. Include key things not to miss.`,
      config: {
        thinkingConfig: { thinkingBudget: 0 }
      }
    });
    return response.text || "No summary available.";
  }

  async getDifferentialDiagnosis(findings: string[], system: string): Promise<DiagnosisSuggestion[]> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Given these physical examination findings in the ${system} system: [${findings.join(', ')}], suggest a list of differential diagnoses. Focus on high-yield and "must-not-miss" conditions.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              condition: { type: Type.STRING },
              probability: { type: Type.STRING, enum: ["High", "Moderate", "Low"] },
              reasoning: { type: Type.STRING },
              keyFindings: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ["condition", "probability", "reasoning", "keyFindings"]
          }
        }
      }
    });

    try {
      return JSON.parse(response.text || "[]");
    } catch (error) {
      console.error("Failed to parse differentials", error);
      return [];
    }
  }

  async getFindingsForCondition(conditionName: string): Promise<ClinicalCondition> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `List all potential physical examination findings for '${conditionName}'. 
      For each specific finding, include a direct 'link' to a high-quality academic reference (e.g. Life in the Fast Lane, Deranged Physiology, or a major medical journal).`,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            name: { type: Type.STRING },
            system: { type: Type.STRING },
            description: { type: Type.STRING },
            findings: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  category: { type: Type.STRING },
                  sign: { type: Type.STRING },
                  significance: { type: Type.STRING },
                  link: { type: Type.STRING, description: "URL to academic reference" }
                },
                required: ["category", "sign", "significance", "link"]
              }
            }
          },
          required: ["name", "description", "findings"]
        }
      }
    });

    try {
      return JSON.parse(response.text || "{}");
    } catch (error) {
      console.error("Failed to parse condition findings", error);
      throw error;
    }
  }
}

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Examination, ClinicalCorrelation, ExamStep } from '../types';
import { GeminiService } from '../services/geminiService';
import { SYSTEM_THEMES, DEFAULT_STYLE } from '../theme';
import Tooltip from './Tooltip';
import DifferentialPanel from './DifferentialPanel';
import { 
  ChevronRight, ClipboardList, Target, Ear, Play, Info, Zap, 
  CheckCircle2, ChevronDown, Lightbulb, Loader2, Sparkles, X, ListCheck, BrainCircuit, ExternalLink, Microscope
} from 'lucide-react';

interface ExamViewProps {
  exam: Examination;
  onBack: () => void;
}

const ExamView: React.FC<ExamViewProps> = ({ exam: initialExam, onBack }) => {
  const [exam, setExam] = useState(initialExam);
  const [activeTab, setActiveTab] = useState<'steps' | 'summary' | 'correlation' | 'media' | 'audio'>('steps');
  const [summary, setSummary] = useState<string | null>(null);
  const [loadingSummary, setLoadingSummary] = useState(false);
  const [isResearching, setIsResearching] = useState(false);
  const [correlation, setCorrelation] = useState<ClinicalCorrelation | null>(null);
  const [loadingCorrelation, setLoadingCorrelation] = useState(false);
  const [isOnline] = useState(navigator.onLine);
  const [checkedSteps, setCheckedSteps] = useState<Set<string>>(new Set());
  const [isChecklistMode, setIsChecklistMode] = useState(false);
  const [expandedCategories, setExpandedCategories] = useState<Set<string>>(new Set());
  const [expandedStep, setExpandedStep] = useState<string | null>(null);
  const [showDifferentialPanel, setShowDifferentialPanel] = useState(false);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  const gemini = new GeminiService();
  const style = SYSTEM_THEMES[exam.system] || DEFAULT_STYLE;

  const categorizedSteps = useMemo(() => {
    const groups: Record<string, ExamStep[]> = {};
    exam.steps.forEach(step => {
      const cat = step.category || 'General';
      if (!groups[cat]) groups[cat] = [];
      groups[cat].push(step);
    });
    return groups;
  }, [exam.steps]);

  useEffect(() => {
    setExpandedCategories(new Set(Object.keys(categorizedSteps)));
  }, [categorizedSteps]);

  useEffect(() => {
    const research = async () => {
      if (exam.steps.length === 0 && isOnline) {
        setIsResearching(true);
        try {
          const res = await gemini.populateExamination(exam);
          setExam(prev => ({ 
            ...prev, 
            ...res,
            isDraft: false 
          }));
        } catch (e) { console.error(e); }
        finally { setIsResearching(false); }
      }
    };
    research();
  }, [exam.id, isOnline]);

  useEffect(() => {
    if (activeTab === 'summary' && !summary && isOnline) {
      setLoadingSummary(true);
      gemini.getExaminationSummary(exam.name).then(s => {
        setSummary(s);
        setLoadingSummary(false);
      });
    }
  }, [activeTab]);

  const fetchCorrelation = async (sign: string) => {
    if (!isOnline) return;
    setLoadingCorrelation(true);
    try {
      const data = await gemini.getClinicalCorrelation(sign, exam.system);
      setCorrelation(data);
      setActiveTab('correlation');
    } finally { setLoadingCorrelation(false); }
  };

  const toggleCategory = (cat: string) => {
    setExpandedCategories(prev => {
      const next = new Set(prev);
      if (next.has(cat)) next.delete(cat);
      else next.add(cat);
      return next;
    });
  };

  const selectedFindingTitles = useMemo(() => {
    return Array.from(checkedSteps)
      .map(id => exam.steps.find(s => s.id === id)?.title || '')
      .filter(t => t !== '');
  }, [checkedSteps, exam.steps]);

  const progress = exam.steps.length > 0 ? Math.round((checkedSteps.size / exam.steps.length) * 100) : 0;

  if (isResearching) return (
    <div className="h-full flex flex-col items-center justify-center p-20 animate-in fade-in zoom-in duration-500">
      <Loader2 className="w-10 h-10 text-blue-600 animate-spin mb-4" />
      <p className="text-xs font-black uppercase text-slate-400 tracking-widest">Synthesizing Protocol & Illustrations...</p>
    </div>
  );

  return (
    <div className="max-w-4xl mx-auto py-6 px-6 animate-in fade-in slide-in-from-bottom-2 duration-700 relative">
      <audio ref={audioRef} />

      {showDifferentialPanel && isChecklistMode && (
        <DifferentialPanel 
          findings={selectedFindingTitles}
          system={exam.system}
          onClose={() => setShowDifferentialPanel(false)}
          isOnline={isOnline}
        />
      )}

      <div className="flex items-center justify-between mb-8">
        <Tooltip content="Return to Repository" position="right">
          <button onClick={onBack} className="flex items-center gap-2 px-5 py-2.5 bg-white/80 backdrop-blur rounded-2xl border border-slate-100 text-[10px] font-black uppercase text-slate-600 hover:text-blue-700 transition-all hover:scale-105 active:scale-95 shadow-sm">
            <ChevronRight className="w-4 h-4 rotate-180" /> Back
          </button>
        </Tooltip>

        <div className="flex gap-3">
          {isChecklistMode && (
            <button 
              onClick={() => setShowDifferentialPanel(!showDifferentialPanel)} 
              className={`px-6 py-2.5 rounded-2xl text-[10px] font-black uppercase flex items-center gap-3 shadow-xl transition-all hover:scale-105 active:scale-95 ${showDifferentialPanel ? 'bg-blue-600 text-white' : 'bg-white text-blue-600 border border-blue-100'}`}
            >
              <BrainCircuit className="w-4 h-4" /> AI Analysis
            </button>
          )}
          <Tooltip content={isChecklistMode ? "Exit Examination Mode" : "Start Simulated OSCE Mode"}>
            <button onClick={() => setIsChecklistMode(!isChecklistMode)} className={`px-6 py-2.5 rounded-2xl text-[10px] font-black uppercase flex items-center gap-3 shadow-xl transition-all hover:scale-105 active:scale-95 ${isChecklistMode ? 'bg-emerald-600 text-white' : 'bg-slate-900 text-white'}`}>
              <ListCheck className="w-4 h-4" /> {isChecklistMode ? 'Complete Exam' : 'OSCE Mode'}
            </button>
          </Tooltip>
        </div>
      </div>

      <div className={`rounded-[40px] overflow-hidden mb-10 border-2 transition-all duration-700 ${style.border} ${style.glow}`}>
        <div className="min-h-[300px] bg-slate-950 relative overflow-hidden flex flex-col md:flex-row">
          {/* Header Illustration */}
          <div className="flex-1 p-10 md:p-12 relative z-10 flex flex-col justify-center">
            <div className="flex items-center gap-3 mb-6">
              <span className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase border-2 ${style.bg} ${style.border} ${style.text}`}>{exam.system}</span>
              <Tooltip content="Tier 1 Evidence Synthesis">
                <Target className="w-4 h-4 text-blue-500" />
              </Tooltip>
            </div>
            <h2 className="text-4xl font-black text-white mb-4 tracking-tighter leading-tight">{exam.name}</h2>
            <p className="text-sm text-slate-400 font-medium max-w-lg leading-relaxed">{exam.shortDescription}</p>
            {isChecklistMode && (
              <div className="mt-8">
                <div className="flex justify-between items-end mb-2">
                  <span className="text-[10px] font-black uppercase text-slate-500 tracking-widest">Protocol Execution</span>
                  <span className="text-xl font-black text-white">{progress}%</span>
                </div>
                <div className="w-full h-3 bg-white/5 rounded-full overflow-hidden border border-white/5 p-0.5">
                  <div className={`h-full ${style.secondary} rounded-full transition-all duration-1000 ease-out shadow-[0_0_15px_rgba(255,255,255,0.3)]`} style={{ width: `${progress}%` }} />
                </div>
              </div>
            )}
          </div>

          {/* System Visualization */}
          {exam.headerImageUrl ? (
            <div className="w-full md:w-1/3 min-h-[200px] relative">
              <img 
                src={exam.headerImageUrl} 
                alt={exam.name} 
                className="absolute inset-0 w-full h-full object-cover opacity-60 hover:opacity-100 transition-opacity duration-1000"
              />
              <div className="absolute inset-0 bg-gradient-to-r md:bg-gradient-to-l from-transparent via-slate-950/20 to-slate-950" />
            </div>
          ) : (
            <div className="absolute top-0 right-0 p-12 opacity-15 pointer-events-none group-hover:rotate-12 transition-transform duration-1000">
               <div className="scale-[6]">{style.icon}</div>
            </div>
          )}
        </div>

        <div className="flex bg-slate-950/90 backdrop-blur-2xl overflow-x-auto border-t border-white/5 scrollbar-hide">
          {/* Cast the array to any[] to ensure map is available even if inferred as unknown */}
          {([
            { id: 'steps', label: 'Protocol', icon: <ClipboardList className="w-4 h-4" /> },
            { id: 'audio', label: 'Audio', icon: <Ear className="w-4 h-4" /> },
            { id: 'media', label: 'Video', icon: <Play className="w-4 h-4" /> },
            { id: 'summary', label: 'Summary', icon: <Info className="w-4 h-4" /> },
            { id: 'correlation', label: 'AI Deep Dive', icon: <Zap className="w-4 h-4" /> }
          ] as any[]).map((tab: any) => (
            <Tooltip key={tab.id} content={`View ${tab.label}`}>
              <button 
                onClick={() => setActiveTab(tab.id)} 
                className={`flex-1 min-w-[100px] py-6 text-[10px] font-black uppercase flex flex-col items-center gap-3 relative transition-all duration-500 ${activeTab === tab.id ? 'text-white' : 'text-slate-500 hover:text-slate-300'}`}
              >
                <div className={`p-2 rounded-xl transition-all duration-500 ${activeTab === tab.id ? `${style.secondary} shadow-lg shadow-${style.secondary}/20 scale-110` : 'bg-white/5'}`}>{tab.icon}</div>
