        )}

        {activeTab === 'summary' && (
          <div className="animate-in zoom-in-95 duration-700 space-y-6">
            {loadingSummary ? (
              <Loader2 className="w-8 h-8 animate-spin mx-auto py-20 text-blue-600" />
            ) : (
              <>
                {summary && (
                  <div className="p-10 bg-white rounded-[40px] border-2 border-slate-100 shadow-xl relative overflow-hidden group/summ">
                    <div className="absolute top-0 left-0 w-2 h-full bg-gradient-to-b from-blue-500 to-indigo-600" />
                    <div className="flex items-center gap-3 mb-6">
                      <Info className="w-5 h-5 text-blue-600" />
                      <h3 className="text-xl font-black text-slate-900 uppercase tracking-tight">Systemic Synthesis</h3>
                    </div>
                    <div className="text-sm leading-[1.8] text-slate-700 font-medium whitespace-pre-line prose prose-slate max-w-none">
                      {summary}
                    </div>
                  </div>
                )}

                {exam.sources && exam.sources.length > 0 && (
                  <div className="p-8 bg-slate-50 rounded-[32px] border border-slate-200">
                    <h4 className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400 mb-6 flex items-center gap-2">
                      <div className="w-1.5 h-4 bg-blue-400 rounded-full" />
                      Verification Sources
                    </h4>
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                      {exam.sources.map((source, idx) => (
                        <a 
                          key={idx} 
                          href={source.uri} 
                          target="_blank" 
                          rel="noopener noreferrer"
                          className="flex items-center justify-between p-4 bg-white rounded-2xl border border-slate-200 hover:border-blue-400 hover:shadow-md transition-all group/src"
                        >
                          <span className="text-[11px] font-bold text-slate-700 truncate mr-2">{source.title}</span>
                          <ExternalLink className="w-3.5 h-3.5 text-slate-300 group-hover/src:text-blue-500" />
                        </a>
                      ))}
                    </div>
                  </div>
                )}
              </>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

export default ExamView;

