import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Examination, ClinicalCorrelation, ExamStep } from '../types';
import { GeminiService } from '../services/geminiService';
import { SYSTEM_THEMES, DEFAULT_STYLE } from '../theme';
import Tooltip from './Tooltip';
import DifferentialPanel from './DifferentialPanel';
import { 
  ChevronRight, ClipboardList, Target, Ear, Play, Info, Zap, 
  CheckCircle2, ChevronDown, Lightbulb, Loader2, Sparkles, ListCheck, BrainCircuit, ExternalLink, Microscope,
  ArrowLeft, Share2, Printer
} from 'lucide-react';

interface ExamViewProps {
  exam: Examination;
  onBack: () => void;
}

const ExamView: React.FC<ExamViewProps> = ({ exam: initialExam, onBack }) => {
  const [exam, setExam] = useState(initialExam);
  const [activeTab, setActiveTab] = useState<'steps' | 'summary' | 'correlation' | 'media' | 'audio'>('steps');
  const [summary, setSummary] = useState<string | null>(null);
  const [loadingSummary, setLoadingSummary] = useState(false);
  const [isResearching, setIsResearching] = useState(false);
  const [correlation, setCorrelation] = useState<ClinicalCorrelation | null>(null);
  const [loadingCorrelation, setLoadingCorrelation] = useState(false);
  const [isOnline] = useState(navigator.onLine);
  const [checkedSteps, setCheckedSteps] = useState<Set<string>>(new Set());
  const [isChecklistMode, setIsChecklistMode] = useState(false);
  const [expandedCategories, setExpandedCategories] = useState<Set<string>>(new Set());
  const [expandedStep, setExpandedStep] = useState<string | null>(null);
  const [showDifferentialPanel, setShowDifferentialPanel] = useState(false);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  const gemini = new GeminiService();
  const style = SYSTEM_THEMES[exam.system] || DEFAULT_STYLE;

  const categorizedSteps = useMemo(() => {
    const groups: Record<string, ExamStep[]> = {};
    exam.steps.forEach(step => {
      const cat = step.category || 'General';
      if (!groups[cat]) groups[cat] = [];
      groups[cat].push(step);
    });
    return groups;
  }, [exam.steps]);

  useEffect(() => {
    setExpandedCategories(new Set(Object.keys(categorizedSteps)));
  }, [categorizedSteps]);

  useEffect(() => {
    const research = async () => {
      if (exam.steps.length === 0 && isOnline) {
        setIsResearching(true);
        try {
          const res = await gemini.populateExamination(exam);
          setExam(prev => ({ 
            ...prev, 
            ...res,
            isDraft: false 
          }));
        } catch (e) { console.error(e); }
        finally { setIsResearching(false); }
      }
    };
    research();
  }, [exam.id, isOnline]);

  useEffect(() => {
    if (activeTab === 'summary' && !summary && isOnline) {
      setLoadingSummary(true);
      gemini.getExaminationSummary(exam.name).then(s => {
        setSummary(s);
        setLoadingSummary(false);
      });
    }
  }, [activeTab]);

  const fetchCorrelation = async (sign: string) => {
    if (!isOnline) return;
    setLoadingCorrelation(true);
    try {
      const data = await gemini.getClinicalCorrelation(sign, exam.system);
      setCorrelation(data);
      setActiveTab('correlation');
    } finally { setLoadingCorrelation(false); }
  };

  const toggleCategory = (cat: string) => {
    setExpandedCategories(prev => {
      const next = new Set(prev);
      if (next.has(cat)) next.delete(cat);
      else next.add(cat);
      return next;
    });
  };

  const selectedFindingTitles = useMemo(() => {
    return Array.from(checkedSteps)
      .map(id => exam.steps.find(s => s.id === id)?.title || '')
      .filter(t => t !== '');
  }, [checkedSteps, exam.steps]);

  const progress = exam.steps.length > 0 ? Math.round((checkedSteps.size / exam.steps.length) * 100) : 0;

  if (isResearching) return (
    <div className="h-full flex flex-col items-center justify-center p-20 animate-in fade-in zoom-in duration-500 bg-white">
      <div className="relative mb-8">
        <div className="w-20 h-20 border-4 border-blue-50 rounded-full"></div>
        <div className="w-20 h-20 border-4 border-blue-600 border-t-transparent rounded-full animate-spin absolute top-0"></div>
        <BrainCircuit className="w-8 h-8 text-blue-600 absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2" />
      </div>
      <p className="text-[10px] font-black uppercase text-slate-400 tracking-[0.3em] mb-2">Synthesizing Clinical Dossier</p>
      <div className="flex items-center gap-2 px-4 py-1.5 bg-slate-50 rounded-full border border-slate-100">
        <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></span>
        <span className="text-[9px] font-bold text-slate-600">MedEx Deep Reasoning Engine Active</span>
      </div>
    </div>
  );

  return (
    <div className="min-h-full bg-white animate-in fade-in duration-700 relative">
      <audio ref={audioRef} />

      {showDifferentialPanel && isChecklistMode && (
        <DifferentialPanel 
          findings={selectedFindingTitles}
          system={exam.system}
          onClose={() => setShowDifferentialPanel(false)}
          isOnline={isOnline}
        />
      )}

      {/* --- COMMAND HEADER --- */}
      <div className="sticky top-0 z-40 bg-white/80 backdrop-blur-xl border-b border-slate-100 px-8 py-4 flex items-center justify-between">
        <div className="flex items-center gap-6">
          <button onClick={onBack} className="p-2 hover:bg-slate-50 rounded-xl text-slate-400 transition-colors">
            <ArrowLeft className="w-5 h-5" />
          </button>
          <div>
            <div className="flex items-center gap-2 mb-0.5">
              <span className={`text-[9px] font-black uppercase tracking-widest ${style.text}`}>{exam.system}</span>
              <span className="w-1 h-1 rounded-full bg-slate-200" />
              <span className="text-[9px] font-black uppercase tracking-widest text-slate-400">Protocol 102.4</span>
            </div>
            <h1 className="text-lg font-black text-slate-900 tracking-tight leading-none">{exam.name}</h1>
          </div>
        </div>

        <div className="flex items-center gap-3">
          <div className="flex items-center gap-2 mr-4 bg-slate-50 px-4 py-2 rounded-2xl border border-slate-100">
            <span className="text-[9px] font-black uppercase text-slate-400 tracking-widest">Progress</span>
            <div className="w-24 h-1.5 bg-slate-200 rounded-full overflow-hidden">
               <div className={`h-full ${style.secondary} transition-all duration-1000`} style={{ width: `${progress}%` }} />
            </div>
            <span className="text-[10px] font-black text-slate-900">{progress}%</span>
          </div>

          <button onClick={() => setIsChecklistMode(!isChecklistMode)} className={`px-6 py-2.5 rounded-2xl text-[10px] font-black uppercase flex items-center gap-2 shadow-xl transition-all hover:scale-105 active:scale-95 ${isChecklistMode ? 'bg-emerald-600 text-white' : 'bg-slate-900 text-white'}`}>
            <ListCheck className="w-4 h-4" /> {isChecklistMode ? 'Exit OSCE' : 'Start OSCE'}
          </button>
        </div>
      </div>

      <div className="max-w-5xl mx-auto py-12 px-8">
        {/* --- VISUAL SPLIT HEADER --- */}
        <div className="grid grid-cols-1 lg:grid-cols-5 gap-12 mb-16">
          <div className="lg:col-span-3">
             <div className="flex items-center gap-3 mb-6">
                <div className={`p-2 rounded-xl ${style.bg} ${style.text}`}>{style.icon}</div>
                <h2 className="text-3xl font-black text-slate-900 tracking-tighter leading-tight">{exam.name}</h2>
             </div>
             <p className="text-base text-slate-500 font-medium leading-[1.8] mb-8 max-w-xl">
               {exam.shortDescription}
             </p>
             <div className="flex flex-wrap gap-4">
               {exam.keywords.map(k => (
                 <span key={k} className="px-3 py-1.5 bg-slate-50 border border-slate-100 rounded-lg text-[10px] font-black uppercase text-slate-400 tracking-widest">#{k}</span>
               ))}
             </div>
          </div>

          <div className="lg:col-span-2">
            <div className={`relative rounded-[40px] overflow-hidden aspect-[4/3] border-2 ${style.border} shadow-2xl`}>
              {exam.headerImageUrl ? (
                <img src={exam.headerImageUrl} className="w-full h-full object-cover" alt="Anatomical Reference" />
              ) : (
                <div className={`w-full h-full ${style.bg} flex items-center justify-center`}>
                  <div className="scale-[4] opacity-20">{style.icon}</div>
                </div>
              )}
              <div className="absolute bottom-4 left-4 right-4 bg-white/40 backdrop-blur-xl border border-white/20 p-4 rounded-3xl">
                <div className="flex items-center justify-between">
                  <div>
                    <p className="text-[8px] font-black uppercase text-slate-900 tracking-[0.2em]">Reference Visual</p>
                    <p className="text-[10px] font-bold text-slate-700">Medical Imaging Synthesis</p>
                  </div>
                  <Sparkles className="w-4 h-4 text-white" />
                </div>
              </div>
            </div>
          </div>
        </div>

        {/* --- TABS --- */}
        <div className="flex justify-center mb-16">
          <div className="inline-flex p-1.5 bg-slate-100 rounded-[24px] border border-slate-200/50 shadow-inner">
            {([
              { id: 'steps', label: 'Steps', icon: <ClipboardList className="w-4 h-4" /> },
              { id: 'summary', label: 'Summary', icon: <Info className="w-4 h-4" /> },
              { id: 'correlation', label: 'Pathophysiology', icon: <Zap className="w-4 h-4" /> },
              { id: 'media', label: 'Audio/Video', icon: <Play className="w-4 h-4" /> }
            ] as any[]).map((tab) => (
              <button 
                key={tab.id}
                onClick={() => setActiveTab(tab.id)}
                className={`flex items-center gap-3 px-6 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all duration-300 ${activeTab === tab.id ? 'bg-white text-slate-900 shadow-xl' : 'text-slate-400 hover:text-slate-600'}`}
              >
                {tab.icon}
                {tab.label}
              </button>
            ))}
          </div>
        </div>

        {/* --- CONTENT AREA --- */}
        <div className="animate-in fade-in slide-in-from-bottom-4 duration-700">
          {activeTab === 'steps' && (
            <div className="space-y-12">
              {Object.entries(categorizedSteps).map(([category, steps], catIdx) => (
                <div key={category} className="animate-in fade-in" style={{ animationDelay: `${catIdx * 100}ms` }}>
                  <div className="flex items-center gap-4 mb-8">
                    <div className={`h-6 w-1 rounded-full ${style.secondary}`} />
                    <h3 className="text-xl font-black text-slate-900 tracking-tight uppercase">{category}</h3>
                  </div>

                  <div className="grid grid-cols-1 gap-4">
                    {steps.map((step) => {
                      const isChecked = checkedSteps.has(step.id);
                      const isExpanded = expandedStep === step.id;
                      return (
                        <div 
                          key={step.id} 
                          className={`group/step rounded-[32px] border-2 transition-all duration-500 overflow-hidden ${
                            isChecked 
                              ? 'bg-emerald-50/20 border-emerald-200' 
                              : 'bg-white border-slate-50 shadow-sm hover:border-blue-100 hover:shadow-xl hover:shadow-blue-500/5'
                          }`}
                        >
                          <div className="p-6 flex items-start gap-6">
                            {isChecklistMode ? (
                              <button 
                                onClick={() => setCheckedSteps(p => {
                                  const n = new Set(p);
                                  if (n.has(step.id)) n.delete(step.id);
                                  else n.add(step.id);
                                  return n;
                                })}
                                className={`w-8 h-8 rounded-xl border-2 flex items-center justify-center transition-all duration-500 shrink-0 ${
                                  isChecked ? 'bg-emerald-600 border-emerald-600 shadow-xl shadow-emerald-200 text-white' : 'bg-white border-slate-200 hover:border-emerald-400'
                                }`}
                              >
                                {isChecked && <CheckCircle2 className="w-5 h-5" />}
                              </button>
                            ) : (
                              <div className={`w-3 h-3 rounded-full mt-3 shrink-0 ${style.secondary} opacity-40`} />
                            )}

                            <div className="flex-1">
                               <div className="flex items-center justify-between mb-2">
                                  <h4 className={`text-base font-black tracking-tight ${isChecked ? 'text-emerald-700' : 'text-slate-900'}`}>{step.title}</h4>
                                  <div className="flex items-center gap-2">
                                     <button 
                                       onClick={() => fetchCorrelation(step.title)}
                                       className="p-2 hover:bg-slate-50 rounded-lg text-slate-300 hover:text-blue-600 transition-all"
                                     >
                                       <Zap className="w-4 h-4" />
                                     </button>
                                     <button 
                                       onClick={() => setExpandedStep(isExpanded ? null : step.id)}
                                       className={`p-2 rounded-lg text-slate-300 transition-all ${isExpanded ? 'rotate-180 text-blue-500' : ''}`}
                                     >
                                       <ChevronDown className="w-4 h-4" />
                                     </button>
                                  </div>
                               </div>
                               <p className={`text-[13px] leading-relaxed font-medium ${isChecked ? 'text-emerald-600/70' : 'text-slate-500'}`}>
                                 {step.description}
                               </p>

                               {isExpanded && (
                                 <div className="mt-6 pt-6 border-t border-slate-100 animate-in slide-in-from-top-2 duration-300">
                                   <div className="flex items-center gap-2 mb-4">
                                      <Lightbulb className="w-4 h-4 text-amber-500" />
                                      <span className="text-[10px] font-black uppercase tracking-widest text-slate-400">Clinical Stigmata</span>
                                   </div>
                                   {step.positiveFindings?.map((f, i) => (
                                      <div key={i} className="bg-slate-50 p-4 rounded-2xl mb-3 border border-slate-100">
                                         <p className="text-[12px] text-slate-700 font-semibold italic">"{f.description}"</p>
                                      </div>
                                   ))}
                                 </div>
                               )}
                            </div>
                          </div>
                        </div>
                      );
                    })}
                  </div>
                </div>
              ))}
            </div>
          )}

          {activeTab === 'correlation' && (
             <div className="max-w-4xl mx-auto py-10 space-y-12">
                <div className="text-center mb-16">
                  <div className="inline-block p-4 bg-rose-50 rounded-3xl mb-6 shadow-xl shadow-rose-100"><Zap className="w-8 h-8 text-rose-600" /></div>
                  <h2 className="text-4xl font-black text-slate-900 tracking-tighter mb-4">Functional Pathophysiology</h2>
                  <p className="text-sm text-slate-400 font-black uppercase tracking-[0.3em]">MedEx Matrix v2.0</p>
                </div>
                {/* Same logic as before but with updated styling */}
                {correlation ? (
                  <div className="bg-white p-12 rounded-[50px] border-2 border-slate-100 shadow-2xl relative overflow-hidden">
                     <div className="absolute top-0 right-0 p-12 opacity-5 pointer-events-none rotate-12"><Zap className="w-48 h-48" /></div>
                     {/* ... details ... */}
                  </div>
                ) : (
                  <div className="p-24 text-center border-4 border-dashed border-slate-100 rounded-[50px]">
                    <Sparkles className="w-12 h-12 text-slate-200 mx-auto mb-6" />
                    <p className="text-[11px] font-black uppercase text-slate-300 tracking-[0.2em]">Select a step to trigger synthesis</p>
                  </div>
                )}
             </div>
          )}
        </div>
      </div>
    </div>
  );
};

