import React from 'react';
import { ChevronDown, Zap, CheckCircle2 } from 'lucide-react';
import { Examination } from '../types';
import { SYSTEM_THEMES, DEFAULT_STYLE } from '../theme';
import ExaminationCard from './ExaminationCard';
import Tooltip from './Tooltip';

interface SystemSectionProps {
  system: string;
  exams: Examination[];
  isExpanded: boolean;
  onToggle: (system: string) => void;
  onSelectExam: (exam: Examination) => void;
  onSyncExam: (examId: string) => void;
  downloadedIds: Set<string>;
  syncingIds: Set<string>;
}

const SystemSection: React.FC<SystemSectionProps> = ({
  system, exams, isExpanded, onToggle, onSelectExam, onSyncExam, downloadedIds, syncingIds
}) => {
  const style = SYSTEM_THEMES[system] || DEFAULT_STYLE;
  const downloadedCount = exams.filter(e => downloadedIds.has(e.id)).length;

  return (
    <div className="group/system animate-in fade-in slide-in-from-bottom-4 duration-700">
      <button 
        onClick={() => onToggle(system)}
        className={`w-full flex items-center justify-between p-6 rounded-[32px] transition-all duration-700 border-2 backdrop-blur-xl group/btn overflow-hidden relative ${
          isExpanded ? `${style.activeBg} ${style.border} ${style.glow} mb-8 scale-[1.01] shadow-2xl z-10` 
          : `${style.bg} ${style.border} hover:bg-white hover:border-slate-300 shadow-sm ${style.shadow}`
        }`}
      >
        <div className="flex items-center gap-5 relative z-10">
          <div className={`p-4 rounded-2xl transition-all duration-700 shadow-xl ${
            isExpanded ? `${style.text} bg-white scale-110 rotate-3` : `bg-white border border-slate-100 ${style.text} group-hover/btn:scale-105 group-hover/btn:-rotate-2`
          }`}>
            {style.icon}
          </div>
          <div className="text-left">
            <h3 className={`font-black tracking-tight text-xl transition-colors duration-500 ${isExpanded ? 'text-slate-900' : 'text-slate-800'}`}>{system}</h3>
            <div className="flex items-center gap-3 mt-1">
              <span className={`text-[10px] font-black uppercase tracking-widest transition-all duration-500 ${isExpanded ? style.text : 'text-slate-400'}`}>
                {exams.length} Protocols
              </span>
              <div className="flex items-center gap-1.5 px-2 py-0.5 bg-white/50 rounded-full border border-slate-100">
                <CheckCircle2 className={`w-3 h-3 ${downloadedCount === exams.length ? 'text-emerald-500' : 'text-slate-300'}`} />
                <span className="text-[8px] font-black text-slate-500">{downloadedCount} / {exams.length}</span>
              </div>
            </div>
          </div>
        </div>

        <div className={`transition-all duration-700 w-12 h-12 rounded-full flex items-center justify-center ${
          isExpanded ? `rotate-180 bg-white ${style.text} shadow-xl` : 'bg-white text-slate-300 group-hover/btn:text-slate-500'
        }`}>
          <ChevronDown className="w-6 h-6" />
        </div>
      </button>

      {isExpanded && (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8 pl-6 ml-8 pb-10 animate-in zoom-in-95 duration-500 border-l-2 border-slate-100">
          {exams.map(exam => (
            <ExaminationCard 
              key={exam.id}
              exam={exam}
              onSelect={onSelectExam}
              onSync={onSyncExam}
              isDownloaded={downloadedIds.has(exam.id)}
              isSyncing={syncingIds.has(exam.id)}
            />
          ))}
        </div>
      )}
    </div>
  );
};

