                          {cause}
                        </li>
                      ))}
                    </ul>
                  </section>

                  <section className="bg-rose-50/40 p-10 rounded-[40px] border border-rose-100">
                    <h5 className="text-[10px] font-black uppercase text-rose-600 mb-4 tracking-widest">Clinical Significance</h5>
                    <p className="text-[14px] leading-relaxed text-slate-800 font-black italic">"{correlation.clinicalSignificance}"</p>
                  </section>
                </div>
              </section>

              {correlation.sources && correlation.sources.length > 0 && (
                <section className="pt-12 border-t border-slate-100">
                  <h5 className="text-[10px] font-black uppercase text-slate-400 mb-6 tracking-widest">Verified Evidence Layer</h5>
