            <button 
              className="px-10 py-4 bg-white border-2 border-slate-100 text-slate-500 rounded-[24px] text-[11px] font-black uppercase tracking-widest flex items-center gap-3 hover:bg-slate-50 transition-all"
            >
              Share Matrix <Share2 className="w-4 h-4" />
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

