                                       <button 
                                         onClick={() => fetchSidePathophysiology(step.title)}
                                         className="p-3 hover:bg-slate-50 rounded-xl text-slate-300 hover:text-rose-600 transition-all border border-transparent hover:border-slate-100"
                                       >
                                         <Zap className="w-5 h-5" />
                                       </button>
