                                      </div>
                                   </div>

                                   <div className="flex flex-wrap gap-3">
                                      {(step.positiveFindings || []).map((f, i) => (
                                         <button 
                                            key={i}
                                            onClick={() => fetchSidePathophysiology(f.description.length > 30 ? step.title : f.description)}
                                            className="group/stigmata flex items-center gap-4 p-4 bg-slate-50 hover:bg-white hover:shadow-2xl hover:shadow-blue-500/10 hover:border-blue-400 border border-slate-100 rounded-2xl transition-all duration-300 text-left max-w-sm relative overflow-hidden"
                                         >
                                            <div className="absolute top-0 right-0 p-2 opacity-0 group-hover/stigmata:opacity-100 transition-opacity">
                                              <Zap className="w-3 h-3 text-rose-500 animate-pulse" />
                                            </div>
                                            <div className="w-2 h-8 rounded-full bg-slate-200 group-hover/stigmata:bg-blue-500 transition-colors" />
                                            <p className="text-[12px] text-slate-700 font-black italic group-hover/stigmata:text-slate-900 transition-colors">
                                              "{f.description}"
                                            </p>
                                         </button>
                                      ))}
                                   </div>

                                   {(!step.positiveFindings || step.positiveFindings.length === 0) && (
                                      <div className="flex items-center gap-3 p-4 bg-slate-50/50 rounded-2xl border border-dashed border-slate-200">
                                         <Info className="w-4 h-4 text-slate-300" />
                                         <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">No specific positive findings indexed</span>
                                      </div>
                                   )}
                                 </div>
                               )}
                            </div>
                          </div>
                        </div>
                      );
                    })}
                  </div>
                </div>
              ))}
            </div>
          )}

          {activeTab === 'correlation' && (
             <div className="max-w-4xl mx-auto py-10 space-y-12">
                <div className="text-center mb-16">
                  <div className="inline-block p-4 bg-rose-50 rounded-3xl mb-6 shadow-xl shadow-rose-100"><Zap className="w-8 h-8 text-rose-600" /></div>
                  <h2 className="text-4xl font-black text-slate-900 tracking-tighter mb-4">Functional Matrix</h2>
                  <p className="text-sm text-slate-400 font-black uppercase tracking-[0.3em]">MedEx Synthesis Suite</p>
                </div>

                {sidePathoData ? (
                  <div className="bg-white p-12 rounded-[50px] border-2 border-slate-100 shadow-2xl relative overflow-hidden animate-in zoom-in-95 duration-500">
                     <div className="absolute top-0 right-0 p-12 opacity-5 pointer-events-none rotate-12"><Zap className="w-48 h-48" /></div>
                     <div className="flex items-center gap-6 mb-10">
