const MedImage: React.FC<{ src?: string; alt: string; fallbackIcon: React.ReactNode; label: string }> = ({ src, alt, fallbackIcon, label }) => {
  const [error, setError] = useState(false);

  if (!src || error) {
    return (
      <div className="w-full aspect-video bg-slate-50 border-2 border-dashed border-slate-200 rounded-[32px] flex flex-col items-center justify-center p-12 text-slate-300">
        <div className="mb-4 opacity-40 scale-[2]">{fallbackIcon}</div>
        <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400">{label} Visualization Unavailable</p>
        <p className="text-[8px] font-bold text-slate-300 uppercase mt-2">Requires Pro Synthesis Layer</p>
      </div>
    );
  }

  return (
    <div className="relative group/viz rounded-[32px] overflow-hidden border border-slate-200 shadow-inner bg-slate-50">
      <img 
        src={src} 
        alt={alt} 
        className="w-full h-auto object-cover transition-transform duration-1000 group-hover/viz:scale-[1.05]" 
        onError={() => setError(true)}
      />
      <div className="absolute bottom-4 left-4 right-4 flex items-center justify-between px-4 py-2 bg-black/40 backdrop-blur-md rounded-2xl">
        <span className="text-[8px] font-black text-white uppercase tracking-widest">{label} Synthesis</span>
        <Sparkles className="w-3 h-3 text-amber-400 animate-pulse" />
      </div>
    </div>
  );
};

const ClinicalCorrelationView: React.FC = () => {
  const [query, setQuery] = useState('');
  const [loading, setLoading] = useState(false);
  const [correlation, setCorrelation] = useState<ClinicalCorrelation | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isProMode, setIsProMode] = useState(false);
  const [showKeyGate, setShowKeyGate] = useState(false);

  const gemini = new GeminiService();

  const handleOpenKeySelector = async () => {
    // @ts-ignore
    await window.aistudio.openSelectKey();
    setShowKeyGate(false);
    setIsProMode(true);
  };

  const handleSearch = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!query.trim()) return;

    setLoading(true);
    setError(null);
    try {
      if (isProMode) {
        // @ts-ignore
        const hasKey = await window.aistudio.hasSelectedApiKey();
        if (!hasKey) {
          setShowKeyGate(true);
          setLoading(false);
          return;
        }
      }

      const result = await gemini.getClinicalCorrelation(query, "advanced clinical diagnostics", isProMode);
      setCorrelation(result);
    } catch (err: any) {
      if (err.message?.includes("Requested entity was not found")) {
        setShowKeyGate(true);
