                          {cause}
                        </li>
                      ))}
                    </ul>
                  </section>

                  <section className="bg-rose-50/40 p-10 rounded-[40px] border border-rose-100">
                    <h5 className="text-[10px] font-black uppercase text-rose-600 mb-4 tracking-widest">Clinical Significance</h5>
                    <p className="text-[14px] leading-relaxed text-slate-800 font-black italic">"{correlation.clinicalSignificance}"</p>
                  </section>
                </div>
              </section>

              {correlation.sources && correlation.sources.length > 0 && (
                <section className="pt-12 border-t border-slate-100">
                  <h5 className="text-[10px] font-black uppercase text-slate-400 mb-6 tracking-widest">Verified Evidence Layer</h5>
                  <div className="flex flex-wrap gap-4">
                    {correlation.sources.map((s, idx) => (
                      <a 
                        key={idx} 
                        href={s.uri} 
                        target="_blank" 
                        rel="noopener noreferrer" 
                        className="flex items-center gap-3 px-6 py-3 bg-white border-2 border-slate-100 rounded-2xl text-[11px] font-bold text-slate-700 hover:border-rose-400 hover:text-rose-600 transition-all shadow-sm group/src"
                      >
                        {s.title}
                        <ExternalLink className="w-3.5 h-3.5 text-slate-300 group-hover/src:text-rose-500" />
                      </a>
                    ))}
                  </div>
                </section>
              )}
            </div>
          </div>

          <div className="p-10 text-center flex justify-center gap-4">
            <button 
              onClick={() => { setCorrelation(null); setQuery(''); }}
              className="px-10 py-4 bg-slate-900 text-white rounded-[24px] text-[11px] font-black uppercase tracking-widest flex items-center gap-3 hover:bg-slate-800 transition-all shadow-xl"
            >
              <ListRestart className="w-4 h-4" /> New Correlation
            </button>
            <button 
              className="px-10 py-4 bg-white border-2 border-slate-100 text-slate-500 rounded-[24px] text-[11px] font-black uppercase tracking-widest flex items-center gap-3 hover:bg-slate-50 transition-all"
            >
              Share Matrix <Share2 className="w-4 h-4" />
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default ClinicalCorrelationView;

