  const [showDifferentialPanel, setShowDifferentialPanel] = useState(false);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  const gemini = new GeminiService();
  const style = SYSTEM_THEMES[exam.system] || DEFAULT_STYLE;

  const categorizedSteps = useMemo(() => {
    const groups: Record<string, ExamStep[]> = {};
    exam.steps.forEach(step => {
      const cat = step.category || 'General';
      if (!groups[cat]) groups[cat] = [];
      groups[cat].push(step);
    });
    return groups;
  }, [exam.steps]);

  useEffect(() => {
    setExpandedCategories(new Set(Object.keys(categorizedSteps)));
  }, [categorizedSteps]);

  useEffect(() => {
    const research = async () => {
      if (exam.steps.length === 0 && isOnline) {
        setIsResearching(true);
        try {
          const res = await gemini.populateExamination(exam);
          setExam(prev => ({ ...prev, ...res, isDraft: false }));
        } catch (e) { console.error(e); }
        finally { setIsResearching(false); }
      }
    };
    research();
  }, [exam.id, isOnline]);

  useEffect(() => {
    if (activeTab === 'summary' && !summary && isOnline) {
      setLoadingSummary(true);
      gemini.getExaminationSummary(exam.name).then(s => {
        setSummary(s);
        setLoadingSummary(false);
      });
    }
  }, [activeTab]);

  const fetchSidePathophysiology = async (sign: string) => {
    if (!isOnline) return;
    setSidePathoSign(sign);
    setLoadingSidePatho(true);
    setSidePathoData(null);
    try {
      const data = await gemini.getClinicalCorrelation(sign, exam.system, true); // Pro Mode by default for deep reasoning
      setSidePathoData(data);
    } catch (e) { console.error(e); }
    finally { setLoadingSidePatho(false); }
  };

  const selectedFindingTitles = useMemo(() => {
    return Array.from(checkedSteps)
      .map(id => exam.steps.find(s => s.id === id)?.title || '')
      .filter(t => t !== '');
  }, [checkedSteps, exam.steps]);

  const progress = exam.steps.length > 0 ? Math.round((checkedSteps.size / exam.steps.length) * 100) : 0;

  if (isResearching) return (
    <div className="h-full flex flex-col items-center justify-center p-20 bg-white">
      <div className="relative mb-8">
        <div className="w-20 h-20 border-4 border-blue-50 rounded-full"></div>
        <div className="w-20 h-20 border-4 border-blue-600 border-t-transparent rounded-full animate-spin absolute top-0"></div>
        <BrainCircuit className="w-8 h-8 text-blue-600 absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2" />
      </div>
      <p className="text-[10px] font-black uppercase text-slate-400 tracking-[0.3em] mb-2">Synthesizing Protocol</p>
    </div>
  );

  return (
    <div className="min-h-full bg-white animate-in fade-in duration-700 relative">
      <audio ref={audioRef} />

      {showDifferentialPanel && isChecklistMode && (
        <DifferentialPanel 
          findings={selectedFindingTitles}
          system={exam.system}
          onClose={() => setShowDifferentialPanel(false)}
          isOnline={isOnline}
        />
      )}

      {/* --- PATHOPHYSIOLOGY SIDE-OVER --- */}
      {sidePathoSign && (
        <>
          <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-[60] animate-in fade-in duration-500" onClick={() => setSidePathoSign(null)} />
          <div className="fixed top-0 right-0 bottom-0 w-full max-w-xl bg-white shadow-[-20px_0_60px_rgba(0,0,0,0.1)] z-[70] animate-in slide-in-from-right duration-500 flex flex-col">
            <header className="p-8 border-b border-slate-100 flex items-center justify-between bg-slate-50/50 sticky top-0 backdrop-blur-md">
               <div className="flex items-center gap-4">
                  <div className="w-12 h-12 bg-rose-600 text-white rounded-2xl flex items-center justify-center shadow-lg shadow-rose-200">
                    <Zap className="w-6 h-6" />
                  </div>
                  <div>
                    <h3 className="text-xl font-black text-slate-900 uppercase tracking-tight">{sidePathoSign}</h3>
                    <p className="text-[10px] font-black text-rose-600 uppercase tracking-widest">Clinical Mechanism</p>
                  </div>
               </div>
               <button onClick={() => setSidePathoSign(null)} className="p-3 hover:bg-slate-100 rounded-2xl text-slate-400 transition-all">
                 <X className="w-5 h-5" />
               </button>
            </header>

            <div className="flex-1 overflow-y-auto custom-scrollbar p-8 space-y-10">
               {loadingSidePatho ? (
                 <div className="h-full flex flex-col items-center justify-center space-y-4">
                   <div className="relative">
                      <div className="w-16 h-16 border-4 border-rose-50 rounded-full"></div>
                      <div className="w-16 h-16 border-4 border-rose-600 border-t-transparent rounded-full animate-spin absolute top-0"></div>
                   </div>
                   <p className="text-[10px] font-black uppercase text-slate-400 tracking-[0.2em]">Synthesizing Diagnostics...</p>
                 </div>
               ) : sidePathoData ? (
                 <div className="animate-in fade-in zoom-in-95 duration-500 space-y-8">
                    <MedImage src={sidePathoData.imageUrl} alt={sidePathoData.sign} label="Primary Sign" fallbackIcon={<Activity />} />

                    {/* Specialized Side-Over Diagrams */}
                    {(sidePathoData.needsCirculationDiagram || sidePathoData.needsPVLoopDiagram || sidePathoData.needsAnatomyDiagram) && (
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        {sidePathoData.needsCirculationDiagram && (
                          <MedImage src={sidePathoData.circulationImageUrl} alt="Circulation" label="Circulation" fallbackIcon={<Waves />} />
                        )}
                        {sidePathoData.needsPVLoopDiagram && (
                          <MedImage src={sidePathoData.pvLoopImageUrl} alt="PV Loop" label="Cardiac Loop" fallbackIcon={<HeartPulse />} />
                        )}
                        {sidePathoData.needsAnatomyDiagram && (
                          <MedImage src={sidePathoData.anatomyImageUrl} alt="Anatomy" label="Anatomy" fallbackIcon={<Layers />} />
                        )}
                      </div>
                    )}

                    <section className="bg-slate-50 p-6 rounded-[32px] border border-slate-100">
                       <div className="flex items-center gap-3 mb-4">
                          <Activity className="w-4 h-4 text-rose-600" />
                          <h4 className="text-[10px] font-black uppercase tracking-widest text-slate-400">Pathophysiology</h4>
                       </div>
                       <p className="text-sm leading-[1.8] text-slate-700 font-medium italic">
                         {sidePathoData.pathophysiology}
                       </p>
                    </section>

                    <section className="grid grid-cols-1 md:grid-cols-2 gap-6">
                       <div className="space-y-4">
                          <h4 className="text-[10px] font-black uppercase tracking-widest text-slate-400 flex items-center gap-2"><BookOpen className="w-4 h-4" /> Causes</h4>
                          <ul className="space-y-2">
                            {(Array.isArray(sidePathoData.causes) ? sidePathoData.causes : []).map((c, i) => (
                              <li key={i} className="flex items-center gap-3 text-[12px] text-slate-600 font-bold">
                                <div className="w-1.5 h-1.5 rounded-full bg-rose-500" />
                                {c}
                              </li>
                            ))}
                          </ul>
                       </div>
                       <div className="bg-rose-50/50 p-6 rounded-3xl border border-rose-100">
                          <h4 className="text-[10px] font-black uppercase tracking-widest text-rose-600 mb-2">Significance</h4>
                          <p className="text-[12px] leading-relaxed text-slate-800 font-bold italic">"{sidePathoData.clinicalSignificance}"</p>
                       </div>
                    </section>
                 </div>
               ) : (
                 <div className="text-center py-20 text-slate-300">
                   <Zap className="w-12 h-12 mx-auto mb-4 opacity-20" />
                   <p className="text-[10px] font-black uppercase tracking-widest">No Analysis Available</p>
                 </div>
               )}
            </div>
          </div>
        </>
      )}

      {/* --- COMMAND HEADER --- */}
      <div className="sticky top-0 z-40 bg-white/80 backdrop-blur-xl border-b border-slate-100 px-8 py-4 flex items-center justify-between">
        <div className="flex items-center gap-6">
          <button onClick={onBack} className="p-2 hover:bg-slate-50 rounded-xl text-slate-400 transition-colors">
            <ArrowLeft className="w-5 h-5" />
          </button>
          <div>
            <div className="flex items-center gap-2 mb-0.5">
              <span className={`text-[9px] font-black uppercase tracking-widest ${style.text}`}>{exam.system}</span>
              <span className="w-1 h-1 rounded-full bg-slate-200" />
              <span className="text-[9px] font-black uppercase tracking-widest text-slate-400">MedEx Core</span>
            </div>
            <h1 className="text-lg font-black text-slate-900 tracking-tight leading-none">{exam.name}</h1>
          </div>
        </div>

        <div className="flex items-center gap-3">
          <div className="flex items-center gap-2 mr-4 bg-slate-50 px-4 py-2 rounded-2xl border border-slate-100">
            <span className="text-[9px] font-black uppercase text-slate-400 tracking-widest">Progress</span>
            <div className="w-24 h-1.5 bg-slate-200 rounded-full overflow-hidden">
               <div className={`h-full ${style.secondary} transition-all duration-1000`} style={{ width: `${progress}%` }} />
            </div>
            <span className="text-[10px] font-black text-slate-900">{progress}%</span>
          </div>
          <button onClick={() => setIsChecklistMode(!isChecklistMode)} className={`px-6 py-2.5 rounded-2xl text-[10px] font-black uppercase flex items-center gap-2 shadow-xl transition-all hover:scale-105 ${isChecklistMode ? 'bg-emerald-600 text-white' : 'bg-slate-900 text-white'}`}>
            <ListCheck className="w-4 h-4" /> {isChecklistMode ? 'Exit OSCE' : 'Start OSCE'}
          </button>
        </div>
      </div>

      <div className="max-w-5xl mx-auto py-12 px-8">
        <div className="grid grid-cols-1 lg:grid-cols-5 gap-12 mb-16">
          <div className="lg:col-span-3">
             <div className="flex items-center gap-3 mb-6">
                <div className={`p-2 rounded-xl ${style.bg} ${style.text}`}>{style.icon}</div>
                <h2 className="text-3xl font-black text-slate-900 tracking-tighter leading-tight">{exam.name}</h2>
             </div>
             <p className="text-base text-slate-500 font-medium leading-[1.8] mb-8 max-w-xl">{exam.shortDescription}</p>
             <div className="flex flex-wrap gap-4">
               {exam.keywords.map(k => (
                 <span key={k} className="px-3 py-1.5 bg-slate-50 border border-slate-100 rounded-lg text-[10px] font-black uppercase text-slate-400 tracking-widest">#{k}</span>
               ))}
             </div>
          </div>

          <div className="lg:col-span-2">
            <div className={`relative rounded-[40px] overflow-hidden aspect-[4/3] border-2 ${style.border} shadow-2xl bg-slate-50`}>
              {exam.headerImageUrl ? (
                <img src={exam.headerImageUrl} className="w-full h-full object-cover" alt="Anatomical Reference" />
              ) : (
                <div className={`w-full h-full ${style.bg} flex items-center justify-center`}>
                  <div className="scale-[4] opacity-20">{style.icon}</div>
                </div>
              )}
            </div>
          </div>
        </div>

        <div className="flex justify-center mb-16">
          <div className="inline-flex p-1.5 bg-slate-100 rounded-[24px] border border-slate-200/50 shadow-inner">
            {[
              { id: 'steps', label: 'Steps', icon: <ClipboardList className="w-4 h-4" /> },
              { id: 'summary', label: 'Summary', icon: <Info className="w-4 h-4" /> },
              { id: 'correlation', label: 'Matrix', icon: <Zap className="w-4 h-4" /> },
              { id: 'media', label: 'Media', icon: <Play className="w-4 h-4" /> }
            ].map((tab) => (
              <button 
                key={tab.id}
                onClick={() => setActiveTab(tab.id as any)}
                className={`flex items-center gap-3 px-6 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all duration-300 ${activeTab === tab.id ? 'bg-white text-slate-900 shadow-xl' : 'text-slate-400 hover:text-slate-600'}`}
              >
                {tab.icon}
                {tab.label}
              </button>
            ))}
          </div>
        </div>

        <div className="animate-in fade-in slide-in-from-bottom-4 duration-700">
          {activeTab === 'steps' && (
            <div className="space-y-12">
              {Object.entries(categorizedSteps).map(([category, steps], catIdx) => (
                <div key={category} className="animate-in fade-in" style={{ animationDelay: `${catIdx * 100}ms` }}>
                  <div className="flex items-center gap-4 mb-8">
                    <div className={`h-6 w-1 rounded-full ${style.secondary}`} />
                    <h3 className="text-xl font-black text-slate-900 tracking-tight uppercase">{category}</h3>
                  </div>

                  <div className="grid grid-cols-1 gap-4">
                    {steps.map((step) => {
                      const isChecked = checkedSteps.has(step.id);
                      const isExpanded = expandedStep === step.id;
                      const hasFindings = step.positiveFindings && step.positiveFindings.length > 0;

                      return (
                        <div key={step.id} className={`group/step rounded-[32px] border-2 transition-all duration-500 overflow-hidden ${isChecked ? 'bg-emerald-50/20 border-emerald-200' : 'bg-white border-slate-50 shadow-sm hover:border-blue-100 hover:shadow-xl'}`}>
                          <div className="p-6 flex items-start gap-6">
                            {isChecklistMode ? (
                              <button onClick={() => setCheckedSteps(p => {
                                const n = new Set(p);
                                if (n.has(step.id)) n.delete(step.id);
                                else n.add(step.id);
                                return n;
                              })} className={`w-10 h-10 rounded-2xl border-2 flex items-center justify-center transition-all duration-500 shrink-0 ${isChecked ? 'bg-emerald-600 border-emerald-600 text-white scale-110' : 'bg-white border-slate-200 hover:border-emerald-400'}`}>
                                {isChecked && <CheckCircle2 className="w-5 h-5" />}
                              </button>
                            ) : (
                              <div className={`w-3 h-3 rounded-full mt-4 shrink-0 ${style.secondary} opacity-40`} />
                            )}

                            <div className="flex-1">
                               <div className="flex items-center justify-between mb-2">
                                  <div className="flex items-center gap-3">
                                    <h4 className={`text-lg font-black tracking-tight ${isChecked ? 'text-emerald-700' : 'text-slate-900'}`}>{step.title}</h4>
                                    {hasFindings && (
                                       <span className="px-2 py-0.5 bg-amber-50 text-amber-600 border border-amber-100 rounded-md text-[7px] font-black uppercase tracking-widest animate-pulse flex items-center gap-1">
                                         <Activity className="w-2.5 h-2.5" /> High Yield
                                       </span>
                                    )}
                                  </div>
                                  <div className="flex items-center gap-2">
                                     <Tooltip content="Pathophysiology Slide-Over">
                                       <button onClick={() => fetchSidePathophysiology(step.title)} className="p-3 hover:bg-slate-50 rounded-xl text-slate-300 hover:text-rose-600 transition-all border border-transparent hover:border-slate-100">
                                         <Zap className="w-5 h-5" />
                                       </button>
                                     </Tooltip>
                                     <button onClick={() => setExpandedStep(isExpanded ? null : step.id)} className={`p-3 rounded-xl text-slate-300 transition-all ${isExpanded ? 'rotate-180 text-blue-500 bg-slate-50' : 'hover:bg-slate-50'}`}>
                                       <ChevronDown className="w-5 h-5" />
                                     </button>
                                  </div>
                               </div>
                               <p className={`text-[13px] leading-relaxed font-medium mb-2 ${isChecked ? 'text-emerald-600/70' : 'text-slate-500'}`}>{step.description}</p>

                               {isExpanded && (
                                 <div className="mt-6 pt-6 border-t border-slate-100 animate-in slide-in-from-top-2 duration-500">
                                   <div className="flex items-center gap-3 mb-6">
                                      <div className="p-2 bg-amber-50 rounded-lg"><Lightbulb className="w-4 h-4 text-amber-600" /></div>
                                      <div>
                                        <span className="text-[10px] font-black uppercase tracking-widest text-slate-800">Clinical Stigmata Matrix</span>
                                        <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest">Tap finding for pathophysiology</p>
                                      </div>
                                   </div>

                                   <div className="flex flex-wrap gap-3">
                                      {(step.positiveFindings || []).map((f, i) => (
                                         <button key={i} onClick={() => fetchSidePathophysiology(f.description.length > 30 ? step.title : f.description)} className="group/stigmata flex items-center gap-4 p-4 bg-slate-50 hover:bg-white hover:shadow-2xl hover:border-rose-300 border border-slate-100 rounded-2xl transition-all duration-300 text-left max-w-sm relative overflow-hidden">
                                            <div className="absolute top-0 right-0 p-2 opacity-0 group-hover/stigmata:opacity-100 transition-opacity"><Zap className="w-3 h-3 text-rose-500 animate-pulse" /></div>
                                            <div className="w-2 h-8 rounded-full bg-slate-200 group-hover/stigmata:bg-rose-500 transition-colors" />
                                            <p className="text-[12px] text-slate-700 font-black italic group-hover/stigmata:text-slate-900 transition-colors">"{f.description}"</p>
                                         </button>
                                      ))}
                                   </div>
                                 </div>
                               )}
                            </div>
                          </div>
                        </div>
                      );
                    })}
                  </div>
                </div>
              ))}
            </div>
          )}

          {activeTab === 'correlation' && (
             <div className="max-w-4xl mx-auto py-10 space-y-12">
                <div className="text-center mb-16">
                  <div className="inline-block p-4 bg-rose-50 rounded-3xl mb-6 shadow-xl shadow-rose-100"><Zap className="w-8 h-8 text-rose-600" /></div>
                  <h2 className="text-4xl font-black text-slate-900 tracking-tighter mb-4">Functional Matrix</h2>
                  <p className="text-sm text-slate-400 font-black uppercase tracking-[0.3em]">Fellowship Synthesis Suite</p>
                </div>

                {sidePathoData ? (
                  <div className="bg-white p-12 rounded-[50px] border-2 border-slate-100 shadow-2xl relative overflow-hidden">
                     <div className="absolute top-0 right-0 p-12 opacity-5 pointer-events-none rotate-12"><Zap className="w-48 h-48" /></div>
                     <div className="flex items-center gap-6 mb-10">
                        <div className="w-16 h-16 bg-rose-600 text-white rounded-3xl flex items-center justify-center shadow-2xl shadow-rose-200"><Zap className="w-8 h-8" /></div>
                        <div>
                          <h3 className="text-3xl font-black text-slate-900 uppercase tracking-tight">{sidePathoData.sign}</h3>
                          <span className="text-[10px] font-black uppercase tracking-widest text-rose-600">Full Diagnostic Record</span>
                        </div>
                     </div>

                     <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
                        <div className="space-y-8">
                           <MedImage src={sidePathoData.imageUrl} alt={sidePathoData.sign} label="Primary Analysis" fallbackIcon={<Activity />} />
                           <div>
                             <h4 className="text-[10px] font-black uppercase tracking-widest text-slate-400 mb-4">Mechanism</h4>
                             <p className="text-sm leading-[1.8] text-slate-700 font-medium italic">{sidePathoData.pathophysiology}</p>
                           </div>
                        </div>
                        <div className="bg-slate-50 p-8 rounded-[40px] border border-slate-100 h-fit">
                           <h4 className="text-[10px] font-black uppercase tracking-widest text-slate-400 mb-4">Clinical Significance</h4>
                           <p className="text-sm font-black text-slate-900 leading-relaxed mb-6">"{sidePathoData.clinicalSignificance}"</p>
                           <div className="flex flex-wrap gap-2">
                             {(Array.isArray(sidePathoData.causes) ? sidePathoData.causes : []).slice(0, 3).map((c, i) => (
                               <span key={i} className="px-3 py-1 bg-white border border-slate-200 rounded-lg text-[8px] font-black uppercase text-slate-400 tracking-widest">{c}</span>
                             ))}
                           </div>
                        </div>
                     </div>
                  </div>
                ) : (
                  <div className="p-24 text-center border-4 border-dashed border-slate-100 rounded-[50px] bg-slate-50/50">
                    <Sparkles className="w-12 h-12 text-slate-200 mx-auto mb-6 animate-pulse" />
                    <p className="text-[11px] font-black uppercase text-slate-300 tracking-[0.2em]">Select clinical sign to begin synthesis</p>
                  </div>
                )}
             </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default ExamView;

export enum ExamSystem {
  GENERAL = 'General Principles',
  CARDIOVASCULAR = 'Cardiovascular',
  RESPIRATORY = 'Respiratory',
  GASTROINTESTINAL = 'Gastrointestinal',
  GENITOURINARY = 'Genitourinary',
  HAEMATOLOGICAL = 'Haematological',
  RHEUMATOLOGICAL = 'Rheumatological',
  ENDOCRINE = 'Endocrine',
  NEUROLOGICAL = 'Nervous System',
  PAEDIATRIC = 'Paediatric & Neonatal',
  WOMENS_HEALTH = 'Women\'s Health',
  SPECIALTY = 'Specialty Systems',
  MENTAL_HEALTH = 'Mental Health',
  ACUTE_CARE = 'Acute Care'
}

export interface ClinicalFinding {
  description: string;
  imageUrl?: string;
  localImageUrl?: string;
}

export interface ExamStep {
  id: string;
  title: string;
  description: string;
  category: string; 
  imageUrl?: string;
  localImageUrl?: string;
  positiveFindings?: ClinicalFinding[];
  negativeFindings?: string[];
  imagePrompt?: string;
}

export interface DiagnosisSuggestion {
  condition: string;
  probability: 'High' | 'Moderate' | 'Low';
  reasoning: string;
  keyFindings: string[];
}

export interface ClinicalCondition {
  name: string;
  system: ExamSystem;
  description: string;
  findings: {
    category: string;
    sign: string;
    significance: string;
    link?: string; // High-quality academic link
  }[];
}

export interface AudioSimulation {
  id: string;
  name: string;
  description: string;
  url: string;
  localUrl?: string;
  type: 'heart' | 'lung' | 'other';
}

export interface GroundingSource {
  title: string;
  uri: string;
}

export interface Examination {
  id: string;
  system: ExamSystem;
  name: string;
  shortDescription: string;
  steps: ExamStep[];
  videoUrl?: string;
  headerImageUrl?: string;
  headerImagePrompt?: string;
  keywords: string[];
  audioSimulations?: AudioSimulation[];
  isDraft?: boolean; 
  sources?: GroundingSource[];
  isDownloaded?: boolean;
  lastUpdated?: number;
  relatedExamIds?: string[];
}

export interface ClinicalCorrelation {
  sign: string;
  pathophysiology: string;
  causes: string[];
  clinicalSignificance: string;
  sources?: GroundingSource[];
  imageUrl?: string;
  imagePrompt?: string;
  // Specialized diagram metadata
  needsCirculationDiagram?: boolean;
  circulationSide?: 'left-sided' | 'right-sided';
  needsPVLoopDiagram?: boolean;
  needsAnatomyDiagram?: boolean;
  circulationImageUrl?: string;
  pvLoopImageUrl?: string;
  anatomyImageUrl?: string;
  // Metadata for anatomy specific synthesis
  affectedAnatomy?: string;
}

export type DownloadTaskStatus = 'pending' | 'downloading' | 'paused' | 'completed' | 'failed' | 'cancelled';
export type DownloadTaskType = 'protocol' | 'media' | 'audio' | 'deep_sync';

export interface DownloadTask {
  id: string;
  examId: string;
  examName: string;
  type: DownloadTaskType;
  status: DownloadTaskStatus;
  progress: number;
  error?: string;
  retryCount: number;
  createdAt: number;
}

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Examination, ClinicalCorrelation, ExamStep } from '../types';
import { GeminiService } from '../services/geminiService';
import { SYSTEM_THEMES, DEFAULT_STYLE } from '../theme';
import Tooltip from './Tooltip';
import DifferentialPanel from './DifferentialPanel';
import { 
  ChevronRight, ClipboardList, Target, Ear, Play, Info, Zap, 
  CheckCircle2, ChevronDown, Lightbulb, Loader2, Sparkles, ListCheck, BrainCircuit, ExternalLink, Microscope,
  ArrowLeft, Share2, Printer, X, BookOpen, Activity, Waves, HeartPulse, Layers
} from 'lucide-react';

interface ExamViewProps {
  exam: Examination;
  onBack: () => void;
}

const MedImage: React.FC<{ src?: string; alt: string; fallbackIcon: React.ReactNode; label: string }> = ({ src, alt, fallbackIcon, label }) => {
  const [error, setError] = useState(false);

  if (!src || error) {
    return (
      <div className="w-full aspect-video bg-slate-50 border-2 border-dashed border-slate-200 rounded-3xl flex flex-col items-center justify-center p-8 text-slate-300">
        <div className="mb-3 opacity-30 scale-150">{fallbackIcon}</div>
        <p className="text-[9px] font-black uppercase tracking-widest text-slate-400">{label} Unavailable</p>
      </div>
    );
  }

  return (
    <div className="relative group/viz rounded-3xl overflow-hidden border border-slate-200 shadow-inner bg-slate-50">
      <img 
        src={src} 
        alt={alt} 
        className="w-full h-auto object-cover transition-transform duration-1000 group-hover/viz:scale-[1.05]" 
        onError={() => setError(true)}
      />
      <div className="absolute bottom-3 left-3 right-3 flex items-center justify-between px-3 py-1.5 bg-black/40 backdrop-blur-md rounded-xl">
        <span className="text-[8px] font-black text-white uppercase tracking-widest">{label}</span>
        <Sparkles className="w-2.5 h-2.5 text-amber-400" />
      </div>
    </div>
  );
};

const ExamView: React.FC<ExamViewProps> = ({ exam: initialExam, onBack }) => {
  const [exam, setExam] = useState(initialExam);
  const [activeTab, setActiveTab] = useState<'steps' | 'summary' | 'correlation' | 'media' | 'audio'>('steps');
  const [summary, setSummary] = useState<string | null>(null);
  const [loadingSummary, setLoadingSummary] = useState(false);
  const [isResearching, setIsResearching] = useState(false);

  const [sidePathoSign, setSidePathoSign] = useState<string | null>(null);
  const [sidePathoData, setSidePathoData] = useState<ClinicalCorrelation | null>(null);
  const [loadingSidePatho, setLoadingSidePatho] = useState(false);

  const [isOnline] = useState(navigator.onLine);
  const [checkedSteps, setCheckedSteps] = useState<Set<string>>(new Set());
  const [isChecklistMode, setIsChecklistMode] = useState(false);
  const [expandedCategories, setExpandedCategories] = useState<Set<string>>(new Set());
  const [expandedStep, setExpandedStep] = useState<string | null>(null);
  const [showDifferentialPanel, setShowDifferentialPanel] = useState(false);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  const gemini = new GeminiService();
  const style = SYSTEM_THEMES[exam.system] || DEFAULT_STYLE;

  const categorizedSteps = useMemo(() => {
    const groups: Record<string, ExamStep[]> = {};
    exam.steps.forEach(step => {
      const cat = step.category || 'General';
      if (!groups[cat]) groups[cat] = [];
      groups[cat].push(step);
    });
    return groups;
  }, [exam.steps]);

  useEffect(() => {
    setExpandedCategories(new Set(Object.keys(categorizedSteps)));
  }, [categorizedSteps]);

  useEffect(() => {
    const research = async () => {
      if (exam.steps.length === 0 && isOnline) {
        setIsResearching(true);
        try {
          const res = await gemini.populateExamination(exam);
          setExam(prev => ({ ...prev, ...res, isDraft: false }));
        } catch (e) { console.error(e); }
        finally { setIsResearching(false); }
      }
    };
    research();
  }, [exam.id, isOnline]);

  useEffect(() => {
    if (activeTab === 'summary' && !summary && isOnline) {
      setLoadingSummary(true);
      gemini.getExaminationSummary(exam.name).then(s => {
        setSummary(s);
        setLoadingSummary(false);
      });
    }
  }, [activeTab]);

  const fetchSidePathophysiology = async (sign: string) => {
    if (!isOnline) return;
    setSidePathoSign(sign);
    setLoadingSidePatho(true);
    setSidePathoData(null);
    try {
      const data = await gemini.getClinicalCorrelation(sign, exam.system, true); // Pro Mode by default for deep reasoning
      setSidePathoData(data);
    } catch (e) { console.error(e); }
    finally { setLoadingSidePatho(false); }
  };

  const selectedFindingTitles = useMemo(() => {
    return Array.from(checkedSteps)
      .map(id => exam.steps.find(s => s.id === id)?.title || '')
      .filter(t => t !== '');
  }, [checkedSteps, exam.steps]);

  const progress = exam.steps.length > 0 ? Math.round((checkedSteps.size / exam.steps.length) * 100) : 0;

  if (isResearching) return (
    <div className="h-full flex flex-col items-center justify-center p-20 bg-white">
      <div className="relative mb-8">
        <div className="w-20 h-20 border-4 border-blue-50 rounded-full"></div>
        <div className="w-20 h-20 border-4 border-blue-600 border-t-transparent rounded-full animate-spin absolute top-0"></div>
        <BrainCircuit className="w-8 h-8 text-blue-600 absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2" />
      </div>
      <p className="text-[10px] font-black uppercase text-slate-400 tracking-[0.3em] mb-2">Synthesizing Protocol</p>
    </div>
  );

  return (
    <div className="min-h-full bg-white animate-in fade-in duration-700 relative">
      <audio ref={audioRef} />

      {showDifferentialPanel && isChecklistMode && (
        <DifferentialPanel 
          findings={selectedFindingTitles}
          system={exam.system}
          onClose={() => setShowDifferentialPanel(false)}
          isOnline={isOnline}
        />
      )}

      {/* --- PATHOPHYSIOLOGY SIDE-OVER --- */}
      {sidePathoSign && (
        <>
          <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-[60] animate-in fade-in duration-500" onClick={() => setSidePathoSign(null)} />
          <div className="fixed top-0 right-0 bottom-0 w-full max-w-xl bg-white shadow-[-20px_0_60px_rgba(0,0,0,0.1)] z-[70] animate-in slide-in-from-right duration-500 flex flex-col">
            <header className="p-8 border-b border-slate-100 flex items-center justify-between bg-slate-50/50 sticky top-0 backdrop-blur-md">
               <div className="flex items-center gap-4">
                  <div className="w-12 h-12 bg-rose-600 text-white rounded-2xl flex items-center justify-center shadow-lg shadow-rose-200">
                    <Zap className="w-6 h-6" />
                  </div>
                  <div>
                    <h3 className="text-xl font-black text-slate-900 uppercase tracking-tight">{sidePathoSign}</h3>
                    <p className="text-[10px] font-black text-rose-600 uppercase tracking-widest">Clinical Mechanism</p>
                  </div>
               </div>
               <button onClick={() => setSidePathoSign(null)} className="p-3 hover:bg-slate-100 rounded-2xl text-slate-400 transition-all">
                 <X className="w-5 h-5" />
               </button>
            </header>

            <div className="flex-1 overflow-y-auto custom-scrollbar p-8 space-y-10">
               {loadingSidePatho ? (
                 <div className="h-full flex flex-col items-center justify-center space-y-4">
                   <div className="relative">
                      <div className="w-16 h-16 border-4 border-rose-50 rounded-full"></div>
                      <div className="w-16 h-16 border-4 border-rose-600 border-t-transparent rounded-full animate-spin absolute top-0"></div>
                   </div>
                   <p className="text-[10px] font-black uppercase text-slate-400 tracking-[0.2em]">Synthesizing Diagnostics...</p>
                 </div>
               ) : sidePathoData ? (
                 <div className="animate-in fade-in zoom-in-95 duration-500 space-y-8">
                    <MedImage src={sidePathoData.imageUrl} alt={sidePathoData.sign} label="Primary Sign" fallbackIcon={<Activity />} />

                    {/* Specialized Side-Over Diagrams */}
                    {(sidePathoData.needsCirculationDiagram || sidePathoData.needsPVLoopDiagram || sidePathoData.needsAnatomyDiagram) && (
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        {sidePathoData.needsCirculationDiagram && (
                          <MedImage src={sidePathoData.circulationImageUrl} alt="Circulation" label="Circulation" fallbackIcon={<Waves />} />
                        )}
                        {sidePathoData.needsPVLoopDiagram && (
                          <MedImage src={sidePathoData.pvLoopImageUrl} alt="PV Loop" label="Cardiac Loop" fallbackIcon={<HeartPulse />} />
                        )}
                        {sidePathoData.needsAnatomyDiagram && (
                          <MedImage src={sidePathoData.anatomyImageUrl} alt="Anatomy" label="Anatomy" fallbackIcon={<Layers />} />
                        )}
                      </div>
                    )}

                    <section className="bg-slate-50 p-6 rounded-[32px] border border-slate-100">
                       <div className="flex items-center gap-3 mb-4">
                          <Activity className="w-4 h-4 text-rose-600" />
                          <h4 className="text-[10px] font-black uppercase tracking-widest text-slate-400">Pathophysiology</h4>
                       </div>
                       <p className="text-sm leading-[1.8] text-slate-700 font-medium italic">
                         {sidePathoData.pathophysiology}
                       </p>
                    </section>

                    <section className="grid grid-cols-1 md:grid-cols-2 gap-6">
                       <div className="space-y-4">
                          <h4 className="text-[10px] font-black uppercase tracking-widest text-slate-400 flex items-center gap-2"><BookOpen className="w-4 h-4" /> Causes</h4>
                          <ul className="space-y-2">
                            {(Array.isArray(sidePathoData.causes) ? sidePathoData.causes : []).map((c, i) => (
                              <li key={i} className="flex items-center gap-3 text-[12px] text-slate-600 font-bold">
                                <div className="w-1.5 h-1.5 rounded-full bg-rose-500" />
                                {c}
                              </li>
                            ))}
                          </ul>
                       </div>
                       <div className="bg-rose-50/50 p-6 rounded-3xl border border-rose-100">
                          <h4 className="text-[10px] font-black uppercase tracking-widest text-rose-600 mb-2">Significance</h4>
                          <p className="text-[12px] leading-relaxed text-slate-800 font-bold italic">"{sidePathoData.clinicalSignificance}"</p>
                       </div>
                    </section>
                 </div>
               ) : (
                 <div className="text-center py-20 text-slate-300">
                   <Zap className="w-12 h-12 mx-auto mb-4 opacity-20" />
                   <p className="text-[10px] font-black uppercase tracking-widest">No Analysis Available</p>
                 </div>
               )}
            </div>
          </div>
        </>
      )}

      {/* --- COMMAND HEADER --- */}
      <div className="sticky top-0 z-40 bg-white/80 backdrop-blur-xl border-b border-slate-100 px-8 py-4 flex items-center justify-between">
        <div className="flex items-center gap-6">
          <button onClick={onBack} className="p-2 hover:bg-slate-50 rounded-xl text-slate-400 transition-colors">
            <ArrowLeft className="w-5 h-5" />
          </button>
          <div>
            <div className="flex items-center gap-2 mb-0.5">
              <span className={`text-[9px] font-black uppercase tracking-widest ${style.text}`}>{exam.system}</span>
              <span className="w-1 h-1 rounded-full bg-slate-200" />
              <span className="text-[9px] font-black uppercase tracking-widest text-slate-400">MedEx Core</span>
            </div>
            <h1 className="text-lg font-black text-slate-900 tracking-tight leading-none">{exam.name}</h1>
          </div>
        </div>

        <div className="flex items-center gap-3">
          <div className="flex items-center gap-2 mr-4 bg-slate-50 px-4 py-2 rounded-2xl border border-slate-100">
            <span className="text-[9px] font-black uppercase text-slate-400 tracking-widest">Progress</span>
            <div className="w-24 h-1.5 bg-slate-200 rounded-full overflow-hidden">
               <div className={`h-full ${style.secondary} transition-all duration-1000`} style={{ width: `${progress}%` }} />
            </div>
            <span className="text-[10px] font-black text-slate-900">{progress}%</span>
          </div>
          <button onClick={() => setIsChecklistMode(!isChecklistMode)} className={`px-6 py-2.5 rounded-2xl text-[10px] font-black uppercase flex items-center gap-2 shadow-xl transition-all hover:scale-105 ${isChecklistMode ? 'bg-emerald-600 text-white' : 'bg-slate-900 text-white'}`}>
            <ListCheck className="w-4 h-4" /> {isChecklistMode ? 'Exit OSCE' : 'Start OSCE'}
          </button>
        </div>
      </div>

      <div className="max-w-5xl mx-auto py-12 px-8">
        <div className="grid grid-cols-1 lg:grid-cols-5 gap-12 mb-16">
          <div className="lg:col-span-3">
             <div className="flex items-center gap-3 mb-6">
                <div className={`p-2 rounded-xl ${style.bg} ${style.text}`}>{style.icon}</div>
                <h2 className="text-3xl font-black text-slate-900 tracking-tighter leading-tight">{exam.name}</h2>
             </div>
             <p className="text-base text-slate-500 font-medium leading-[1.8] mb-8 max-w-xl">{exam.shortDescription}</p>
             <div className="flex flex-wrap gap-4">
               {exam.keywords.map(k => (
                 <span key={k} className="px-3 py-1.5 bg-slate-50 border border-slate-100 rounded-lg text-[10px] font-black uppercase text-slate-400 tracking-widest">#{k}</span>
               ))}
             </div>
          </div>

          <div className="lg:col-span-2">
            <div className={`relative rounded-[40px] overflow-hidden aspect-[4/3] border-2 ${style.border} shadow-2xl bg-slate-50`}>
              {exam.headerImageUrl ? (
                <img src={exam.headerImageUrl} className="w-full h-full object-cover" alt="Anatomical Reference" />
              ) : (
                <div className={`w-full h-full ${style.bg} flex items-center justify-center`}>
                  <div className="scale-[4] opacity-20">{style.icon}</div>
                </div>
              )}
            </div>
          </div>
        </div>

        <div className="flex justify-center mb-16">
          <div className="inline-flex p-1.5 bg-slate-100 rounded-[24px] border border-slate-200/50 shadow-inner">
            {[
              { id: 'steps', label: 'Steps', icon: <ClipboardList className="w-4 h-4" /> },
              { id: 'summary', label: 'Summary', icon: <Info className="w-4 h-4" /> },
              { id: 'correlation', label: 'Matrix', icon: <Zap className="w-4 h-4" /> },
              { id: 'media', label: 'Media', icon: <Play className="w-4 h-4" /> }
            ].map((tab) => (
              <button 
                key={tab.id}
                onClick={() => setActiveTab(tab.id as any)}
                className={`flex items-center gap-3 px-6 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all duration-300 ${activeTab === tab.id ? 'bg-white text-slate-900 shadow-xl' : 'text-slate-400 hover:text-slate-600'}`}
              >
                {tab.icon}
                {tab.label}
              </button>
            ))}
          </div>
        </div>

        <div className="animate-in fade-in slide-in-from-bottom-4 duration-700">
          {activeTab === 'steps' && (
            <div className="space-y-12">
              {Object.entries(categorizedSteps).map(([category, steps], catIdx) => (
                <div key={category} className="animate-in fade-in" style={{ animationDelay: `${catIdx * 100}ms` }}>
                  <div className="flex items-center gap-4 mb-8">
                    <div className={`h-6 w-1 rounded-full ${style.secondary}`} />
                    <h3 className="text-xl font-black text-slate-900 tracking-tight uppercase">{category}</h3>
                  </div>

                  <div className="grid grid-cols-1 gap-4">
                    {steps.map((step) => {
                      const isChecked = checkedSteps.has(step.id);
                      const isExpanded = expandedStep === step.id;
                      const hasFindings = step.positiveFindings && step.positiveFindings.length > 0;

                      return (
                        <div key={step.id} className={`group/step rounded-[32px] border-2 transition-all duration-500 overflow-hidden ${isChecked ? 'bg-emerald-50/20 border-emerald-200' : 'bg-white border-slate-50 shadow-sm hover:border-blue-100 hover:shadow-xl'}`}>
                          <div className="p-6 flex items-start gap-6">
                            {isChecklistMode ? (
                              <button onClick={() => setCheckedSteps(p => {
                                const n = new Set(p);
                                if (n.has(step.id)) n.delete(step.id);
                                else n.add(step.id);
                                return n;
                              })} className={`w-10 h-10 rounded-2xl border-2 flex items-center justify-center transition-all duration-500 shrink-0 ${isChecked ? 'bg-emerald-600 border-emerald-600 text-white scale-110' : 'bg-white border-slate-200 hover:border-emerald-400'}`}>
                                {isChecked && <CheckCircle2 className="w-5 h-5" />}
                              </button>
                            ) : (
                              <div className={`w-3 h-3 rounded-full mt-4 shrink-0 ${style.secondary} opacity-40`} />
                            )}

                            <div className="flex-1">
                               <div className="flex items-center justify-between mb-2">
                                  <div className="flex items-center gap-3">
                                    <h4 className={`text-lg font-black tracking-tight ${isChecked ? 'text-emerald-700' : 'text-slate-900'}`}>{step.title}</h4>
                                    {hasFindings && (
                                       <span className="px-2 py-0.5 bg-amber-50 text-amber-600 border border-amber-100 rounded-md text-[7px] font-black uppercase tracking-widest animate-pulse flex items-center gap-1">
                                         <Activity className="w-2.5 h-2.5" /> High Yield
                                       </span>
                                    )}
                                  </div>
                                  <div className="flex items-center gap-2">
                                     <Tooltip content="Pathophysiology Slide-Over">
                                       <button onClick={() => fetchSidePathophysiology(step.title)} className="p-3 hover:bg-slate-50 rounded-xl text-slate-300 hover:text-rose-600 transition-all border border-transparent hover:border-slate-100">
                                         <Zap className="w-5 h-5" />
                                       </button>
                                     </Tooltip>
                                     <button onClick={() => setExpandedStep(isExpanded ? null : step.id)} className={`p-3 rounded-xl text-slate-300 transition-all ${isExpanded ? 'rotate-180 text-blue-500 bg-slate-50' : 'hover:bg-slate-50'}`}>
                                       <ChevronDown className="w-5 h-5" />
                                     </button>
                                  </div>
                               </div>
                               <p className={`text-[13px] leading-relaxed font-medium mb-2 ${isChecked ? 'text-emerald-600/70' : 'text-slate-500'}`}>{step.description}</p>

                               {isExpanded && (
                                 <div className="mt-6 pt-6 border-t border-slate-100 animate-in slide-in-from-top-2 duration-500">
                                   <div className="flex items-center gap-3 mb-6">
                                      <div className="p-2 bg-amber-50 rounded-lg"><Lightbulb className="w-4 h-4 text-amber-600" /></div>
                                      <div>
                                        <span className="text-[10px] font-black uppercase tracking-widest text-slate-800">Clinical Stigmata Matrix</span>
                                        <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest">Tap finding for pathophysiology</p>
                                      </div>
                                   </div>

                                   <div className="flex flex-wrap gap-3">
                                      {/* Defensive check for positiveFindings as an array to fix "Property 'map' does not exist on type 'unknown'" */}
                                      {(Array.isArray(step.positiveFindings) ? step.positiveFindings : []).map((f, i) => (
                                         <button key={i} onClick={() => fetchSidePathophysiology(f.description.length > 30 ? step.title : f.description)} className="group/stigmata flex items-center gap-4 p-4 bg-slate-50 hover:bg-white hover:shadow-2xl hover:border-rose-300 border border-slate-100 rounded-2xl transition-all duration-300 text-left max-w-sm relative overflow-hidden">
                                            <div className="absolute top-0 right-0 p-2 opacity-0 group-hover/stigmata:opacity-100 transition-opacity"><Zap className="w-3 h-3 text-rose-500 animate-pulse" /></div>
                                            <div className="w-2 h-8 rounded-full bg-slate-200 group-hover/stigmata:bg-rose-500 transition-colors" />
                                            <p className="text-[12px] text-slate-700 font-black italic group-hover/stigmata:text-slate-900 transition-colors">"{f.description}"</p>
                                         </button>
                                      ))}
                                   </div>
                                 </div>
                               )}
                            </div>
                          </div>
                        </div>
                      );
                    })}
                  </div>
                </div>
              ))}
            </div>
          )}

          {activeTab === 'correlation' && (
             <div className="max-w-4xl mx-auto py-10 space-y-12">
                <div className="text-center mb-16">
                  <div className="inline-block p-4 bg-rose-50 rounded-3xl mb-6 shadow-xl shadow-rose-100"><Zap className="w-8 h-8 text-rose-600" /></div>
                  <h2 className="text-4xl font-black text-slate-900 tracking-tighter mb-4">Functional Matrix</h2>
                  <p className="text-sm text-slate-400 font-black uppercase tracking-[0.3em]">Fellowship Synthesis Suite</p>
                </div>

                {sidePathoData ? (
                  <div className="bg-white p-12 rounded-[50px] border-2 border-slate-100 shadow-2xl relative overflow-hidden">
                     <div className="absolute top-0 right-0 p-12 opacity-5 pointer-events-none rotate-12"><Zap className="w-48 h-48" /></div>
                     <div className="flex items-center gap-6 mb-10">
                        <div className="w-16 h-16 bg-rose-600 text-white rounded-3xl flex items-center justify-center shadow-2xl shadow-rose-200"><Zap className="w-8 h-8" /></div>
                        <div>
                          <h3 className="text-3xl font-black text-slate-900 uppercase tracking-tight">{sidePathoData.sign}</h3>
                          <span className="text-[10px] font-black uppercase tracking-widest text-rose-600">Full Diagnostic Record</span>
                        </div>
                     </div>

                     <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
                        <div className="space-y-8">
                           <MedImage src={sidePathoData.imageUrl} alt={sidePathoData.sign} label="Primary Analysis" fallbackIcon={<Activity />} />
                           <div>
                             <h4 className="text-[10px] font-black uppercase tracking-widest text-slate-400 mb-4">Mechanism</h4>
                             <p className="text-sm leading-[1.8] text-slate-700 font-medium italic">{sidePathoData.pathophysiology}</p>
                           </div>
                        </div>
                        <div className="bg-slate-50 p-8 rounded-[40px] border border-slate-100 h-fit">
                           <h4 className="text-[10px] font-black uppercase tracking-widest text-slate-400 mb-4">Clinical Significance</h4>
                           <p className="text-sm font-black text-slate-900 leading-relaxed mb-6">"{sidePathoData.clinicalSignificance}"</p>
                           <div className="flex flex-wrap gap-2">
                             {(Array.isArray(sidePathoData.causes) ? sidePathoData.causes : []).slice(0, 3).map((c, i) => (
                               <span key={i} className="px-3 py-1 bg-white border border-slate-200 rounded-lg text-[8px] font-black uppercase text-slate-400 tracking-widest">{c}</span>
                             ))}
                           </div>
                        </div>
                     </div>
                  </div>
                ) : (
                  <div className="p-24 text-center border-4 border-dashed border-slate-100 rounded-[50px] bg-slate-50/50">
                    <Sparkles className="w-12 h-12 text-slate-200 mx-auto mb-6 animate-pulse" />
                    <p className="text-[11px] font-black uppercase text-slate-300 tracking-[0.2em]">Select clinical sign to begin synthesis</p>
                  </div>
                )}
             </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default ExamView;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Examination, ClinicalCorrelation, ExamStep } from '../types';
import { GeminiService } from '../services/geminiService';
import { SYSTEM_THEMES, DEFAULT_STYLE } from '../theme';
import Tooltip from './Tooltip';
import DifferentialPanel from './DifferentialPanel';
import { 
  ClipboardList, Info, Zap, 
  CheckCircle2, ChevronDown, Lightbulb, Sparkles, ListCheck, BrainCircuit, X, BookOpen, Activity, Waves, HeartPulse, Layers, ArrowLeft, ChevronRight, Stethoscope
} from 'lucide-react';

interface ExamViewProps {
  exam: Examination;
  onBack: () => void;
}

const MedImage: React.FC<{ src?: string; alt: string; fallbackIcon: React.ReactNode; label: string }> = ({ src, alt, fallbackIcon, label }) => {
  const [error, setError] = useState(false);

  if (!src || error) {
    return (
      <div className="w-full aspect-video bg-slate-50 border-2 border-dashed border-slate-200 rounded-3xl flex flex-col items-center justify-center p-8 text-slate-300">
        <div className="mb-3 opacity-30 scale-150">{fallbackIcon}</div>
        <p className="text-[9px] font-black uppercase tracking-widest text-slate-400">{label} Unavailable</p>
      </div>
    );
  }

  return (
    <div className="relative group/viz rounded-3xl overflow-hidden border border-slate-200 shadow-inner bg-slate-50">
      <img 
        src={src} 
        alt={alt} 
        className="w-full h-auto object-cover transition-transform duration-1000 group-hover/viz:scale-[1.05]" 
        onError={() => setError(true)}
      />
      <div className="absolute bottom-3 left-3 right-3 flex items-center justify-between px-3 py-1.5 bg-black/40 backdrop-blur-md rounded-xl">
        <span className="text-[8px] font-black text-white uppercase tracking-widest">{label}</span>
        <Sparkles className="w-2.5 h-2.5 text-amber-400" />
