                   <div className="relative">
                      <div className="w-16 h-16 border-4 border-rose-50 rounded-full"></div>
                      <div className="w-16 h-16 border-4 border-rose-600 border-t-transparent rounded-full animate-spin absolute top-0"></div>
                   </div>
                   <p className="text-[10px] font-black uppercase text-slate-400 tracking-[0.2em]">Synthesizing Diagnostics...</p>
                 </div>
