const ExamView: React.FC<ExamViewProps> = ({ exam: initialExam, onBack }) => {
  const [exam, setExam] = useState(initialExam);
  const [activeTab, setActiveTab] = useState<'steps' | 'summary' | 'correlation' | 'media' | 'audio'>('steps');
  const [summary, setSummary] = useState<string | null>(null);
  const [loadingSummary, setLoadingSummary] = useState(false);
  const [isResearching, setIsResearching] = useState(false);

  const [sidePathoSign, setSidePathoSign] = useState<string | null>(null);
  const [sidePathoData, setSidePathoData] = useState<ClinicalCorrelation | null>(null);
  const [loadingSidePatho, setLoadingSidePatho] = useState(false);

  const [isOnline] = useState(navigator.onLine);
  const [checkedSteps, setCheckedSteps] = useState<Set<string>>(new Set());
  const [isChecklistMode, setIsChecklistMode] = useState(false);
  const [showDifferentialPanel, setShowDifferentialPanel] = useState(false);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  const gemini = new GeminiService();
  const style = SYSTEM_THEMES[exam.system] || DEFAULT_STYLE;

  const categorizedSteps = useMemo(() => {
    const groups: Record<string, ExamStep[]> = {};
    exam.steps.forEach(step => {
      const cat = step.category || 'General';
      if (!groups[cat]) groups[cat] = [];
      groups[cat].push(step);
    });
    return groups;
  }, [exam.steps]);

  useEffect(() => {
    const research = async () => {
      if (exam.steps.length === 0 && isOnline) {
        setIsResearching(true);
        try {
          const res = await gemini.populateExamination(exam);
          setExam(prev => ({ ...prev, ...res, isDraft: false }));
        } catch (e) { console.error(e); }
        finally { setIsResearching(false); }
      }
    };
    research();
  }, [exam.id, isOnline]);

  useEffect(() => {
    if (activeTab === 'summary' && !summary && isOnline) {
      setLoadingSummary(true);
      gemini.getExaminationSummary(exam.name).then(s => {
        setSummary(s);
        setLoadingSummary(false);
      });
    }
  }, [activeTab]);

  const fetchSidePathophysiology = async (sign: string) => {
    if (!isOnline) return;
    setSidePathoSign(sign);
    setLoadingSidePatho(true);
    setSidePathoData(null);
    try {
      const data = await gemini.getClinicalCorrelation(sign, exam.system, true);
      setSidePathoData(data);
    } catch (e) { console.error(e); }
    finally { setLoadingSidePatho(false); }
  };

  const selectedFindingTitles = useMemo(() => {
    return Array.from(checkedSteps)
      .map(id => exam.steps.find(s => s.id === id)?.title || '')
      .filter(t => t !== '');
  }, [checkedSteps, exam.steps]);

  const progress = exam.steps.length > 0 ? Math.round((checkedSteps.size / exam.steps.length) * 100) : 0;

  if (isResearching) return (
    <div className="h-full flex flex-col items-center justify-center p-20 bg-white">
      <div className="relative mb-8">
        <div className="w-20 h-20 border-4 border-blue-50 rounded-full"></div>
        <div className="w-20 h-20 border-4 border-blue-600 border-t-transparent rounded-full animate-spin absolute top-0"></div>
        <BrainCircuit className="w-8 h-8 text-blue-600 absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2" />
      </div>
      <p className="text-[10px] font-black uppercase text-slate-400 tracking-[0.3em] mb-2">Synthesizing Protocol</p>
    </div>
  );

  return (
    <div className="min-h-full bg-white animate-in fade-in duration-700 relative">
      <audio ref={audioRef} />

      {showDifferentialPanel && isChecklistMode && (
        <DifferentialPanel 
          findings={selectedFindingTitles}
          system={exam.system}
          onClose={() => setShowDifferentialPanel(false)}
          isOnline={isOnline}
        />
      )}

      {/* --- PATHOPHYSIOLOGY SIDE-OVER --- */}
      {sidePathoSign && (
        <>
          <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-[60] animate-in fade-in duration-500" onClick={() => setSidePathoSign(null)} />
          <div className="fixed top-0 right-0 bottom-0 w-full max-w-xl bg-white shadow-[-20px_0_60px_rgba(0,0,0,0.1)] z-[70] animate-in slide-in-from-right duration-500 flex flex-col">
            <header className="p-8 border-b border-slate-100 flex items-center justify-between bg-slate-50/50 sticky top-0 backdrop-blur-md">
               <div className="flex items-center gap-4">
                  <div className="w-12 h-12 bg-rose-600 text-white rounded-2xl flex items-center justify-center shadow-lg shadow-rose-200">
                    <Zap className="w-6 h-6" />
                  </div>
                  <div>
                    <h3 className="text-xl font-black text-slate-900 uppercase tracking-tight">{sidePathoSign}</h3>
                    <p className="text-[10px] font-black text-rose-600 uppercase tracking-widest">Clinical Mechanism</p>
                  </div>
               </div>
               <button onClick={() => setSidePathoSign(null)} className="p-3 hover:bg-slate-100 rounded-2xl text-slate-400 transition-all">
                 <X className="w-5 h-5" />
