                           <div className="flex flex-wrap gap-2">
                             {(Array.isArray(sidePathoData.causes) ? sidePathoData.causes : []).slice(0, 3).map((c, i) => (
                               <span key={i} className="px-3 py-1 bg-white border border-slate-200 rounded-lg text-[8px] font-black uppercase text-slate-400 tracking-widest">{c}</span>
                             ))}
                           </div>
                        </div>
                     </div>
                  </div>
                ) : (
                  <div className="p-24 text-center border-4 border-dashed border-slate-100 rounded-[50px] bg-slate-50/50">
                    <Sparkles className="w-12 h-12 text-slate-200 mx-auto mb-6 animate-pulse" />
                    <p className="text-[11px] font-black uppercase text-slate-300 tracking-[0.2em]">Select clinical sign to begin synthesis</p>
                  </div>
                )}
             </div>
          )}
        </div>
      </div>
    </div>
  );
};

