        {[
          { label: 'Aortic', color: 'bg-red-500' },
          { label: 'Pulm', color: 'bg-blue-500' },
          { label: 'Tricus', color: 'bg-emerald-500' },
          { label: 'Mitral', color: 'bg-amber-500' }
