        </div>

        <div className="animate-in fade-in slide-in-from-bottom-4 duration-700">
          {activeTab === 'steps' && (
            <div className="space-y-12">
              {/* Fixing TypeScript unknown error by explicitly casting entries */}
              {(Object.entries(categorizedSteps) as [string, ExamStep[]][]).map(([category, steps], catIdx) => {
                const isCvsAuscultation = exam.system === 'Cardiovascular' && (category.toLowerCase().includes('auscultation') || category.toLowerCase().includes('precordium'));

                return (
                  <div key={category} className="animate-in fade-in" style={{ animationDelay: `${catIdx * 100}ms` }}>
                    <div className="flex items-center gap-4 mb-8">
                      <div className={`h-6 w-1 rounded-full ${style.secondary}`} />
                      <h3 className="text-xl font-black text-slate-900 tracking-tight uppercase">{category}</h3>
                    </div>

                    <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">
                      <div className={`${isCvsAuscultation ? 'lg:col-span-7' : 'lg:col-span-12'} space-y-4`}>
                        <div className="bg-white rounded-[40px] border border-slate-100 shadow-sm overflow-hidden">
                          <ul className="divide-y divide-slate-50">
                            {steps.map((step) => {
                              const isChecked = checkedSteps.has(step.id);
                              const hasFindings = Array.isArray(step.positiveFindings) && step.positiveFindings.length > 0;
                              const hasNegativeFindings = Array.isArray(step.negativeFindings) && step.negativeFindings.length > 0;

                              return (
                                <li key={step.id} className={`p-6 transition-all duration-500 flex items-start gap-6 ${isChecked ? 'bg-emerald-50/30' : 'hover:bg-slate-50/50'}`}>
                                  {isChecklistMode ? (
                                    <button 
                                      onClick={() => setCheckedSteps(p => {
                                        const n = new Set(p);
                                        if (n.has(step.id)) n.delete(step.id);
                                        else n.add(step.id);
                                        return n;
                                      })} 
                                      className={`w-10 h-10 rounded-2xl border-2 flex items-center justify-center transition-all duration-500 shrink-0 ${isChecked ? 'bg-emerald-600 border-emerald-600 text-white shadow-lg' : 'bg-white border-slate-200'}`}
                                    >
                                      {isChecked && <CheckCircle2 className="w-5 h-5" />}
                                    </button>
                                  ) : (
                                    <div className={`w-2 h-2 rounded-full mt-3 shrink-0 ${style.secondary} opacity-40`} />
                                  )}

                                  <div className="flex-1">
                                    <div className="flex items-center gap-3 mb-1">
                                      <h4 className={`text-sm font-black tracking-tight ${isChecked ? 'text-emerald-700' : 'text-slate-900'}`}>{step.title}</h4>
                                      {hasFindings && (
                                        <div className="flex items-center gap-1.5 px-2 py-0.5 bg-amber-50 text-amber-600 border border-amber-100 rounded-lg text-[7px] font-black uppercase tracking-widest animate-pulse">
                                          <Sparkles className="w-2.5 h-2.5" /> High Yield
                                        </div>
                                      )}
