                            {steps.map((step) => {
                              const isChecked = checkedSteps.has(step.id);
                              const hasFindings = Array.isArray(step.positiveFindings) && step.positiveFindings.length > 0;
                              const hasNegativeFindings = Array.isArray(step.negativeFindings) && step.negativeFindings.length > 0;

                              return (
                                <li key={step.id} className={`p-6 transition-all duration-500 flex items-start gap-6 ${isChecked ? 'bg-emerald-50/30' : 'hover:bg-slate-50/50'}`}>
                                  {isChecklistMode ? (
                                    <button 
                                      onClick={() => setCheckedSteps(p => {
                                        const n = new Set(p);
                                        if (n.has(step.id)) n.delete(step.id);
                                        else n.add(step.id);
                                        return n;
                                      })} 
                                      className={`w-10 h-10 rounded-2xl border-2 flex items-center justify-center transition-all duration-500 shrink-0 ${isChecked ? 'bg-emerald-600 border-emerald-600 text-white shadow-lg' : 'bg-white border-slate-200'}`}
                                    >
                                      {isChecked && <CheckCircle2 className="w-5 h-5" />}
                                    </button>
                                  ) : (
                                    <div className={`w-2 h-2 rounded-full mt-3 shrink-0 ${style.secondary} opacity-40`} />
                                  )}

                                  <div className="flex-1">
                                    <div className="flex items-center gap-3 mb-1">
                                      <h4 className={`text-sm font-black tracking-tight ${isChecked ? 'text-emerald-700' : 'text-slate-900'}`}>{step.title}</h4>
                                      {hasFindings && (
                                        <div className="flex items-center gap-1.5 px-2 py-0.5 bg-amber-50 text-amber-600 border border-amber-100 rounded-lg text-[7px] font-black uppercase tracking-widest animate-pulse">
                                          <Sparkles className="w-2.5 h-2.5" /> High Yield
                                        </div>
                                      )}
                                    </div>
                                    <p className={`text-[12px] leading-relaxed font-medium ${isChecked ? 'text-emerald-600/70' : 'text-slate-500'}`}>{step.description}</p>

                                    <div className="mt-4 flex flex-col gap-3">
                                      {/* Pathological Findings Section */}
                                      {hasFindings && (
                                        <div className="space-y-2">
                                          <div className="flex items-center gap-2 mb-1">
                                            <Zap className="w-2.5 h-2.5 text-rose-500" />
                                            <span className="text-[8px] font-black uppercase tracking-[0.1em] text-slate-400">Pathological Signs</span>
                                          </div>
                                          <div className="flex flex-wrap gap-2">
                                            {(step.positiveFindings as any[])?.map((f, i) => (
                                              <button 
                                                key={i} 
                                                onClick={() => fetchSidePathophysiology(f.description.length > 30 ? step.title : f.description)} 
                                                className="group/sign flex items-center gap-3 px-4 py-2 bg-slate-100/50 hover:bg-rose-600 border border-slate-200 hover:border-rose-600 rounded-xl transition-all duration-300 text-left"
                                              >
                                                <Zap className="w-3 h-3 text-rose-500 group-hover/sign:text-white" />
                                                <span className="text-[10px] font-black text-slate-700 group-hover/sign:text-white uppercase tracking-widest italic leading-none">{f.description}</span>
                                              </button>
                                            ))}
                                          </div>
                                        </div>
                                      )}

                                      {/* Expected Normals Section */}
                                      {hasNegativeFindings && (
                                        <div className="space-y-2">
                                          <div className="flex items-center gap-2 mb-1">
                                            <ShieldCheck className="w-2.5 h-2.5 text-emerald-500" />
                                            <span className="text-[8px] font-black uppercase tracking-[0.1em] text-slate-400">Expected Normal Findings</span>
                                          </div>
                                          <div className="flex flex-wrap gap-2">
                                            {step.negativeFindings?.map((nf, i) => (
                                              <div 
                                                key={i} 
                                                className="flex items-center gap-2 px-3 py-1.5 bg-emerald-50/50 border border-emerald-100 rounded-xl"
                                              >
                                                <CircleCheck className="w-3 h-3 text-emerald-500" />
                                                <span className="text-[9px] font-bold text-emerald-700 uppercase tracking-tight italic leading-none">{nf}</span>
                                              </div>
                                            ))}
                                          </div>
                                        </div>
                                      )}
                                    </div>
                                  </div>
                                </li>
                              );
                            })}
                          </ul>
                        </div>
                      </div>

                      {isCvsAuscultation && (
                        <div className="lg:col-span-5 sticky top-32">
                          <AuscultationDiagram />
                          <div className="mt-8 bg-blue-50 p-6 rounded-3xl border border-blue-100">
                             <div className="flex items-center gap-3 mb-2">
                               <Stethoscope className="w-4 h-4 text-blue-600" />
