                             <p className="text-[11px] font-bold text-blue-700 leading-relaxed italic">
                               "Listen at each site with both bell and diaphragm. Maneuvers like leaning forward (AR) or rolling left (MR/MS) are essential for diagnostic synthesis."
                             </p>
                          </div>
                        </div>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          )}

          {activeTab === 'summary' && (
            <div className="max-w-3xl mx-auto py-10">
