                       </h4>
                       <p className="text-base leading-[2] text-slate-700 font-medium italic">
                         {sidePathoData.pathophysiology}
                       </p>
                    </section>

                    <section className="bg-rose-600 p-10 rounded-[48px] text-white shadow-2xl relative overflow-hidden">
                       <Zap className="absolute -right-8 -bottom-8 w-40 h-40 opacity-10 rotate-12" />
                       <h4 className="text-[11px] font-black uppercase tracking-[0.2em] mb-4 text-rose-200">Clinical Pearl</h4>
                       <p className="text-xl font-black leading-tight italic">
                         "{sidePathoData.clinicalSignificance}"
                       </p>
                    </section>
                 </div>
               ) : (
                 <div className="text-center py-20 text-slate-300">
                   <Zap className="w-12 h-12 mx-auto mb-4 opacity-20" />
                   <p className="text-[10px] font-black uppercase tracking-widest">Correlation Synthesis Failed</p>
                 </div>
               )}
            </div>
          </div>
        </div>
      )}

      {/* --- HEADER --- */}
      <div className="sticky top-0 z-40 bg-white/80 backdrop-blur-xl border-b border-slate-100 px-8 py-4 flex items-center justify-between">
        <div className="flex items-center gap-6">
          <button onClick={onBack} className="p-2 hover:bg-slate-50 rounded-xl text-slate-400 transition-colors">
            <ArrowLeft className="w-5 h-5" />
          </button>
          <div>
            <div className="flex items-center gap-2 mb-0.5">
              <span className={`text-[9px] font-black uppercase tracking-widest ${style.text}`}>{exam.system}</span>
