                <div className="bg-white rounded-[40px] border border-slate-100 shadow-sm overflow-hidden divide-y divide-slate-50">
                  {steps.map((step) => {
                    const isChecked = checkedSteps.has(step.id);
                    return (
                      <div key={step.id} className={`p-8 transition-all flex items-start gap-8 ${isChecked ? 'bg-emerald-50/30' : ''}`}>
                        {isChecklistMode ? (
                          <button 
                            onClick={() => setCheckedSteps(p => { const n = new Set(p); if (n.has(step.id)) n.delete(step.id); else n.add(step.id); return n; })}
                            className={`w-12 h-12 rounded-2xl border-2 flex items-center justify-center shrink-0 ${isChecked ? 'bg-emerald-600 border-emerald-600 text-white shadow-lg' : 'bg-white border-slate-200'}`}
                          >
                            {isChecked && <CheckCircle2 className="w-6 h-6" />}
                          </button>
                        ) : <div className={`w-3 h-3 rounded-full mt-4 shrink-0 ${style.secondary} opacity-40`} />}

                        <div className="flex-1">
                          <h4 className="text-base font-black text-slate-900 mb-2">{step.title}</h4>
                          <p className="text-[13px] leading-relaxed text-slate-500 font-medium mb-6">{step.description}</p>

                          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                            {step.positiveFindings && step.positiveFindings.length > 0 && (
                              <div className="space-y-4">
                                <div className="flex items-center gap-2 text-rose-500">
                                  <Zap className="w-3.5 h-3.5" />
                                  <span className="text-[9px] font-black uppercase tracking-widest">Pathological Signs</span>
                                </div>
                                <div className="flex flex-wrap gap-2">
                                  {step.positiveFindings.map((f, i) => (
                                    <button 
                                      key={i} 
                                      onClick={() => fetchClinicalCorrelation(f.description)}
                                      className="group/sign flex items-center gap-3 px-4 py-2.5 bg-rose-50 border border-rose-100 rounded-2xl hover:bg-rose-600 hover:text-white transition-all text-left"
                                    >
                                      <Zap className="w-3 h-3 group-hover/sign:text-white" />
                                      <span className="text-[10px] font-black uppercase italic leading-none">{f.description}</span>
                                    </button>
                                  ))}
                                </div>
                              </div>
                            )}

                            {step.negativeFindings && step.negativeFindings.length > 0 && (
                              <div className="space-y-4">
                                <div className="flex items-center gap-2 text-emerald-500">
                                  <ShieldCheck className="w-3.5 h-3.5" />
                                  <span className="text-[9px] font-black uppercase tracking-widest">Normal Findings</span>
                                </div>
                                <div className="flex flex-wrap gap-2">
                                  {step.negativeFindings.map((nf, i) => (
                                    <div key={i} className="flex items-center gap-3 px-4 py-2.5 bg-emerald-50 border border-emerald-100 rounded-2xl">
                                      <CircleCheck className="w-3 h-3 text-emerald-500" />
                                      <span className="text-[10px] font-bold text-emerald-700 uppercase leading-none italic">{nf}</span>
                                    </div>
                                  ))}
                                </div>
                              </div>
                            )}
                          </div>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            ))}
          </div>
        )}

        {activeTab === 'summary' && (
          <div className="max-w-3xl mx-auto py-10">
            <div className="bg-white p-12 rounded-[50px] border-2 border-slate-100 shadow-xl">
               <div className="flex items-center gap-4 mb-10">
                  <div className={`p-4 rounded-3xl ${style.bg} ${style.text}`}><Info className="w-8 h-8" /></div>
                  <h3 className="text-2xl font-black text-slate-900 uppercase">Protocol Review</h3>
               </div>
               {loadingSummary ? <Loader2 className="w-8 h-8 animate-spin mx-auto text-slate-300" /> : <p className="text-sm leading-[2] text-slate-600 whitespace-pre-wrap italic">{summary}</p>}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

