const App: React.FC = () => {
  const [searchQuery, setSearchQuery] = useState('');
  const [currentView, setCurrentView] = useState<'library' | 'downloads' | 'finder' | 'correlation' | 'vault'>('library');

  const { downloadedIds, syncingIds, startDownload } = useDownloadStatus();

  const { 
    selectedSystem, setSelectedSystem, selectedExam, setSelectedExam, 
    displayGroups, expandedSystems, toggleSystemExpansion, handleSelectExam,
    downloadedExams
  } = useExaminations(searchQuery, null, downloadedIds);

  const handleSystemSelect = (system: ExamSystem | null) => {
    setSelectedSystem(system);
    setCurrentView('library');
    setSelectedExam(null);
  };

  return (
    <div className="flex h-screen bg-[#FDFDFF] selection:bg-blue-100 overflow-hidden">
      <Sidebar 
        selectedSystem={selectedSystem} 
        onSelectSystem={handleSystemSelect} 
        searchQuery={searchQuery}
        onSearch={setSearchQuery}
        onViewDownloads={() => setCurrentView('downloads')}
        onViewFinder={() => setCurrentView('finder')}
        onViewCorrelation={() => setCurrentView('correlation')}
        onViewVault={() => { setCurrentView('vault'); setSelectedSystem(null); setSelectedExam(null); }}
        currentView={currentView}
      />

      <main className="flex-1 overflow-y-auto custom-scrollbar relative bg-white/50">
        <div className="absolute top-0 right-0 w-[500px] h-[500px] bg-blue-500/5 blur-[120px] rounded-full pointer-events-none -z-10"></div>

        {selectedExam ? (
          <ExamView exam={selectedExam} onBack={() => setSelectedExam(null)} />
        ) : currentView === 'downloads' ? (
          <DownloadManager />
        ) : currentView === 'finder' ? (
          <ClinicalFinder />
        ) : currentView === 'correlation' ? (
          <ClinicalCorrelationView />
        ) : currentView === 'vault' ? (
          <KnowledgeVault 
            onSelectExam={handleSelectExam} 
            onSyncExam={startDownload} 
            syncingIds={syncingIds} 
          />
        ) : (
          <LibraryView 
            displayGroups={displayGroups}
            expandedSystems={expandedSystems}
            toggleSystemExpansion={toggleSystemExpansion}
            onSelectExam={handleSelectExam}
            onSyncExam={startDownload}
            downloadedIds={downloadedIds}
            syncingIds={syncingIds}
            downloadedExams={downloadedExams}
            isSearching={!!searchQuery}
          />
        )}
      </main>
    </div>
  );
};

