export type DownloadTaskStatus = 'pending' | 'downloading' | 'paused' | 'completed' | 'failed' | 'cancelled';
export type DownloadTaskType = 'protocol' | 'media' | 'audio' | 'deep_sync';

export interface DownloadTask {
  id: string;
  examId: string;
  examName: string;
  type: DownloadTaskType;
  status: DownloadTaskStatus;
  progress: number;
  error?: string;
  retryCount: number;
  createdAt: number;
}

import { DownloadTask, DownloadTaskStatus, Examination, ExamStep } from '../types';
import { GeminiService } from './geminiService';
import { storage } from './storageService';
import { EXAMINATIONS } from '../constants';

export class DownloadManagerService {
  private tasks: DownloadTask[] = [];
  private isPaused: boolean = false;
  private maxConcurrency: number = 1;
  private activeCount: number = 0;
  private listeners: Set<(tasks: DownloadTask[]) => void> = new Set();
  private gemini = new GeminiService();

  constructor() {
    const saved = localStorage.getItem('medex_download_queue');
    if (saved) {
      this.tasks = JSON.parse(saved).map((t: any) => ({
        ...t,
        status: (t.status === 'downloading' || t.status === 'pending') ? 'pending' : t.status
      }));
    }
    this.processQueue();
  }

  private notify() {
    localStorage.setItem('medex_download_queue', JSON.stringify(this.tasks));
    this.listeners.forEach(l => l([...this.tasks]));
  }

  subscribe(listener: (tasks: DownloadTask[]) => void) {
    this.listeners.add(listener);
    listener([...this.tasks]);
    return () => this.listeners.delete(listener);
  }

  async downloadAll() {
    const allDownloaded = await storage.getAllDownloaded();
    const downloadedIds = new Set(allDownloaded.map(e => e.id));

    const toDownload = EXAMINATIONS.filter(exam => 
      !downloadedIds.has(exam.id) && 
      !this.tasks.find(t => t.examId === exam.id && t.status !== 'failed')
    );

    toDownload.forEach(exam => {
      this.addTask(exam.id);
    });
  }

  async clearArchive() {
    if (!confirm("Are you sure you want to purge the Knowledge Vault? This will delete all persistent offline files.")) return;
    await storage.clearArchive();
    this.tasks = [];
    this.notify();
    window.location.reload();
  }

  addTask(examId: string, type: DownloadTask['type'] = 'deep_sync') {
    const exam = EXAMINATIONS.find(e => e.id === examId);
    if (!exam) return;

    const existing = this.tasks.find(t => t.examId === examId && t.status !== 'completed');
    if (existing) return;

    const newTask: DownloadTask = {
      id: Math.random().toString(36).substr(2, 9),
      examId,
      examName: exam.name,
      type,
      status: 'pending',
      progress: 0,
      retryCount: 0,
      createdAt: Date.now()
    };

    this.tasks = [...this.tasks, newTask];
    this.notify();
    this.processQueue();
  }

  private async processQueue() {
    if (this.isPaused || this.activeCount >= this.maxConcurrency) return;

    const nextTask = this.tasks.find(t => t.status === 'pending');
    if (!nextTask) return;

    this.activeCount++;
    await this.runTask(nextTask);
    this.activeCount--;
    this.processQueue();
  }

  private async fetchAndStoreAsset(url: string, prefix: string): Promise<string | undefined> {
    try {
      const response = await fetch(url);
      if (!response.ok) throw new Error(`HTTP ${response.status}`);
      const blob = await response.blob();
      const assetId = `${prefix}_${Math.random().toString(36).substr(2, 5)}`;
      await storage.saveAsset(assetId, blob);
      return assetId; // Return the ID in the asset store
    } catch (e) {
      console.warn(`Asset fetch/store failed: ${url}`, e);
      return undefined;
    }
  }

  private async runTask(task: DownloadTask) {
    task.status = 'downloading';
    task.progress = 5;
    this.notify();

    try {
      const baseExam = EXAMINATIONS.find(e => e.id === task.examId);
      if (!baseExam) throw new Error('Exam definition not found');

      // STAGE 1: PROTOCOL SYNTHESIS
      task.progress = 15;
      task.error = "Synthesizing Protocol Structure...";
      this.notify();
      const populated = await this.gemini.populateExamination(baseExam);

      // STAGE 2: ASSET SERIALIZATION (TO DISK FOLDERS)
      task.progress = 40;
      task.error = "Archiving Visual Stigmata to Vault...";
      this.notify();

      // Store header image
      let headerAssetId: string | undefined;
      if (populated.headerImageUrl) {
        headerAssetId = await this.fetchAndStoreAsset(populated.headerImageUrl, `header_${task.examId}`);
      }

      // Store step images
      const processedSteps: ExamStep[] = await Promise.all((populated.steps || []).map(async (step, idx) => {
        const stepProgress = 40 + Math.floor((idx / (populated.steps?.length || 1)) * 50);
        if (task.progress < stepProgress) {
          task.progress = stepProgress;
          this.notify();
        }

        const processedStep = { ...step };
        if (step.imageUrl) {
          processedStep.localImageUrl = await this.fetchAndStoreAsset(step.imageUrl, `step_${step.id}`);
        }

        // Handle positive finding images if present
        if (step.positiveFindings) {
          processedStep.positiveFindings = await Promise.all(step.positiveFindings.map(async (pf, pfIdx) => {
            if (pf.imageUrl) {
              const pfAssetId = await this.fetchAndStoreAsset(pf.imageUrl, `finding_${step.id}_${pfIdx}`);
              return { ...pf, localImageUrl: pfAssetId };
            }
            return pf;
          }));
        }
        return processedStep;
      }));

      // FINALIZATION: SAVE METADATA TO IDB
      // Fix: Separate headerImageUrl (remote) and localHeaderImageUrl (storage ID)
      const finalExam: Examination = {
        ...baseExam,
        ...populated,
        steps: processedSteps,
        headerImageUrl: populated.headerImageUrl, 
        localHeaderImageUrl: headerAssetId,
        isDownloaded: true,
        isDraft: false
      };

      await storage.saveExamination(finalExam);

      task.status = 'completed';
      task.progress = 100;
      task.error = undefined;
    } catch (err: any) {
      console.error('Download pipeline failure', err);
      task.status = 'failed';
      task.error = err?.message || 'Download Failed';
    } finally {
      this.notify();
    }
  }

  togglePause() { this.isPaused = !this.isPaused; if (!this.isPaused) this.processQueue(); this.notify(); }
  cancelTask(taskId: string) { this.tasks = this.tasks.filter(t => t.id !== taskId); this.notify(); this.processQueue(); }
  getTasks() { return [...this.tasks]; }
  getPauseState() { return this.isPaused; }
}

