}

const KnowledgeVault: React.FC<KnowledgeVaultProps> = ({ onSelectExam, onSyncExam, syncingIds }) => {
  const [downloadedExams, setDownloadedExams] = useState<Examination[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const load = async () => {
      const all = await storage.getAllDownloaded();
      setDownloadedExams(all);
      setLoading(false);
    };
    load();
  }, []);

  const filteredExams = useMemo(() => {
    return downloadedExams.filter(e => 
      e.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
      e.system.toLowerCase().includes(searchQuery.toLowerCase())
    );
  }, [downloadedExams, searchQuery]);

  const stats = useMemo(() => {
    const systems = new Set(downloadedExams.map(e => e.system)).size;
    return { count: downloadedExams.length, systems };
