                {activeDownloads}
              </span>
            )}
          </button>
        </Tooltip>

        <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest px-2 mb-2 mt-5">Sections</p>
        {Object.values(ExamSystem).map((system) => (
          <Tooltip key={system} content={`${system} Suite`} position="right">
            <button
              onClick={() => onSelectSystem(system)}
              className={`w-full flex items-center gap-2.5 px-3 py-2 rounded-xl text-[11px] font-bold transition-all duration-200 ${
                currentView === 'library' && selectedSystem === system ? 'bg-blue-600 text-white shadow-lg shadow-blue-200' : 'text-slate-600 hover:bg-slate-50'
              }`}
            >
              {SYSTEM_THEMES[system]?.icon}
              <span className="truncate">{system}</span>
            </button>
          </Tooltip>
        ))}
      </nav>

      <div className="p-4 border-t border-slate-50 bg-slate-50/50 shrink-0 space-y-3">
        <div 
          onClick={onToggleEdit}
          className={`flex items-center justify-between p-3 rounded-2xl cursor-pointer transition-all border ${isEditMode ? 'bg-amber-500 text-white border-amber-600 shadow-lg shadow-amber-200' : 'bg-white text-slate-400 border-slate-100 hover:border-slate-300'}`}
        >
          <div className="flex items-center gap-2.5">
             <Code2 className="w-4 h-4" />
             <span className="text-[10px] font-black uppercase truncate">Edit Mode</span>
          </div>
          {isEditMode ? <ToggleRight className="w-5 h-5" /> : <ToggleLeft className="w-5 h-5" />}
        </div>

        <div className="flex items-center gap-3 px-2">
          <div className="w-8 h-8 rounded-xl bg-white border border-slate-200 flex items-center justify-center text-blue-600 shadow-sm">
            <HardDrive className="w-4 h-4" />
          </div>
          <div className="overflow-hidden">
            <p className="text-[10px] font-black text-slate-900 uppercase truncate">Secure Disk</p>
            <p className="text-[8px] font-bold text-slate-400 tracking-wider truncate">VAULT LINKED</p>
          </div>
        </div>
      </div>
    </aside>
  );
};

export default Sidebar;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Examination, ClinicalCorrelation, ExamStep, GroundingSource } from '../types';
import { GeminiService } from '../services/geminiService';
import { storage } from '../services/storageService';
import { SYSTEM_THEMES, DEFAULT_STYLE } from '../theme';
import Tooltip from './Tooltip';
import DifferentialPanel from './DifferentialPanel';
import ImageModal from './ImageModal';
import { 
  ClipboardList, Info, Zap, 
  CheckCircle2, ChevronDown, Lightbulb, Sparkles, ListCheck, BrainCircuit, X, BookOpen, Activity, Waves, HeartPulse, Layers, ArrowLeft, ChevronRight, Stethoscope, Loader2,
  ShieldCheck, CircleCheck, ExternalLink, GraduationCap, Microscope, HardDrive, Save, Edit3, Trash
} from 'lucide-react';

interface ExamViewProps {
  exam: Examination;
  onBack: () => void;
  isEditMode?: boolean;
  onUpdate?: (updated: Examination) => void;
}

const MedImage: React.FC<{ 
  src?: string; 
  localId?: string;
  alt: string; 
  fallbackIcon: React.ReactNode; 
  label: string;
  onEnlarge?: (src: string, alt: string) => void;
}> = ({ src, localId, alt, fallbackIcon, label, onEnlarge }) => {
  const [error, setError] = useState(false);
  const [resolvedUrl, setResolvedUrl] = useState<string | null>(null);

  useEffect(() => {
    if (localId) {
      storage.getAssetUrl(localId).then(setResolvedUrl);
    }
  }, [localId]);

  const activeSrc = resolvedUrl || src;

  if (!activeSrc || error) {
    return (
      <div className="w-full aspect-video bg-slate-50 border-2 border-dashed border-slate-200 rounded-3xl flex flex-col items-center justify-center p-8 text-slate-300">
        <div className="mb-3 opacity-30 scale-150">{fallbackIcon}</div>
        <p className="text-[9px] font-black uppercase tracking-widest text-slate-400">{label} Unavailable</p>
      </div>
    );
  }

  return (
    <div 
      className="relative group/viz rounded-3xl overflow-hidden border border-slate-200 shadow-inner bg-slate-50 cursor-zoom-in"
      onClick={() => onEnlarge?.(activeSrc, alt)}
    >
      <img 
        src={activeSrc} 
        alt={alt} 
        className="w-full h-auto object-cover transition-transform duration-1000 group-hover/viz:scale-[1.05]" 
        onError={() => setError(true)}
      />
      <div className="absolute bottom-3 left-3 right-3 flex items-center justify-between px-3 py-1.5 bg-black/40 backdrop-blur-md rounded-xl opacity-100 group-hover/viz:bg-black/60 transition-all">
        <div className="flex items-center gap-2">
           <span className="text-[8px] font-black text-white uppercase tracking-widest">{label}</span>
           {resolvedUrl && <HardDrive className="w-2.5 h-2.5 text-emerald-400" />}
        </div>
        <Sparkles className="w-2.5 h-2.5 text-amber-400" />
      </div>
    </div>
  );
};

const ExamView: React.FC<ExamViewProps> = ({ exam: initialExam, onBack, isEditMode, onUpdate }) => {
  const [exam, setExam] = useState(initialExam);
  const [isDirty, setIsDirty] = useState(false);
  const [activeTab, setActiveTab] = useState<'steps' | 'summary' | 'correlation'>('steps');
  const [summary, setSummary] = useState<string | null>(null);
  const [loadingSummary, setLoadingSummary] = useState(false);
  const [isResearching, setIsResearching] = useState(false);

  const [sidePathoSign, setSidePathoSign] = useState<string | null>(null);
  const [sidePathoData, setSidePathoData] = useState<ClinicalCorrelation | null>(null);
  const [loadingSidePatho, setLoadingSidePatho] = useState(false);
  const [enlargedImage, setEnlargedImage] = useState<{src: string, alt: string} | null>(null);

  const [isOnline] = useState(navigator.onLine);
  const [checkedSteps, setCheckedSteps] = useState<Set<string>>(new Set());
  const [isChecklistMode, setIsChecklistMode] = useState(false);

  const gemini = new GeminiService();
  const style = SYSTEM_THEMES[exam.system] || DEFAULT_STYLE;

  useEffect(() => {
    setExam(initialExam);
    setIsDirty(false);
  }, [initialExam]);

  const categorizedSteps = useMemo(() => {
    const groups: Record<string, ExamStep[]> = {};
    exam.steps.forEach(step => {
      const cat = step.category || 'General';
      if (!groups[cat]) groups[cat] = [];
      groups[cat].push(step);
    });
    return groups;
  }, [exam.steps]);

  useEffect(() => {
    const research = async () => {
      if (exam.steps.length === 0 && isOnline && !exam.isDownloaded) {
        setIsResearching(true);
        try {
          const res = await gemini.populateExamination(exam);
          const populated = { ...exam, ...res, isDraft: false };
          setExam(populated);
          setIsDirty(true);
        } catch (e) { console.error(e); }
        finally { setIsResearching(false); }
      }
    };
    research();
  }, [exam.id, isOnline, exam.isDownloaded]);

  const handleSave = async () => {
    try {
      await storage.saveExamination({ ...exam, isDownloaded: true });
      setIsDirty(false);
      onUpdate?.(exam);
    } catch (e) {
      alert("Failed to commit changes to the Vault.");
    }
  };

  const updateStepField = (stepId: string, field: keyof ExamStep, value: string) => {
    const newSteps = exam.steps.map(s => s.id === stepId ? { ...s, [field]: value } : s);
    setExam({ ...exam, steps: newSteps });
    setIsDirty(true);
  };

  const updateGeneralField = (field: keyof Examination, value: string) => {
    setExam({ ...exam, [field]: value });
    setIsDirty(true);
  };

  const fetchClinicalCorrelation = async (sign: string) => {
    if (!isOnline) return;
    setSidePathoSign(sign);
    setLoadingSidePatho(true);
    setSidePathoData(null);
    try {
      const data = await gemini.getClinicalCorrelation(sign, exam.system, false);
      setSidePathoData(data);
    } catch (e) { console.error(e); }
    finally { setLoadingSidePatho(false); }
  };

  const progress = exam.steps.length > 0 ? Math.round((checkedSteps.size / exam.steps.length) * 100) : 0;

  if (isResearching) return (
    <div className="h-full flex flex-col items-center justify-center p-20 bg-white">
      <div className="relative mb-8">
        <div className="w-20 h-20 border-4 border-blue-50 rounded-full"></div>
        <div className="w-20 h-20 border-4 border-blue-600 border-t-transparent rounded-full animate-spin absolute top-0"></div>
        <BrainCircuit className="w-8 h-8 text-blue-600 absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2" />
      </div>
      <p className="text-[10px] font-black uppercase text-slate-400 tracking-[0.3em] mb-2">Synthesizing Protocol</p>
    </div>
  );

  return (
    <div className="min-h-full bg-white animate-in fade-in duration-700 relative">
      {enlargedImage && (
        <ImageModal 
          src={enlargedImage.src} 
          alt={enlargedImage.alt} 
          onClose={() => setEnlargedImage(null)} 
        />
      )}

      {/* --- FLOATING COMMIT BAR --- */}
      {isEditMode && isDirty && (
        <div className="fixed bottom-10 left-1/2 -translate-x-1/2 z-[60] animate-in slide-in-from-bottom-10">
          <button 
            onClick={handleSave}
            className="flex items-center gap-3 px-8 py-4 bg-amber-600 text-white rounded-[24px] shadow-2xl shadow-amber-500/40 hover:bg-amber-700 transition-all font-black uppercase text-[11px] tracking-widest"
          >
            <Save className="w-5 h-5" /> Commit Changes to Vault
          </button>
        </div>
      )}

      {/* --- CLINICAL CORRELATION MODAL --- */}
      {sidePathoSign && (
        <div className="fixed inset-0 z-[70] flex items-center justify-center p-4 sm:p-10">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-500" onClick={() => setSidePathoSign(null)} />
          <div className="relative w-full max-w-3xl max-h-full bg-white shadow-2xl rounded-[40px] overflow-hidden animate-in zoom-in-95 duration-500 flex flex-col">
            <header className="p-8 border-b border-slate-100 flex items-center justify-between bg-slate-50/50 sticky top-0 backdrop-blur-md z-20">
               <div className="flex items-center gap-5">
                  <div className="w-14 h-14 bg-rose-600 text-white rounded-[20px] flex items-center justify-center shadow-2xl shadow-rose-200">
                    <Zap className="w-7 h-7" />
                  </div>
                  <div>
                    <h3 className="text-2xl font-black text-slate-900 uppercase tracking-tight">{sidePathoSign}</h3>
                    <p className="text-[10px] font-black text-rose-600 uppercase tracking-widest">Clinical Matrix Synthesis</p>
                  </div>
               </div>
               <button onClick={() => setSidePathoSign(null)} className="p-3 hover:bg-slate-100 rounded-2xl text-slate-400 transition-all hover:scale-110 active:scale-95">
                 <X className="w-6 h-6" />
               </button>
            </header>

            <div className="flex-1 overflow-y-auto custom-scrollbar p-8 sm:p-12 space-y-12">
               {loadingSidePatho ? (
                 <div className="py-24 flex flex-col items-center justify-center space-y-6">
                   <div className="relative">
                      <div className="w-20 h-20 border-4 border-rose-50 rounded-full"></div>
                      <div className="w-20 h-20 border-4 border-rose-600 border-t-transparent rounded-full animate-spin absolute top-0"></div>
                      <Microscope className="w-8 h-8 text-rose-600 absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2" />
                   </div>
                   <p className="text-[11px] font-black uppercase text-slate-400 tracking-[0.4em]">Synthesizing Reasoning...</p>
                 </div>
               ) : sidePathoData ? (
                 <div className="animate-in fade-in slide-in-from-bottom-6 duration-700 space-y-12 pb-8">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                      <MedImage 
                        src={sidePathoData.imageUrl} 
                        alt={sidePathoData.sign} 
                        label="Primary Stigmata" 
                        fallbackIcon={<Activity />}
                        onEnlarge={(src, alt) => setEnlargedImage({src, alt})}
                      />
                      <div className="bg-slate-50/50 p-8 rounded-[40px] border border-slate-100 flex flex-col justify-center">
                         <h4 className="text-[10px] font-black uppercase tracking-widest text-slate-400 mb-6 flex items-center gap-2">
                           <BookOpen className="w-4 h-4" /> Key Differentials
                         </h4>
                         <ul className="space-y-3">
                            {(Array.isArray(sidePathoData.causes) ? sidePathoData.causes : []).map((c, i) => (
                              <li key={i} className="flex items-center gap-4 text-sm text-slate-700 font-black">
                                <div className="w-2 h-2 rounded-full bg-rose-500 shadow-lg shadow-rose-200 shrink-0" />
                                {c}
                              </li>
                            ))}
                          </ul>
                      </div>
                    </div>

                    <section className="bg-white p-10 rounded-[48px] border-2 border-slate-100 shadow-xl relative overflow-hidden">
                       <div className="absolute top-0 left-0 w-2 h-full bg-rose-600" />
                       <h4 className="text-xl font-black text-slate-900 tracking-tight mb-4 flex items-center gap-3">
                         <GraduationCap className="w-6 h-6 text-rose-600" /> Pathophysiology
                       </h4>
                       <p className="text-base leading-[2] text-slate-700 font-medium italic">
                         {sidePathoData.pathophysiology}
                       </p>
                    </section>
                 </div>
               ) : null}
            </div>
          </div>
        </div>
      )}

      {/* --- HEADER --- */}
      <div className="sticky top-0 z-40 bg-white/80 backdrop-blur-xl border-b border-slate-100 px-8 py-4 flex items-center justify-between">
        <div className="flex items-center gap-6">
          <button onClick={onBack} className="p-2 hover:bg-slate-50 rounded-xl text-slate-400 transition-colors">
            <ArrowLeft className="w-5 h-5" />
          </button>
          <div>
            <div className="flex items-center gap-2 mb-0.5">
              <span className={`text-[9px] font-black uppercase tracking-widest ${style.text}`}>{exam.system}</span>
              <span className="w-1 h-1 rounded-full bg-slate-200" />
              {exam.isDownloaded && <HardDrive className="w-3 h-3 text-emerald-500" />}
              {isEditMode ? (
                 <input 
                  type="text"
                  value={exam.name}
                  onChange={(e) => updateGeneralField('name', e.target.value)}
                  className="bg-amber-50 border-b border-amber-300 text-lg font-black text-slate-900 tracking-tight outline-none px-1 rounded-sm focus:ring-1 focus:ring-amber-400"
                />
              ) : (
                <h1 className="text-lg font-black text-slate-900 tracking-tight">{exam.name}</h1>
              )}
            </div>
          </div>
        </div>
        <div className="flex items-center gap-4">
          <div className="flex items-center gap-2 px-4 py-2 bg-slate-50 rounded-2xl border border-slate-100">
            <span className="text-[10px] font-black text-slate-900">{progress}% Complete</span>
          </div>
          <button onClick={() => setIsChecklistMode(!isChecklistMode)} className={`px-6 py-2.5 rounded-2xl text-[10px] font-black uppercase flex items-center gap-2 shadow-xl transition-all ${isChecklistMode ? 'bg-emerald-600 text-white' : 'bg-slate-900 text-white'}`}>
            <ListCheck className="w-4 h-4" /> {isChecklistMode ? 'Exit OSCE' : 'Start OSCE'}
          </button>
        </div>
      </div>

      <div className="max-w-5xl mx-auto py-12 px-8">
        <div className="grid grid-cols-1 lg:grid-cols-5 gap-12 mb-16">
          <div className="lg:col-span-3">
             <div className="flex items-center gap-3 mb-6">
                <div className={`p-2 rounded-xl ${style.bg} ${style.text}`}>{style.icon}</div>
                {isEditMode ? (
                  <span className="flex items-center gap-2 text-amber-600 font-black uppercase text-[10px] tracking-widest"><Edit3 className="w-3 h-3" /> Drafting Mode</span>
                ) : (
                  <h2 className="text-3xl font-black text-slate-900 tracking-tighter leading-tight">{exam.name}</h2>
                )}
             </div>
             {isEditMode ? (
               <textarea 
                  value={exam.shortDescription}
                  onChange={(e) => updateGeneralField('shortDescription', e.target.value)}
                  className="w-full min-h-[100px] p-4 bg-amber-50/30 border border-amber-200 rounded-2xl text-base text-slate-600 font-medium leading-[1.8] outline-none focus:ring-2 focus:ring-amber-400"
               />
             ) : (
               <p className="text-base text-slate-500 font-medium leading-[1.8] mb-8">{exam.shortDescription}</p>
             )}
          </div>
          <div className="lg:col-span-2">
            <MedImage 
              src={!exam.localHeaderImageUrl ? exam.headerImageUrl : undefined} 
              localId={exam.localHeaderImageUrl}
              alt="Anatomy Header" 
              label="Header Matrix" 
              fallbackIcon={style.icon} 
              onEnlarge={(src, alt) => setEnlargedImage({src, alt})}
            />
          </div>
        </div>

        <div className="flex justify-center mb-16">
          <div className="inline-flex p-1.5 bg-slate-100 rounded-[24px] border border-slate-200/50 shadow-inner">
            {[
              { id: 'steps', label: 'Protocol', icon: <ClipboardList className="w-4 h-4" /> },
              { id: 'summary', label: 'Clinical Summary', icon: <Info className="w-4 h-4" /> }
            ].map((tab) => (
              <button 
                key={tab.id}
                onClick={() => setActiveTab(tab.id as any)}
                className={`flex items-center gap-3 px-6 py-3 rounded-2xl text-[10px] font-black uppercase transition-all ${activeTab === tab.id ? 'bg-white text-slate-900 shadow-xl' : 'text-slate-400'}`}
              >
                {tab.icon} {tab.label}
              </button>
            ))}
          </div>
        </div>

        {activeTab === 'steps' && (
          <div className="space-y-12">
            {(Object.entries(categorizedSteps) as [string, ExamStep[]][]).map(([category, steps], catIdx) => (
              <div key={category} className="animate-in fade-in" style={{ animationDelay: `${catIdx * 100}ms` }}>
                <h3 className="text-xl font-black text-slate-900 tracking-tight uppercase mb-8 flex items-center gap-4">
                  <div className={`h-6 w-1 rounded-full ${style.secondary}`} />
                  {category}
                </h3>
                <div className="bg-white rounded-[40px] border border-slate-100 shadow-sm overflow-hidden divide-y divide-slate-50">
                  {steps.map((step) => {
                    const isChecked = checkedSteps.has(step.id);
                    return (
                      <div key={step.id} className={`p-8 transition-all flex items-start gap-8 ${isChecked ? 'bg-emerald-50/30' : ''} ${isEditMode ? 'hover:bg-amber-50/10' : ''}`}>
                        {isChecklistMode ? (
                          <button 
                            onClick={() => setCheckedSteps(p => { const n = new Set(p); if (n.has(step.id)) n.delete(step.id); else n.add(step.id); return n; })}
                            className={`w-12 h-12 rounded-2xl border-2 flex items-center justify-center shrink-0 ${isChecked ? 'bg-emerald-600 border-emerald-600 text-white shadow-lg' : 'bg-white border-slate-200'}`}
                          >
                            {isChecked && <CheckCircle2 className="w-6 h-6" />}
                          </button>
                        ) : <div className={`w-3 h-3 rounded-full mt-4 shrink-0 ${style.secondary} opacity-40`} />}

                        <div className="flex-1">
                          {isEditMode ? (
                            <div className="space-y-3">
                              <input 
                                type="text"
                                value={step.title}
                                onChange={(e) => updateStepField(step.id, 'title', e.target.value)}
                                className="w-full bg-amber-50 border-b border-amber-300 text-base font-black text-slate-900 outline-none focus:ring-1 focus:ring-amber-400 p-1"
                              />
                              <textarea 
                                value={step.description}
                                onChange={(e) => updateStepField(step.id, 'description', e.target.value)}
                                className="w-full min-h-[60px] p-3 bg-amber-50/30 border border-amber-200 rounded-xl text-[13px] leading-relaxed text-slate-500 font-medium outline-none focus:ring-1 focus:ring-amber-400"
                              />
                            </div>
                          ) : (
                            <>
                              <h4 className="text-base font-black text-slate-900 mb-2">{step.title}</h4>
                              <p className="text-[13px] leading-relaxed text-slate-500 font-medium mb-6">{step.description}</p>
                            </>
                          )}

                          <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mt-6">
                            <div className="flex-1">
                              {step.positiveFindings && step.positiveFindings.length > 0 && (
                                <div className="space-y-4">
                                  <div className="flex items-center gap-2 text-rose-500">
                                    <Zap className="w-3.5 h-3.5" />
                                    <span className="text-[9px] font-black uppercase tracking-widest">Pathological Signs</span>
                                  </div>
                                  <div className="flex flex-wrap gap-2">
                                    {step.positiveFindings.map((f, i) => (
                                      <button 
                                        key={i} 
                                        onClick={() => fetchClinicalCorrelation(f.description)}
                                        className="group/sign flex items-center gap-3 px-4 py-2.5 bg-rose-50 border border-rose-100 rounded-2xl hover:bg-rose-600 hover:text-white transition-all text-left"
                                      >
                                        <Zap className="w-3 h-3 group-hover/sign:text-white" />
                                        <span className="text-[10px] font-black uppercase italic leading-none">{f.description}</span>
                                      </button>
                                    ))}
                                  </div>
                                </div>
                              )}
                            </div>

                            {(step.localImageUrl || step.imageUrl) && (
                              <div className="max-w-[200px]">
                                <MedImage 
                                  src={!step.localImageUrl ? step.imageUrl : undefined}
                                  localId={step.localImageUrl}
                                  alt={step.title}
                                  label="Protocol Reference"
                                  fallbackIcon={<Layers />}
                                  onEnlarge={(src, alt) => setEnlargedImage({src, alt})}
                                />
                              </div>
                            )}
                          </div>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

