import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { ClinicalCorrelation, Examination, GroundingSource, DiagnosisSuggestion, ClinicalCondition, ExamStep, AudioSimulation } from "../types";

export class GeminiService {

  public async generateIllustration(prompt: string, isPro: boolean = false): Promise<string | undefined> {
    // Always initialize GoogleGenAI inside the method to use the latest API key
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    try {
      if (isPro) {
        // High-fidelity path using Imagen
        const response = await ai.models.generateImages({
          model: 'imagen-4.0-generate-001',
          prompt: `A professional medical textbook illustration. Topic: ${prompt}. Style: Clean, detailed scientific diagram, white background, precise anatomical labeling, realistic colors. No text watermarks. High resolution.`,
          config: {
            numberOfImages: 1,
            aspectRatio: '16:9',
          },
        });
        const base64Bytes = response.generatedImages[0].image.imageBytes;
        return `data:image/png;base64,${base64Bytes}`;
      } else {
        // Standard path using gemini-2.5-flash-image
        const response = await ai.models.generateContent({
          model: 'gemini-2.5-flash-image',
          contents: {
            parts: [
              {
                text: `Generate a professional medical textbook illustration of: ${prompt}. Clean white background, scientific diagram style, clear labeling.`,
              },
            ],
          },
          config: {
            imageConfig: {
              aspectRatio: "16:9"
            }
          }
        });

        // Search for the image part in the response
        for (const part of response.candidates[0].content.parts) {
          if (part.inlineData) {
            return `data:image/png;base64,${part.inlineData.data}`;
          }
        }
      }
    } catch (error: any) {
      console.error("Illustration generation failed", error);
      return undefined;
    }
    return undefined;
  }

  async getClinicalCorrelation(sign: string, context: string, isPro: boolean = false): Promise<ClinicalCorrelation> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const model = isPro ? "gemini-3-pro-preview" : "gemini-3-flash-preview";

    // Removing googleSearch from JSON response request to comply with "do not parse JSON with search" rule
    const textResponse: GenerateContentResponse = await ai.models.generateContent({
      model: model,
      contents: `Explain the clinical and physiological significance of '${sign}' in a ${context} context. 
      ${isPro ? 'Provide deep fellowship-level (CICM/ANZCA) analysis.' : 'Provide a clear, high-yield clinical explanation.'}
      Focus on pathophysiology, pressure-volume loops if relevant, and causes.

      Determine if this sign significantly involves:
      1. Systemic or Pulmonary circulation (e.g. valve pathology, shunts, heart failure).
      2. Cardiac function/contractility (e.g. ejection fraction, pressure changes).
      3. Specific anatomical structures.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            sign: { type: Type.STRING },
            pathophysiology: { type: Type.STRING },
            causes: { type: Type.ARRAY, items: { type: Type.STRING } },
            clinicalSignificance: { type: Type.STRING },
            imagePrompt: { type: Type.STRING, description: "Prompt for a main medical illustration." },
            needsCirculationDiagram: { type: Type.BOOLEAN },
            circulationSide: { type: Type.STRING, enum: ["left-sided", "right-sided"] },
            needsPVLoopDiagram: { type: Type.BOOLEAN },
            needsAnatomyDiagram: { type: Type.BOOLEAN },
            affectedAnatomy: { type: Type.STRING, description: "The specific body part or organ affected." }
          },
          required: ["sign", "pathophysiology", "causes", "clinicalSignificance", "imagePrompt", "needsCirculationDiagram", "needsPVLoopDiagram", "needsAnatomyDiagram"]
        }
      }
    });

    let correlation: ClinicalCorrelation;
    try {
      // Direct access to .text property as per guidelines
      correlation = JSON.parse(textResponse.text || "{}") as ClinicalCorrelation;
      correlation.sources = []; // Sources are empty since search tool was removed for JSON safety
      if (!correlation.causes) correlation.causes = [];
    } catch (error) {
      console.error("Failed to parse correlation text", error);
      throw error;
    }

    // Main illustration
    correlation.imageUrl = await this.generateIllustration(correlation.imagePrompt || correlation.sign, isPro);

    // Specialized diagrams using requested prompts
    if (correlation.needsCirculationDiagram) {
      const side = correlation.circulationSide || 'systemic';
      correlation.circulationImageUrl = await this.generateIllustration(`Diagram of ${side} circulation illustrating the mechanism of ${correlation.sign}`, isPro);
    }

    if (correlation.needsPVLoopDiagram) {
      correlation.pvLoopImageUrl = await this.generateIllustration(`Cardiac pressure-volume loop diagram for ${correlation.sign}`, isPro);
    }

    if (correlation.needsAnatomyDiagram) {
      const part = correlation.affectedAnatomy || correlation.sign;
      correlation.anatomyImageUrl = await this.generateIllustration(`Anatomy of the ${part}`, isPro);
    }

    return correlation;
  }

  async populateExamination(exam: Examination): Promise<Partial<Examination>> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const prompt = `Research the official medical protocol for a '${exam.name}' within the ${exam.system} system. 
    Use reliable medical sources.
    Provide a detailed, step-by-step examination protocol and a prompt for a high-quality header illustration.
    For each step, if a specific medical diagram (like a JVP waveform, a dermatome map, or a specific anatomical slice) would be highly beneficial, include a detailed 'imagePrompt'.

    Structure the response as JSON with:
    1. steps: an array of objects { id, title, description, category, positiveFindings: [{ description: string }], imagePrompt?: string }
    2. headerImagePrompt: string`;

    // Removing googleSearch from JSON response request to comply with "do not parse JSON with search" rule
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: "gemini-3-flash-preview", 
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            steps: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING },
                  title: { type: Type.STRING },
                  description: { type: Type.STRING },
                  category: { type: Type.STRING },
                  imagePrompt: { type: Type.STRING, description: "Detailed prompt for a step-specific diagram if useful." },
                  positiveFindings: {
                    type: Type.ARRAY,
                    items: {
                      type: Type.OBJECT,
                      properties: { description: { type: Type.STRING } }
                    }
                  }
                },
                required: ["id", "title", "description", "category"]
              }
            },
            headerImagePrompt: { type: Type.STRING }
          },
          required: ["steps", "headerImagePrompt"]
        }
      }
    });

    try {
      const data = JSON.parse(response.text || "{}");
      const headerImageUrl = await this.generateIllustration(data.headerImagePrompt, false);
      return { 
        steps: data.steps || [], 
        sources: [], 
        headerImageUrl, 
        headerImagePrompt: data.headerImagePrompt 
      };
    } catch (error) {
      console.error("Failed to parse examination data", error);
      throw error;
    }
  }

  async getExaminationSummary(examName: string): Promise<string> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Provide a concise clinical summary and purpose of the ${examName} following the style of Talley and O'Connor. Include key things not to miss.`,
    });
    return response.text || "No summary available.";
  }

  async getDifferentialDiagnosis(findings: string[], system: string): Promise<DiagnosisSuggestion[]> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Given these physical examination findings in the ${system} system: [${findings.join(', ')}], suggest a list of differential diagnoses.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              condition: { type: Type.STRING },
              probability: { type: Type.STRING, enum: ["High", "Moderate", "Low"] },
              reasoning: { type: Type.STRING },
              keyFindings: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ["condition", "probability", "reasoning", "keyFindings"]
          }
        }
      }
    });

    try {
      return JSON.parse(response.text || "[]");
    } catch (error) {
      console.error("Failed to parse differentials", error);
      return [];
    }
  }

  async getFindingsForCondition(conditionName: string): Promise<ClinicalCondition> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    // Removing googleSearch from JSON response request for consistency and compliance
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `List potential findings for '${conditionName}'.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            name: { type: Type.STRING },
            system: { type: Type.STRING },
            description: { type: Type.STRING },
            findings: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  category: { type: Type.STRING },
                  sign: { type: Type.STRING },
                  significance: { type: Type.STRING },
                  link: { type: Type.STRING }
                },
                required: ["category", "sign", "significance", "link"]
              }
            }
          },
          required: ["name", "description", "findings"]
        }
      }
    });

    try {
      return JSON.parse(response.text || "{}");
    } catch (error) {
      console.error("Failed to parse condition findings", error);
      throw error;
    }
  }
}

import { DownloadTask, DownloadTaskStatus, Examination, ExamStep } from '../types';
import { GeminiService } from './geminiService';
import { storage } from './storageService';
import { EXAMINATIONS } from '../constants';

export class DownloadManagerService {
  private tasks: DownloadTask[] = [];
  private isPaused: boolean = false;
  private maxConcurrency: number = 1;
  private activeCount: number = 0;
  private listeners: Set<(tasks: DownloadTask[]) => void> = new Set();
  private gemini = new GeminiService();

  constructor() {
    const saved = localStorage.getItem('medex_download_queue');
    if (saved) {
      this.tasks = JSON.parse(saved).map((t: any) => ({
        ...t,
        status: (t.status === 'downloading' || t.status === 'pending') ? 'pending' : t.status
      }));
    }
    this.processQueue();
  }

  private notify() {
    localStorage.setItem('medex_download_queue', JSON.stringify(this.tasks));
    this.listeners.forEach(l => l([...this.tasks]));
  }

  subscribe(listener: (tasks: DownloadTask[]) => void) {
    this.listeners.add(listener);
    listener([...this.tasks]);
    return () => this.listeners.delete(listener);
  }

  async downloadAll() {
    const allDownloaded = await storage.getAllDownloaded();
    const downloadedIds = new Set(allDownloaded.map(e => e.id));

    const toDownload = EXAMINATIONS.filter(exam => 
      !downloadedIds.has(exam.id) && 
      !this.tasks.find(t => t.examId === exam.id && t.status !== 'failed')
    );

    toDownload.forEach(exam => {
      this.addTask(exam.id);
    });
  }

  async clearArchive() {
    if (!confirm("Are you sure you want to purge the Knowledge Vault? This will delete all persistent offline files.")) return;
    await storage.clearArchive();
    this.tasks = [];
    this.notify();
    window.location.reload();
  }

  addTask(examId: string, type: DownloadTask['type'] = 'deep_sync') {
    const exam = EXAMINATIONS.find(e => e.id === examId);
    if (!exam) return;

    const existing = this.tasks.find(t => t.examId === examId && t.status !== 'completed');
    if (existing) return;

    const newTask: DownloadTask = {
      id: Math.random().toString(36).substr(2, 9),
      examId,
      examName: exam.name,
      type,
      status: 'pending',
      progress: 0,
      retryCount: 0,
      createdAt: Date.now()
    };

    this.tasks = [...this.tasks, newTask];
    this.notify();
    this.processQueue();
  }

  private async processQueue() {
    if (this.isPaused || this.activeCount >= this.maxConcurrency) return;

    const nextTask = this.tasks.find(t => t.status === 'pending');
    if (!nextTask) return;

    this.activeCount++;
    await this.runTask(nextTask);
    this.activeCount--;
    this.processQueue();
  }

  private async fetchAndStoreAsset(url: string, prefix: string): Promise<string | undefined> {
    try {
      const response = await fetch(url);
      if (!response.ok) throw new Error(`HTTP ${response.status}`);
      const blob = await response.blob();
      const assetId = `${prefix}_${Math.random().toString(36).substr(2, 5)}`;
      await storage.saveAsset(assetId, blob);
      return assetId; // Return the ID in the asset store
    } catch (e) {
      console.warn(`Asset fetch/store failed: ${url}`, e);
      return undefined;
    }
  }

  private async runTask(task: DownloadTask) {
    task.status = 'downloading';
    task.progress = 5;
    this.notify();

    try {
      const baseExam = EXAMINATIONS.find(e => e.id === task.examId);
      if (!baseExam) throw new Error('Exam definition not found');

      // STAGE 1: PROTOCOL SYNTHESIS
      task.progress = 15;
      task.error = "Synthesizing Protocol Structure...";
      this.notify();
      const populated = await this.gemini.populateExamination(baseExam);

      // STAGE 2: ASSET SERIALIZATION (TO DISK FOLDERS)
      task.progress = 40;
      task.error = "Archiving Visual Stigmata to Vault...";
      this.notify();

      // Store header image
      let headerAssetId: string | undefined;
      if (populated.headerImageUrl) {
        headerAssetId = await this.fetchAndStoreAsset(populated.headerImageUrl, `header_${task.examId}`);
      }

      // Store step images
      const processedSteps: ExamStep[] = await Promise.all((populated.steps || []).map(async (step, idx) => {
        const stepProgress = 40 + Math.floor((idx / (populated.steps?.length || 1)) * 50);
        if (task.progress < stepProgress) {
          task.progress = stepProgress;
          this.notify();
        }

        const processedStep = { ...step };

        // AUTO-GENERATE STEP IMAGE IF PROMPT EXISTS BUT NO URL
        let activeImageUrl = step.imageUrl;
        if (!activeImageUrl && step.imagePrompt) {
          try {
            activeImageUrl = await this.gemini.generateIllustration(step.imagePrompt, false);
          } catch (e) {
            console.warn(`Failed to auto-generate image for step: ${step.title}`);
          }
        }

        if (activeImageUrl) {
          processedStep.localImageUrl = await this.fetchAndStoreAsset(activeImageUrl, `step_${step.id}`);
        }

        // Handle positive finding images if present
        if (step.positiveFindings) {
          processedStep.positiveFindings = await Promise.all(step.positiveFindings.map(async (pf, pfIdx) => {
            if (pf.imageUrl) {
              const pfAssetId = await this.fetchAndStoreAsset(pf.imageUrl, `finding_${step.id}_${pfIdx}`);
              return { ...pf, localImageUrl: pfAssetId };
            }
            return pf;
          }));
        }
        return processedStep;
      }));

      // FINALIZATION: SAVE METADATA TO IDB
      const finalExam: Examination = {
        ...baseExam,
        ...populated,
        steps: processedSteps,
        headerImageUrl: populated.headerImageUrl, 
        localHeaderImageUrl: headerAssetId,
        isDownloaded: true,
        isDraft: false
      };

      await storage.saveExamination(finalExam);

      task.status = 'completed';
      task.progress = 100;
      task.error = undefined;
    } catch (err: any) {
      console.error('Download pipeline failure', err);
      task.status = 'failed';
      task.error = err?.message || 'Download Failed';
    } finally {
      this.notify();
    }
  }

  togglePause() { this.isPaused = !this.isPaused; if (!this.isPaused) this.processQueue(); this.notify(); }
  cancelTask(taskId: string) { this.tasks = this.tasks.filter(t => t.id !== taskId); this.notify(); this.processQueue(); }
  getTasks() { return [...this.tasks]; }
  getPauseState() { return this.isPaused; }
}

export const downloadManager = new DownloadManagerService();

import { storage } from '../services/storageService';

const objectUrlCache: Map<string, string> = new Map();

export const getLocalAssetUrl = async (id: string): Promise<string | null> => {
  if (!id) return null;
  if (objectUrlCache.has(id)) return objectUrlCache.get(id)!;

  const url = await storage.getAssetUrl(id);
  if (url) {
    objectUrlCache.set(id, url);
  }
  return url;
};

export const clearAssetCache = () => {
  objectUrlCache.forEach(url => URL.revokeObjectURL(url));
  objectUrlCache.clear();
};

import React, { useState, useEffect } from 'react';
import { HardDrive, Sparkles } from 'lucide-react';
import { getLocalAssetUrl } from '../../utils/assetHelper';

interface MedImageProps {
  src?: string;
  localId?: string;
  alt: string;
  fallbackIcon: React.ReactNode;
  label: string;
  onEnlarge?: (src: string, alt: string) => void;
  className?: string;
}

const MedImage: React.FC<MedImageProps> = ({ 
  src, localId, alt, fallbackIcon, label, onEnlarge, className = "" 
}) => {
  const [error, setError] = useState(false);
  const [resolvedUrl, setResolvedUrl] = useState<string | null>(null);

  useEffect(() => {
    let mounted = true;
    if (localId) {
      getLocalAssetUrl(localId).then(url => {
        if (mounted) setResolvedUrl(url);
      });
    }
    return () => { mounted = false; };
  }, [localId]);

  const activeSrc = resolvedUrl || src;

  if (!activeSrc || error) {
    return (
      <div className={`w-full aspect-video bg-slate-50 border-2 border-dashed border-slate-200 rounded-3xl flex flex-col items-center justify-center p-8 text-slate-300 ${className}`}>
        <div className="mb-3 opacity-30 scale-150">{fallbackIcon}</div>
        <p className="text-[9px] font-black uppercase tracking-widest text-slate-400">{label} Unavailable</p>
      </div>
    );
  }

  return (
    <div 
