import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { ClinicalCorrelation, Examination, DiagnosisSuggestion, ClinicalCondition } from "../types";

export class GeminiService {
  private getAI() {
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  public async generateIllustration(prompt: string, isPro: boolean = false): Promise<string | undefined> {
    const ai = this.getAI();
    try {
      if (isPro) {
        const response = await ai.models.generateImages({
          model: 'imagen-4.0-generate-001',
          prompt: `A professional medical textbook illustration. Topic: ${prompt}. Style: Clean, detailed scientific diagram, white background, precise anatomical labeling, realistic colors. High resolution.`,
          config: { numberOfImages: 1, aspectRatio: '16:9' },
        });
        return `data:image/png;base64,${response.generatedImages[0].image.imageBytes}`;
      } else {
        const response = await ai.models.generateContent({
          model: 'gemini-2.5-flash-image',
          contents: { parts: [{ text: `Generate a professional medical textbook illustration of: ${prompt}. Clean white background, scientific diagram style, clear labeling.` }] },
          config: { imageConfig: { aspectRatio: "16:9" } }
        });
        for (const part of response.candidates[0].content.parts) {
          if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
    } catch (error) {
      console.error("Illustration generation failed", error);
    }
    return undefined;
  }

  async getClinicalCorrelation(sign: string, context: string, isPro: boolean = false): Promise<ClinicalCorrelation> {
    const ai = this.getAI();
    const model = isPro ? "gemini-3-pro-preview" : "gemini-3-flash-preview";
    const response: GenerateContentResponse = await ai.models.generateContent({
      model,
      contents: `Explain the clinical and physiological significance of '${sign}' in a ${context} context. Focus on pathophysiology and causes. Determine if this sign involves circulatory changes or specific anatomy.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            sign: { type: Type.STRING },
            pathophysiology: { type: Type.STRING },
            causes: { type: Type.ARRAY, items: { type: Type.STRING } },
            clinicalSignificance: { type: Type.STRING },
            imagePrompt: { type: Type.STRING },
            needsCirculationDiagram: { type: Type.BOOLEAN },
            circulationSide: { type: Type.STRING, enum: ["left-sided", "right-sided"] },
            needsPVLoopDiagram: { type: Type.BOOLEAN },
            needsAnatomyDiagram: { type: Type.BOOLEAN },
            affectedAnatomy: { type: Type.STRING }
          },
          required: ["sign", "pathophysiology", "causes", "clinicalSignificance", "imagePrompt", "needsCirculationDiagram", "needsPVLoopDiagram", "needsAnatomyDiagram"]
        }
      }
    });

    const correlation = JSON.parse(response.text || "{}") as ClinicalCorrelation;
    correlation.imageUrl = await this.generateIllustration(correlation.imagePrompt || correlation.sign, isPro);
    if (correlation.needsCirculationDiagram) correlation.circulationImageUrl = await this.generateIllustration(`Diagram of ${correlation.circulationSide || 'systemic'} circulation for ${correlation.sign}`, isPro);
    if (correlation.needsPVLoopDiagram) correlation.pvLoopImageUrl = await this.generateIllustration(`Cardiac pressure-volume loop for ${correlation.sign}`, isPro);
    if (correlation.needsAnatomyDiagram) correlation.anatomyImageUrl = await this.generateIllustration(`Anatomy of the ${correlation.affectedAnatomy || correlation.sign}`, isPro);

    return correlation;
  }

  async populateExamination(exam: Examination): Promise<Partial<Examination>> {
    const ai = this.getAI();
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: "gemini-3-flash-preview", 
      contents: `Detailed clinical protocol for '${exam.name}' within the ${exam.system} system.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            steps: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING },
                  title: { type: Type.STRING },
                  description: { type: Type.STRING },
                  category: { type: Type.STRING },
                  imagePrompt: { type: Type.STRING },
                  positiveFindings: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { description: { type: Type.STRING } } } }
                },
                required: ["id", "title", "description", "category"]
              }
            },
            headerImagePrompt: { type: Type.STRING }
          },
          required: ["steps", "headerImagePrompt"]
        }
      }
    });

    const data = JSON.parse(response.text || "{}");
    const headerImageUrl = await this.generateIllustration(data.headerImagePrompt, false);
    return { steps: data.steps || [], headerImageUrl, headerImagePrompt: data.headerImagePrompt };
  }

  async getDifferentialDiagnosis(findings: string[], system: string): Promise<DiagnosisSuggestion[]> {
    const ai = this.getAI();
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Differential diagnosis for: [${findings.join(', ')}] in ${system}.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              condition: { type: Type.STRING },
              probability: { type: Type.STRING, enum: ["High", "Moderate", "Low"] },
              reasoning: { type: Type.STRING },
              keyFindings: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ["condition", "probability", "reasoning", "keyFindings"]
          }
        }
      }
    });
    return JSON.parse(response.text || "[]");
  }

  async getFindingsForCondition(conditionName: string): Promise<ClinicalCondition> {
    const ai = this.getAI();
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Physical exam findings for '${conditionName}'.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            name: { type: Type.STRING },
            system: { type: Type.STRING },
            description: { type: Type.STRING },
            findings: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: { category: { type: Type.STRING }, sign: { type: Type.STRING }, significance: { type: Type.STRING }, link: { type: Type.STRING } },
                required: ["category", "sign", "significance", "link"]
              }
            }
          },
          required: ["name", "description", "findings"]
        }
      }
    });
    return JSON.parse(response.text || "{}");
  }
}

