import React, { useState, useEffect, useMemo } from 'react';
import { Examination, ClinicalCorrelation, ExamStep } from '../types';
import { GeminiService } from '../services/geminiService';
import { SYSTEM_THEMES, DEFAULT_STYLE } from '../theme';
import { useExamEditor } from '../hooks/useExamEditor';
import MedImage from './common/MedImage';
import ImageModal from './ImageModal';
import CorrelationModal from './ExamView/CorrelationModal';
import { 
  ClipboardList, Info, Zap, CheckCircle2, ListCheck, BrainCircuit, Layers, ArrowLeft, GraduationCap, Microscope, Save, Edit3 
} from 'lucide-react';

interface ExamViewProps {
  exam: Examination;
  onBack: () => void;
  isEditMode?: boolean;
  onUpdate?: (updated: Examination) => void;
}

const ExamView: React.FC<ExamViewProps> = ({ exam: initialExam, onBack, isEditMode, onUpdate }) => {
  const { 
    exam, setExam, isDirty, updateGeneralField, updateStepField, handleSave 
  } = useExamEditor(initialExam, onUpdate);

  const [activeTab, setActiveTab] = useState<'steps' | 'summary'>('steps');
  const [isResearching, setIsResearching] = useState(false);
  const [sidePathoSign, setSidePathoSign] = useState<string | null>(null);
  const [sidePathoData, setSidePathoData] = useState<ClinicalCorrelation | null>(null);
  const [loadingSidePatho, setLoadingSidePatho] = useState(false);
  const [enlargedImage, setEnlargedImage] = useState<{src: string, alt: string} | null>(null);
  const [checkedSteps, setCheckedSteps] = useState<Set<string>>(new Set());
  const [isChecklistMode, setIsChecklistMode] = useState(false);

  const gemini = useMemo(() => new GeminiService(), []);
  const style = SYSTEM_THEMES[exam.system] || DEFAULT_STYLE;

  const categorizedSteps = useMemo(() => {
    const groups: Record<string, ExamStep[]> = {};
    exam.steps.forEach(step => {
      const cat = step.category || 'General';
      if (!groups[cat]) groups[cat] = [];
      groups[cat].push(step);
    });
    return groups;
  }, [exam.steps]);

  useEffect(() => {
    const research = async () => {
      if (exam.steps.length === 0 && navigator.onLine && !exam.isDownloaded) {
        setIsResearching(true);
        try {
          const res = await gemini.populateExamination(exam);
          setExam(prev => ({ ...prev, ...res, isDraft: false }));
        } catch (e) { console.error(e); }
        finally { setIsResearching(false); }
      }
    };
    research();
  }, [exam.id, exam.isDownloaded, gemini, setExam]);

  const fetchClinicalCorrelation = async (sign: string) => {
    if (!navigator.onLine) return;
    setSidePathoSign(sign);
    setLoadingSidePatho(true);
    setSidePathoData(null);
    try {
      const data = await gemini.getClinicalCorrelation(sign, exam.system, false);
      setSidePathoData(data);
    } catch (e) { console.error(e); }
    finally { setLoadingSidePatho(false); }
  };

  const progress = exam.steps.length > 0 ? Math.round((checkedSteps.size / exam.steps.length) * 100) : 0;

  if (isResearching) return (
    <div className="h-full flex flex-col items-center justify-center p-20 bg-white">
      <div className="relative mb-8">
        <div className="w-20 h-20 border-4 border-blue-50 rounded-full"></div>
        <div className="w-20 h-20 border-4 border-blue-600 border-t-transparent rounded-full animate-spin absolute top-0"></div>
        <BrainCircuit className="w-8 h-8 text-blue-600 absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2" />
      </div>
      <p className="text-[10px] font-black uppercase text-slate-400 tracking-[0.3em] mb-2">Synthesizing Protocol</p>
    </div>
  );

  return (
    <div className="min-h-full bg-white animate-in fade-in duration-700 relative">
      {enlargedImage && (
        <ImageModal src={enlargedImage.src} alt={enlargedImage.alt} onClose={() => setEnlargedImage(null)} />
      )}

      {sidePathoSign && (
        <CorrelationModal 
          sign={sidePathoSign} 
          data={sidePathoData} 
          loading={loadingSidePatho} 
          onClose={() => setSidePathoSign(null)} 
          onEnlarge={(src, alt) => setEnlargedImage({ src, alt })}
        />
      )}

      {isEditMode && isDirty && (
        <div className="fixed bottom-10 left-1/2 -translate-x-1/2 z-[60] animate-in slide-in-from-bottom-10">
          <button onClick={handleSave} className="flex items-center gap-3 px-8 py-4 bg-amber-600 text-white rounded-[24px] shadow-2xl hover:bg-amber-700 transition-all font-black uppercase text-[11px] tracking-widest">
            <Save className="w-5 h-5" /> Commit Changes to Vault
          </button>
        </div>
      )}

      <div className="sticky top-0 z-40 bg-white/80 backdrop-blur-xl border-b border-slate-100 px-8 py-4 flex items-center justify-between">
        <div className="flex items-center gap-6">
          <button onClick={onBack} className="p-2 hover:bg-slate-50 rounded-xl text-slate-400 transition-colors"><ArrowLeft className="w-5 h-5" /></button>
          <div className="flex items-center gap-2">
            <span className={`text-[9px] font-black uppercase tracking-widest ${style.text}`}>{exam.system}</span>
            <span className="w-1 h-1 rounded-full bg-slate-200" />
            {isEditMode ? (
              <input type="text" value={exam.name} onChange={(e) => updateGeneralField('name', e.target.value)} className="bg-amber-50 border-b border-amber-300 text-lg font-black outline-none px-1 rounded-sm focus:ring-1 focus:ring-amber-400" />
            ) : <h1 className="text-lg font-black text-slate-900">{exam.name}</h1>}
          </div>
        </div>
        <div className="flex items-center gap-4">
          <div className="flex items-center gap-2 px-4 py-2 bg-slate-50 rounded-2xl border border-slate-100"><span className="text-[10px] font-black text-slate-900">{progress}% Complete</span></div>
          <button onClick={() => setIsChecklistMode(!isChecklistMode)} className={`px-6 py-2.5 rounded-2xl text-[10px] font-black uppercase flex items-center gap-2 shadow-xl transition-all ${isChecklistMode ? 'bg-emerald-600 text-white' : 'bg-slate-900 text-white'}`}><ListCheck className="w-4 h-4" /> {isChecklistMode ? 'Exit OSCE' : 'Start OSCE'}</button>
        </div>
      </div>

      <div className="max-w-5xl mx-auto py-12 px-8">
        <div className="grid grid-cols-1 lg:grid-cols-5 gap-12 mb-16">
          <div className="lg:col-span-3">
             <div className="flex items-center gap-3 mb-6">
                <div className={`p-2 rounded-xl ${style.bg} ${style.text}`}>{style.icon}</div>
                {isEditMode ? <span className="flex items-center gap-2 text-amber-600 font-black uppercase text-[10px] tracking-widest"><Edit3 className="w-3 h-3" /> Drafting Mode</span> : <h2 className="text-3xl font-black text-slate-900 tracking-tighter leading-tight">{exam.name}</h2>}
             </div>
             {isEditMode ? (
               <textarea value={exam.shortDescription} onChange={(e) => updateGeneralField('shortDescription', e.target.value)} className="w-full min-h-[100px] p-4 bg-amber-50/30 border border-amber-200 rounded-2xl text-base text-slate-600 font-medium leading-[1.8] outline-none focus:ring-2 focus:ring-amber-400" />
             ) : <p className="text-base text-slate-500 font-medium leading-[1.8] mb-8">{exam.shortDescription}</p>}
          </div>
          <div className="lg:col-span-2">
            <MedImage src={!exam.localHeaderImageUrl ? exam.headerImageUrl : undefined} localId={exam.localHeaderImageUrl} alt="Anatomy Header" label="Header Matrix" fallbackIcon={style.icon} onEnlarge={(src, alt) => setEnlargedImage({src, alt})} />
          </div>
        </div>

        <div className="flex justify-center mb-16">
          <div className="inline-flex p-1.5 bg-slate-100 rounded-[24px] border border-slate-200/50 shadow-inner">
            {[
              { id: 'steps', label: 'Protocol', icon: <ClipboardList className="w-4 h-4" /> },
              { id: 'summary', label: 'Clinical Summary', icon: <Info className="w-4 h-4" /> }
            ].map((tab) => (
              <button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`flex items-center gap-3 px-6 py-3 rounded-2xl text-[10px] font-black uppercase transition-all ${activeTab === tab.id ? 'bg-white text-slate-900 shadow-xl' : 'text-slate-400'}`}>{tab.icon} {tab.label}</button>
            ))}
          </div>
        </div>

        {activeTab === 'steps' && (
          <div className="space-y-12">
            {Object.entries(categorizedSteps).map(([category, steps], catIdx) => (
              <div key={category} className="animate-in fade-in" style={{ animationDelay: `${catIdx * 100}ms` }}>
                <h3 className="text-xl font-black text-slate-900 tracking-tight uppercase mb-8 flex items-center gap-4"><div className={`h-6 w-1 rounded-full ${style.secondary}`} />{category}</h3>
                <div className="bg-white rounded-[40px] border border-slate-100 shadow-sm overflow-hidden divide-y divide-slate-50">
                  {steps.map((step) => {
                    const isChecked = checkedSteps.has(step.id);
                    return (
                      <div key={step.id} className={`p-8 transition-all flex items-start gap-8 ${isChecked ? 'bg-emerald-50/30' : ''} ${isEditMode ? 'hover:bg-amber-50/10' : ''}`}>
                        {isChecklistMode ? (
                          <button onClick={() => setCheckedSteps(p => { const n = new Set(p); if (n.has(step.id)) n.delete(step.id); else n.add(step.id); return n; })} className={`w-12 h-12 rounded-2xl border-2 flex items-center justify-center shrink-0 ${isChecked ? 'bg-emerald-600 border-emerald-600 text-white shadow-lg' : 'bg-white border-slate-200'}`}>{isChecked && <CheckCircle2 className="w-6 h-6" />}</button>
                        ) : <div className={`w-3 h-3 rounded-full mt-4 shrink-0 ${style.secondary} opacity-40`} />}
                        <div className="flex-1">
                          {isEditMode ? (
                            <div className="space-y-3">
                              <input type="text" value={step.title} onChange={(e) => updateStepField(step.id, 'title', e.target.value)} className="w-full bg-amber-50 border-b border-amber-300 text-base font-black outline-none focus:ring-1 focus:ring-amber-400 p-1" />
                              <textarea value={step.description} onChange={(e) => updateStepField(step.id, 'description', e.target.value)} className="w-full min-h-[60px] p-3 bg-amber-50/30 border border-amber-200 rounded-xl text-[13px] leading-relaxed outline-none focus:ring-1 focus:ring-amber-400" />
                            </div>
                          ) : (
                            <><h4 className="text-base font-black text-slate-900 mb-2">{step.title}</h4><p className="text-[13px] leading-relaxed text-slate-500 font-medium mb-6">{step.description}</p></>
                          )}
                          <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mt-6">
                            <div className="flex-1">
                              {step.positiveFindings && step.positiveFindings.length > 0 && (
                                <div className="space-y-4">
                                  <div className="flex items-center gap-2 text-rose-500"><Zap className="w-3.5 h-3.5" /><span className="text-[9px] font-black uppercase tracking-widest">Pathological Signs</span></div>
                                  <div className="flex flex-wrap gap-2">
                                    {step.positiveFindings.map((f, i) => (
                                      <button key={i} onClick={() => fetchClinicalCorrelation(f.description)} className="group/sign flex items-center gap-3 px-4 py-2.5 bg-rose-50 border border-rose-100 rounded-2xl hover:bg-rose-600 hover:text-white transition-all text-left"><Zap className="w-3 h-3 group-hover/sign:text-white" /><span className="text-[10px] font-black uppercase italic leading-none">{f.description}</span></button>
                                    ))}
                                  </div>
                                </div>
                              )}
                            </div>
                            {(step.localImageUrl || step.imageUrl) && (
                              <div className="max-w-[200px]"><MedImage src={!step.localImageUrl ? step.imageUrl : undefined} localId={step.localImageUrl} alt={step.title} label="Protocol Reference" fallbackIcon={<Layers />} onEnlarge={(src, alt) => setEnlargedImage({src, alt})} /></div>
                            )}
                          </div>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default ExamView;

