                                <ImageIcon className="w-4 h-4 text-slate-400" />
                                <input 
                                  placeholder="Step Image Prompt (for AI generation)" 
                                  className="bg-transparent text-[10px] font-bold outline-none flex-1"
                                  value={step.imagePrompt || ''}
                                  onChange={(e) => updateStepField(step.id, 'imagePrompt', e.target.value)}
                                />
                              </div>
                            </div>
                          ) : (
                            <><h4 className="text-base font-black text-slate-900 mb-2">{step.title}</h4><p className="text-[13px] leading-relaxed text-slate-500 font-medium mb-6">{step.description}</p></>
                          )}

                          <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mt-6">
                            <div className="flex-1">
                              <div className="space-y-4">
                                <div className="flex items-center gap-2 text-rose-500"><Zap className="w-3.5 h-3.5" /><span className="text-[9px] font-black uppercase tracking-widest">Pathological Signs</span></div>
                                <div className="flex flex-wrap gap-2">
                                  {(step.positiveFindings || []).map((f, i) => (
                                    <div key={i} className="flex items-center">
                                      <button onClick={() => fetchClinicalCorrelation(f.description)} className="group/sign flex items-center gap-3 px-4 py-2.5 bg-rose-50 border border-rose-100 rounded-l-2xl hover:bg-rose-600 hover:text-white transition-all text-left"><Zap className="w-3 h-3 group-hover/sign:text-white" /><span className="text-[10px] font-black uppercase italic leading-none">{f.description}</span></button>
                                      {isEditMode && (
                                        <button onClick={() => removeFinding(step.id, i)} className="px-2 py-2.5 bg-rose-100 text-rose-600 border border-l-0 border-rose-200 rounded-r-2xl hover:bg-rose-200"><X className="w-3 h-3" /></button>
                                      )}
                                    </div>
                                  ))}
                                  {isEditMode && (
                                    <form 
                                      className="flex items-center" 
                                      onSubmit={(e) => { e.preventDefault(); if(newFindingText[step.id]) { addFinding(step.id, newFindingText[step.id]); setNewFindingText({...newFindingText, [step.id]: ''}); } }}
                                    >
                                      <input 
                                        className="px-4 py-2 bg-amber-50 border border-amber-200 rounded-l-2xl text-[10px] font-bold outline-none w-32 focus:ring-1 focus:ring-amber-400"
                                        placeholder="Add sign..."
                                        value={newFindingText[step.id] || ''}
                                        onChange={(e) => setNewFindingText({...newFindingText, [step.id]: e.target.value})}
                                      />
                                      <button type="submit" className="px-3 py-2.5 bg-amber-600 text-white rounded-r-2xl"><Plus className="w-3 h-3" /></button>
                                    </form>
                                  )}
                                </div>
                              </div>
                            </div>
                            {(step.localImageUrl || step.imageUrl) && (
                              <div className="max-w-[200px]"><MedImage src={!step.localImageUrl ? step.imageUrl : undefined} localId={step.localImageUrl} alt={step.title} label="Protocol Reference" fallbackIcon={<Layers />} onEnlarge={(src, alt) => setEnlargedImage({src, alt})} /></div>
                            )}
                          </div>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            ))}

            {isEditMode && (
              <button 
                onClick={() => addStep('New Section')}
                className="w-full py-10 border-2 border-dashed border-amber-200 rounded-[40px] text-amber-600 font-black uppercase text-[12px] tracking-widest hover:bg-amber-50 transition-all flex flex-col items-center gap-3"
              >
                <Plus className="w-8 h-8" /> Add New Examination Section
              </button>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

