import { useState, useEffect } from 'react';
import { Examination, ExamStep, ClinicalFinding } from '../types';
import { storage } from '../services/storageService';

export function useExamEditor(initialExam: Examination, onUpdate?: (updated: Examination) => void) {
  const [exam, setExam] = useState(initialExam);
  const [isDirty, setIsDirty] = useState(false);

  useEffect(() => {
    setExam(initialExam);
    setIsDirty(false);
  }, [initialExam]);

  const updateGeneralField = (field: keyof Examination, value: any) => {
    setExam(prev => ({ ...prev, [field]: value }));
    setIsDirty(true);
  };

  const updateStepField = (stepId: string, field: keyof ExamStep, value: any) => {
    setExam(prev => {
      const newSteps = prev.steps.map(s => s.id === stepId ? { ...s, [field]: value } : s);
      return { ...prev, steps: newSteps };
    });
    setIsDirty(true);
  };

  const addStep = (category: string) => {
    const newStep: ExamStep = {
      id: `step-${Math.random().toString(36).substr(2, 9)}`,
      title: 'New Clinical Step',
      description: 'Describe the maneuver...',
      category: category,
      positiveFindings: []
    };
    setExam(prev => ({ ...prev, steps: [...prev.steps, newStep] }));
    setIsDirty(true);
  };

  const removeStep = (stepId: string) => {
    setExam(prev => ({ ...prev, steps: prev.steps.filter(s => s.id !== stepId) }));
    setIsDirty(true);
  };

  const moveStep = (index: number, direction: 'up' | 'down') => {
    setExam(prev => {
      const newSteps = [...prev.steps];
      const targetIndex = direction === 'up' ? index - 1 : index + 1;
      if (targetIndex < 0 || targetIndex >= newSteps.length) return prev;
      [newSteps[index], newSteps[targetIndex]] = [newSteps[targetIndex], newSteps[index]];
      return { ...prev, steps: newSteps };
    });
    setIsDirty(true);
  };

  const addFinding = (stepId: string, description: string) => {
    setExam(prev => {
      const newSteps = prev.steps.map(s => {
        if (s.id === stepId) {
          const findings = s.positiveFindings || [];
          return { ...s, positiveFindings: [...findings, { description }] };
        }
        return s;
      });
      return { ...prev, steps: newSteps };
    });
    setIsDirty(true);
  };

  const removeFinding = (stepId: string, findingIndex: number) => {
    setExam(prev => {
      const newSteps = prev.steps.map(s => {
        if (s.id === stepId && s.positiveFindings) {
          return { ...s, positiveFindings: s.positiveFindings.filter((_, i) => i !== findingIndex) };
        }
        return s;
      });
      return { ...prev, steps: newSteps };
    });
    setIsDirty(true);
  };

  const handleSave = async () => {
    try {
      const updatedExam = { ...exam, isDownloaded: true, lastUpdated: Date.now() };
      await storage.saveExamination(updatedExam);
      setIsDirty(false);
      onUpdate?.(updatedExam);
      return true;
    } catch (e) {
      console.error("Save failed", e);
      return false;
    }
  };

  return {
    exam,
    setExam,
    isDirty,
    setIsDirty,
    updateGeneralField,
    updateStepField,
    addStep,
    removeStep,
    moveStep,
    addFinding,
    removeFinding,
    handleSave
  };
}

import React, { useState, useEffect, useMemo } from 'react';
import { Examination, ClinicalCorrelation, ExamStep } from '../types';
import { GeminiService } from '../services/geminiService';
import { SYSTEM_THEMES, DEFAULT_STYLE } from '../theme';
import { useExamEditor } from '../hooks/useExamEditor';
import MedImage from './common/MedImage';
import ImageModal from './ImageModal';
import CorrelationModal from './ExamView/CorrelationModal';
import { 
  ClipboardList, Info, Zap, CheckCircle2, ListCheck, BrainCircuit, Layers, 
  ArrowLeft, GraduationCap, Microscope, Save, Edit3, Trash2, ChevronUp, 
  ChevronDown, Plus, X, Image as ImageIcon, BookOpen, Hash
} from 'lucide-react';

interface ExamViewProps {
  exam: Examination;
  onBack: () => void;
  isEditMode?: boolean;
  onUpdate?: (updated: Examination) => void;
}

const ExamView: React.FC<ExamViewProps> = ({ exam: initialExam, onBack, isEditMode, onUpdate }) => {
  const { 
    exam, setExam, isDirty, updateGeneralField, updateStepField, 
    addStep, removeStep, moveStep, addFinding, removeFinding, handleSave 
  } = useExamEditor(initialExam, onUpdate);

  const [activeTab, setActiveTab] = useState<'steps' | 'summary'>('steps');
  const [isResearching, setIsResearching] = useState(false);
  const [sidePathoSign, setSidePathoSign] = useState<string | null>(null);
  const [sidePathoData, setSidePathoData] = useState<ClinicalCorrelation | null>(null);
  const [loadingSidePatho, setLoadingSidePatho] = useState(false);
  const [enlargedImage, setEnlargedImage] = useState<{src: string, alt: string} | null>(null);
  const [checkedSteps, setCheckedSteps] = useState<Set<string>>(new Set());
  const [isChecklistMode, setIsChecklistMode] = useState(false);
  const [newFindingText, setNewFindingText] = useState<Record<string, string>>({});

  const gemini = useMemo(() => new GeminiService(), []);
  const style = SYSTEM_THEMES[exam.system] || DEFAULT_STYLE;

  const categorizedSteps = useMemo(() => {
    const groups: Record<string, { steps: ExamStep[], indices: number[] }> = {};
    exam.steps.forEach((step, index) => {
      const cat = step.category || 'General';
      if (!groups[cat]) groups[cat] = { steps: [], indices: [] };
      groups[cat].steps.push(step);
      groups[cat].indices.push(index);
    });
    return groups;
  }, [exam.steps]);

  useEffect(() => {
    const research = async () => {
      if (exam.steps.length === 0 && navigator.onLine && !exam.isDownloaded) {
        setIsResearching(true);
        try {
          const res = await gemini.populateExamination(exam);
          setExam(prev => ({ ...prev, ...res, isDraft: false }));
        } catch (e) { console.error(e); }
        finally { setIsResearching(false); }
      }
    };
    research();
  }, [exam.id, exam.isDownloaded, gemini, setExam]);

  const fetchClinicalCorrelation = async (sign: string) => {
    if (!navigator.onLine) return;
    setSidePathoSign(sign);
    setLoadingSidePatho(true);
    setSidePathoData(null);
    try {
      const data = await gemini.getClinicalCorrelation(sign, exam.system, false);
      setSidePathoData(data);
    } catch (e) { console.error(e); }
    finally { setLoadingSidePatho(false); }
  };

  const progress = exam.steps.length > 0 ? Math.round((checkedSteps.size / exam.steps.length) * 100) : 0;

  if (isResearching) return (
    <div className="h-full flex flex-col items-center justify-center p-20 bg-white">
      <div className="relative mb-8">
        <div className="w-20 h-20 border-4 border-blue-50 rounded-full"></div>
        <div className="w-20 h-20 border-4 border-blue-600 border-t-transparent rounded-full animate-spin absolute top-0"></div>
        <BrainCircuit className="w-8 h-8 text-blue-600 absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2" />
      </div>
      <p className="text-[10px] font-black uppercase text-slate-400 tracking-[0.3em] mb-2">Synthesizing Protocol</p>
    </div>
  );

  return (
    <div className="min-h-full bg-white animate-in fade-in duration-700 relative pb-40">
      {enlargedImage && (
        <ImageModal src={enlargedImage.src} alt={enlargedImage.alt} onClose={() => setEnlargedImage(null)} />
      )}

      {sidePathoSign && (
        <CorrelationModal 
          sign={sidePathoSign} 
          data={sidePathoData} 
          loading={loadingSidePatho} 
          onClose={() => setSidePathoSign(null)} 
          onEnlarge={(src, alt) => setEnlargedImage({ src, alt })}
        />
      )}

      {isEditMode && isDirty && (
        <div className="fixed bottom-10 left-1/2 -translate-x-1/2 z-[60] animate-in slide-in-from-bottom-10">
          <button onClick={handleSave} className="flex items-center gap-3 px-8 py-4 bg-amber-600 text-white rounded-[24px] shadow-2xl hover:bg-amber-700 transition-all font-black uppercase text-[11px] tracking-widest">
            <Save className="w-5 h-5" /> Commit Changes to Vault
          </button>
        </div>
      )}

      <div className="sticky top-0 z-40 bg-white/80 backdrop-blur-xl border-b border-slate-100 px-8 py-4 flex items-center justify-between">
        <div className="flex items-center gap-6">
          <button onClick={onBack} className="p-2 hover:bg-slate-50 rounded-xl text-slate-400 transition-colors"><ArrowLeft className="w-5 h-5" /></button>
          <div className="flex items-center gap-2">
            <span className={`text-[9px] font-black uppercase tracking-widest ${style.text}`}>{exam.system}</span>
            <span className="w-1 h-1 rounded-full bg-slate-200" />
            {isEditMode ? (
              <input type="text" value={exam.name} onChange={(e) => updateGeneralField('name', e.target.value)} className="bg-amber-50 border-b border-amber-300 text-lg font-black outline-none px-1 rounded-sm focus:ring-1 focus:ring-amber-400" />
            ) : <h1 className="text-lg font-black text-slate-900">{exam.name}</h1>}
          </div>
        </div>
        <div className="flex items-center gap-4">
          <div className="flex items-center gap-2 px-4 py-2 bg-slate-50 rounded-2xl border border-slate-100"><span className="text-[10px] font-black text-slate-900">{progress}% Complete</span></div>
          <button onClick={() => setIsChecklistMode(!isChecklistMode)} className={`px-6 py-2.5 rounded-2xl text-[10px] font-black uppercase flex items-center gap-2 shadow-xl transition-all ${isChecklistMode ? 'bg-emerald-600 text-white' : 'bg-slate-900 text-white'}`}><ListCheck className="w-4 h-4" /> {isChecklistMode ? 'Exit OSCE' : 'Start OSCE'}</button>
        </div>
      </div>

      <div className="max-w-5xl mx-auto py-12 px-8">
        <div className="grid grid-cols-1 lg:grid-cols-5 gap-12 mb-16">
