          </div>
        )}

        {activeTab === 'summary' && (
          <div className="animate-in slide-in-from-bottom-6 duration-700">
             <div className="bg-slate-50/50 p-12 rounded-[60px] border border-slate-100 relative">
                <div className="absolute top-10 right-10 text-slate-100"><BookOpen className="w-32 h-32" /></div>
                <div className="relative z-10">
                   <h3 className="text-3xl font-black text-slate-900 tracking-tight mb-8 flex items-center gap-4">
                     <GraduationCap className="w-8 h-8 text-blue-600" />
                     Clinical Synthesis & Pearls
                   </h3>
                   {isEditMode ? (
                     <textarea 
                       className="w-full min-h-[400px] p-8 bg-white border border-amber-200 rounded-[40px] text-base leading-[2] text-slate-700 font-medium italic outline-none focus:ring-4 focus:ring-amber-500/10"
                       value={exam.shortDescription}
                       onChange={(e) => updateGeneralField('shortDescription', e.target.value)}
                       placeholder="Enter clinical pearls, not-to-miss signs, and diagnostic summaries..."
                     />
                   ) : (
                     <div className="space-y-8">
                       <p className="text-lg leading-[2.2] text-slate-600 font-medium italic border-l-4 border-blue-500 pl-8">
                         {exam.shortDescription}
                       </p>
                       <div className="grid grid-cols-1 md:grid-cols-2 gap-8 pt-12">
                         <div className="p-8 bg-white rounded-[40px] border border-slate-200 shadow-sm">
                            <h4 className="text-[10px] font-black uppercase tracking-widest text-blue-600 mb-4 flex items-center gap-2">
                              <Zap className="w-4 h-4" /> Exam Focus
                            </h4>
                            <p className="text-sm text-slate-500 leading-relaxed">
                              Focus on precise maneuver execution and fluid transition between anatomical regions.
                            </p>
                         </div>
                         <div className="p-8 bg-white rounded-[40px] border border-slate-200 shadow-sm">
                            <h4 className="text-[10px] font-black uppercase tracking-widest text-rose-600 mb-4 flex items-center gap-2">
                              <Microscope className="w-4 h-4" /> Red Flags
                            </h4>
                            <p className="text-sm text-slate-500 leading-relaxed">
                              Immediate senior review for symptoms of clinical instability or rapidly progressing systemic stigmata.
                            </p>
                         </div>
                       </div>
                     </div>
                   )}
                </div>
             </div>
          </div>
        )}
      </div>
    </div>
  );
};

