import React, { useState, useEffect } from 'react';
import { HardDrive, Sparkles, ImageOff, Maximize2, Move, Trash2, Layout, LayoutPanelLeft, LayoutPanelTop, Plus, Wand2, Upload } from 'lucide-react';
import { getLocalAssetUrl } from '../../utils/assetHelper';
import { ImageSize, ImagePosition, ImageConfig } from '../../types';

interface MedImageProps {
  src?: string;
  localId?: string;
  alt: string;
  fallbackIcon?: React.ReactNode;
  label: string;
  onEnlarge?: (src: string, alt: string) => void;
  className?: string;
  isEditMode?: boolean;
  config?: ImageConfig;
  onUpdateConfig?: (config: ImageConfig) => void;
  onDelete?: () => void;
  onUpload?: () => void;
  onGenerate?: () => void;
}

const MedImage: React.FC<MedImageProps> = ({ 
  src, localId, alt, fallbackIcon, label, onEnlarge, className = "",
  isEditMode, config = { size: 'md', position: 'right' }, onUpdateConfig, onDelete, onUpload, onGenerate
}) => {
  const [error, setError] = useState(false);
  const [resolvedUrl, setResolvedUrl] = useState<string | null>(null);

  useEffect(() => {
    let mounted = true;
    if (localId) {
      getLocalAssetUrl(localId).then(url => {
        if (mounted) setResolvedUrl(url);
      });
    } else {
      setResolvedUrl(null);
    }
    return () => { mounted = false; };
  }, [localId]);

  const activeSrc = resolvedUrl || src;

  const sizeClasses = {
    sm: 'max-w-[150px]',
    md: 'max-w-[300px]',
    lg: 'max-w-[500px]',
    full: 'w-full'
  };

  if (!activeSrc || error) {
    return (
      <div className={`w-full aspect-video bg-slate-50 border-2 border-dashed border-slate-200 rounded-3xl flex flex-col items-center justify-center p-8 text-slate-300 relative group/noimg ${className}`}>
        <div className="mb-3 opacity-30 scale-150">{fallbackIcon || <ImageOff />}</div>
        <p className="text-[9px] font-black uppercase tracking-widest text-slate-400">{label} Empty</p>

        {isEditMode && (
          <div className="absolute inset-0 bg-white/60 backdrop-blur-sm opacity-0 group-hover/noimg:opacity-100 transition-opacity flex items-center justify-center gap-4 rounded-3xl">
             <button onClick={onGenerate} className="p-3 bg-blue-600 text-white rounded-2xl hover:bg-blue-700 shadow-xl transition-all" title="AI Generate">
               <Wand2 className="w-5 h-5" />
             </button>
             <button onClick={onUpload} className="p-3 bg-slate-900 text-white rounded-2xl hover:bg-black shadow-xl transition-all" title="Upload Local">
               <Upload className="w-5 h-5" />
             </button>
          </div>
        )}
      </div>
    );
  }

  return (
    <div 
      className={`relative group/viz rounded-3xl overflow-hidden border border-slate-200 shadow-inner bg-slate-50 transition-all duration-500 ${sizeClasses[config.size]} ${className}`}
    >
      <img 
        src={activeSrc} 
        alt={alt} 
        className="w-full h-auto object-cover transition-transform duration-1000 group-hover/viz:scale-[1.05] cursor-zoom-in" 
        onClick={() => onEnlarge?.(activeSrc, alt)}
        onError={() => setError(true)}
      />

      {/* Default Label Overlay */}
      <div className="absolute bottom-3 left-3 right-3 flex items-center justify-between px-3 py-1.5 bg-black/40 backdrop-blur-md rounded-xl opacity-100 group-hover/viz:bg-black/60 transition-all pointer-events-none">
        <div className="flex items-center gap-2">
           <span className="text-[8px] font-black text-white uppercase tracking-widest">{label}</span>
           {resolvedUrl && <HardDrive className="w-2.5 h-2.5 text-emerald-400" />}
        </div>
        <Sparkles className="w-2.5 h-2.5 text-amber-400" />
      </div>

      {/* Edit Controls Overlay */}
      {isEditMode && (
        <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-[2px] opacity-0 group-hover/viz:opacity-100 transition-all flex flex-col items-center justify-center gap-6">
           <div className="flex items-center gap-2 p-2 bg-white/90 rounded-2xl shadow-2xl backdrop-blur-xl">
              {(['sm', 'md', 'lg', 'full'] as ImageSize[]).map((s) => (
                <button 
                  key={s}
                  onClick={() => onUpdateConfig?.({ ...config, size: s })}
                  className={`px-3 py-1.5 rounded-lg text-[9px] font-black uppercase transition-all ${config.size === s ? 'bg-blue-600 text-white shadow-lg' : 'hover:bg-slate-100 text-slate-400'}`}
                >
                  {s}
                </button>
              ))}
           </div>

           <div className="flex items-center gap-2 p-2 bg-white/90 rounded-2xl shadow-2xl backdrop-blur-xl">
              <button 
                onClick={() => onUpdateConfig?.({ ...config, position: 'left' })}
                className={`p-2 rounded-lg transition-all ${config.position === 'left' ? 'bg-slate-900 text-white shadow-lg' : 'hover:bg-slate-100 text-slate-400'}`}
                title="Align Left"
              >
                <LayoutPanelLeft className="w-4 h-4" />
              </button>
              <button 
                onClick={() => onUpdateConfig?.({ ...config, position: 'right' })}
                className={`p-2 rounded-lg transition-all ${config.position === 'right' ? 'bg-slate-900 text-white shadow-lg' : 'hover:bg-slate-100 text-slate-400'}`}
                title="Align Right"
              >
                <LayoutPanelLeft className="w-4 h-4 rotate-180" />
              </button>
              <button 
                onClick={() => onUpdateConfig?.({ ...config, position: 'top' })}
                className={`p-2 rounded-lg transition-all ${config.position === 'top' ? 'bg-slate-900 text-white shadow-lg' : 'hover:bg-slate-100 text-slate-400'}`}
                title="Align Top (Hero)"
              >
                <LayoutPanelTop className="w-4 h-4" />
              </button>
           </div>

           <div className="flex items-center gap-3">
              <button 
                onClick={onUpload}
                className="p-3 bg-white text-slate-900 rounded-2xl hover:bg-slate-100 shadow-xl transition-all"
                title="Replace Image"
              >
                <Upload className="w-5 h-5" />
              </button>
              <button 
                onClick={onDelete}
                className="p-3 bg-red-600 text-white rounded-2xl hover:bg-red-700 shadow-xl transition-all"
                title="Delete Image"
              >
                <Trash2 className="w-5 h-5" />
              </button>
           </div>
        </div>
      )}
    </div>
  );
};

export default MedImage;

import React, { useState, useEffect, useMemo } from 'react';
import { Examination, ClinicalCorrelation, ExamStep, ImageConfig } from '../types';
import { GeminiService } from '../services/geminiService';
import { SYSTEM_THEMES, DEFAULT_STYLE } from '../theme';
import { useExamEditor } from '../hooks/useExamEditor';
import { storage } from '../services/storageService';
import MedImage from './common/MedImage';
import ImageModal from './ImageModal';
import CorrelationModal from './ExamView/CorrelationModal';
import { 
  ClipboardList, Info, Zap, CheckCircle2, ListCheck, BrainCircuit, Layers, 
  ArrowLeft, GraduationCap, Microscope, Save, Edit3, Trash2, ChevronUp, 
  ChevronDown, Plus, X, Image as ImageIcon, BookOpen, Hash, RefreshCw
} from 'lucide-react';

interface ExamViewProps {
  exam: Examination;
  onBack: () => void;
  isEditMode?: boolean;
  onUpdate?: (updated: Examination) => void;
}

const ExamView: React.FC<ExamViewProps> = ({ exam: initialExam, onBack, isEditMode, onUpdate }) => {
  const { 
    exam, setExam, isDirty, updateGeneralField, updateStepField, 
    addStep, removeStep, moveStep, addFinding, removeFinding, handleSave 
  } = useExamEditor(initialExam, onUpdate);

  const [activeTab, setActiveTab] = useState<'steps' | 'summary'>('steps');
  const [isResearching, setIsResearching] = useState(false);
  const [sidePathoSign, setSidePathoSign] = useState<string | null>(null);
  const [sidePathoData, setSidePathoData] = useState<ClinicalCorrelation | null>(null);
  const [loadingSidePatho, setLoadingSidePatho] = useState(false);
  const [enlargedImage, setEnlargedImage] = useState<{src: string, alt: string} | null>(null);
  const [checkedSteps, setCheckedSteps] = useState<Set<string>>(new Set());
  const [isChecklistMode, setIsChecklistMode] = useState(false);
  const [newFindingText, setNewFindingText] = useState<Record<string, string>>({});

  const gemini = useMemo(() => new GeminiService(), []);
  const style = SYSTEM_THEMES[exam.system] || DEFAULT_STYLE;

  const categorizedSteps = useMemo(() => {
    const groups: Record<string, { steps: ExamStep[], indices: number[] }> = {};
    exam.steps.forEach((step, index) => {
      const cat = step.category || 'General';
      if (!groups[cat]) groups[cat] = { steps: [], indices: [] };
      groups[cat].steps.push(step);
      groups[cat].indices.push(index);
    });
    return groups;
  }, [exam.steps]);

  useEffect(() => {
    const research = async () => {
      if (exam.steps.length === 0 && navigator.onLine && !exam.isDownloaded) {
        setIsResearching(true);
        try {
          const res = await gemini.populateExamination(exam);
          setExam(prev => ({ ...prev, ...res, isDraft: false }));
        } catch (e) { console.error(e); }
        finally { setIsResearching(false); }
      }
    };
    research();
  }, [exam.id, exam.isDownloaded, gemini, setExam]);

  const fetchClinicalCorrelation = async (sign: string) => {
    if (!navigator.onLine) return;
    setSidePathoSign(sign);
    setLoadingSidePatho(true);
    setSidePathoData(null);
    try {
      const data = await gemini.getClinicalCorrelation(sign, exam.system, false);
      setSidePathoData(data);
    } catch (e) { console.error(e); }
    finally { setLoadingSidePatho(false); }
  };

  const handleImageUpload = async (stepId: string | 'header') => {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = 'image/*';
    input.onchange = async (e: any) => {
      const file = e.target.files?.[0];
      if (!file) return;

      const assetId = `custom_${Math.random().toString(36).substr(2, 9)}`;
      await storage.saveAsset(assetId, file);

      if (stepId === 'header') {
        updateGeneralField('localHeaderImageUrl', assetId);
      } else {
        updateStepField(stepId, 'localImageUrl', assetId);
      }
    };
    input.click();
  };

  const handleImageGenerate = async (stepId: string | 'header') => {
    const prompt = stepId === 'header' ? exam.headerImagePrompt : exam.steps.find(s => s.id === stepId)?.imagePrompt;
    if (!prompt) {
      alert("Please provide an image prompt first.");
      return;
    }

    try {
      const url = await gemini.generateIllustration(prompt, false);
      if (url) {
        if (stepId === 'header') {
          updateGeneralField('headerImageUrl', url);
        } else {
          updateStepField(stepId, 'imageUrl', url);
        }
      }
    } catch (e) {
      alert("Generation failed. Check connectivity.");
    }
  };

  const progress = exam.steps.length > 0 ? Math.round((checkedSteps.size / exam.steps.length) * 100) : 0;

  if (isResearching) return (
    <div className="h-full flex flex-col items-center justify-center p-20 bg-white">
      <div className="relative mb-8">
        <div className="w-20 h-20 border-4 border-blue-50 rounded-full"></div>
        <div className="w-20 h-20 border-4 border-blue-600 border-t-transparent rounded-full animate-spin absolute top-0"></div>
        <BrainCircuit className="w-8 h-8 text-blue-600 absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2" />
      </div>
      <p className="text-[10px] font-black uppercase text-slate-400 tracking-[0.3em] mb-2">Synthesizing Protocol</p>
    </div>
  );

  return (
    <div className="min-h-full bg-white animate-in fade-in duration-700 relative pb-40">
      {enlargedImage && (
        <ImageModal src={enlargedImage.src} alt={enlargedImage.alt} onClose={() => setEnlargedImage(null)} />
      )}

      {sidePathoSign && (
        <CorrelationModal 
          sign={sidePathoSign} 
          data={sidePathoData} 
          loading={loadingSidePatho} 
          onClose={() => setSidePathoSign(null)} 
          onEnlarge={(src, alt) => setEnlargedImage({ src, alt })}
        />
      )}

      {isEditMode && isDirty && (
        <div className="fixed bottom-10 left-1/2 -translate-x-1/2 z-[60] animate-in slide-in-from-bottom-10">
          <button onClick={handleSave} className="flex items-center gap-3 px-8 py-4 bg-amber-600 text-white rounded-[24px] shadow-2xl hover:bg-amber-700 transition-all font-black uppercase text-[11px] tracking-widest">
            <Save className="w-5 h-5" /> Commit Changes to Vault
          </button>
        </div>
      )}

      <div className="sticky top-0 z-40 bg-white/80 backdrop-blur-xl border-b border-slate-100 px-8 py-4 flex items-center justify-between">
        <div className="flex items-center gap-6">
          <button onClick={onBack} className="p-2 hover:bg-slate-50 rounded-xl text-slate-400 transition-colors"><ArrowLeft className="w-5 h-5" /></button>
          <div className="flex items-center gap-2">
            <span className={`text-[9px] font-black uppercase tracking-widest ${style.text}`}>{exam.system}</span>
            <span className="w-1 h-1 rounded-full bg-slate-200" />
            {isEditMode ? (
              <input type="text" value={exam.name} onChange={(e) => updateGeneralField('name', e.target.value)} className="bg-amber-50 border-b border-amber-300 text-lg font-black outline-none px-1 rounded-sm focus:ring-1 focus:ring-amber-400" />
            ) : <h1 className="text-lg font-black text-slate-900">{exam.name}</h1>}
          </div>
        </div>
        <div className="flex items-center gap-4">
          <div className="flex items-center gap-2 px-4 py-2 bg-slate-50 rounded-2xl border border-slate-100"><span className="text-[10px] font-black text-slate-900">{progress}% Complete</span></div>
          <button onClick={() => setIsChecklistMode(!isChecklistMode)} className={`px-6 py-2.5 rounded-2xl text-[10px] font-black uppercase flex items-center gap-2 shadow-xl transition-all ${isChecklistMode ? 'bg-emerald-600 text-white' : 'bg-slate-900 text-white'}`}><ListCheck className="w-4 h-4" /> {isChecklistMode ? 'Exit OSCE' : 'Start OSCE'}</button>
        </div>
      </div>

      <div className="max-w-5xl mx-auto py-12 px-8">
        <div className="grid grid-cols-1 lg:grid-cols-5 gap-12 mb-16 items-center">
          <div className="lg:col-span-3">
             <div className="flex items-center gap-3 mb-6">
                <div className={`p-2 rounded-xl ${style.bg} ${style.text}`}>{style.icon}</div>
                {isEditMode ? <span className="flex items-center gap-2 text-amber-600 font-black uppercase text-[10px] tracking-widest"><Edit3 className="w-3 h-3" /> Drafting Mode</span> : <h2 className="text-3xl font-black text-slate-900 tracking-tighter leading-tight">{exam.name}</h2>}
             </div>
             {isEditMode ? (
               <textarea value={exam.shortDescription} onChange={(e) => updateGeneralField('shortDescription', e.target.value)} className="w-full min-h-[100px] p-4 bg-amber-50/30 border border-amber-200 rounded-2xl text-base text-slate-600 font-medium leading-[1.8] outline-none focus:ring-2 focus:ring-amber-400" />
             ) : <p className="text-base text-slate-500 font-medium leading-[1.8] mb-8">{exam.shortDescription}</p>}

             {isEditMode && (
               <div className="mt-6 flex flex-wrap gap-2">
                 <div className="flex items-center gap-2 px-3 py-1 bg-slate-100 rounded-xl text-[10px] font-black text-slate-400 uppercase tracking-widest">
                   <Hash className="w-3 h-3" /> Keywords
                 </div>
                 {exam.keywords.map((kw, i) => (
                   <div key={i} className="flex items-center bg-white border border-slate-200 rounded-xl overflow-hidden shadow-sm">
                     <span className="px-3 py-1 text-[10px] font-bold text-slate-600">{kw}</span>
                     <button onClick={() => updateGeneralField('keywords', exam.keywords.filter((_, idx) => idx !== i))} className="p-1.5 bg-slate-50 text-slate-400 hover:text-red-500 border-l border-slate-100"><X className="w-3 h-3" /></button>
                   </div>
                 ))}
                 <button 
                  onClick={() => {
                    const next = prompt("Enter new keyword:");
                    if (next) updateGeneralField('keywords', [...exam.keywords, next]);
                  }}
                  className="px-3 py-1 border border-dashed border-amber-300 text-amber-600 rounded-xl text-[10px] font-black uppercase hover:bg-amber-50"
                 >
                   + Add Keyword
                 </button>
               </div>
             )}
          </div>
          <div className="lg:col-span-2">
            <MedImage 
              src={!exam.localHeaderImageUrl ? exam.headerImageUrl : undefined} 
              localId={exam.localHeaderImageUrl} 
              alt="Anatomy Header" 
              label="Header Matrix" 
              fallbackIcon={style.icon} 
              onEnlarge={(src, alt) => setEnlargedImage({src, alt})}
              isEditMode={isEditMode}
              config={exam.headerImageConfig}
              onUpdateConfig={(cfg) => updateGeneralField('headerImageConfig', cfg)}
