import { DownloadTask, DownloadTaskStatus, Examination, ExamStep } from '../types';
import { GeminiService } from './geminiService';
import { storage } from './storageService';
import { EXAMINATIONS } from '../constants';

export class DownloadManagerService {
  private tasks: DownloadTask[] = [];
  private isPaused: boolean = false;
  private maxConcurrency: number = 1;
  private activeCount: number = 0;
  private listeners: Set<(tasks: DownloadTask[]) => void> = new Set();
  private gemini = new GeminiService();

  constructor() {
    const saved = localStorage.getItem('medex_download_queue');
    if (saved) {
      this.tasks = JSON.parse(saved).map((t: any) => ({
        ...t,
        status: (t.status === 'downloading' || t.status === 'pending') ? 'pending' : t.status
      }));
    }
    this.processQueue();
  }

  private notify() {
    localStorage.setItem('medex_download_queue', JSON.stringify(this.tasks));
    this.listeners.forEach(l => l([...this.tasks]));
  }

  subscribe(listener: (tasks: DownloadTask[]) => void) {
    this.listeners.add(listener);
    listener([...this.tasks]);
    return () => this.listeners.delete(listener);
  }

  async downloadAll() {
    const allDownloaded = await storage.getAllDownloaded();
    const downloadedIds = new Set(allDownloaded.map(e => e.id));

    // Filter examinations that aren't already downloaded or in the queue
    const toDownload = EXAMINATIONS.filter(exam => 
      !downloadedIds.has(exam.id) && 
      !this.tasks.find(t => t.examId === exam.id && t.status !== 'failed')
    );

    // PRIORITY LOGIC: Treat drafts and empty protocols as urgent gaps in the library
    toDownload.sort((a, b) => {
      const aIsPriority = a.isDraft || a.steps.length === 0;
      const bIsPriority = b.isDraft || b.steps.length === 0;

      if (aIsPriority && !bIsPriority) return -1;
      if (!aIsPriority && bIsPriority) return 1;
      return 0;
    });

    toDownload.forEach(exam => {
      this.addTask(exam.id);
    });
  }

  async clearArchive() {
    if (!confirm("Are you sure you want to purge the Knowledge Vault? This will delete all persistent offline files.")) return;
    await storage.clearArchive();
    this.tasks = [];
    this.notify();
    window.location.reload();
  }

  addTask(examId: string, type: DownloadTask['type'] = 'deep_sync') {
    const exam = EXAMINATIONS.find(e => e.id === examId);
    if (!exam) return;

    const existing = this.tasks.find(t => t.examId === examId && t.status !== 'completed');
    if (existing) return;

    const newTask: DownloadTask = {
      id: Math.random().toString(36).substr(2, 9),
      examId,
      examName: exam.name,
      type,
      status: 'pending',
      progress: 0,
      retryCount: 0,
      createdAt: Date.now()
    };

    this.tasks = [...this.tasks, newTask];
    this.notify();
    this.processQueue();
  }

  private async processQueue() {
    if (this.isPaused || this.activeCount >= this.maxConcurrency) return;

    const nextTask = this.tasks.find(t => t.status === 'pending');
    if (!nextTask) return;

    this.activeCount++;
    await this.runTask(nextTask);
    this.activeCount--;
    this.processQueue();
  }

  private async fetchAndStoreAsset(url: string, prefix: string): Promise<string | undefined> {
    try {
      const response = await fetch(url);
      if (!response.ok) throw new Error(`HTTP ${response.status}`);
      const blob = await response.blob();
      const assetId = `${prefix}_${Math.random().toString(36).substr(2, 5)}`;
      await storage.saveAsset(assetId, blob);
      return assetId; // Return the ID in the asset store
    } catch (e) {
      console.warn(`Asset fetch/store failed: ${url}`, e);
      return undefined;
    }
  }

  private async runTask(task: DownloadTask) {
    task.status = 'downloading';
    task.progress = 5;
    this.notify();

    try {
      const baseExam = EXAMINATIONS.find(e => e.id === task.examId);
      if (!baseExam) throw new Error('Exam definition not found');

      // STAGE 1: PROTOCOL SYNTHESIS
      task.progress = 15;
      task.error = "Synthesizing Protocol Structure...";
      this.notify();
      const populated = await this.gemini.populateExamination(baseExam);

      // STAGE 2: ASSET SERIALIZATION (TO DISK FOLDERS)
      task.progress = 40;
      task.error = "Archiving Visual Stigmata to Vault...";
      this.notify();

      // Store header image
      let headerAssetId: string | undefined;
      if (populated.headerImageUrl) {
        headerAssetId = await this.fetchAndStoreAsset(populated.headerImageUrl, `header_${task.examId}`);
      }

      // Store step images
      const processedSteps: ExamStep[] = await Promise.all((populated.steps || []).map(async (step, idx) => {
        const stepProgress = 40 + Math.floor((idx / (populated.steps?.length || 1)) * 50);
        if (task.progress < stepProgress) {
          task.progress = stepProgress;
          this.notify();
        }

        const processedStep = { ...step };

        // AUTO-GENERATE STEP IMAGE IF PROMPT EXISTS BUT NO URL
        let activeImageUrl = step.imageUrl;
        if (!activeImageUrl && step.imagePrompt) {
          try {
            activeImageUrl = await this.gemini.generateIllustration(step.imagePrompt, false);
          } catch (e) {
            console.warn(`Failed to auto-generate image for step: ${step.title}`);
          }
        }

        if (activeImageUrl) {
          processedStep.localImageUrl = await this.fetchAndStoreAsset(activeImageUrl, `step_${step.id}`);
        }

        // Handle positive finding images if present
        if (step.positiveFindings) {
          processedStep.positiveFindings = await Promise.all(step.positiveFindings.map(async (pf, pfIdx) => {
            if (pf.imageUrl) {
              const pfAssetId = await this.fetchAndStoreAsset(pf.imageUrl, `finding_${step.id}_${pfIdx}`);
              return { ...pf, localImageUrl: pfAssetId };
            }
            return pf;
          }));
        }
        return processedStep;
      }));

      // FINALIZATION: SAVE METADATA TO IDB
      const finalExam: Examination = {
        ...baseExam,
        ...populated,
        steps: processedSteps,
        headerImageUrl: populated.headerImageUrl, 
        localHeaderImageUrl: headerAssetId,
        isDownloaded: true,
        isDraft: false
      };

      await storage.saveExamination(finalExam);

      task.status = 'completed';
      task.progress = 100;
      task.error = undefined;
    } catch (err: any) {
      console.error('Download pipeline failure', err);
      task.status = 'failed';
      task.error = err?.message || 'Download Failed';
    } finally {
      this.notify();
    }
  }

  togglePause() { this.isPaused = !this.isPaused; if (!this.isPaused) this.processQueue(); this.notify(); }
  cancelTask(taskId: string) { this.tasks = this.tasks.filter(t => t.id !== taskId); this.notify(); this.processQueue(); }
  getTasks() { return [...this.tasks]; }
  getPauseState() { return this.isPaused; }
}

export const downloadManager = new DownloadManagerService();

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { ClinicalCorrelation, Examination, DiagnosisSuggestion, ClinicalCondition } from "../types";

export class GeminiService {
  private getAI() {
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  /**
   * Helper to wrap API calls with exponential backoff and retry logic.
   * Handles 429 (Rate Limit) and 500 (Transient Server) errors.
   */
  private async withRetry<T>(fn: () => Promise<T>, maxRetries = 3, initialDelay = 1500): Promise<T> {
    let lastError: any;
    for (let attempt = 0; attempt < maxRetries; attempt++) {
      try {
        return await fn();
      } catch (error: any) {
        lastError = error;
        const status = error?.status || (error?.error?.code);

        // If it's not a retryable error, throw immediately
        if (status !== 429 && status !== 500 && !error?.message?.includes('429') && !error?.message?.includes('500')) {
          throw error;
        }

        const delay = initialDelay * Math.pow(2, attempt);
        console.warn(`Gemini API Error ${status}. Retrying in ${delay}ms... (Attempt ${attempt + 1}/${maxRetries})`);
        await new Promise(resolve => setTimeout(resolve, delay));
      }
    }
    throw lastError;
  }

  public async generateIllustration(prompt: string, isPro: boolean = false): Promise<string | undefined> {
    return this.withRetry(async () => {
      const ai = this.getAI();
      try {
        if (isPro) {
          const response = await ai.models.generateImages({
            model: 'imagen-4.0-generate-001',
            prompt: `A professional medical textbook illustration. Topic: ${prompt}. Style: Clean, detailed scientific diagram, white background, precise anatomical labeling, realistic colors. High resolution.`,
            config: { numberOfImages: 1, aspectRatio: '16:9' },
          });
          return `data:image/png;base64,${response.generatedImages[0].image.imageBytes}`;
        } else {
          const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash-image',
            contents: { parts: [{ text: `Generate a professional medical textbook illustration of: ${prompt}. Clean white background, scientific diagram style, clear labeling.` }] },
            config: { imageConfig: { aspectRatio: "16:9" } }
          });
          for (const part of response.candidates[0].content.parts) {
            if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
          }
        }
      } catch (error) {
        console.error("Illustration generation failed", error);
        throw error; // Rethrow for withRetry to catch
      }
      return undefined;
    });
  }

  async getClinicalCorrelation(sign: string, context: string, isPro: boolean = false): Promise<ClinicalCorrelation> {
    return this.withRetry(async () => {
      const ai = this.getAI();
      const model = isPro ? "gemini-3-pro-preview" : "gemini-3-flash-preview";
      const response: GenerateContentResponse = await ai.models.generateContent({
        model,
        contents: `Explain the clinical and physiological significance of '${sign}' in a ${context} context. Focus on pathophysiology and causes. Determine if this sign involves circulatory changes or specific anatomy.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              sign: { type: Type.STRING },
              pathophysiology: { type: Type.STRING },
              causes: { type: Type.ARRAY, items: { type: Type.STRING } },
              clinicalSignificance: { type: Type.STRING },
              imagePrompt: { type: Type.STRING },
              needsCirculationDiagram: { type: Type.BOOLEAN },
              circulationSide: { type: Type.STRING, enum: ["left-sided", "right-sided"] },
              needsPVLoopDiagram: { type: Type.BOOLEAN },
              needsAnatomyDiagram: { type: Type.BOOLEAN },
              affectedAnatomy: { type: Type.STRING }
            },
            required: ["sign", "pathophysiology", "causes", "clinicalSignificance", "imagePrompt", "needsCirculationDiagram", "needsPVLoopDiagram", "needsAnatomyDiagram"]
          }
        }
      });

      const correlation = JSON.parse(response.text || "{}") as ClinicalCorrelation;
      correlation.imageUrl = await this.generateIllustration(correlation.imagePrompt || correlation.sign, isPro);
      if (correlation.needsCirculationDiagram) correlation.circulationImageUrl = await this.generateIllustration(`Diagram of ${correlation.circulationSide || 'systemic'} circulation for ${correlation.sign}`, isPro);
      if (correlation.needsPVLoopDiagram) correlation.pvLoopImageUrl = await this.generateIllustration(`Cardiac pressure-volume loop for ${correlation.sign}`, isPro);
      if (correlation.needsAnatomyDiagram) correlation.anatomyImageUrl = await this.generateIllustration(`Anatomy of the ${correlation.affectedAnatomy || correlation.sign}`, isPro);

      return correlation;
    });
  }

  async populateExamination(exam: Examination): Promise<Partial<Examination>> {
    return this.withRetry(async () => {
      const ai = this.getAI();
      const response: GenerateContentResponse = await ai.models.generateContent({
        model: "gemini-3-flash-preview", 
        contents: `Detailed clinical protocol for '${exam.name}' within the ${exam.system} system.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              steps: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    id: { type: Type.STRING },
                    title: { type: Type.STRING },
                    description: { type: Type.STRING },
                    category: { type: Type.STRING },
                    imagePrompt: { type: Type.STRING },
                    positiveFindings: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { description: { type: Type.STRING } } } }
                  },
                  required: ["id", "title", "description", "category"]
                }
              },
              headerImagePrompt: { type: Type.STRING }
            },
            required: ["steps", "headerImagePrompt"]
          }
        }
      });

      const data = JSON.parse(response.text || "{}");
      const headerImageUrl = await this.generateIllustration(data.headerImagePrompt, false);
      return { steps: data.steps || [], headerImageUrl, headerImagePrompt: data.headerImagePrompt };
    });
  }

  async getDifferentialDiagnosis(findings: string[], system: string): Promise<DiagnosisSuggestion[]> {
    return this.withRetry(async () => {
      const ai = this.getAI();
      const response: GenerateContentResponse = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Differential diagnosis for: [${findings.join(', ')}] in ${system}.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                condition: { type: Type.STRING },
                probability: { type: Type.STRING, enum: ["High", "Moderate", "Low"] },
                reasoning: { type: Type.STRING },
                keyFindings: { type: Type.ARRAY, items: { type: Type.STRING } }
              },
              required: ["condition", "probability", "reasoning", "keyFindings"]
            }
          }
        }
      });
      return JSON.parse(response.text || "[]");
    });
  }

  async getFindingsForCondition(conditionName: string): Promise<ClinicalCondition> {
    return this.withRetry(async () => {
      const ai = this.getAI();
      const response: GenerateContentResponse = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Physical exam findings for '${conditionName}'.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              name: { type: Type.STRING },
              system: { type: Type.STRING },
              description: { type: Type.STRING },
              findings: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: { category: { type: Type.STRING }, sign: { type: Type.STRING }, significance: { type: Type.STRING }, link: { type: Type.STRING } },
                  required: ["category", "sign", "significance", "link"]
                }
              }
            },
            required: ["name", "description", "findings"]
          }
        }
      });
      return JSON.parse(response.text || "{}");
    });
  }
}

import { DownloadTask, DownloadTaskStatus, Examination, ExamStep } from '../types';
import { GeminiService } from './geminiService';
import { storage } from './storageService';
import { EXAMINATIONS } from '../constants';

export class DownloadManagerService {
  private tasks: DownloadTask[] = [];
  private isPaused: boolean = false;
  private maxConcurrency: number = 1;
  private activeCount: number = 0;
  private listeners: Set<(tasks: DownloadTask[]) => void> = new Set();
  private gemini = new GeminiService();

  constructor() {
    const saved = localStorage.getItem('medex_download_queue');
    if (saved) {
      this.tasks = JSON.parse(saved).map((t: any) => ({
        ...t,
        status: (t.status === 'downloading' || t.status === 'pending') ? 'pending' : t.status
      }));
    }
    this.processQueue();
  }

  private notify() {
    localStorage.setItem('medex_download_queue', JSON.stringify(this.tasks));
    this.listeners.forEach(l => l([...this.tasks]));
  }

  subscribe(listener: (tasks: DownloadTask[]) => void) {
    this.listeners.add(listener);
    listener([...this.tasks]);
    return () => this.listeners.delete(listener);
  }

  async downloadAll() {
    const allDownloaded = await storage.getAllDownloaded();
    const downloadedIds = new Set(allDownloaded.map(e => e.id));

    const toDownload = EXAMINATIONS.filter(exam => 
      !downloadedIds.has(exam.id) && 
      !this.tasks.find(t => t.examId === exam.id && t.status !== 'failed')
    );

    // Treat drafts and empty protocols as priority
    toDownload.sort((a, b) => {
      const aIsPriority = a.isDraft || a.steps.length === 0;
      const bIsPriority = b.isDraft || b.steps.length === 0;
      if (aIsPriority && !bIsPriority) return -1;
      if (!aIsPriority && bIsPriority) return 1;
      return 0;
    });

    toDownload.forEach(exam => {
      this.addTask(exam.id);
    });
  }

  retryTask(taskId: string) {
    const task = this.tasks.find(t => t.id === taskId);
    if (task) {
      task.status = 'pending';
      task.error = undefined;
      task.retryCount = 0;
      this.notify();
      this.processQueue();
    }
  }

  async clearArchive() {
    if (!confirm("Are you sure you want to purge the Knowledge Vault? This will delete all persistent offline files.")) return;
    await storage.clearArchive();
    this.tasks = [];
    this.notify();
    window.location.reload();
  }

  addTask(examId: string, type: DownloadTask['type'] = 'deep_sync') {
    const exam = EXAMINATIONS.find(e => e.id === examId);
    if (!exam) return;

    const existing = this.tasks.find(t => t.examId === examId && t.status !== 'completed');
    if (existing) return;

    const newTask: DownloadTask = {
      id: Math.random().toString(36).substr(2, 9),
      examId,
      examName: exam.name,
      type,
      status: 'pending',
      progress: 0,
      retryCount: 0,
      createdAt: Date.now()
    };

    this.tasks = [...this.tasks, newTask];
    this.notify();
    this.processQueue();
  }

  private async processQueue() {
    if (this.isPaused || this.activeCount >= this.maxConcurrency) return;

    const nextTask = this.tasks.find(t => t.status === 'pending');
    if (!nextTask) return;

    this.activeCount++;
    await this.runTask(nextTask);
    this.activeCount--;
    this.processQueue();
  }

  private async fetchAndStoreAsset(url: string, prefix: string): Promise<string | undefined> {
    try {
      const response = await fetch(url);
      if (!response.ok) throw new Error(`HTTP ${response.status}`);
      const blob = await response.blob();
      const assetId = `${prefix}_${Math.random().toString(36).substr(2, 5)}`;
      await storage.saveAsset(assetId, blob);
      return assetId;
    } catch (e) {
      console.warn(`Asset fetch/store failed: ${url}`, e);
      return undefined;
    }
  }

  private async runTask(task: DownloadTask) {
    task.status = 'downloading';
    task.progress = 5;
    this.notify();

    try {
      const baseExam = EXAMINATIONS.find(e => e.id === task.examId);
      if (!baseExam) throw new Error('Exam definition not found');

      // STAGE 1: PROTOCOL SYNTHESIS
      task.progress = 15;
      task.error = "Synthesizing Protocol Structure...";
      this.notify();
      const populated = await this.gemini.populateExamination(baseExam);

      // STAGE 2: ASSET SERIALIZATION
      task.progress = 40;
      task.error = "Archiving Visual Stigmata to Vault...";
      this.notify();

      let headerAssetId: string | undefined;
      if (populated.headerImageUrl) {
        headerAssetId = await this.fetchAndStoreAsset(populated.headerImageUrl, `header_${task.examId}`);
      }

      const processedSteps: ExamStep[] = await Promise.all((populated.steps || []).map(async (step, idx) => {
        const stepProgress = 40 + Math.floor((idx / (populated.steps?.length || 1)) * 50);
        if (task.progress < stepProgress) {
          task.progress = stepProgress;
          this.notify();
        }

        const processedStep = { ...step };
        let activeImageUrl = step.imageUrl;

        if (!activeImageUrl && step.imagePrompt) {
          try {
            activeImageUrl = await this.gemini.generateIllustration(step.imagePrompt, false);
          } catch (e) {
            console.warn(`Transient image generation error for step: ${step.title}`);
          }
        }

        if (activeImageUrl) {
          processedStep.localImageUrl = await this.fetchAndStoreAsset(activeImageUrl, `step_${step.id}`);
        }

        if (step.positiveFindings) {
          processedStep.positiveFindings = await Promise.all(step.positiveFindings.map(async (pf, pfIdx) => {
            if (pf.imageUrl) {
              const pfAssetId = await this.fetchAndStoreAsset(pf.imageUrl, `finding_${step.id}_${pfIdx}`);
              return { ...pf, localImageUrl: pfAssetId };
            }
            return pf;
          }));
        }
        return processedStep;
      }));

      const finalExam: Examination = {
        ...baseExam,
        ...populated,
        steps: processedSteps,
        headerImageUrl: populated.headerImageUrl, 
        localHeaderImageUrl: headerAssetId,
        isDownloaded: true,
        isDraft: false
      };

      await storage.saveExamination(finalExam);
      task.status = 'completed';
      task.progress = 100;
      task.error = undefined;
    } catch (err: any) {
      console.error('Download pipeline failure', err);
      task.status = 'failed';
      const isQuotaError = err?.message?.includes('429') || err?.status === 429;
      task.error = isQuotaError ? 'Quota Exceeded - Check Billing/Plan' : (err?.message || 'Download Failed');
    } finally {
      this.notify();
    }
  }

  togglePause() { this.isPaused = !this.isPaused; if (!this.isPaused) this.processQueue(); this.notify(); }
  cancelTask(taskId: string) { this.tasks = this.tasks.filter(t => t.id !== taskId); this.notify(); this.processQueue(); }
  getTasks() { return [...this.tasks]; }
  getPauseState() { return this.isPaused; }
}

export const downloadManager = new DownloadManagerService();

import React, { useState, useEffect, useMemo } from 'react';
import { downloadManager } from '../services/downloadManagerService';
import { DownloadTask } from '../types';
import Tooltip from './Tooltip';
import { 
  CloudDownload, 
  Trash2, 
  Pause, 
  CheckCircle2, 
  AlertCircle,
  Loader2,
  ArrowDownToLine,
  RefreshCw,
  FileText,
  Brain,
  Image as ImageIcon,
  Sparkles,
  Library
} from 'lucide-react';

const DownloadManager: React.FC = () => {
  const [tasks, setTasks] = useState<DownloadTask[]>([]);
  const [isPaused, setIsPaused] = useState(false);
  const [isDraggingOverTrash, setIsDraggingOverTrash] = useState(false);

  useEffect(() => {
    const unsub = downloadManager.subscribe((newTasks) => {
      setTasks(newTasks);
      setIsPaused(downloadManager.getPauseState());
    });
    return () => { unsub(); };
  }, []);

  const stats = useMemo(() => {
    const completed = tasks.filter(t => t.status === 'completed').length;
    const active = tasks.filter(t => t.status === 'downloading').length;
    const queued = tasks.filter(t => t.status === 'pending').length;
    const failed = tasks.filter(t => t.status === 'failed').length;
    return { completed, active, queued, failed, total: tasks.length };
  }, [tasks]);

  const getStatusIcon = (status: DownloadTask['status']) => {
    switch (status) {
      case 'completed': return <CheckCircle2 className="w-4 h-4 text-green-500" />;
      case 'failed': return <AlertCircle className="w-4 h-4 text-red-500" />;
      case 'downloading': return <Loader2 className="w-4 h-4 text-blue-500 animate-spin" />;
      case 'paused': return <Pause className="w-4 h-4 text-slate-400" />;
      default: return <RefreshCw className="w-4 h-4 text-slate-300" />;
    }
  };

  const getSubTaskStatus = (progress: number, start: number, end: number) => {
    if (progress >= end) return 'completed';
    if (progress >= start) return 'active';
    return 'pending';
  };

  const SubTaskPip: React.FC<{ 
    label: string; 
    icon: React.ReactNode; 
    status: 'completed' | 'active' | 'pending';
    error?: boolean;
  }> = ({ label, icon, status, error }) => {
    const colors = {
      completed: 'text-emerald-500 border-emerald-100 bg-emerald-50',
      active: 'text-blue-600 border-blue-200 bg-blue-50 animate-pulse',
      pending: 'text-slate-300 border-slate-50 bg-slate-50/50'
    };

    return (
      <div className={`flex flex-col items-center gap-1.5 flex-1 p-2 rounded-xl border transition-all duration-500 ${colors[status]} ${error && status === 'active' ? 'text-red-500 border-red-100 bg-red-50' : ''}`}>
        <div className="shrink-0">{status === 'completed' ? <CheckCircle2 className="w-3.5 h-3.5" /> : icon}</div>
        <span className="text-[7px] font-black uppercase tracking-tighter text-center">{label}</span>
      </div>
    );
  };

  return (
    <div className="max-w-4xl mx-auto py-8 px-6 animate-in fade-in duration-700 flex flex-col h-full overflow-hidden">
      <header className="flex items-center justify-between mb-8 shrink-0">
        <div className="flex items-center gap-4">
           <div className="p-3 bg-blue-50 rounded-2xl border border-blue-100 text-blue-600 shadow-sm"><CloudDownload className="w-6 h-6" /></div>
           <div>
             <h1 className="text-2xl font-black text-slate-900 tracking-tight uppercase">Data Pipeline</h1>
             <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Resilient Library Sync</p>
           </div>
        </div>

        <div className="flex items-center gap-3">
          <Tooltip content="Purge all downloaded data">
            <button 
              onClick={() => downloadManager.clearArchive()}
              className="p-3 bg-white border border-slate-200 text-slate-400 hover:text-red-500 hover:border-red-200 rounded-xl transition-all shadow-sm"
            >
              <Trash2 className="w-4 h-4" />
            </button>
          </Tooltip>

          <button 
            onClick={() => downloadManager.downloadAll()}
            className="px-6 py-2.5 bg-slate-900 text-white rounded-xl font-black uppercase tracking-widest text-[10px] transition-all hover:bg-slate-800 shadow-xl flex items-center gap-2"
          >
            <Library className="w-4 h-4" /> Sync Entire Library
          </button>

          <Tooltip content={isPaused ? "Resume Pipeline" : "Pause Queue"}>
            <button 
              onClick={() => downloadManager.togglePause()}
              className={`px-6 py-2.5 rounded-xl font-black uppercase tracking-widest text-[10px] transition-all shadow-xl ${isPaused ? 'bg-emerald-600 text-white' : 'bg-white border border-slate-200 text-slate-600'}`}
            >
              {isPaused ? 'Resume' : 'Pause'}
            </button>
          </Tooltip>
        </div>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-8 flex-1 min-h-0">
        <div className="lg:col-span-3 flex flex-col min-h-0">
          <div className="flex-1 bg-slate-50/50 rounded-[40px] border border-slate-100 overflow-y-auto p-6 space-y-4 custom-scrollbar">
            {tasks.length === 0 ? (
              <div className="h-full flex flex-col items-center justify-center text-slate-300 animate-in fade-in duration-1000">
                <div className="p-6 bg-white rounded-full shadow-inner border border-slate-50 mb-4">
                  <ArrowDownToLine className="w-10 h-10 opacity-20" />
                </div>
                <p className="text-[11px] font-black uppercase tracking-[0.3em]">No Active Transfers</p>
                <p className="text-[9px] font-bold text-slate-400 uppercase mt-2">Add protocols or use 'Sync All' to begin</p>
              </div>
            ) : tasks.map((task, idx) => {
              const p = task.progress;
              const isFailed = task.status === 'failed';
              const isQueued = task.status === 'pending';

              return (
                <div 
                  key={task.id} 
                  draggable 
                  onDragStart={(e) => e.dataTransfer.setData('taskId', task.id)}
                  className={`p-6 bg-white rounded-[32px] border transition-all duration-500 animate-in slide-in-from-right-4 group/task ${
                    isQueued ? 'opacity-60 grayscale-[0.5] border-slate-50' : 'border-slate-100 shadow-sm hover:shadow-md'
                  }`} 
                  style={{ animationDelay: `${idx * 100}ms` }}
                >
                  <div className="flex items-center justify-between gap-4 mb-6">
                     <div className="flex items-center gap-4">
                        <div className={`p-3 rounded-2xl transition-all duration-500 ${isFailed ? 'bg-red-50' : 'bg-slate-50'}`}>
                          {getStatusIcon(task.status)}
                        </div>
                        <div>
                          <div className="flex items-center gap-2">
                             <h4 className="text-sm font-black text-slate-900 leading-none">{task.examName}</h4>
                             {isFailed && (
                               <button 
                                 onClick={() => downloadManager.retryTask(task.id)}
                                 className="flex items-center gap-1.5 px-2 py-0.5 bg-red-100 text-red-600 rounded-md text-[8px] font-black uppercase hover:bg-red-600 hover:text-white transition-all"
                               >
                                 <RefreshCw className="w-2.5 h-2.5" /> Retry
                               </button>
                             )}
                          </div>
                          <div className="flex items-center gap-2 mt-1">
                             <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{task.type}</span>
                             <span className="w-1 h-1 rounded-full bg-slate-200" />
                             <span className={`text-[9px] font-bold italic ${isFailed ? 'text-red-500' : isQueued ? 'text-slate-400' : 'text-blue-500'}`}>
                               {task.error || (task.status === 'completed' ? 'Stored' : isQueued ? 'Waiting in Queue...' : 'Syncing Assets...')}
                             </span>
                          </div>
                        </div>
                     </div>
                     <div className="text-right">
                        <div className={`text-lg font-black tabular-nums tracking-tighter ${isQueued ? 'text-slate-300' : 'text-slate-900'}`}>{p}%</div>
                     </div>
                  </div>

                  <div className="flex gap-2 items-stretch">
                    <SubTaskPip label="Protocol" icon={<FileText className="w-3.5 h-3.5" />} status={getSubTaskStatus(p, 0, 15)} error={isFailed} />
                    <SubTaskPip label="Reasoning" icon={<Brain className="w-3.5 h-3.5" />} status={getSubTaskStatus(p, 16, 40)} error={isFailed} />
                    <SubTaskPip label="Stigmata" icon={<ImageIcon className="w-3.5 h-3.5" />} status={getSubTaskStatus(p, 41, 75)} error={isFailed} />
                    <SubTaskPip label="Verify" icon={<CheckCircle2 className="w-3.5 h-3.5" />} status={getSubTaskStatus(p, 96, 100)} error={isFailed} />
                  </div>

                  <div className="mt-4 w-full h-1 bg-slate-50 rounded-full overflow-hidden">
                    <div 
                      className={`h-full transition-all duration-1000 ${isFailed ? 'bg-red-500' : 'bg-blue-600'}`} 
                      style={{ width: `${p}%` }} 
                    />
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        <div className="space-y-6 flex flex-col">
          <div 
            onDrop={(e) => { e.preventDefault(); const id = e.dataTransfer.getData('taskId'); if(id) downloadManager.cancelTask(id); setIsDraggingOverTrash(false); }}
            onDragOver={(e) => { e.preventDefault(); setIsDraggingOverTrash(true); }}
            onDragLeave={() => setIsDraggingOverTrash(false)}
            className={`flex-1 min-h-[150px] rounded-[40px] border-2 border-dashed flex flex-col items-center justify-center transition-all duration-500 relative overflow-hidden group/trash ${isDraggingOverTrash ? 'border-red-500 bg-red-50 text-red-500 scale-105 rotate-2' : 'border-slate-200 bg-white text-slate-400 hover:border-slate-300'}`}
          >
            <Trash2 className={`w-8 h-8 mb-3 transition-transform ${isDraggingOverTrash ? 'animate-bounce scale-125' : 'group-hover/trash:rotate-12'}`} />
            <p className="text-[10px] font-black uppercase tracking-[0.2em] text-center px-4">Cancel Download</p>
          </div>

          <div className="p-8 bg-slate-900 rounded-[40px] text-white shadow-2xl relative overflow-hidden">
             <div className="relative z-10">
               <div className="flex items-center gap-2 text-blue-400 mb-4">
                  <Sparkles className="w-4 h-4" />
                  <span className="text-[9px] font-black uppercase tracking-widest">Library Pulse</span>
               </div>
               <div className="space-y-1 mb-6">
                 <p className="text-3xl font-black tracking-tighter tabular-nums">
                   {stats.completed}<span className="text-slate-500 mx-1">/</span>{stats.total || '0'}
                 </p>
                 <p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Active Batch Status</p>
               </div>
               <div className="flex items-center gap-3 mb-2">
                 <div className="flex-1 h-1.5 bg-slate-800 rounded-full overflow-hidden">
                   <div 
                     className="h-full bg-blue-500 transition-all duration-1000" 
                     style={{ width: `${stats.total > 0 ? (stats.completed / stats.total) * 100 : 0}%` }} 
                   />
                 </div>
               </div>
               {stats.failed > 0 && (
                 <p className="text-[8px] font-black text-red-400 uppercase tracking-widest mt-2 flex items-center gap-1">
                   <AlertCircle className="w-2.5 h-2.5" /> {stats.failed} Pipeline Disruptions
                 </p>
               )}
               {stats.queued > 0 && (
                 <p className="text-[8px] font-black text-blue-400 uppercase tracking-widest mt-1">
                   {stats.queued} Sequential Tasks Pending
                 </p>
               )}
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default DownloadManager;
